function activeDataScope() {
  return DATA_SCOPES.includes(state.dataScope) ? state.dataScope : DEFAULT_DATA_SCOPE;
}

function dataScopeLabel() {
  return activeDataScope() === "real" ? "all real stations" : "operational stations";
}

function routeKeyForPage(page) {
  return PAGE_ROUTE_KEYS[page] || page || "observe";
}

function isLiveSimulationTime() {
  return state.globalSimulationTime === "LIVE";
}

function simulationTimeMs() {
  if (isLiveSimulationTime()) {
    return Date.now();
  }
  const parsed = Number(state.globalSimulationTime);
  return Number.isFinite(parsed) ? parsed : Date.now();
}

function simulationTimeIso() {
  return new Date(simulationTimeMs()).toISOString();
}

function temporalQueryParams() {
  return {
    simulation_time: isLiveSimulationTime() ? "LIVE" : simulationTimeIso(),
    depth_m: Number(state.selectedZDepth || 0),
  };
}

function datetimeLocalValue(timestampMs) {
  const date = new Date(timestampMs);
  if (Number.isNaN(date.getTime())) {
    return "";
  }
  return date.toISOString().slice(0, 16);
}

function parseDatetimeLocalAsUtc(value) {
  const normalized = String(value || "").trim();
  if (!normalized) {
    return null;
  }
  const timestamp = new Date(`${normalized.length === 16 ? normalized + ":00" : normalized}Z`).getTime();
  return Number.isFinite(timestamp) ? timestamp : null;
}

function temporalModeLabel() {
  return isLiveSimulationTime() ? "LIVE" : shortTime(simulationTimeIso());
}

function copernicusAnimationRequestProfile(fieldId, coverage = state.copernicusWindCoverage) {
  const profile = COPERNICUS_DENSE_ANIMATION_PROFILES[fieldId] || COPERNICUS_DENSE_ANIMATION_PROFILES.wind;
  const normalizedCoverage = coverage === "global" ? "global" : "mission";
  return {
    ...profile,
    maxPoints: normalizedCoverage === "global" ? profile.globalPoints : profile.missionPoints,
  };
}

function normalizedCopernicusTimelineMode(mode = state.copernicusTimelineMode) {
  return Object.prototype.hasOwnProperty.call(COPERNICUS_TIMELINE_MODES, mode) ? mode : "recent";
}

function copernicusTimelineProfile(mode = state.copernicusTimelineMode) {
  return COPERNICUS_TIMELINE_MODES[normalizedCopernicusTimelineMode(mode)] || COPERNICUS_TIMELINE_MODES.recent;
}

function copernicusTimelineModeLabel(mode = state.copernicusTimelineMode) {
  return copernicusTimelineProfile(mode).label;
}

function copernicusUsesNumericTimeline(mode = state.copernicusTimelineMode) {
  return normalizedCopernicusTimelineMode(mode) === "recent";
}

function copernicusCacheKey(fieldId, coverage = state.copernicusWindCoverage) {
  const temporalParams = temporalQueryParams();
  const normalizedField = COPERNICUS_OVERLAY_MODES.includes(fieldId) ? fieldId : "wind";
  const normalizedCoverage = coverage === "global" ? "global" : "mission";
  const profile = copernicusAnimationRequestProfile(normalizedField, normalizedCoverage);
  const timelineMode = normalizedCopernicusTimelineMode();
  const forecastLead = copernicusFieldSupportsForecast(normalizedField) ? (state.copernicusForecastLead || 0) : 0;
  return `${normalizedField}:${normalizedCoverage}:${timelineMode}:${temporalParams.simulation_time}:${temporalParams.depth_m}:${profile.frameCount}:${profile.windowHours}:${profile.maxPoints}:fc${forecastLead}`;
}

function activateCachedCopernicusField(fieldId = state.mapOverlayMode, coverage = state.copernicusWindCoverage) {
  if (!COPERNICUS_OVERLAY_MODES.includes(fieldId)) {
    return false;
  }
  const normalizedCoverage = coverage === "global" ? "global" : "mission";
  const cached = state.copernicusFieldCache[copernicusCacheKey(fieldId, normalizedCoverage)];
  if (cached && Date.now() - cached.fetchedAt < 15 * 60 * 1000) {
    state.copernicusWindField = cached.payload;
    state.copernicusWindState = "ready";
    state.copernicusWindMessage = "";
    state.copernicusFieldLoadedId = fieldId;
    state.copernicusWindLoadedCoverage = normalizedCoverage;
    state.copernicusWindFetchedAt = cached.fetchedAt;
    state.copernicusFieldFrameIndex = 0;
    state.copernicusFieldAnimationStartedAt = performance.now();
    return true;
  }
  state.copernicusWindField = null;
  state.copernicusWindLoadedCoverage = null;
  state.copernicusFieldLoadedId = null;
  state.copernicusWindFetchedAt = 0;
  state.copernicusWindState = "idle";
  state.copernicusWindMessage = "";
  return false;
}

function clearCopernicusNumericFieldState() {
  state.copernicusWindField = null;
  state.copernicusWindLoadedCoverage = null;
  state.copernicusFieldLoadedId = null;
  state.copernicusWindFetchedAt = 0;
  state.copernicusWindState = "idle";
  state.copernicusWindMessage = "";
  state.copernicusWindPromise = null;
  state.copernicusWindPromiseKey = null;
  state.copernicusFieldFrameIndex = 0;
  state.copernicusFieldAnimationStartedAt = 0;
}

function copernicusCatalogLayerForField(fieldId = state.mapOverlayMode) {
  if (!COPERNICUS_OVERLAY_MODES.includes(fieldId)) {
    return null;
  }
  return (state.layers || []).find(
    (layer) =>
      layerProvider(layer) === "copernicus-marine" &&
      layer.source_type === "wmts" &&
      layer.tags?.field_id === fieldId
  ) || null;
}

function activeCopernicusCatalogLayer(fieldId = state.mapOverlayMode) {
  const layer = copernicusCatalogLayerForField(fieldId);
  return layer && layerCatalogActiveEntry(layer.layer_id) ? layer : null;
}

function activeCopernicusCatalogEntry(fieldId = state.mapOverlayMode) {
  const layer = activeCopernicusCatalogLayer(fieldId);
  return layer ? layerCatalogActiveEntry(layer.layer_id) : null;
}

