const $ = (id) => document.getElementById(id);

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function formatName(value) {
  return String(value || "unknown")
    .replace(/[-_]/g, " ")
    .replace(/\b\w/g, (letter) => letter.toUpperCase());
}

function telemetryLabel(name) {
  return TELEMETRY_LABELS[name] || formatName(name);
}

function friendlyUnit(unit = "") {
  const normalized = String(unit || "");
  if (normalized === "degC") {
    return "deg C";
  }
  if (normalized === "deg") {
    return "deg";
  }
  return normalized;
}

function formatValue(value, unit = "") {
  if (value === null || value === undefined || value === "") {
    return "-";
  }
  if (typeof value === "number") {
    const rounded = Math.abs(value) >= 100 ? value.toFixed(0) : value.toFixed(2).replace(/\.?0+$/, "");
    return `${rounded}${unit ? ` ${friendlyUnit(unit)}` : ""}`;
  }
  return `${value}${unit ? ` ${friendlyUnit(unit)}` : ""}`;
}

function shortTime(value) {
  if (!value) {
    return "-";
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return value;
  }
  return date.toLocaleString([], {
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function formatAge(seconds) {
  const value = Number(seconds);
  if (!Number.isFinite(value)) {
    return "-";
  }
  if (value < 90) {
    return `${Math.round(value)} sec`;
  }
  if (value < 5400) {
    return `${Math.round(value / 60)} min`;
  }
  if (value < 172800) {
    return `${Math.round(value / 3600)} hr`;
  }
  return `${Math.round(value / 86400)} days`;
}

function stationCoordinates(feature) {
  const coordinates = feature?.geometry?.coordinates || [];
  if (coordinates.length < 2) {
    return "-";
  }
  return `${Number(coordinates[1]).toFixed(4)}, ${Number(coordinates[0]).toFixed(4)}`;
}

function featureEntityId(feature) {
  const props = feature?.properties || {};
  return props.node_id || props.device_id || props.label || props.site || "";
}

function resetStationContextUi() {
  if ($("station-freshness")) {
    $("station-freshness").textContent = "No station";
    $("station-freshness").className = "pill";
  }
  if ($("station-kpis")) {
    $("station-kpis").innerHTML = "";
  }
  if ($("station-metrics")) {
    $("station-metrics").innerHTML = `<div class="empty">No station selected.</div>`;
  }
  if ($("station-chart")) {
    $("station-chart").innerHTML = `<div class="empty">Recent metric history will appear here.</div>`;
  }
}

function renderContextDrawer() {
  const drawer = $("context-drawer");
  if (!drawer) {
    return;
  }
  const entity = state.selectedMapEntity;
  const isOpen = Boolean(entity);
  drawer.hidden = !isOpen;
  drawer.classList.toggle("is-open", isOpen);
  document.body.classList.toggle("has-context-drawer", isOpen);
  if (!isOpen) {
    return;
  }

  const selectedId = entity.id || "";
  const feature =
    entity.type === "node"
      ? state.features.find((item) => featureEntityId(item) === selectedId || item.properties?.node_id === selectedId) || state.selectedFeature
      : null;
  const props = feature?.properties || {};
  const label = props.label || props.site || props.node_id || props.device_id || selectedId || "Selected entity";
  const subtitle =
    entity.type === "node" && feature
      ? `${stationCoordinates(feature)} | ${formatName(props.tags?.source || props.source_class || "station")} | age ${formatAge(props.age_s)}`
      : "Context is attached to the selected map object.";

  if ($("context-drawer-type")) {
    $("context-drawer-type").textContent = entity.type === "node" ? "Station Context" : `${formatName(entity.type)} Context`;
  }
  if ($("context-drawer-title")) {
    $("context-drawer-title").textContent = label;
  }
  if ($("context-drawer-subtitle")) {
    $("context-drawer-subtitle").textContent = subtitle;
  }
  const nodeReady = entity.type === "node" && Boolean(props.node_id || selectedId);
  if ($("context-route-button")) {
    $("context-route-button").disabled = !nodeReady;
  }
  if ($("context-message-button")) {
    $("context-message-button").disabled = !nodeReady;
  }
}

function setSelectedMapEntity(entity) {
  state.selectedMapEntity = entity || null;
  renderContextDrawer();
}

function clearSelectedMapEntity({ clearFeature = false } = {}) {
  state.selectedMapEntity = null;
  if (clearFeature) {
    state.selectedFeature = null;
    state.selectedDetail = null;
    resetStationContextUi();
    renderChartSuite();
    renderMapVisualizationDock();
    renderGlobeScene();
  }
  renderContextDrawer();
}

function formatLatLng(latlng, precision = 5) {
  if (!latlng || !Number.isFinite(Number(latlng.lat)) || !Number.isFinite(Number(latlng.lng ?? latlng.lon))) {
    return "-";
  }
  const lat = Number(latlng.lat);
  const lon = Number(latlng.lng ?? latlng.lon);
  return `${lat.toFixed(precision)}, ${lon.toFixed(precision)}`;
}

async function writeClipboardText(text) {
  if (navigator.clipboard?.writeText) {
    await navigator.clipboard.writeText(text);
    return;
  }
  const textarea = document.createElement("textarea");
  textarea.value = text;
  document.body.appendChild(textarea);
  textarea.select();
  document.execCommand("copy");
  textarea.remove();
}

function apiUrl(path, params = {}) {
  const url = new URL(path, gatewayBase);
  for (const [key, value] of Object.entries(params)) {
    if (value !== undefined && value !== null && value !== "") {
      url.searchParams.set(key, value);
    }
  }
  return url.toString();
}

async function api(path, params = {}, options = {}) {
  const ownerHeaders = state.ownerApiKey ? { "X-OMEGA-API-Key": state.ownerApiKey } : {};
  const response = await fetch(apiUrl(path, params), {
    ...options,
    headers: {
      "Content-Type": "application/json",
      ...ownerHeaders,
      ...(options.headers || {}),
    },
  });
  if (!response.ok) {
    const text = await response.text();
    let message = text || `${response.status} ${response.statusText}`;
    try {
      const parsed = JSON.parse(text);
      message = typeof parsed.detail === "string" ? parsed.detail : JSON.stringify(parsed.detail || parsed);
    } catch {
      // Keep the raw response text.
    }
    throw new Error(message);
  }
  return response.json();
}

function apiGet(path, params = {}) {
  return api(path, params);
}

function apiPost(path, body = {}, params = {}) {
  return api(path, params, {
    method: "POST",
    body: JSON.stringify(body || {}),
  });
}

function credentialRestartHint() {
  return "If you set the key in PowerShell after the gateway was already running, restart the gateway from that same PowerShell session or put the variables in ~/.omega-wave/secrets.env.";
}

