/** Average care-difficulty across all pets in the sanctuary. Endangered
 *  species (lower difficulty) slow the whole tank's decay, since they're
 *  bred + handled with more care. */
function _bbsAqAvgDifficulty(s) {
  if (!s.pets || !s.pets.length) return 1.0;
  const sum = s.pets.reduce((acc, p) => {
    const sp = BBS_AQ_SPECIES.find((x) => x.id === p.species);
    return acc + (sp?.difficulty ?? 1.0);
  }, 0);
  return sum / s.pets.length;
}

/** Fresh-start state — no habitat, no pets, picker will show. */
function _bbsAqFreshState() {
  return { habitat: null, pets: [], selectedPetId: null, log: [] };
}

function _bbsAqLoad() {
  let s = state.bbsAq;
  if (s) return s;
  s = _bbsLoadJson(BBS_AQ_KEY, null);
  if (!s) {
    s = _bbsAqFreshState();
    _bbsSaveJson(BBS_AQ_KEY, s);
    state.bbsAq = s;
    return s;
  }
  // Migrate v2 single-pet schema { species, name, ... } to v3 multi-pet
  // schema { habitat, pets: [...], ... } if needed.
  if (!s.pets) {
    if (s.species) {
      const sp = BBS_AQ_SPECIES.find((x) => x.id === s.species);
      s.habitat = sp?.habitat ?? "reef";
      s.pets = [{
        id: "pet-" + Math.random().toString(36).slice(2, 8),
        species: s.species,
        name: s.name || (sp?.name ?? "Pet"),
        adoptedAt: s.adoptedAt || Math.floor(Date.now() / 1000),
        factIndex: s.factIndex || 0,
      }];
      s.selectedPetId = s.pets[0].id;
      delete s.species;
      delete s.name;
      delete s.color;
      delete s.adoptedAt;
      delete s.factIndex;
    } else {
      s.habitat = null;
      s.pets = [];
      s.selectedPetId = null;
    }
  }
  // If we have pets, apply offline decay scaled by average difficulty
  if (s.pets.length > 0) {
    const diff = _bbsAqAvgDifficulty(s);
    const now = Math.floor(Date.now() / 1000);
    const delta = Math.min(60 * 60 * 12, now - (s.lastTick || now));
    if (delta > 0) {
      const ticks = Math.floor(delta / 60);
      if (ticks > 0) {
        s.hunger      = Math.max(0, (s.hunger ?? 80)      - ticks * 0.8 * diff);
        s.happiness   = Math.max(0, (s.happiness ?? 80)   - ticks * 0.5 * diff);
        s.energy      = Math.max(0, (s.energy ?? 80)      - ticks * 0.3 * diff);
        s.cleanliness = Math.max(0, (s.cleanliness ?? 80) - ticks * 0.4 * diff);
        s.lastTick = now;
        if (ticks > 5) s.log.push(`While you were away (${ticks} min), stats decayed.`);
        if (s.hunger === 0 && s.cleanliness === 0) s.dead = true;
      }
    }
    // Ensure selectedPetId is valid
    if (!s.pets.find((p) => p.id === s.selectedPetId)) {
      s.selectedPetId = s.pets[0]?.id || null;
    }
  } else {
    // No pets — clear shared stats so the next adoption starts fresh
    s.hunger = s.happiness = s.energy = s.cleanliness = undefined;
    s.dead = false;
  }
  _bbsSaveJson(BBS_AQ_KEY, s);
  state.bbsAq = s;
  return s;
}

/** Pick a habitat — wipes any prior pets since habitats don't share species. */
function _bbsAqSetHabitat(habitatId) {
  const h = BBS_AQ_HABITATS.find((x) => x.id === habitatId);
  if (!h) return;
  state.bbsAq = {
    habitat: h.id,
    pets: [],
    selectedPetId: null,
    hunger: 95, happiness: 95, energy: 95, cleanliness: 100,
    lightOn: true,
    lastTick: Math.floor(Date.now() / 1000),
    dead: false,
    log: [`Opened the ${h.name} sanctuary.`],
  };
  _bbsAqSave();
}

/** Add a pet of the given species to the sanctuary. */
function _bbsAqAdopt(speciesId, name) {
  const sp = BBS_AQ_SPECIES.find((x) => x.id === speciesId) || BBS_AQ_SPECIES[0];
  const now = Math.floor(Date.now() / 1000);
  const s = state.bbsAq || _bbsAqFreshState();
  // Lazy-init shared stats if this is the first pet
  if (!s.pets || s.pets.length === 0) {
    s.habitat = s.habitat || sp.habitat;
    s.hunger = 95; s.happiness = 95; s.energy = 95; s.cleanliness = 100;
    s.lightOn = true;
    s.lastTick = now;
    s.dead = false;
    if (!Array.isArray(s.log)) s.log = [];
  }
  const pet = {
    id: "pet-" + Math.random().toString(36).slice(2, 8),
    species: sp.id,
    name: name || sp.name.split(" ")[0],
    adoptedAt: now,
    factIndex: 0,
  };
  s.pets.push(pet);
  s.selectedPetId = pet.id;
  s.log.push(`Welcomed ${pet.name} (${sp.name}) into the ${BBS_AQ_HABITATS.find((h) => h.id === s.habitat)?.name || "sanctuary"}.`);
  state.bbsAq = s;
  _bbsAqSave();
}

/** Release the currently-selected pet back to the ocean. */
function _bbsAqRelease(petId) {
  const s = _bbsAqLoad();
  const idx = s.pets.findIndex((p) => p.id === petId);
  if (idx < 0) return;
  const pet = s.pets[idx];
  const sp = BBS_AQ_SPECIES.find((x) => x.id === pet.species);
  s.log.push(`Released ${pet.name} the ${sp?.name || pet.species} back to the open ocean.`);
  s.pets.splice(idx, 1);
  if (s.selectedPetId === petId) {
    s.selectedPetId = s.pets[0]?.id || null;
  }
  _bbsAqSave();
}

/** Days the sanctuary has been kept — uses the oldest pet's adoptedAt
 *  so adding new pets doesn't reset the streak. */
function _bbsAqDaysCared() {
  const s = state.bbsAq;
  if (!s?.pets?.length) return 0;
  const oldestAdopt = Math.min(...s.pets.map((p) => p.adoptedAt || Date.now() / 1000));
  const sec = Math.floor(Date.now() / 1000) - oldestAdopt;
  return Math.max(0, Math.floor(sec / 86400));
}

/** Returns the currently-selected pet, or the first pet if no selection. */
function _bbsAqSelectedPet(s) {
  s = s || state.bbsAq;
  if (!s?.pets?.length) return null;
  return s.pets.find((p) => p.id === s.selectedPetId) || s.pets[0];
}
function _bbsAqSave() { _bbsSaveJson(BBS_AQ_KEY, state.bbsAq); }
function _bbsAqPush(line) {
  state.bbsAq.log.push(line);
  if (state.bbsAq.log.length > 8) state.bbsAq.log.shift();
}
function _bbsAqMood(s) {
  // Lowest of the four stats picks the mood expression.
  const lowest = Math.min(s.hunger, s.happiness, s.energy, s.cleanliness);
  if (s.dead) return { face: "x_x", label: "(deceased)" };
  if (lowest < 20) return { face: ">_<", label: "very unhappy" };
  if (lowest < 40) return { face: "._.", label: "needs care" };
  if (lowest < 60) return { face: "o_O", label: "okay-ish" };
  if (lowest < 80) return { face: "^_^", label: "good" };
  return { face: "*_*", label: "thriving" };
}
function _bbsAqRender() {
  const s = _bbsAqLoad();
  const pickerSection = document.getElementById("bbs-aq-picker-section");
  const activeWrap = document.getElementById("bbs-aq-active-wrap");
  const habitatPickerSection = document.getElementById("bbs-aq-habitat-picker-section");

  // STATE 1: No habitat chosen → show habitat picker (3 cards)
  if (!s.habitat) {
    if (habitatPickerSection) habitatPickerSection.hidden = false;
    if (pickerSection) pickerSection.hidden = true;
    if (activeWrap) activeWrap.hidden = true;
    _bbsAqRenderHabitatPicker();
    return;
  }
  // STATE 2: Habitat but no pets → show species picker filtered to habitat
  if (!s.pets || s.pets.length === 0) {
    if (habitatPickerSection) habitatPickerSection.hidden = true;
    if (pickerSection) pickerSection.hidden = false;
    if (activeWrap) activeWrap.hidden = true;
    _bbsAqRenderPicker();
    return;
  }
  // STATE 3: Habitat + pets → active sanctuary view
  if (habitatPickerSection) habitatPickerSection.hidden = true;
  if (pickerSection) pickerSection.hidden = true;
  if (activeWrap) activeWrap.hidden = false;
  const stage = $("bbs-aq-stage");
  const stats = $("bbs-aq-stats");
  const banner = $("bbs-aq-banner");
  const logEl = $("bbs-aq-log");
  const petCard = document.getElementById("bbs-aq-pet-card");
  const badgesEl = document.getElementById("bbs-aq-badges");
  const factEl = document.getElementById("bbs-aq-fact");
  const mood = _bbsAqMood(s);
  const habitat = BBS_AQ_HABITATS.find((h) => h.id === s.habitat);
  const selectedPet = _bbsAqSelectedPet(s);
  const selectedSp = selectedPet ? BBS_AQ_SPECIES.find((x) => x.id === selectedPet.species) : null;

  // Roster strip — chips for each pet, click to select, X to release
  if (petCard) {
    const days = _bbsAqDaysCared();
    const remaining = habitat.species.filter(
      (id) => !s.pets.find((p) => p.species === id)
    );
    petCard.innerHTML = `
      <div class="bbs-aq-roster">
        ${s.pets.map((pet) => {
          const sp = BBS_AQ_SPECIES.find((x) => x.id === pet.species);
          if (!sp) return "";
          const iucn = BBS_IUCN[sp.status];
          const isSel = pet.id === s.selectedPetId;
          return `<button type="button" class="bbs-aq-roster-chip${isSel ? " is-selected" : ""}" data-aq-select="${escapeHtml(pet.id)}" title="${escapeHtml(sp.name)} · ${escapeHtml(iucn.label)}">
            <span class="bbs-aq-roster-icon" style="color: ${iucn.color}">${_bbsAqRosterIcon(sp.id)}</span>
            <span class="bbs-aq-roster-name">${escapeHtml(pet.name)}</span>
            <span class="bbs-aq-roster-iucn" style="color: ${iucn.color}">${sp.status}</span>
            <span class="bbs-aq-roster-release" data-aq-release="${escapeHtml(pet.id)}" title="Release ${escapeHtml(pet.name)} to the ocean">×</span>
          </button>`;
        }).join("")}
        ${remaining.length > 0
          ? `<button type="button" class="bbs-aq-roster-add" data-aq-act="adopt-new" title="Adopt another species from this habitat">+ Add another</button>`
          : `<span class="bbs-aq-roster-full" title="Every species in this habitat is adopted">All species adopted</span>`}
      </div>
      <div class="bbs-aq-pet-card-meta">
        <span class="bbs-aq-streak" title="Days since the sanctuary opened">${days}d cared</span>
        <span class="bbs-aq-mood" title="Mood from lowest stat">${escapeHtml(mood.face)} ${escapeHtml(mood.label)}</span>
        <span class="bbs-aq-pet-count" title="Total pets in sanctuary">${s.pets.length} ${s.pets.length === 1 ? "creature" : "creatures"}</span>
      </div>
    `;
  }

  if (banner) {
    banner.innerHTML = `${escapeHtml(habitat.name)} <span class="bbs-aq-banner-sub">${s.pets.length} ${s.pets.length === 1 ? "species" : "species"}</span>`;
  }

  // The tank — habitat-specific background + decorations + multiple pets
  if (stage) {
    stage.className = "bbs-aq-stage is-habitat-" + s.habitat
      + (s.lightOn ? " is-lit" : " is-dark")
      + (s.dead ? " is-dead" : "")
      + ((s.cleanliness ?? 100) < 30 ? " is-dirty" : "");
    // Fingerprint includes habitat + pet ids + dead state so adding/removing
    // pets rebuilds the tank, but care actions don't.
    const fingerprint = [
      s.habitat,
      s.dead ? "dead" : "alive",
      ...s.pets.map((p) => `${p.id}:${p.species}`),
    ].join("|");
    if (stage.dataset.aqFingerprint !== fingerprint) {
      stage.dataset.aqFingerprint = fingerprint;
      stage.innerHTML = _bbsAqStageHtml(s, habitat);
    } else if (s.dead && !stage.querySelector(".bbs-aq-dead-banner")) {
      const deadBanner = document.createElement("div");
      deadBanner.className = "bbs-aq-dead-banner";
      deadBanner.textContent = "×_×  YOUR PETS HAVE DIED  ×_×";
      stage.querySelector(".bbs-aq-water")?.appendChild(deadBanner);
    }
    // Selected ring — update without rebuilding the whole stage
    stage.querySelectorAll(".bbs-aq-fish").forEach((el) => {
      el.classList.toggle("is-selected", el.dataset.aqPetId === s.selectedPetId);
    });
  }

  // Vital signs (stat bars) — shared tank stats
  if (stats) {
    const bar = (label, val) => {
      const pct = Math.max(0, Math.min(100, Math.round(val ?? 0)));
      const cls = pct < 25 ? "is-low" : pct < 50 ? "is-mid" : "is-ok";
      return `<div class="bbs-aq-stat">
        <span class="bbs-aq-stat-label">${escapeHtml(label)}</span>
        <span class="bbs-aq-stat-bar"><span class="bbs-aq-stat-fill ${cls}" style="width:${pct}%"></span></span>
        <span class="bbs-aq-stat-pct">${pct}</span>
      </div>`;
    };
    stats.innerHTML = bar("Hunger",       s.hunger)
                   + bar("Happiness",    s.happiness)
                   + bar("Energy",       s.energy)
                   + bar("Cleanliness",  s.cleanliness);
  }

  // Earned badges — based on streak + wellness + most-endangered pet
  if (badgesEl) {
    const days = _bbsAqDaysCared();
    const wellness = Math.round(((s.hunger ?? 0) + (s.happiness ?? 0) + (s.energy ?? 0) + (s.cleanliness ?? 0)) / 4);
    const hasEndangered = s.pets.some((p) => {
      const sp = BBS_AQ_SPECIES.find((x) => x.id === p.species);
      return sp?.status === "EN" || sp?.status === "CR";
    });
    const badges = [];
    if (days >= 1)   badges.push({ icon: "🌱", label: "Day 1" });
    if (days >= 7)   badges.push({ icon: "🪸", label: "Reef Week" });
    if (days >= 30)  badges.push({ icon: "🐚", label: "30-Day Steward" });
    if (days >= 100) badges.push({ icon: "🐋", label: "Century Keeper" });
    if (wellness >= 80) badges.push({ icon: "🌟", label: "Thriving" });
    if (hasEndangered) badges.push({ icon: "🛟", label: "Endangered Steward" });
    if (s.pets.length >= 2) badges.push({ icon: "🐠", label: "Multi-Species" });
    if (s.pets.length >= habitat.species.length) badges.push({ icon: "🏝", label: `Full ${habitat.name}` });
    badgesEl.innerHTML = badges.length
      ? badges.map((b) => `<span class="bbs-aq-badge"><span>${b.icon}</span><strong>${escapeHtml(b.label)}</strong></span>`).join("")
      : `<span class="bbs-aq-empty-badges">Care for the sanctuary for 1 day to earn your first badge.</span>`;
  }

  // Rotating fact card — facts for the selected pet
  if (factEl) {
    if (!selectedPet || !selectedSp) {
      factEl.innerHTML = `<div class="bbs-aq-fact-text">Select a pet from the roster to see its biology.</div>`;
    } else {
      if (selectedPet.factIndex == null) selectedPet.factIndex = 0;
      const fact = selectedSp.facts[selectedPet.factIndex % selectedSp.facts.length] || "";
      factEl.innerHTML = `<div class="bbs-aq-fact-text">${escapeHtml(fact)}</div>
        <div class="bbs-aq-fact-meta">
          <span class="bbs-aq-fact-source">From the field — biology of ${escapeHtml(selectedPet.name)} <em>(${escapeHtml(selectedSp.scientific)})</em></span>
          <button type="button" class="button button-secondary" data-aq-act="next-fact" title="Show another fact">↻ Next fact</button>
        </div>`;
    }
  }

  // Sanctuary log (last 8 lines)
  if (logEl) {
    logEl.innerHTML = s.log.slice(-8).map((l) => `<div class="bbs-aq-log-line">› ${escapeHtml(l)}</div>`).join("");
  }
}

/** Build the tank's inner HTML for the given sanctuary state + habitat.
 *  Only called when habitat/pet-roster/dead changes — so the swimming pets
 *  keep their CSS animations through care actions. */
function _bbsAqStageHtml(s, habitat) {
  const decorations = _bbsAqHabitatDecorations(habitat.id);
  // For each pet, render a fish element with its swim class. Multiple pets
  // of the same species get different animation-delays so they don't overlap.
  const speciesCount = {};
  const petsHtml = s.pets.map((pet) => {
    const sp = BBS_AQ_SPECIES.find((x) => x.id === pet.species);
    if (!sp) return "";
    const idx = speciesCount[sp.swim] = (speciesCount[sp.swim] || 0) + 1;
    const delay = (idx - 1) * 2.7;   // seconds offset within the swim cycle
    return `<div class="bbs-aq-fish is-swim-${escapeHtml(sp.swim)}"
                 data-aq-pet-id="${escapeHtml(pet.id)}"
                 style="animation-delay: ${delay}s"
                 aria-label="${escapeHtml(pet.name)} the ${escapeHtml(sp.name)}">
      <div class="bbs-aq-fish-flip" style="animation-delay: ${delay}s">
        <svg viewBox="0 0 140 60" width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
          ${_bbsAqSpeciesSvg(sp.id)}
        </svg>
      </div>
    </div>`;
  }).join("\n");
  return `
      <div class="bbs-aq-water">
        <!-- Surface ripples at the top edge -->
        <div class="bbs-aq-surface"></div>

        <!-- Sun rays beaming down from the surface (habitat-tinted) -->
        <div class="bbs-aq-ray bbs-aq-ray-1"></div>
        <div class="bbs-aq-ray bbs-aq-ray-2"></div>
        <div class="bbs-aq-ray bbs-aq-ray-3"></div>

        <!-- Habitat-specific background decorations (schools, kelp, drift, etc) -->
        ${decorations.background}

        <!-- Bubbles -->
        <div class="bbs-aq-bubble bbs-aq-bubble-lg" style="left:14%;animation-delay:0s"></div>
        <div class="bbs-aq-bubble"             style="left:24%;animation-delay:2.1s"></div>
        <div class="bbs-aq-bubble bbs-aq-bubble-sm" style="left:36%;animation-delay:1.3s"></div>
        <div class="bbs-aq-bubble"             style="left:48%;animation-delay:3.6s"></div>
        <div class="bbs-aq-bubble bbs-aq-bubble-sm" style="left:62%;animation-delay:2.4s"></div>
        <div class="bbs-aq-bubble bbs-aq-bubble-lg" style="left:74%;animation-delay:4.7s"></div>
        <div class="bbs-aq-bubble"             style="left:84%;animation-delay:3.7s"></div>
        <div class="bbs-aq-bubble bbs-aq-bubble-sm" style="left:92%;animation-delay:1.1s"></div>

        <!-- All adopted pets — each with its species swim animation -->
        ${petsHtml}

        <!-- Habitat-specific foreground decorations (coral, anemone, kelp) -->
        ${decorations.foreground}

        ${s.dead ? '<div class="bbs-aq-dead-banner">×_×  YOUR PETS HAVE DIED  ×_×</div>' : ""}
      </div>
      <!-- Floor with habitat-specific texture (sand / rock / pebbles) -->
      <div class="bbs-aq-floor bbs-aq-floor-${escapeHtml(habitat.id)}">
        ${decorations.floor}
      </div>
    `;
}

/** Returns habitat-specific decoration HTML fragments. Each habitat has
 *  a different background (schools/jellies/drift), foreground (coral/anemone
 *  /kelp/rocks), and floor (sand/pebbles/sea bed). */
function _bbsAqHabitatDecorations(habitatId) {
  if (habitatId === "reef") {
    return {
      background: `
        <!-- Smaller schools of sparkly reef fish -->
        <svg class="bbs-aq-school bbs-aq-school-1" viewBox="0 0 200 40" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <g fill="rgba(255,220,150,0.55)">
            <path d="M 10 20 q 6 -5 12 0 q -6 5 -12 0 z M 22 20 l -3 -2 v 4 z" />
            <path d="M 40 18 q 6 -5 12 0 q -6 5 -12 0 z M 52 18 l -3 -2 v 4 z" />
            <path d="M 65 26 q 6 -5 12 0 q -6 5 -12 0 z M 77 26 l -3 -2 v 4 z" />
            <path d="M 92 22 q 6 -5 12 0 q -6 5 -12 0 z M 104 22 l -3 -2 v 4 z" />
            <path d="M 120 17 q 6 -5 12 0 q -6 5 -12 0 z M 132 17 l -3 -2 v 4 z" />
            <path d="M 150 24 q 6 -5 12 0 q -6 5 -12 0 z M 162 24 l -3 -2 v 4 z" />
          </g>
        </svg>`,
      foreground: `
        <!-- Reef foreground: pink coral on the left, purple anemone on the right, orange starfish -->
        <svg class="bbs-aq-coral bbs-aq-coral-1" viewBox="0 0 60 70" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <g fill="#ff8a7a">
            <path d="M 22 70 Q 18 50, 14 38 Q 12 30, 18 24 Q 24 18, 22 8 Q 25 4, 28 10 Q 30 18, 26 24 Q 32 30, 28 44 Q 24 56, 30 70 Z" />
            <circle cx="22" cy="8" r="3" fill="#ffae9a" />
            <circle cx="14" cy="34" r="2.5" fill="#ffae9a" />
            <circle cx="28" cy="44" r="2.5" fill="#ffae9a" />
          </g>
          <g fill="#ffb39a">
            <path d="M 40 70 Q 36 56, 38 44 Q 42 36, 38 24 Q 42 18, 46 26 Q 48 36, 44 46 Q 46 58, 48 70 Z" />
            <circle cx="40" cy="24" r="2.2" fill="#ffd4c0" />
            <circle cx="44" cy="44" r="2" fill="#ffd4c0" />
          </g>
        </svg>
        <svg class="bbs-aq-anemone" viewBox="0 0 60 40" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <ellipse cx="30" cy="34" rx="18" ry="5" fill="#a056b8" opacity="0.85" />
          <g stroke="#c876dc" stroke-width="3" stroke-linecap="round" fill="none">
            <path class="bbs-aq-anemone-tent" d="M 14 32 Q 12 18, 16 6" />
            <path class="bbs-aq-anemone-tent" d="M 20 33 Q 18 20, 22 4" style="animation-delay:0.4s" />
            <path class="bbs-aq-anemone-tent" d="M 28 34 Q 30 18, 28 2" style="animation-delay:0.8s" />
            <path class="bbs-aq-anemone-tent" d="M 36 34 Q 38 20, 36 4" style="animation-delay:0.2s" />
            <path class="bbs-aq-anemone-tent" d="M 44 33 Q 46 22, 42 6" style="animation-delay:0.6s" />
          </g>
        </svg>
        <svg class="bbs-aq-starfish" viewBox="0 0 40 40" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <path d="M 20 4 L 24 16 L 36 18 L 27 26 L 30 38 L 20 32 L 10 38 L 13 26 L 4 18 L 16 16 Z" fill="#ff9966" stroke="#cc6644" stroke-width="1.2" stroke-linejoin="round" />
          <circle cx="18" cy="22" r="1.4" fill="#cc6644" />
          <circle cx="23" cy="20" r="1.4" fill="#cc6644" />
          <circle cx="22" cy="26" r="1.4" fill="#cc6644" />
        </svg>`,
      floor: `
        <span class="bbs-aq-pebble" style="left:12%; width:8px; height:5px; background:#e8d4a8"></span>
        <span class="bbs-aq-pebble" style="left:28%; width:6px; height:4px; background:#d2c098"></span>
        <span class="bbs-aq-pebble" style="left:45%; width:10px; height:6px; background:#eedab8"></span>
        <span class="bbs-aq-pebble" style="left:62%; width:5px; height:3px; background:#c8b890"></span>
        <span class="bbs-aq-pebble" style="left:78%; width:7px; height:5px; background:#ddc8a0"></span>
        <span class="bbs-aq-pebble" style="left:88%; width:6px; height:4px; background:#b8a888"></span>`,
    };
  }
  if (habitatId === "open") {
    return {
      background: `
        <!-- Deeper pelagic blue, no shore fish — instead drifting jellies + far-off schools -->
        <svg class="bbs-aq-school bbs-aq-school-1" viewBox="0 0 200 40" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <g fill="rgba(180,210,240,0.36)">
            <path d="M 10 20 q 6 -5 12 0 q -6 5 -12 0 z M 22 20 l -3 -2 v 4 z" />
            <path d="M 40 18 q 6 -5 12 0 q -6 5 -12 0 z M 52 18 l -3 -2 v 4 z" />
            <path d="M 65 26 q 6 -5 12 0 q -6 5 -12 0 z M 77 26 l -3 -2 v 4 z" />
            <path d="M 92 22 q 6 -5 12 0 q -6 5 -12 0 z M 104 22 l -3 -2 v 4 z" />
            <path d="M 120 17 q 6 -5 12 0 q -6 5 -12 0 z M 132 17 l -3 -2 v 4 z" />
            <path d="M 150 24 q 6 -5 12 0 q -6 5 -12 0 z M 162 24 l -3 -2 v 4 z" />
          </g>
        </svg>
        <svg class="bbs-aq-school bbs-aq-school-2" viewBox="0 0 160 30" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <g fill="rgba(170,205,230,0.24)">
            <path d="M 10 15 q 5 -4 10 0 q -5 4 -10 0 z M 20 15 l -2.5 -1.5 v 3 z" />
            <path d="M 35 13 q 5 -4 10 0 q -5 4 -10 0 z M 45 13 l -2.5 -1.5 v 3 z" />
            <path d="M 60 18 q 5 -4 10 0 q -5 4 -10 0 z M 70 18 l -2.5 -1.5 v 3 z" />
            <path d="M 85 16 q 5 -4 10 0 q -5 4 -10 0 z M 95 16 l -2.5 -1.5 v 3 z" />
            <path d="M 115 19 q 5 -4 10 0 q -5 4 -10 0 z M 125 19 l -2.5 -1.5 v 3 z" />
          </g>
        </svg>
        <!-- Tiny far-off jelly silhouette (background depth) -->
        <svg class="bbs-aq-jelly" viewBox="0 0 40 60" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <path d="M 4 22 Q 4 4, 20 4 Q 36 4, 36 22 Q 36 26, 32 28 L 8 28 Q 4 26, 4 22 Z" fill="rgba(220,210,230,0.5)" />
          <path d="M 12 28 Q 11 44, 14 56" stroke="rgba(220,210,230,0.4)" stroke-width="1.2" fill="none" />
          <path d="M 20 28 Q 19 44, 22 56" stroke="rgba(220,210,230,0.4)" stroke-width="1.2" fill="none" />
          <path d="M 28 28 Q 29 44, 26 56" stroke="rgba(220,210,230,0.4)" stroke-width="1.2" fill="none" />
        </svg>`,
      foreground: `
        <!-- Open ocean foreground is empty — pelagic depth has no coral or kelp -->`,
      floor: `
        <!-- Deep abyssal floor — barely visible, distant rocks -->
        <span class="bbs-aq-pebble" style="left:20%; width:5px; height:3px; background:#1a3a55; opacity:0.6"></span>
        <span class="bbs-aq-pebble" style="left:55%; width:7px; height:4px; background:#1c3850; opacity:0.55"></span>
        <span class="bbs-aq-pebble" style="left:78%; width:5px; height:3px; background:#163050; opacity:0.5"></span>`,
    };
  }
  if (habitatId === "kelp") {
    return {
      background: `
        <!-- Dappled green light + small drift particles -->
        <svg class="bbs-aq-school bbs-aq-school-2" viewBox="0 0 160 30" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <g fill="rgba(180,220,200,0.32)">
            <path d="M 10 15 q 5 -4 10 0 q -5 4 -10 0 z M 20 15 l -2.5 -1.5 v 3 z" />
            <path d="M 35 13 q 5 -4 10 0 q -5 4 -10 0 z M 45 13 l -2.5 -1.5 v 3 z" />
            <path d="M 60 18 q 5 -4 10 0 q -5 4 -10 0 z M 70 18 l -2.5 -1.5 v 3 z" />
            <path d="M 85 16 q 5 -4 10 0 q -5 4 -10 0 z M 95 16 l -2.5 -1.5 v 3 z" />
            <path d="M 115 19 q 5 -4 10 0 q -5 4 -10 0 z M 125 19 l -2.5 -1.5 v 3 z" />
          </g>
        </svg>`,
      foreground: `
        <!-- Tall kelp strands dominate -->
        <svg class="bbs-aq-kelp bbs-aq-kelp-1" viewBox="0 0 30 90" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <path d="M 15 90 Q 8 70, 12 50 Q 18 30, 14 14 Q 16 4, 20 0" stroke="#3eaa6c" stroke-width="4" fill="none" stroke-linecap="round" />
          <ellipse cx="14" cy="34" rx="4" ry="3" fill="#54c780" />
          <ellipse cx="13" cy="58" rx="4" ry="3" fill="#54c780" />
          <ellipse cx="16" cy="20" rx="3" ry="2.5" fill="#54c780" />
        </svg>
        <svg class="bbs-aq-kelp bbs-aq-kelp-2" viewBox="0 0 30 70" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <path d="M 15 70 Q 22 52, 16 36 Q 8 22, 14 6" stroke="#cf6f44" stroke-width="4" fill="none" stroke-linecap="round" />
          <ellipse cx="18" cy="42" rx="3" ry="2.5" fill="#e58964" />
          <ellipse cx="13" cy="22" rx="3" ry="2.5" fill="#e58964" />
        </svg>
        <svg class="bbs-aq-kelp bbs-aq-kelp-3" viewBox="0 0 30 100" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
          <path d="M 15 100 Q 8 80, 14 64 Q 22 46, 12 28 Q 16 12, 14 0" stroke="#5a8f4d" stroke-width="4" fill="none" stroke-linecap="round" />
          <ellipse cx="14" cy="74" rx="4" ry="3" fill="#7ab068" />
          <ellipse cx="18" cy="48" rx="4" ry="3" fill="#7ab068" />
          <ellipse cx="14" cy="22" rx="3" ry="2.5" fill="#7ab068" />
        </svg>`,
      floor: `
        <!-- Rocky temperate floor — slate + sand mix -->
        <span class="bbs-aq-pebble" style="left:10%; width:12px; height:7px; background:#5a6065; border-radius:60% 40% 50% 60%"></span>
        <span class="bbs-aq-pebble" style="left:25%; width:8px; height:5px; background:#4d525a"></span>
        <span class="bbs-aq-pebble" style="left:42%; width:14px; height:8px; background:#65706a; border-radius:50%"></span>
        <span class="bbs-aq-pebble" style="left:60%; width:6px; height:4px; background:#54595e"></span>
        <span class="bbs-aq-pebble" style="left:75%; width:10px; height:6px; background:#5e6660"></span>
        <span class="bbs-aq-pebble" style="left:90%; width:7px; height:5px; background:#4a504f"></span>`,
    };
  }
  return { background: "", foreground: "", floor: "" };
}

/** Small inline SVG icon for the roster chips — uses the species' swim
 *  signature for a recognizable silhouette. */
function _bbsAqRosterIcon(speciesId) {
  return `<svg viewBox="0 0 140 60" width="22" height="14" xmlns="http://www.w3.org/2000/svg" style="display:block">${_bbsAqSpeciesSvg(speciesId)}</svg>`;
}

/** Render the habitat picker (3 cards — Coral Reef / Open Ocean / Kelp Forest). */
function _bbsAqRenderHabitatPicker() {
  const el = document.getElementById("bbs-aq-habitat-picker");
  if (!el) return;
  el.innerHTML = BBS_AQ_HABITATS.map((h) => {
    const speciesPreviewIds = h.species.slice(0, 3);
    return `<button type="button" class="bbs-aq-habitat-card" data-aq-set-habitat="${escapeHtml(h.id)}" title="Open the ${escapeHtml(h.name)} sanctuary">
      <div class="bbs-aq-habitat-preview" style="background: linear-gradient(180deg, ${h.palette[0]} 0%, ${h.palette[1]} 50%, ${h.palette[2]} 100%);">
        ${speciesPreviewIds.map((id, i) => `<div class="bbs-aq-habitat-preview-fish" style="top: ${30 + i * 18}%; left: ${20 + i * 22}%; color: ${i === 0 ? "#ff8a7a" : i === 1 ? "#5aa066" : "#dcc8a0"}">
          <svg viewBox="0 0 140 60" width="40" height="18" xmlns="http://www.w3.org/2000/svg">${_bbsAqSpeciesSvg(id)}</svg>
        </div>`).join("")}
      </div>
      <div class="bbs-aq-habitat-meta">
        <strong>${escapeHtml(h.name)}</strong>
        <p>${escapeHtml(h.description)}</p>
        <div class="bbs-aq-habitat-species">
          ${h.species.map((id) => {
            const sp = BBS_AQ_SPECIES.find((x) => x.id === id);
            if (!sp) return "";
            const iucn = BBS_IUCN[sp.status];
            return `<span class="bbs-aq-tag" style="color: ${iucn.color}; border-color: ${iucn.color}55">${escapeHtml(sp.name)}</span>`;
          }).join("")}
        </div>
      </div>
    </button>`;
  }).join("");
}

/** Render the species adoption picker — filtered to the current habitat. */
function _bbsAqRenderPicker() {
  const el = document.getElementById("bbs-aq-picker");
  if (!el) return;
  const s = state.bbsAq;
  const habitat = BBS_AQ_HABITATS.find((h) => h.id === s?.habitat);
  if (!habitat) return;
  // Show species that belong to this habitat AND aren't already adopted
  const adoptedIds = new Set((s.pets || []).map((p) => p.species));
  const available = habitat.species
    .map((id) => BBS_AQ_SPECIES.find((x) => x.id === id))
    .filter((sp) => sp && !adoptedIds.has(sp.id));
  if (available.length === 0) {
    el.innerHTML = `<p class="bbs-aq-empty-picker">You've adopted every species in this habitat. Switch habitat to find more.</p>`;
    return;
  }
  el.innerHTML = available.map((sp) => {
    const iucn = BBS_IUCN[sp.status];
    const diff = sp.difficulty < 0.9 ? "Easy" : sp.difficulty <= 1.05 ? "Normal" : "Challenging";
    return `<button type="button" class="bbs-aq-picker-card" data-aq-adopt="${escapeHtml(sp.id)}" title="Adopt ${escapeHtml(sp.name)}">
      <div class="bbs-aq-picker-preview">
        <svg viewBox="0 0 140 60" width="100%" height="100%" xmlns="http://www.w3.org/2000/svg" style="color: hsl(18, 78%, 55%)">
          ${_bbsAqSpeciesSvg(sp.id)}
        </svg>
      </div>
      <div class="bbs-aq-picker-meta">
        <strong>${escapeHtml(sp.name)}</strong>
        <em>${escapeHtml(sp.scientific)}</em>
        <p class="bbs-aq-picker-desc">${escapeHtml(sp.description)}</p>
        <div class="bbs-aq-picker-tags">
          <span class="bbs-aq-iucn" style="background: ${iucn.color}22; color: ${iucn.color}; border-color: ${iucn.color}77">${sp.status} · ${escapeHtml(iucn.label)}</span>
          <span class="bbs-aq-tag">Care: ${escapeHtml(diff)}</span>
        </div>
      </div>
    </button>`;
  }).join("");
}
function renderBbsAquarium() {
  _bbsAqRender();
  // Start the slow decay timer — 1 tick every 30s while on this section.
  if (!state.bbsAqTimer) {
    state.bbsAqTimer = setInterval(() => {
      if (state.bbsSection !== "aquarium") { clearInterval(state.bbsAqTimer); state.bbsAqTimer = null; return; }
      const s = _bbsAqLoad();
      if (s.dead) return;
      s.hunger      = Math.max(0, s.hunger - 0.6);
      s.happiness   = Math.max(0, s.happiness - 0.4);
      s.energy      = Math.max(0, s.energy - 0.25);
      s.cleanliness = Math.max(0, s.cleanliness - 0.3);
      s.lastTick = Math.floor(Date.now() / 1000);
      if (s.hunger === 0 && s.cleanliness === 0 && !s.dead) {
        s.dead = true;
        _bbsAqPush(`${s.name} has died. Hunger AND cleanliness hit zero.`);
      }
      _bbsAqSave();
      _bbsAqRender();
    }, 30000);
  }
}
function _bbsAqAct(action, arg) {
  const s = _bbsAqLoad();
  // ── State-changing flow controls (work even with no pets) ──
  if (action === "set-habitat") {
    _bbsAqSetHabitat(arg);
    _bbsAqRender();
    return;
  }
  if (action === "change-habitat") {
    if (s.pets && s.pets.length > 0) {
      if (!confirm("Switching habitat will release every pet in the sanctuary. Continue?")) return;
    }
    state.bbsAq = _bbsAqFreshState();
    _bbsAqSave();
    _bbsAqRender();
    return;
  }
  if (action === "adopt-new") {
    // Open the species picker for the current habitat
    _bbsAqRender();
    // Force the picker to show by clearing the active wrap state
    const pickerSection = document.getElementById("bbs-aq-picker-section");
    const activeWrap = document.getElementById("bbs-aq-active-wrap");
    if (pickerSection) pickerSection.hidden = false;
    if (activeWrap) activeWrap.hidden = true;
    _bbsAqRenderPicker();
    return;
  }
  if (action === "adopt") {
    const sp = BBS_AQ_SPECIES.find((x) => x.id === arg);
    const defaultName = sp?.name.split(" ")[0] || "Pet";
    const name = (prompt(`Name your ${sp?.name || "new pet"} (or leave blank for "${defaultName}"):`, "") || "").trim().slice(0, 24);
    _bbsAqAdopt(arg, name);
    _bbsAqRender();
    return;
  }
  if (action === "release-pet") {
    const pet = s.pets?.find((p) => p.id === arg);
    if (!pet) return;
    if (!confirm(`Release ${pet.name} back to the open ocean?`)) return;
    _bbsAqRelease(arg);
    _bbsAqRender();
    return;
  }
  if (action === "select-pet") {
    s.selectedPetId = arg;
    _bbsAqSave();
    _bbsAqRender();
    return;
  }
  if (action === "next-fact") {
    const pet = _bbsAqSelectedPet(s);
    if (pet) pet.factIndex = ((pet.factIndex || 0) + 1);
    _bbsAqSave();
    _bbsAqRender();
    return;
  }
  // ── Care actions — need a pet to act on, blocked when dead ──
  if (!s.pets || s.pets.length === 0) return;
  if (s.dead) return;
  if (action === "feed") {
    s.hunger = Math.min(100, (s.hunger ?? 80) + 30);
    s.cleanliness = Math.max(0, (s.cleanliness ?? 80) - 6);
    _bbsAqPush(`Fed the sanctuary. Hunger +30, tank gets a little dirty.`);
  } else if (action === "play") {
    if ((s.energy ?? 0) < 10) { _bbsAqPush(`The pets are too tired to play.`); }
    else {
      s.happiness = Math.min(100, (s.happiness ?? 80) + 25);
      s.energy    = Math.max(0, (s.energy ?? 80) - 15);
      _bbsAqPush(`Enrichment play session. Happiness +25, Energy -15.`);
    }
  } else if (action === "sleep") {
    s.energy = Math.min(100, (s.energy ?? 80) + 40);
    s.happiness = Math.min(100, (s.happiness ?? 80) + 5);
    _bbsAqPush(`Dimmed the lights for rest. Energy +40.`);
  } else if (action === "clean") {
    s.cleanliness = 100;
    s.happiness = Math.min(100, (s.happiness ?? 80) + 10);
    _bbsAqPush(`Scrubbed the tank. Cleanliness 100, mood lifted.`);
  } else if (action === "light") {
    s.lightOn = !s.lightOn;
    _bbsAqPush(`Tank light ${s.lightOn ? "ON" : "OFF"}.`);
  } else if (action === "rename") {
    const pet = _bbsAqSelectedPet(s);
    if (!pet) return;
    const newName = (prompt(`Rename ${pet.name} (max 24 chars):`, pet.name) || "").trim().slice(0, 24);
    if (newName) { pet.name = newName; _bbsAqPush(`Renamed selected pet to ${pet.name}.`); }
  }
  s.lastTick = Math.floor(Date.now() / 1000);
  _bbsAqSave();
  _bbsAqRender();
}

/* ── MAIL ──────────────────────────────────────────────────────────── */
function renderBbsMail() {
  if (!state.bbsMail) {
    // Seed with welcome message from SYSOP if the local store is empty.
    const stored = _bbsLoadJson(BBS_MAIL_KEY, null);
    // Real seed mail — only system + AI senders, no invented co-users.
    state.bbsMail = stored || [
      { id: "m1", from: "SYSOP", to: "you", subj: "Welcome to OMEGA-wave Forum",        date: "2026-05-28 10:00", read: false, body: "Welcome. Mail is local-only for now — your inbox lives in this browser until peer federation is wired up. Use the compose form below to send a note to SYSOP, HONU, or any other system handle.\n\nWhen real mesh peers come online they'll show up as recipients automatically. Mark this read to clear the unread count." },
      { id: "m2", from: "HONU",  to: "you", subj: "Tip — Cmd+K to jump anywhere",        date: "2026-05-28 10:02", read: false, body: "Quick tip: hit Cmd+K (or Ctrl+K on Windows) from anywhere in the portal to open the command palette. From there you can jump to any page, switch sections, run a recipe, or call any of my tools. Arrow keys navigate, Enter activates, Escape closes.\n\nAlso: \"@honu\" in chat addresses me directly." },
    ];
    _bbsSaveJson(BBS_MAIL_KEY, state.bbsMail);
  }
  const list = $("bbs-mail-list");
  if (!list) return;
  if (!state.bbsMail.length) {
    list.innerHTML = `<div class="empty">No mail. Compose your first message below.</div>`;
  } else {
    const header = `<div class="bbs-mail-row bbs-mail-row-head">
      <span class="bbs-mc-num">#</span>
      <span class="bbs-mc-status">STATUS</span>
      <span class="bbs-mc-from">FROM</span>
      <span class="bbs-mc-subj">SUBJECT</span>
      <span class="bbs-mc-date">DATE</span>
    </div>`;
    list.innerHTML = header + state.bbsMail.map((m, i) => `
      <button type="button" class="bbs-mail-row ${m.read ? "" : "is-unread"}" data-bbs-mail-open="${escapeHtml(m.id)}">
        <span class="bbs-mc-num">${i + 1}</span>
        <span class="bbs-mc-status">[${m.read ? "READ" : "NEW "}]</span>
        <span class="bbs-mc-from">${escapeHtml(m.from)}</span>
        <span class="bbs-mc-subj">${escapeHtml(m.subj)}</span>
        <span class="bbs-mc-date">${escapeHtml(m.date)}</span>
      </button>
      ${state.bbsMailOpenId === m.id ? `<article class="bbs-mail-body"><pre>${escapeHtml(m.body)}</pre><div class="bbs-mail-actions"><button type="button" class="button button-secondary" data-bbs-mail-delete="${escapeHtml(m.id)}">[Delete]</button></div></article>` : ""}
    `).join("");
  }
}

/* ── GAMES ─────────────────────────────────────────────────────────── */
function renderBbsGames() {
  const grid = $("bbs-games-grid");
  if (grid) {
    grid.innerHTML = BBS_GAMES.map((g) => {
      const score = _bbsLoadJson(BBS_GAME_SCORES_KEY, {})[g.id];
      return `<div class="bbs-game-card">
        <div class="bbs-game-icon">${_bbsGameIcon(g.icon)}</div>
        <div class="bbs-game-body">
          <div class="bbs-game-head">
            <strong>${escapeHtml(g.title)}</strong>
            <span class="bbs-game-genre">${escapeHtml(g.genre)}</span>
          </div>
          <p class="bbs-game-desc">${escapeHtml(g.desc)}</p>
          <div class="bbs-game-foot">
            ${score != null ? `<span class="pill ok">High: ${escapeHtml(String(score))}</span>` : `<span class="pill">No score yet</span>`}
            <button type="button" class="button ${g.play ? "button-primary" : "button-secondary"}" data-bbs-game-play="${escapeHtml(g.id)}" ${g.play ? "" : "disabled title='Stub — coming next round'"}>${g.play ? "[Play]" : "[Soon]"}</button>
          </div>
        </div>
      </div>`;
    }).join("");
  }
  // Active game stage is hidden until a game is launched.
  const section = $("bbs-game-active-section");
  if (section && !state.bbsActiveGame) section.hidden = true;
}

function _bbsRecordGameScore(id, score) {
  const all = _bbsLoadJson(BBS_GAME_SCORES_KEY, {});
  if (all[id] == null || score > all[id]) all[id] = score;
  _bbsSaveJson(BBS_GAME_SCORES_KEY, all);
}

function bbsLaunchGame(id) {
  state.bbsActiveGame = id;
  const section = $("bbs-game-active-section");
  const banner = $("bbs-game-banner");
  const stage = $("bbs-game-stage");
  const game = BBS_GAMES.find((g) => g.id === id);
  if (!section || !stage || !game) return;
  section.hidden = false;
  if (banner) banner.innerHTML = `— [ PLAYING · ${escapeHtml(game.title.toUpperCase())} ] —`;
  // Each launcher seeds (or restores) the game state and kicks off the
  // first render. The renderers are pure: they read state and paint a
  // monospace screen + a row of action buttons. Click delegation lives
  // in bindBbsSectionEvents.
  if      (id === "buoy-roulette") { state.bbsBuoyState = { credits: 100, spins: 0, lastResult: null }; _bbsRenderBuoyRoulette(stage); }
  else if (id === "number-guess")  { state.bbsGuessState = { target: Math.floor(Math.random() * 127) + 1, guesses: 0, log: [] }; _bbsRenderNumberGuess(stage); }
  else if (id === "sector-trader") { _stLaunch(stage); }
  else if (id === "legend-buoy")   { _lbLaunch(stage); }
  else if (id === "fleet-realms")  { _frLaunch(stage); }
  else if (id === "global-war")    { _gwLaunch(stage); }
  else if (id === "overkill")      { _ooLaunch(stage); }
  else if (id === "net-cast")      { _ncLaunch(stage); }
  else if (id === "sonar-hunt")    { _shLaunch(stage); }
  else if (id === "lighthouse-def"){ _ldLaunch(stage); }
}

function _bbsRenderBuoyRoulette(stage) {
  const s = state.bbsBuoyState;
  stage.innerHTML = `<pre class="bbs-game-screen">
  ┌──────────── BUOY ROULETTE ────────────┐
  │                                       │
  │  Credits: <strong>${String(s.credits).padStart(4, " ")}</strong>             Spins: ${String(s.spins).padStart(3, " ")}   │
  │                                       │
  │  Pick where the buoy will drift:      │
  │                                       │
  │    [N] NORTH  (3×)                    │
  │    [E] EAST   (4×)                    │
  │    [S] SOUTH  (3×)                    │
  │    [W] WEST   (5×, longest odds)      │
  │                                       │
  │  Last result: ${(s.lastResult || "— spin the wheel —").padEnd(24, " ")}│
  │                                       │
  └───────────────────────────────────────┘
  </pre>
  <div class="bbs-game-controls">
    <button type="button" class="button button-primary" data-bbs-buoy-bet="N">N (3×)</button>
    <button type="button" class="button button-primary" data-bbs-buoy-bet="E">E (4×)</button>
    <button type="button" class="button button-primary" data-bbs-buoy-bet="S">S (3×)</button>
    <button type="button" class="button button-primary" data-bbs-buoy-bet="W">W (5×)</button>
    <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
  </div>`;
}
function _bbsPlayBuoy(pick) {
  const s = state.bbsBuoyState;
  if (!s) return;
  s.spins++;
  // Weighted random — W is rarer (matches the 5× payout)
  const dirs = ["N","N","N","E","E","E","E","S","S","S","W","W"];
  const drift = dirs[Math.floor(Math.random() * dirs.length)];
  const payouts = { N: 3, E: 4, S: 3, W: 5 };
  const win = drift === pick;
  const delta = win ? payouts[pick] * 10 - 10 : -10;
  s.credits += delta;
  s.lastResult = `Drift was ${drift} — ${win ? "WIN +" + (delta) : "lose -10"} credits`;
  if (s.credits <= 0) {
    s.lastResult = `Drift was ${drift} — bankrupt at spin ${s.spins}`;
    _bbsRecordGameScore("buoy-roulette", s.spins);
    state.bbsBuoyState = null;
    const stage = $("bbs-game-stage");
    if (stage) stage.innerHTML = `<pre class="bbs-game-screen">  ┌────── GAME OVER ──────┐
  │  Bankrupt at spin ${String(s.spins).padStart(3," ")}  │
  │  Highscore saved.     │
  └───────────────────────┘</pre><div class="bbs-game-controls"><button type="button" class="button button-primary" data-bbs-game-play="buoy-roulette">[New game]</button> <button type="button" class="button button-secondary" data-bbs-game-quit>[Back]</button></div>`;
    return;
  }
  if (s.credits > 500) _bbsRecordGameScore("buoy-roulette", s.spins);
  _bbsRenderBuoyRoulette($("bbs-game-stage"));
}

function _bbsRenderNumberGuess(stage) {
  const s = state.bbsGuessState;
  const logHtml = s.log.length ? s.log.map((l) => `  ${l}`).join("\n") : "  (no guesses yet)";
  stage.innerHTML = `<pre class="bbs-game-screen">
  ┌──────── STORM NUMBER (1–127) ────────┐
  │                                      │
  │  I'm thinking of a storm category    │
  │  1–127. Guess it in the fewest tries.│
  │                                      │
  │  Guesses: ${String(s.guesses).padStart(3, " ")}                        │
  │                                      │
  │  Log:                                │
${logHtml.split("\n").map((l) => `  │${l.padEnd(38, " ")}│`).join("\n")}
  │                                      │
  └──────────────────────────────────────┘
  </pre>
  <div class="bbs-game-controls">
    <input id="bbs-guess-input" type="number" min="1" max="127" placeholder="1–127" class="bbs-guess-input" autocomplete="off" />
    <button type="button" class="button button-primary" data-bbs-guess-submit>[Guess]</button>
    <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
  </div>`;
}
function _bbsPlayGuess(n) {
  const s = state.bbsGuessState;
  if (!s) return;
  if (!Number.isFinite(n) || n < 1 || n > 127) return;
  s.guesses++;
  if (n === s.target) {
    s.log.push(`#${s.guesses}: ${n} — CORRECT! Solved in ${s.guesses} guess${s.guesses === 1 ? "" : "es"}`);
    _bbsRecordGameScore("number-guess", -s.guesses); // negative so "highscore" = fewest tries
    _bbsRenderNumberGuess($("bbs-game-stage"));
    setTimeout(() => {
      const stage = $("bbs-game-stage");
      if (stage) stage.innerHTML += `<div class="bbs-game-controls"><button type="button" class="button button-primary" data-bbs-game-play="number-guess">[Play again]</button></div>`;
    }, 100);
    state.bbsGuessState = null;
    return;
  }
  s.log.push(`#${s.guesses}: ${n} — ${n < s.target ? "too low" : "too high"}`);
  if (s.log.length > 6) s.log.shift();
  _bbsRenderNumberGuess($("bbs-game-stage"));
}

/* ════════════════════════════════════════════════════════════════════
   GAME: Sector Trader  (Trade Wars 2002 in marine drag)
   ════════════════════════════════════════════════════════════════════
   - 20 Pacific sectors arranged in a graph.
   - 4 commodities — Fish, Fuel, Data, Salvage — each sector buys+sells at
     varying prices so arbitrage routes exist.
   - Player has a ship with hull, shields, cargo holds, credits, fuel.
   - Moves cost 1 fuel + 1 turn. 30% chance of pirate encounter; 10%
     customs (random fine); rest is empty space.
   - Combat: roll-based; you choose Fight / Run; outcome scales with
     shields vs pirate strength.
   - Goal: 100,000 credits net worth (cargo at avg price + credits).
   - State persists to localStorage so a session can be resumed. */
const ST_SAVE_KEY = "omega-bbs-game-sector-trader-v1";
const ST_COMMS = [
  { key: "fish",    label: "Fish",    base: 18,  unit: "ton",   weight: 1 },
  { key: "fuel",    label: "Fuel",    base: 26,  unit: "drum",  weight: 1 },
  { key: "data",    label: "Data",    base: 42,  unit: "block", weight: 1 },
  { key: "salvage", label: "Salvage", base: 11,  unit: "crate", weight: 2 },
];

function _stMakeUniverse() {
  // Build 20 sectors arranged ~4x5; each sector picks a "specialty"
  // commodity to be cheap on and an "import" to be expensive on, so
  // arbitrage routes naturally exist.
  const names = [
    "Hopkins Reef", "Pillar Pt", "San Pedro", "Bodega Bay",
    "Half Moon",     "Long Beach", "Catalina",  "Pt Arena",
    "Eureka",        "Crescent",   "Newport",    "Astoria",
    "La Push",       "Cape Flatt",  "Sitka",      "Kodiak",
    "Adak",          "Honolulu",    "Hilo",       "Midway",
  ];
  const sectors = [];
  for (let i = 0; i < 20; i++) {
    const specialty = i % ST_COMMS.length;
    const importIdx = (i + 2) % ST_COMMS.length;
    const prices = {};
    for (let c = 0; c < ST_COMMS.length; c++) {
      const base = ST_COMMS[c].base;
      let mult = 1.0;
      if (c === specialty) mult = 0.55 + Math.random() * 0.2;  // cheap
      else if (c === importIdx) mult = 1.35 + Math.random() * 0.4; // pricey
      else mult = 0.85 + Math.random() * 0.35;
      prices[ST_COMMS[c].key] = Math.max(2, Math.round(base * mult));
    }
    // Neighbors: 4-grid + a couple long-range jumps
    const row = Math.floor(i / 5);
    const col = i % 5;
    const neighbors = [];
    if (col > 0) neighbors.push(i - 1);
    if (col < 4) neighbors.push(i + 1);
    if (row > 0) neighbors.push(i - 5);
    if (row < 3) neighbors.push(i + 5);
    sectors.push({ id: i + 1, name: names[i], prices, neighbors: neighbors.map((n) => n + 1) });
  }
  return sectors;
}

function _stLaunch(stage) {
  let s = _bbsLoadJson(ST_SAVE_KEY, null);
  if (!s || !s.sectors || !s.player) {
    s = {
      sectors: _stMakeUniverse(),
      player: {
        sector: 1,
        credits: 1500,
        hull: 100, hullMax: 100,
        shields: 50, shieldsMax: 50,
        fuel: 80, fuelMax: 80,
        holds: 50,
        cargo: { fish: 0, fuel: 0, data: 0, salvage: 0 },
        turns: 0,
      },
      log: ["Welcome to Sector Trader. You start with $1500 and a Class-1 trader. Goal: 100,000 credits net worth."],
      lastEvent: null,
    };
    _bbsSaveJson(ST_SAVE_KEY, s);
  }
  state.stState = s;
  _stRender(stage);
}

function _stNetWorth(p) {
  // Avg base price * cargo count + credits. Cheap heuristic but lets
  // the player see how their hoard compares to the win threshold.
  let cargoValue = 0;
  for (const c of ST_COMMS) cargoValue += (p.cargo[c.key] || 0) * c.base;
  return p.credits + cargoValue;
}
function _stCargoUsed(p) {
  let used = 0;
  for (const c of ST_COMMS) used += (p.cargo[c.key] || 0) * c.weight;
  return used;
}
function _stCurrentSector() { return state.stState.sectors[state.stState.player.sector - 1]; }
function _stPush(line) {
  state.stState.log.push(line);
  if (state.stState.log.length > 8) state.stState.log.shift();
  _bbsSaveJson(ST_SAVE_KEY, state.stState);
}
function _stSave() { _bbsSaveJson(ST_SAVE_KEY, state.stState); }

function _stRender(stage) {
  const s = state.stState;
  if (!s) return;
  const p = s.player;
  const sec = _stCurrentSector();
  const used = _stCargoUsed(p);
  const nw = _stNetWorth(p);
  const wonAlready = nw >= 100000;

  const cargoLines = ST_COMMS.map((c) =>
    `  ${c.label.padEnd(8)} ${String(p.cargo[c.key] || 0).padStart(3)} ${c.unit.padEnd(6)} @ ${String(sec.prices[c.key]).padStart(3)} cr`
  ).join("\n");

  const neighborLine = sec.neighbors.map((n) => `[${n}]${s.sectors[n - 1].name}`).join("  ");
  const logBlock = s.log.map((l) => `  > ${l}`).join("\n");

  const screen = `┌── SECTOR TRADER ─ ${("Sector " + sec.id + ": " + sec.name).padEnd(30)} ─┐
│  Credits: ${String(p.credits).padStart(6)}    Net worth: ${String(nw).padStart(6)} / 100,000   │
│  Hull: ${String(p.hull).padStart(3)}/${p.hullMax}  Shields: ${String(p.shields).padStart(2)}/${p.shieldsMax}  Fuel: ${String(p.fuel).padStart(2)}/${p.fuelMax}  Turns: ${String(p.turns).padStart(3)} │
│  Cargo: ${used}/${p.holds} holds used                              │
└─────────────────────────────────────────────────────────────┘
   COMMODITY     QTY  UNIT     PRICE
${cargoLines}

   Neighbors:  ${neighborLine}

   Recent log:
${logBlock}
${wonAlready ? "\n   ★★★ NET WORTH ≥ 100,000 — YOU WIN! ★★★" : ""}`;

  const moveButtons = sec.neighbors
    .map((n) => `<button type="button" class="button button-secondary" data-st-move="${n}" ${p.fuel < 1 ? "disabled" : ""}>→ S${n} ${s.sectors[n - 1].name}</button>`)
    .join("");
  const tradeButtons = ST_COMMS.map((c) => `
    <button type="button" class="button button-secondary" data-st-buy="${c.key}" title="Buy 1 ${c.label} for ${sec.prices[c.key]} cr">Buy 1 ${c.label}</button>
    <button type="button" class="button button-secondary" data-st-sell="${c.key}" title="Sell 1 ${c.label} for ${sec.prices[c.key]} cr" ${(p.cargo[c.key] || 0) === 0 ? "disabled" : ""}>Sell 1 ${c.label}</button>
  `).join("");

  stage.innerHTML = `<pre class="bbs-game-screen">${screen}</pre>
    <div class="bbs-game-controls">${moveButtons}</div>
    <div class="bbs-game-controls">${tradeButtons}</div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-st-buy-max="fish" title="Buy as many Fish as cargo + credits allow">Buy MAX Fish</button>
      <button type="button" class="button button-secondary" data-st-sell-all="fish" ${(p.cargo.fish || 0) === 0 ? "disabled" : ""}>Sell ALL Fish</button>
      <button type="button" class="button button-secondary" data-st-refuel title="Refuel at this sector — 4 cr per drum">Refuel (4 cr/u)</button>
      <button type="button" class="button button-secondary" data-st-repair title="Repair hull at this sector — 6 cr per HP">Repair (6 cr/HP)</button>
    </div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-st-reset title="Wipe save and start a new game">[New game]</button>
      <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit to lobby]</button>
    </div>`;
}

function _stMove(toId) {
  const s = state.stState;
  const p = s.player;
  const sec = _stCurrentSector();
  if (!sec.neighbors.includes(toId)) { _stPush(`Sector ${toId} is not adjacent.`); _stRender($("bbs-game-stage")); return; }
  if (p.fuel < 1) { _stPush(`No fuel. Refuel before moving.`); _stRender($("bbs-game-stage")); return; }
  p.fuel -= 1; p.turns += 1; p.sector = toId;
  // Encounter roll
  const roll = Math.random();
  if (roll < 0.30) {
    // Pirate
    const strength = 10 + Math.floor(Math.random() * 35);
    const damage = Math.max(0, strength - p.shields);
    p.shields = Math.max(0, p.shields - strength);
    p.hull = Math.max(0, p.hull - damage);
    _stPush(`Pirate ambush in S${toId}! Took ${damage} hull (shields absorbed ${strength - damage}).`);
    if (p.hull <= 0) {
      _stPush(`Your ship is destroyed at S${toId}. Game over.`);
      _bbsRecordGameScore("sector-trader", _stNetWorth(p));
      _bbsSaveJson(ST_SAVE_KEY, null);
      state.stState = null;
      const stage = $("bbs-game-stage");
      if (stage) stage.innerHTML = `<pre class="bbs-game-screen">  ┌── GAME OVER ──┐
  │  Ship lost in │
  │  hostile space.│
  │  Score saved.  │
  └────────────────┘</pre>
        <div class="bbs-game-controls"><button type="button" class="button button-primary" data-bbs-game-play="sector-trader">[New game]</button> <button type="button" class="button button-secondary" data-bbs-game-quit>[Back]</button></div>`;
      return;
    }
  } else if (roll < 0.40) {
    // Customs
    const fine = Math.floor(50 + Math.random() * 250);
    p.credits = Math.max(0, p.credits - fine);
    _stPush(`Customs inspection in S${toId}. Fined ${fine} cr for undeclared cargo.`);
  } else {
    _stPush(`Jumped to S${toId} — ${_stCurrentSector().name}.`);
  }
  _stSave();
  _stRender($("bbs-game-stage"));
}
function _stBuy(key, qty = 1) {
  const s = state.stState; const p = s.player; const sec = _stCurrentSector();
  const comm = ST_COMMS.find((c) => c.key === key);
  if (!comm) return;
  const price = sec.prices[key];
  for (let n = 0; n < qty; n++) {
    const used = _stCargoUsed(p);
    if (p.credits < price) { _stPush(`Not enough credits for ${comm.label}.`); break; }
    if (used + comm.weight > p.holds) { _stPush(`Cargo full at ${used}/${p.holds}.`); break; }
    p.credits -= price;
    p.cargo[key] = (p.cargo[key] || 0) + 1;
  }
  _stPush(`Bought ${qty} ${comm.label} at ${price} cr each.`);
  _stSave();
  _stRender($("bbs-game-stage"));
}
function _stSell(key, qty = 1) {
  const s = state.stState; const p = s.player; const sec = _stCurrentSector();
  const comm = ST_COMMS.find((c) => c.key === key);
  if (!comm) return;
  const price = sec.prices[key];
  const have = p.cargo[key] || 0;
  const real = Math.min(qty, have);
  p.cargo[key] = have - real;
  p.credits += real * price;
  _stPush(`Sold ${real} ${comm.label} at ${price} cr each → +${real * price} cr.`);
  _stSave();
  _stRender($("bbs-game-stage"));
}
function _stRefuel() {
  const p = state.stState.player;
  const need = p.fuelMax - p.fuel;
  if (need === 0) { _stPush(`Fuel already full.`); _stRender($("bbs-game-stage")); return; }
  const cost = need * 4;
  if (p.credits < cost) { _stPush(`Need ${cost} cr to top off fuel.`); _stRender($("bbs-game-stage")); return; }
  p.credits -= cost; p.fuel = p.fuelMax;
  _stPush(`Refueled. -${cost} cr.`); _stSave(); _stRender($("bbs-game-stage"));
}
function _stRepair() {
  const p = state.stState.player;
  const need = p.hullMax - p.hull;
  if (need === 0) { _stPush(`Hull already full.`); _stRender($("bbs-game-stage")); return; }
  const cost = need * 6;
  if (p.credits < cost) { _stPush(`Need ${cost} cr to repair.`); _stRender($("bbs-game-stage")); return; }
  p.credits -= cost; p.hull = p.hullMax; p.shields = p.shieldsMax;
  _stPush(`Hull + shields repaired. -${cost} cr.`); _stSave(); _stRender($("bbs-game-stage"));
}
function _stReset() {
  _bbsSaveJson(ST_SAVE_KEY, null);
  state.stState = null;
  _stLaunch($("bbs-game-stage"));
}


/* ════════════════════════════════════════════════════════════════════
   GAME: Legend of the Black Buoy  (LORD-style daily RPG)
   ════════════════════════════════════════════════════════════════════
   Locations: Reef (random sea-monster fights, gain XP+gold), Shipyard
   (spend gold + XP to upgrade stats), Harbor Inn (heal for gold),
   Black Market (buy weapons/armor), The Master (boss battles to gain
   levels). 12 Reef fights per session, then save. */
const LB_SAVE_KEY = "omega-bbs-game-lord-v1";
const LB_MONSTERS_TIER = [
  { name: "Tidepool Crab",  hp: 12, atk: 4,  def: 1, gold: 5,   xp: 8 },
  { name: "Striped Bass",   hp: 18, atk: 6,  def: 2, gold: 9,   xp: 14 },
  { name: "Spiny Urchin",   hp: 22, atk: 5,  def: 4, gold: 11,  xp: 18 },
  { name: "Lionfish",       hp: 28, atk: 8,  def: 3, gold: 17,  xp: 26 },
  { name: "Giant Octopus",  hp: 44, atk: 12, def: 6, gold: 29,  xp: 44 },
  { name: "Tiger Shark",    hp: 60, atk: 16, def: 5, gold: 48,  xp: 68 },
  { name: "Sea Serpent",    hp: 85, atk: 21, def: 9, gold: 80,  xp: 105 },
  { name: "Mother Kraken",  hp: 140, atk: 30, def: 14, gold: 180, xp: 240 },
];
const LB_WEAPONS = [
  { id: "fist",     name: "Bare hands",      atk: 0,  cost: 0 },
  { id: "harpoon",  name: "Fish-spear",      atk: 4,  cost: 50 },
  { id: "speargun", name: "Pneumatic speargun", atk: 9, cost: 200 },
  { id: "trident",  name: "Boatswain's trident", atk: 16, cost: 800 },
  { id: "stormfork",name: "Stormfork of Triton", atk: 27, cost: 2400 },
];
const LB_ARMOR = [
  { id: "shirt",   name: "Cotton shirt",     def: 0,  cost: 0 },
  { id: "wetsuit", name: "3mm wetsuit",      def: 3,  cost: 60 },
  { id: "drysuit", name: "Drysuit + plating",def: 8,  cost: 250 },
  { id: "carbon",  name: "Carbon dive armor",def: 14, cost: 900 },
  { id: "krakhide",name: "Krakenhide cuirass",def: 22, cost: 2800 },
];

function _lbLaunch(stage) {
  let s = _bbsLoadJson(LB_SAVE_KEY, null);
  if (!s) {
    s = {
      hp: 30, hpMax: 30,
      atk: 5, def: 2,
      gold: 25, xp: 0, level: 1,
      fightsLeft: 12,
      weapon: "fist", armor: "shirt",
      log: ["Welcome. You wash up on the docks with nothing but the wetsuit on your back."],
      enemy: null,
      location: "lobby",
    };
    _bbsSaveJson(LB_SAVE_KEY, s);
  }
  state.lbState = s;
  _lbRender(stage);
}

function _lbSave() { _bbsSaveJson(LB_SAVE_KEY, state.lbState); }
function _lbPush(line) {
  state.lbState.log.push(line);
  if (state.lbState.log.length > 6) state.lbState.log.shift();
  _lbSave();
}
function _lbEffectiveAtk() {
  const s = state.lbState;
  return s.atk + (LB_WEAPONS.find((w) => w.id === s.weapon)?.atk || 0);
}
function _lbEffectiveDef() {
  const s = state.lbState;
  return s.def + (LB_ARMOR.find((a) => a.id === s.armor)?.def || 0);
}

function _lbRender(stage) {
  const s = state.lbState;
  if (!s) return;
  const wpn = LB_WEAPONS.find((w) => w.id === s.weapon)?.name || "Bare hands";
  const arm = LB_ARMOR.find((a) => a.id === s.armor)?.name || "Cotton shirt";
  const stats = `┌── LEGEND OF THE BLACK BUOY ─ Level ${s.level} ─┐
│  HP: ${String(s.hp).padStart(3)}/${s.hpMax}  ATK: ${String(_lbEffectiveAtk()).padStart(2)}  DEF: ${String(_lbEffectiveDef()).padStart(2)}            │
│  Gold: ${String(s.gold).padStart(5)}  XP: ${String(s.xp).padStart(4)}/${100 * s.level}             │
│  Weapon: ${wpn.padEnd(28)}│
│  Armor:  ${arm.padEnd(28)}│
│  Reef fights remaining today: ${String(s.fightsLeft).padStart(2)}/12        │
└─────────────────────────────────────────────┘`;
  const logBlock = s.log.map((l) => `  > ${l}`).join("\n");

  let body = "";
  if (s.location === "lobby") {
    body = `\n   You're at the docks. Choose where to go:\n\n${logBlock}`;
  } else if (s.location === "reef" && s.enemy) {
    const e = s.enemy;
    body = `\n   ⚔  In combat at the Reef.
   Enemy: ${e.name}   HP: ${e.hp}/${e.hpMax}   ATK: ${e.atk}   DEF: ${e.def}

${logBlock}`;
  } else if (s.location === "reef") {
    body = `\n   The Reef is quiet... for now. Hit [Hunt] to find prey.\n\n${logBlock}`;
  } else if (s.location === "inn") {
    body = `\n   The Harbor Inn smells of chowder and damp rope.
   - Meal:  ${10 * s.level} gold → restore HP to max.
   - Rest:  100 gold → restore HP + refresh 1 Reef fight.\n\n${logBlock}`;
  } else if (s.location === "shipyard") {
    const atkCost = 8 * s.level;
    const defCost = 8 * s.level;
    const hpCost = 6 * s.level;
    body = `\n   The Shipyard. Spend XP and gold to upgrade.
   - +1 ATK:  ${atkCost} XP + ${atkCost * 2} gold
   - +1 DEF:  ${defCost} XP + ${defCost * 2} gold
   - +5 HP:   ${hpCost} XP + ${hpCost * 2} gold\n\n${logBlock}`;
  } else if (s.location === "market") {
    body = `\n   The Black Market — pick a weapon or armor upgrade.\n\n${logBlock}`;
  } else if (s.location === "master") {
    body = `\n   The Master at the end of the pier.
   You must reach Level ${s.level} XP (${100 * s.level}) before you can challenge.
   Current XP: ${s.xp}/${100 * s.level}\n\n${logBlock}`;
  }

  let actions = "";
  if (s.location === "lobby") {
    actions = `<button type="button" class="button button-secondary" data-lb-go="reef" ${s.fightsLeft === 0 ? "disabled title='No fights left today; visit the Inn to rest'" : ""}>[R] Reef</button>
      <button type="button" class="button button-secondary" data-lb-go="inn">[I] Harbor Inn</button>
      <button type="button" class="button button-secondary" data-lb-go="shipyard">[Y] Shipyard</button>
      <button type="button" class="button button-secondary" data-lb-go="market">[B] Black Market</button>
      <button type="button" class="button button-secondary" data-lb-go="master">[M] Master</button>`;
  } else if (s.location === "reef" && s.enemy) {
    actions = `<button type="button" class="button button-primary" data-lb-cb="attack">[A]ttack</button>
      <button type="button" class="button button-secondary" data-lb-cb="defend">[D]efend</button>
      <button type="button" class="button button-secondary" data-lb-cb="run">[R]un</button>`;
  } else if (s.location === "reef") {
    actions = `<button type="button" class="button button-primary" data-lb-hunt>[H]unt</button>
      <button type="button" class="button button-secondary" data-lb-go="lobby">[L]eave</button>`;
  } else if (s.location === "inn") {
    actions = `<button type="button" class="button button-primary" data-lb-inn="meal">Buy meal (${10 * s.level}g)</button>
      <button type="button" class="button button-secondary" data-lb-inn="rest" ${s.gold < 100 ? "disabled" : ""}>Rest (100g)</button>
      <button type="button" class="button button-secondary" data-lb-go="lobby">[L]eave</button>`;
  } else if (s.location === "shipyard") {
    actions = `<button type="button" class="button button-secondary" data-lb-train="atk">+1 ATK</button>
      <button type="button" class="button button-secondary" data-lb-train="def">+1 DEF</button>
      <button type="button" class="button button-secondary" data-lb-train="hp">+5 HP</button>
      <button type="button" class="button button-secondary" data-lb-go="lobby">[L]eave</button>`;
  } else if (s.location === "market") {
    const wRows = LB_WEAPONS.map((w) => `<button type="button" class="button button-secondary" data-lb-buy-w="${w.id}" ${s.weapon === w.id ? "disabled title='Equipped'" : s.gold < w.cost ? "disabled" : ""}>${w.name} +${w.atk} (${w.cost}g)</button>`).join("");
    const aRows = LB_ARMOR.map((a) => `<button type="button" class="button button-secondary" data-lb-buy-a="${a.id}" ${s.armor === a.id ? "disabled title='Equipped'" : s.gold < a.cost ? "disabled" : ""}>${a.name} +${a.def} (${a.cost}g)</button>`).join("");
    actions = `${wRows}${aRows}<button type="button" class="button button-secondary" data-lb-go="lobby">[L]eave</button>`;
  } else if (s.location === "master") {
    const canChallenge = s.xp >= 100 * s.level;
    actions = `<button type="button" class="button button-primary" data-lb-master ${canChallenge ? "" : "disabled"}>Challenge the Master</button>
      <button type="button" class="button button-secondary" data-lb-go="lobby">[L]eave</button>`;
  }
  // Add reset always
  actions += `<button type="button" class="button button-secondary" data-lb-reset title="Erase save and start fresh">[New character]</button>
    <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>`;

  stage.innerHTML = `<pre class="bbs-game-screen">${stats}${body}</pre>
    <div class="bbs-game-controls">${actions}</div>`;
}

function _lbGo(loc) {
  state.lbState.location = loc;
  if (loc !== "reef") state.lbState.enemy = null;
  _lbSave(); _lbRender($("bbs-game-stage"));
}
function _lbHunt() {
  const s = state.lbState;
  if (s.fightsLeft <= 0) { _lbPush("No fights left today. Rest at the Inn."); _lbRender($("bbs-game-stage")); return; }
  // Pick a tier based on player level
  const tierIdx = Math.min(LB_MONSTERS_TIER.length - 1, Math.max(0, Math.floor(s.level / 2) + Math.floor(Math.random() * 2)));
  const tpl = LB_MONSTERS_TIER[tierIdx];
  s.enemy = { ...tpl, hpMax: tpl.hp };
  s.fightsLeft -= 1;
  _lbPush(`A ${s.enemy.name} attacks! It's swimming aggressively.`);
  _lbRender($("bbs-game-stage"));
}
function _lbCombat(action) {
  const s = state.lbState;
  const e = s.enemy;
  if (!e) return;
  if (action === "run") {
    if (Math.random() < 0.6) { _lbPush(`You escape the ${e.name}.`); s.enemy = null; }
    else { const dmg = Math.max(1, e.atk - _lbEffectiveDef()); s.hp = Math.max(0, s.hp - dmg); _lbPush(`The ${e.name} catches you. ${dmg} damage taken.`); }
  } else if (action === "attack") {
    const myAtk = _lbEffectiveAtk() + Math.floor(Math.random() * 6);
    const enemyDef = e.def;
    const dmg = Math.max(1, myAtk - enemyDef);
    e.hp -= dmg;
    _lbPush(`You strike for ${dmg}. ${e.name}: ${Math.max(0, e.hp)}/${e.hpMax}.`);
    if (e.hp <= 0) {
      _lbPush(`The ${e.name} is dead! +${e.gold} gold, +${e.xp} XP.`);
      s.gold += e.gold; s.xp += e.xp;
      s.enemy = null;
      _lbSave(); _lbRender($("bbs-game-stage")); return;
    }
    // Enemy counterattack
    const dmg2 = Math.max(1, e.atk - _lbEffectiveDef() + Math.floor(Math.random() * 4) - 2);
    s.hp = Math.max(0, s.hp - dmg2);
    _lbPush(`${e.name} bites back for ${dmg2}.`);
  } else if (action === "defend") {
    const reducedAtk = Math.max(0, e.atk - _lbEffectiveDef() * 2);
    s.hp = Math.max(0, s.hp - Math.floor(reducedAtk * 0.5));
    _lbPush(`You raise your guard. ${Math.floor(reducedAtk * 0.5)} damage taken.`);
  }
  if (s.hp <= 0) {
    _lbPush(`You fall. The tide carries you back to shore. Lose half your gold.`);
    s.gold = Math.floor(s.gold / 2);
    s.hp = Math.max(1, Math.floor(s.hpMax * 0.3));
    s.enemy = null; s.location = "lobby";
    _bbsRecordGameScore("legend-buoy", s.level);
  }
  _lbSave(); _lbRender($("bbs-game-stage"));
}
function _lbInn(action) {
  const s = state.lbState;
  if (action === "meal") {
    const cost = 10 * s.level;
    if (s.gold < cost) { _lbPush(`Not enough gold for a meal.`); _lbRender($("bbs-game-stage")); return; }
    s.gold -= cost; s.hp = s.hpMax;
    _lbPush(`Chowder, sourdough, hot coffee. HP restored.`);
  } else if (action === "rest") {
    if (s.gold < 100) { _lbPush(`Not enough gold to rest.`); _lbRender($("bbs-game-stage")); return; }
    s.gold -= 100; s.hp = s.hpMax;
    s.fightsLeft = Math.min(12, s.fightsLeft + 1);
    _lbPush(`A full night's sleep. HP full + 1 extra Reef fight today.`);
  }
  _lbSave(); _lbRender($("bbs-game-stage"));
}
function _lbTrain(stat) {
  const s = state.lbState;
  const cost = (stat === "hp" ? 6 : 8) * s.level;
  if (s.xp < cost) { _lbPush(`Need ${cost} XP to train.`); _lbRender($("bbs-game-stage")); return; }
  if (s.gold < cost * 2) { _lbPush(`Need ${cost * 2} gold to train.`); _lbRender($("bbs-game-stage")); return; }
  s.xp -= cost; s.gold -= cost * 2;
  if (stat === "atk") { s.atk += 1; _lbPush(`Trained ATK. Now ${s.atk}.`); }
  else if (stat === "def") { s.def += 1; _lbPush(`Trained DEF. Now ${s.def}.`); }
  else if (stat === "hp") { s.hpMax += 5; s.hp += 5; _lbPush(`Trained HP. Now ${s.hpMax} max.`); }
  _lbSave(); _lbRender($("bbs-game-stage"));
}
function _lbBuyWeapon(id) {
  const s = state.lbState; const w = LB_WEAPONS.find((x) => x.id === id);
  if (!w || s.gold < w.cost) return;
  s.gold -= w.cost; s.weapon = w.id;
  _lbPush(`Bought + equipped ${w.name}.`); _lbSave(); _lbRender($("bbs-game-stage"));
}
function _lbBuyArmor(id) {
  const s = state.lbState; const a = LB_ARMOR.find((x) => x.id === id);
  if (!a || s.gold < a.cost) return;
  s.gold -= a.cost; s.armor = a.id;
  _lbPush(`Bought + equipped ${a.name}.`); _lbSave(); _lbRender($("bbs-game-stage"));
}
function _lbMaster() {
  const s = state.lbState;
  const need = 100 * s.level;
  if (s.xp < need) return;
  // Boss fight is auto-resolved with a roll based on stats.
  const myPower = _lbEffectiveAtk() + _lbEffectiveDef() + s.hpMax / 5;
  const bossPower = s.level * 25;
  const roll = Math.random();
  const win = (myPower * (0.6 + roll * 0.8)) >= bossPower;
  if (win) {
    s.xp -= need;
    s.level += 1; s.hpMax += 10; s.hp = s.hpMax; s.atk += 1; s.def += 1;
    _lbPush(`★ You defeat the Master and ascend to level ${s.level}. +10 HP, +1 ATK, +1 DEF.`);
    _bbsRecordGameScore("legend-buoy", s.level);
  } else {
    s.hp = Math.max(1, Math.floor(s.hp / 2));
    _lbPush(`The Master defeats you. Train more before returning. HP halved.`);
  }
  _lbSave(); _lbRender($("bbs-game-stage"));
}
function _lbReset() {
  _bbsSaveJson(LB_SAVE_KEY, null);
  state.lbState = null;
  _lbLaunch($("bbs-game-stage"));
}


/* ════════════════════════════════════════════════════════════════════
   GAME: Fleet Realms Elite  (BRE/SRE-style empire builder)
   ════════════════════════════════════════════════════════════════════
   Six rival fleets (you + 5 AI) compete across 30 turns. Each turn you
   spend Action Points: recruit ships, raid a neighbor, fortify, scout.
   Win condition: highest score at turn 30 (ships + gold + raids won). */
const FR_SAVE_KEY = "omega-bbs-game-fleet-realms-v1";
const FR_FLEETS = ["You", "Black Tide", "Silver Reef", "Iron Anchor", "Coral Pact", "Drift King"];

function _frLaunch(stage) {
  let s = _bbsLoadJson(FR_SAVE_KEY, null);
  if (!s) {
    s = {
      turn: 1, maxTurns: 30,
      ap: 4, apMax: 4,
      fleets: FR_FLEETS.map((name, i) => ({ name, ships: 10, gold: 200, defense: 5, raidsWon: 0, alive: true, isYou: i === 0 })),
      log: ["Turn 1. You command 10 ships and 200 gold. 4 actions/turn, 30 turns total."],
    };
    _bbsSaveJson(FR_SAVE_KEY, s);
  }
  state.frState = s;
  _frRender(stage);
}
function _frSave() { _bbsSaveJson(FR_SAVE_KEY, state.frState); }
function _frPush(l) {
  state.frState.log.push(l);
  if (state.frState.log.length > 8) state.frState.log.shift();
  _frSave();
}
function _frScore(f) { return f.ships * 10 + f.gold + f.raidsWon * 30 + f.defense * 5; }
function _frRender(stage) {
  const s = state.frState; if (!s) return;
  const you = s.fleets[0];
  const otherFleets = s.fleets.filter((f) => f.alive && !f.isYou);
  const rankings = s.fleets.slice().sort((a, b) => _frScore(b) - _frScore(a));
  const ranking = rankings.map((f, i) => `  ${(i + 1) + "."} ${f.name.padEnd(14)} ships=${String(f.ships).padStart(3)}  gold=${String(f.gold).padStart(4)}  raids=${String(f.raidsWon).padStart(2)}  score=${String(_frScore(f)).padStart(4)}${f.isYou ? "  ← YOU" : ""}${f.alive ? "" : "  (eliminated)"}`).join("\n");
  const logBlock = s.log.map((l) => `  > ${l}`).join("\n");
  const ended = s.turn > s.maxTurns || !you.alive;
  const screen = `┌── FLEET REALMS ELITE ─ Turn ${s.turn}/${s.maxTurns}  AP ${s.ap}/${s.apMax} ─┐
│  Your fleet:  ships=${String(you.ships).padStart(3)}  gold=${String(you.gold).padStart(4)}  def=${String(you.defense).padStart(2)} │
│  Raids won:   ${String(you.raidsWon).padStart(2)}  Score: ${String(_frScore(you)).padStart(5)}             │
└────────────────────────────────────────────────────┘

   STANDINGS
${ranking}

   Recent:
${logBlock}
${ended ? "\n   ── CAMPAIGN OVER ──" : ""}`;

  const raidButtons = otherFleets.map((f) => `<button type="button" class="button button-secondary" data-fr-raid="${escapeHtml(f.name)}" ${s.ap < 2 ? "disabled" : ""}>⚔ Raid ${f.name}</button>`).join("");
  const actionButtons = ended ? "" : `
    <button type="button" class="button button-secondary" data-fr-act="recruit"  ${s.ap < 1 || you.gold < 50 ? "disabled" : ""}>+5 ships (50g, 1 AP)</button>
    <button type="button" class="button button-secondary" data-fr-act="fortify"  ${s.ap < 1 || you.gold < 30 ? "disabled" : ""}>+1 def (30g, 1 AP)</button>
    <button type="button" class="button button-secondary" data-fr-act="forage"   ${s.ap < 1 ? "disabled" : ""}>Forage (+80–160g, 1 AP)</button>
    <button type="button" class="button button-secondary" data-fr-act="scout"    ${s.ap < 1 ? "disabled" : ""}>Scout (peek at AI, 1 AP)</button>
    ${raidButtons}
    <button type="button" class="button button-primary" data-fr-act="endturn">[End turn]</button>`;
  stage.innerHTML = `<pre class="bbs-game-screen">${screen}</pre>
    <div class="bbs-game-controls">${actionButtons}</div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-fr-reset>[New campaign]</button>
      <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
    </div>`;
}
function _frAct(action, target) {
  const s = state.frState; const you = s.fleets[0];
  if (s.turn > s.maxTurns || !you.alive) return;
  if (action === "recruit") { if (s.ap < 1 || you.gold < 50) return; you.gold -= 50; you.ships += 5; s.ap -= 1; _frPush(`Recruited 5 ships. Now ${you.ships}.`); }
  else if (action === "fortify") { if (s.ap < 1 || you.gold < 30) return; you.gold -= 30; you.defense += 1; s.ap -= 1; _frPush(`Fortifications +1. Defense ${you.defense}.`); }
  else if (action === "forage") { if (s.ap < 1) return; const g = 80 + Math.floor(Math.random() * 81); you.gold += g; s.ap -= 1; _frPush(`Foraging brought +${g} gold.`); }
  else if (action === "scout") { if (s.ap < 1) return; s.ap -= 1; const f = s.fleets.filter((x) => x.alive && !x.isYou)[Math.floor(Math.random() * (s.fleets.filter((x) => x.alive && !x.isYou).length))]; _frPush(`Scout: ${f.name} has ${f.ships} ships, ${f.gold}g, def ${f.defense}.`); }
  else if (action === "raid" && target) {
    if (s.ap < 2) return;
    const enemy = s.fleets.find((f) => f.name === target && f.alive && !f.isYou);
    if (!enemy) return;
    s.ap -= 2;
    const youPower = you.ships * (1 + Math.random() * 0.4);
    const enemyPower = enemy.ships * (1 + Math.random() * 0.3) + enemy.defense * 2;
    const win = youPower > enemyPower;
    if (win) {
      const lost = Math.max(1, Math.floor(enemy.ships * (0.15 + Math.random() * 0.2)));
      const looted = Math.max(50, Math.floor(enemy.gold * (0.3 + Math.random() * 0.4)));
      you.ships = Math.max(0, you.ships - Math.floor(lost / 2));
      enemy.ships = Math.max(0, enemy.ships - lost);
      enemy.gold = Math.max(0, enemy.gold - looted);
      you.gold += looted;
      you.raidsWon += 1;
      _frPush(`Raid on ${enemy.name} succeeded. +${looted}g, sunk ${lost} of theirs, lost ${Math.floor(lost / 2)} of ours.`);
      if (enemy.ships <= 0) { enemy.alive = false; _frPush(`${enemy.name} is eliminated.`); }
    } else {
      const myLost = Math.max(2, Math.floor(you.ships * 0.18));
      you.ships = Math.max(0, you.ships - myLost);
      _frPush(`Raid on ${enemy.name} failed. Lost ${myLost} ships.`);
      if (you.ships <= 0) { you.alive = false; _frPush(`Your fleet is destroyed. Campaign over.`); }
    }
  } else if (action === "endturn") { _frEndTurn(); return; }
  _frSave(); _frRender($("bbs-game-stage"));
}
function _frEndTurn() {
  const s = state.frState;
  // AI moves: each AI gets 3 AP, simple greedy decisions
  for (const f of s.fleets) {
    if (!f.alive || f.isYou) continue;
    let ap = 3;
    while (ap > 0) {
      const choice = Math.random();
      if (choice < 0.3 && f.gold >= 50) { f.gold -= 50; f.ships += 5; ap -= 1; }
      else if (choice < 0.5) { const g = 60 + Math.floor(Math.random() * 60); f.gold += g; ap -= 1; }
      else if (choice < 0.7 && f.gold >= 30) { f.gold -= 30; f.defense += 1; ap -= 1; }
      else if (ap >= 2 && f.ships > 8) {
        // Possibly raid you
        const targets = s.fleets.filter((x) => x.alive && x.name !== f.name);
        const tgt = targets[Math.floor(Math.random() * targets.length)];
        if (tgt) {
          const myP = f.ships * 1.1;
          const tgtP = tgt.ships * 1.05 + tgt.defense * 2;
          if (myP > tgtP * (0.8 + Math.random() * 0.3)) {
            const loss = Math.max(1, Math.floor(tgt.ships * 0.15));
            const loot = Math.max(40, Math.floor(tgt.gold * 0.3));
            tgt.ships = Math.max(0, tgt.ships - loss);
            tgt.gold = Math.max(0, tgt.gold - loot);
            f.gold += loot; f.raidsWon += 1;
            _frPush(`${f.name} raided ${tgt.name}, sank ${loss} ships, took ${loot}g.`);
            if (tgt.ships <= 0) { tgt.alive = false; _frPush(`${tgt.name} eliminated.`); }
          } else {
            const myLoss = Math.max(1, Math.floor(f.ships * 0.12));
            f.ships = Math.max(0, f.ships - myLoss);
          }
        }
        ap -= 2;
      } else { ap = 0; }
    }
  }
  s.turn += 1; s.ap = s.apMax;
  _frPush(`Turn ${s.turn} begins.`);
  if (s.turn > s.maxTurns) {
    const rankings = s.fleets.slice().sort((a, b) => _frScore(b) - _frScore(a));
    _frPush(`Campaign over. Winner: ${rankings[0].name} (score ${_frScore(rankings[0])}).`);
    _bbsRecordGameScore("fleet-realms", _frScore(s.fleets[0]));
  }
  _frSave(); _frRender($("bbs-game-stage"));
}
function _frReset() { _bbsSaveJson(FR_SAVE_KEY, null); state.frState = null; _frLaunch($("bbs-game-stage")); }


/* ════════════════════════════════════════════════════════════════════
   GAME: Global War: Pacific  (Risk-style territory dice)
   ════════════════════════════════════════════════════════════════════
   12 Pacific zones, you start with 3, AI with 3, 6 neutral. Roll dice
   to attack adjacent zones. Hold + reinforce; last fleet standing wins. */
const GW_ZONES = [
  { id: 1, name: "Aleutian Arc",   neighbors: [2, 3] },
  { id: 2, name: "Bering Sea",     neighbors: [1, 3, 4] },
  { id: 3, name: "Gulf of Alaska", neighbors: [1, 2, 4, 5] },
  { id: 4, name: "Salish Sea",     neighbors: [2, 3, 5, 6] },
  { id: 5, name: "California Curr",neighbors: [3, 4, 6, 7] },
  { id: 6, name: "Baja Pacific",   neighbors: [4, 5, 7, 8] },
  { id: 7, name: "Hawaii",         neighbors: [5, 6, 8, 11] },
  { id: 8, name: "Eq Pacific",     neighbors: [6, 7, 9, 11] },
  { id: 9, name: "Tasman Sea",     neighbors: [8, 10, 12] },
  { id: 10, name: "Coral Sea",     neighbors: [9, 11, 12] },
  { id: 11, name: "Marianas",      neighbors: [7, 8, 10, 12] },
  { id: 12, name: "Sea of Japan",  neighbors: [9, 10, 11] },
];

function _gwLaunch(stage) {
  const owners = {};   // zone id -> "you" | "ai" | "neutral"
  const armies = {};
  const youZones = [1, 4, 7];
  const aiZones  = [9, 12, 6];
  for (const z of GW_ZONES) {
    owners[z.id] = youZones.includes(z.id) ? "you" : aiZones.includes(z.id) ? "ai" : "neutral";
    armies[z.id] = owners[z.id] === "neutral" ? (2 + Math.floor(Math.random() * 3)) : 5;
  }
  state.gwState = { owners, armies, reserves: 4, log: [`Turn 1. You hold S1, S4, S7. Each has 5 ships + 4 in reserves.`], turn: 1 };
  _gwRender(stage);
}
function _gwSave() { /* in-memory only — short game */ }
function _gwPush(l) {
  state.gwState.log.push(l);
  if (state.gwState.log.length > 6) state.gwState.log.shift();
}
function _gwRoll(n) { return Math.floor(Math.random() * 6) + 1; }
function _gwAttack(from, to) {
  const s = state.gwState;
  const zf = GW_ZONES.find((z) => z.id === from);
  const zt = GW_ZONES.find((z) => z.id === to);
  if (!zf || !zt || !zf.neighbors.includes(to)) return;
  if (s.owners[from] !== "you" || s.owners[to] === "you") return;
  if (s.armies[from] < 2) { _gwPush(`Need at least 2 in S${from} to attack.`); _gwRender($("bbs-game-stage")); return; }
  const r1 = _gwRoll(); const r2 = _gwRoll();
  _gwPush(`S${from} → S${to}. Your ${r1} vs their ${r2}.`);
  if (r1 >= r2) {
    s.armies[to] -= 1;
    if (s.armies[to] <= 0) {
      s.owners[to] = "you";
      s.armies[to] = 1;
      s.armies[from] -= 1;
      _gwPush(`Captured S${to} — ${zt.name}!`);
    }
  } else {
    s.armies[from] -= 1;
    _gwPush(`Lost a ship in S${from}.`);
  }
  _gwCheckWin();
  _gwRender($("bbs-game-stage"));
}
function _gwReinforce(zone) {
  const s = state.gwState;
  if (s.owners[zone] !== "you") return;
  if (s.reserves <= 0) return;
  s.armies[zone] += 1; s.reserves -= 1;
  _gwPush(`Reinforced S${zone}. ${s.reserves} reserves left.`);
  _gwRender($("bbs-game-stage"));
}
function _gwEndTurn() {
  const s = state.gwState;
  // AI: pick a random "ai" zone and attack a random non-ai neighbor
  const aiZones = Object.keys(s.owners).filter((id) => s.owners[id] === "ai").map(Number);
  for (const zid of aiZones) {
    if (s.armies[zid] < 2) continue;
    const z = GW_ZONES.find((zz) => zz.id === zid);
    const targets = z.neighbors.filter((n) => s.owners[n] !== "ai");
    if (!targets.length) continue;
    const tgt = targets[Math.floor(Math.random() * targets.length)];
    const r1 = _gwRoll(), r2 = _gwRoll();
    if (r1 > r2) {
      s.armies[tgt] -= 1;
      if (s.armies[tgt] <= 0) {
        const wasYou = s.owners[tgt] === "you";
        s.owners[tgt] = "ai"; s.armies[tgt] = 1; s.armies[zid] -= 1;
        _gwPush(`AI captured S${tgt}${wasYou ? " (FROM YOU)" : ""}.`);
      }
    } else { s.armies[zid] -= 1; }
  }
  // Add reserves equal to # zones you hold (min 3)
  const yourZones = Object.keys(s.owners).filter((id) => s.owners[id] === "you").length;
  s.reserves = Math.max(3, yourZones);
  s.turn += 1;
  _gwPush(`Turn ${s.turn}. +${s.reserves} reserves available.`);
  _gwCheckWin();
  _gwRender($("bbs-game-stage"));
}
function _gwCheckWin() {
  const s = state.gwState;
  const youCount = Object.values(s.owners).filter((o) => o === "you").length;
  const aiCount  = Object.values(s.owners).filter((o) => o === "ai").length;
  if (youCount === 0) { _gwPush(`You hold no zones. Defeat.`); s.ended = true; _bbsRecordGameScore("global-war", -s.turn); }
  else if (aiCount === 0) { _gwPush(`AI eliminated. Victory in ${s.turn} turns.`); s.ended = true; _bbsRecordGameScore("global-war", s.turn); }
}
function _gwRender(stage) {
  const s = state.gwState; if (!s) return;
  const grid = GW_ZONES.map((z) => {
    const o = s.owners[z.id]; const a = s.armies[z.id];
    const mark = o === "you" ? "U" : o === "ai" ? "X" : "·";
    return `  [${mark}] S${String(z.id).padStart(2)} ${z.name.padEnd(16)} (${a})  → ${z.neighbors.map((n) => "S" + n).join(", ")}`;
  }).join("\n");
  const logBlock = s.log.map((l) => `  > ${l}`).join("\n");
  const screen = `┌── GLOBAL WAR: PACIFIC ─ Turn ${s.turn} ─ Reserves: ${s.reserves} ─┐
│  [U]=You  [X]=Enemy  [·]=Neutral             │
└──────────────────────────────────────────────┘

${grid}

   Recent:
${logBlock}
${s.ended ? "\n   ── CAMPAIGN OVER ──" : ""}`;

  // Attack pickers — show only your zones with >=2 armies and their valid targets
  let actions = "";
  if (!s.ended) {
    const yourZones = GW_ZONES.filter((z) => s.owners[z.id] === "you" && s.armies[z.id] >= 2);
    actions += yourZones.flatMap((z) => z.neighbors
      .filter((n) => s.owners[n] !== "you")
      .map((n) => `<button type="button" class="button button-secondary" data-gw-attack="${z.id}-${n}">S${z.id}→S${n}</button>`)).join("");
    // Reinforce buttons for your zones
    const reinforce = GW_ZONES.filter((z) => s.owners[z.id] === "you")
      .map((z) => `<button type="button" class="button button-secondary" data-gw-reinforce="${z.id}" ${s.reserves <= 0 ? "disabled" : ""}>+1 to S${z.id}</button>`).join("");
    actions += reinforce;
    actions += `<button type="button" class="button button-primary" data-gw-end>[End turn]</button>`;
  }
  stage.innerHTML = `<pre class="bbs-game-screen">${screen}</pre>
    <div class="bbs-game-controls">${actions}</div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-gw-reset>[New campaign]</button>
      <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
    </div>`;
}
function _gwReset() { state.gwState = null; _gwLaunch($("bbs-game-stage")); }


/* ════════════════════════════════════════════════════════════════════
   GAME: Operation Overkill III  (8 levels of node-crawl combat)
   ════════════════════════════════════════════════════════════════════
   Each "level" is a flooded refinery deck. Move through rooms, loot
   for ammo, fight mutants. Reach the exit to descend. Survive 8. */
const OO_SAVE_KEY = "omega-bbs-game-overkill-v1";
function _ooLaunch(stage) {
  let s = _bbsLoadJson(OO_SAVE_KEY, null);
  if (!s) {
    s = { level: 1, hp: 30, hpMax: 30, ammo: 12, room: 1, killed: 0, log: ["You drop into Deck 1 of the flooded refinery. 30 HP, 12 rounds."], event: null };
    _bbsSaveJson(OO_SAVE_KEY, s);
  }
  state.ooState = s;
  _ooRender(stage);
}
function _ooSave() { _bbsSaveJson(OO_SAVE_KEY, state.ooState); }
function _ooPush(l) {
  state.ooState.log.push(l);
  if (state.ooState.log.length > 6) state.ooState.log.shift();
  _ooSave();
}
function _ooRender(stage) {
  const s = state.ooState; if (!s) return;
  const screen = `┌── OPERATION OVERKILL III ─ Deck ${s.level}/8 ─ Room ${s.room}/5 ─┐
│  HP: ${String(s.hp).padStart(2)}/${s.hpMax}  Ammo: ${String(s.ammo).padStart(2)}  Kills: ${String(s.killed).padStart(3)}        │
└─────────────────────────────────────────────────────┘

   ${s.event ? "▼ EVENT IN ROOM " + s.room + ":  " + s.event : "Pick an action to advance."}

   Recent:
${s.log.map((l) => `  > ${l}`).join("\n")}
${s.dead ? "\n   ── DEAD ──" : (s.won ? "\n   ── REFINERY CLEARED ── " : "")}`;
  let actions = "";
  if (s.dead || s.won) {
    actions = "";
  } else if (s.event) {
    if (s.event.startsWith("Mutant")) {
      actions = `<button type="button" class="button button-primary" data-oo-act="shoot" ${s.ammo <= 0 ? "disabled" : ""}>🔫 Shoot (-1 ammo)</button>
        <button type="button" class="button button-secondary" data-oo-act="melee">🔪 Melee</button>
        <button type="button" class="button button-secondary" data-oo-act="flee">🏃 Flee</button>`;
    } else if (s.event.startsWith("Loot")) {
      actions = `<button type="button" class="button button-primary" data-oo-act="loot">📦 Take loot</button>
        <button type="button" class="button button-secondary" data-oo-act="ignore">↷ Ignore</button>`;
    } else {
      actions = `<button type="button" class="button button-primary" data-oo-act="continue">[Continue]</button>`;
    }
  } else {
    actions = `<button type="button" class="button button-primary" data-oo-act="advance">[Advance →]</button>`;
  }
  stage.innerHTML = `<pre class="bbs-game-screen">${screen}</pre>
    <div class="bbs-game-controls">${actions}</div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-oo-reset>[New run]</button>
      <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
    </div>`;
}
function _ooAct(action) {
  const s = state.ooState; if (!s) return;
  if (s.dead || s.won) return;
  if (action === "advance") {
    const r = Math.random();
    if (r < 0.5) {
      const power = 4 + s.level * 2 + Math.floor(Math.random() * 5);
      s.event = `Mutant Drifter (atk ${power})`; _ooPush(`Encountered a mutant drifter.`);
    } else if (r < 0.8) {
      s.event = `Loot crate — could be ammo or stim`;
    } else {
      s.event = `Quiet room. Just pipes and water.`;
      _ooPush(`Room ${s.room} is clear.`);
    }
  } else if (action === "shoot") {
    if (s.ammo <= 0) return;
    s.ammo -= 1;
    const hit = Math.random() < 0.85;
    if (hit) {
      s.killed += 1; _ooPush(`Shot fired. Mutant down.`);
      s.event = null;
    } else {
      const dmg = 3 + Math.floor(Math.random() * 4);
      s.hp -= dmg; _ooPush(`Missed! Mutant clawed you for ${dmg}.`);
    }
  } else if (action === "melee") {
    const win = Math.random() < 0.55;
    if (win) { s.killed += 1; _ooPush(`Melee kill.`); s.event = null; }
    else { const dmg = 4 + Math.floor(Math.random() * 6); s.hp -= dmg; _ooPush(`Melee fail. -${dmg} HP.`); }
  } else if (action === "flee") {
    if (Math.random() < 0.7) { _ooPush(`Slipped past it.`); s.event = null; }
    else { const dmg = 2 + Math.floor(Math.random() * 4); s.hp -= dmg; _ooPush(`Caught while fleeing. -${dmg} HP.`); }
  } else if (action === "loot") {
    const kind = Math.random();
    if (kind < 0.5) { const a = 3 + Math.floor(Math.random() * 4); s.ammo += a; _ooPush(`Looted ${a} rounds.`); }
    else if (kind < 0.85) { const h = 5 + Math.floor(Math.random() * 6); s.hp = Math.min(s.hpMax, s.hp + h); _ooPush(`Stim pack. +${h} HP.`); }
    else { _ooPush(`Loot crate was empty.`); }
    s.event = null;
  } else if (action === "ignore" || action === "continue") {
    s.event = null;
  }
  if (s.hp <= 0) { s.dead = true; _ooPush(`You're killed by a mutant. Killed ${s.killed} on the way down.`); _bbsRecordGameScore("overkill", s.killed); }
  if (!s.event && !s.dead) {
    s.room += 1;
    if (s.room > 5) { s.room = 1; s.level += 1; _ooPush(`Reached Deck ${s.level}.`); }
    if (s.level > 8) { s.won = true; _ooPush(`★ Refinery cleared. Final kills: ${s.killed}.`); _bbsRecordGameScore("overkill", s.killed + 100); }
  }
  _ooSave(); _ooRender($("bbs-game-stage"));
}
function _ooReset() { _bbsSaveJson(OO_SAVE_KEY, null); state.ooState = null; _ooLaunch($("bbs-game-stage")); }


/* ════════════════════════════════════════════════════════════════════
   GAME: Net Cast  (Fishing simulator)
   ════════════════════════════════════════════════════════════════════
   - 6 species at varying depths and bite difficulty.
   - Time of day cycle (Dawn / Day / Dusk / Night) modifies bite chance
     per species; each cast advances time by 1 step.
   - 4 tackle tiers (Hand line → Rod → Reel → Deep-sea Rig), each opens
     deeper waters and reduces miss rate.
   - Daily catch goal: 200 lb. Sell at the dock for credits, upgrade
     gear, push for the Mother Kraken at the abyss. Save persists. */
const NC_SAVE_KEY = "omega-bbs-game-netcast-v1";
const NC_TIME_CYCLE = ["Dawn", "Day", "Dusk", "Night"];
const NC_SPECIES = [
  { id: "perch",   name: "Perch",        depth: 1, weight: [1, 3],   sell: 6,  bite: { Dawn: 0.55, Day: 0.4, Dusk: 0.5, Night: 0.15 } },
  { id: "rockcod", name: "Rockcod",      depth: 1, weight: [3, 8],   sell: 11, bite: { Dawn: 0.35, Day: 0.5, Dusk: 0.45, Night: 0.2 } },
  { id: "tuna",    name: "Yellowfin",    depth: 2, weight: [12, 40], sell: 28, bite: { Dawn: 0.4, Day: 0.55, Dusk: 0.4, Night: 0.1 } },
  { id: "marlin",  name: "Blue Marlin",  depth: 2, weight: [80, 220],sell: 60, bite: { Dawn: 0.2, Day: 0.35, Dusk: 0.3, Night: 0.05 } },
  { id: "swordfish",name: "Swordfish",   depth: 3, weight: [100, 280],sell: 80, bite: { Dawn: 0.25, Day: 0.15, Dusk: 0.35, Night: 0.55 } },
  { id: "kraken",  name: "Mother Kraken",depth: 4, weight: [400, 900],sell: 240,bite: { Dawn: 0.05, Day: 0.05, Dusk: 0.1, Night: 0.25 } },
];
const NC_TACKLE = [
  { id: "hand",    name: "Hand line",        depth: 1, miss: 0.4, cost: 0 },
  { id: "rod",     name: "Spinning rod",     depth: 2, miss: 0.25, cost: 150 },
  { id: "reel",    name: "Heavy reel",       depth: 3, miss: 0.15, cost: 600 },
  { id: "deepsea", name: "Deep-sea rig",     depth: 4, miss: 0.08, cost: 2200 },
];
function _ncLaunch(stage) {
  let s = _bbsLoadJson(NC_SAVE_KEY, null);
  if (!s) {
    s = { tackle: "hand", credits: 50, dayLb: 0, totalLb: 0, totalCatches: 0, time: 0, log: ["Welcome to Net Cast. Hand line in hand, dock at dawn. Goal: 200 lb / day."] };
    _bbsSaveJson(NC_SAVE_KEY, s);
  }
  state.ncState = s;
  _ncRender(stage);
}
function _ncSave() { _bbsSaveJson(NC_SAVE_KEY, state.ncState); }
function _ncPush(l) {
  state.ncState.log.push(l);
  if (state.ncState.log.length > 8) state.ncState.log.shift();
  _ncSave();
}
function _ncCurrentTackle() { return NC_TACKLE.find((t) => t.id === state.ncState.tackle); }
function _ncRender(stage) {
  const s = state.ncState; if (!s) return;
  const t = _ncCurrentTackle();
  const tod = NC_TIME_CYCLE[s.time % 4];
  const species = NC_SPECIES.filter((sp) => sp.depth <= t.depth);
  const speciesLine = species.map((sp) => {
    const rate = Math.round(sp.bite[tod] * 100);
    return `  ${sp.name.padEnd(15)} d=${sp.depth} | ${tod} bite ${String(rate).padStart(2)}% | sell ${sp.sell}/lb`;
  }).join("\n");
  const tackleLine = NC_TACKLE.map((tk) => {
    const tag = tk.id === s.tackle ? "← equipped" : (s.credits >= tk.cost ? `(${tk.cost} cr)` : `(${tk.cost} cr — short ${tk.cost - s.credits})`);
    return `  ${tk.name.padEnd(20)} d≤${tk.depth} miss ${Math.round(tk.miss*100)}%  ${tag}`;
  }).join("\n");
  const goalMet = s.dayLb >= 200;
  const screen = `┌── NET CAST ─ ${tod.padEnd(5)} ─ Tackle: ${t.name.padEnd(20)} ─┐
│  Credits: ${String(s.credits).padStart(5)}    Day catch: ${String(s.dayLb).padStart(3)}/200 lb  │
│  All-time: ${String(s.totalLb).padStart(5)} lb in ${String(s.totalCatches).padStart(3)} catches      │
└────────────────────────────────────────────────────┘

   SPECIES IN REACH:
${speciesLine}

   TACKLE SHOP:
${tackleLine}

   Log:
${s.log.map((l) => `  > ${l}`).join("\n")}
${goalMet ? "\n   ★ Daily goal hit. Cash out at the dock or keep fishing." : ""}`;

  const castButtons = species.map((sp) => `<button type="button" class="button button-secondary" data-nc-cast="${sp.id}">🎣 Cast for ${sp.name}</button>`).join("");
  const upgradeButtons = NC_TACKLE.filter((tk) => tk.id !== s.tackle && s.credits >= tk.cost).map((tk) => `<button type="button" class="button button-primary" data-nc-upgrade="${tk.id}">⬆ Upgrade to ${tk.name}</button>`).join("");

  stage.innerHTML = `<pre class="bbs-game-screen">${screen}</pre>
    <div class="bbs-game-controls">${castButtons}</div>
    <div class="bbs-game-controls">
      ${upgradeButtons}
      <button type="button" class="button button-primary" data-nc-cashout ${s.dayLb === 0 ? "disabled" : ""}>💵 Cash out catch (${s.dayLb} lb)</button>
      <button type="button" class="button button-secondary" data-nc-rest>🌅 New day (reset day catch)</button>
    </div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-nc-reset>[New game]</button>
      <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
    </div>`;
}
function _ncCast(speciesId) {
  const s = state.ncState; const t = _ncCurrentTackle();
  const sp = NC_SPECIES.find((x) => x.id === speciesId);
  if (!sp || sp.depth > t.depth) return;
  const tod = NC_TIME_CYCLE[s.time % 4];
  s.time += 1; // each cast advances time
  // Miss?
  if (Math.random() < t.miss) {
    _ncPush(`${tod}: cast for ${sp.name} — line snapped, no fish.`);
    _ncRender($("bbs-game-stage")); return;
  }
  // Bite check
  if (Math.random() > sp.bite[tod]) {
    _ncPush(`${tod}: cast for ${sp.name} — no bite.`);
    _ncRender($("bbs-game-stage")); return;
  }
  // Catch: weight in range
  const [lo, hi] = sp.weight;
  const lb = lo + Math.floor(Math.random() * (hi - lo + 1));
  s.dayLb += lb; s.totalLb += lb; s.totalCatches += 1;
  _ncPush(`${tod}: 🎣 Caught a ${lb} lb ${sp.name}!`);
  // Big fish bonus log
  if (sp.id === "kraken") _ncPush(`★ A LEGENDARY catch. Word will spread on the dock.`);
  _ncSave(); _ncRender($("bbs-game-stage"));
}
function _ncUpgrade(tkId) {
  const s = state.ncState; const tk = NC_TACKLE.find((x) => x.id === tkId);
  if (!tk || s.credits < tk.cost) return;
  s.credits -= tk.cost; s.tackle = tk.id;
  _ncPush(`Upgraded to ${tk.name}. Deeper water unlocked.`);
  _ncSave(); _ncRender($("bbs-game-stage"));
}
function _ncCashout() {
  const s = state.ncState;
  if (s.dayLb <= 0) return;
  // Sell at the average species price weighted by reach
  const t = _ncCurrentTackle();
  const reach = NC_SPECIES.filter((sp) => sp.depth <= t.depth);
  const avg = reach.reduce((n, sp) => n + sp.sell, 0) / reach.length;
  const earn = Math.round(s.dayLb * avg);
  s.credits += earn;
  _ncPush(`Cashed out ${s.dayLb} lb at ~${avg.toFixed(0)} cr/lb → +${earn} cr.`);
  if (s.dayLb >= 200) _bbsRecordGameScore("net-cast", s.totalLb);
  s.dayLb = 0;
  _ncSave(); _ncRender($("bbs-game-stage"));
}
function _ncRest() {
  const s = state.ncState;
  s.dayLb = 0; s.time = 0;
  _ncPush(`New day. The dock is quiet. Time resets to Dawn.`);
  _ncSave(); _ncRender($("bbs-game-stage"));
}
function _ncReset() { _bbsSaveJson(NC_SAVE_KEY, null); state.ncState = null; _ncLaunch($("bbs-game-stage")); }


/* ════════════════════════════════════════════════════════════════════
   GAME: Sonar Hunt  (Battleship variant)
   ════════════════════════════════════════════════════════════════════
   6×6 grid hides 5 enemy subs of varying sizes (1×4, 1×3, 2×2, 1×1).
   You have 30 pings. Each ping reveals: HIT or MISS. Hit cells flash.
   Sink all subs to win. Bonus pings on sinking a sub. Score = pings
   remaining when all subs are sunk. */
const SH_GRID_SIZE = 6;
const SH_FLEET = [{ name: "Cruiser", len: 4 }, { name: "Frigate", len: 3 }, { name: "Patrol A", len: 2 }, { name: "Patrol B", len: 2 }, { name: "Scout", len: 1 }];
function _shLaunch(stage) {
  // Place fleet randomly
  const board = Array.from({ length: SH_GRID_SIZE * SH_GRID_SIZE }, () => ({ ship: null, hit: false }));
  const ships = [];
  for (const tpl of SH_FLEET) {
    let placed = false;
    for (let tries = 0; tries < 200 && !placed; tries++) {
      const horiz = Math.random() < 0.5;
      const r = Math.floor(Math.random() * SH_GRID_SIZE);
      const c = Math.floor(Math.random() * SH_GRID_SIZE);
      const cells = [];
      let ok = true;
      for (let i = 0; i < tpl.len; i++) {
        const rr = horiz ? r : r + i;
        const cc = horiz ? c + i : c;
        if (rr >= SH_GRID_SIZE || cc >= SH_GRID_SIZE) { ok = false; break; }
        const idx = rr * SH_GRID_SIZE + cc;
        if (board[idx].ship != null) { ok = false; break; }
        cells.push(idx);
      }
      if (!ok) continue;
      const shipId = ships.length;
      for (const idx of cells) board[idx].ship = shipId;
      ships.push({ name: tpl.name, len: tpl.len, cells, hits: 0, sunk: false });
      placed = true;
    }
  }
  state.shState = { board, ships, pings: 30, sunk: 0, log: [`Sonar Hunt — 5 enemy subs in the silt. 30 pings. Click a cell.`] };
  _shRender(stage);
}
function _shPush(l) {
  state.shState.log.push(l);
  if (state.shState.log.length > 8) state.shState.log.shift();
}
function _shRender(stage) {
  const s = state.shState; if (!s) return;
  const won = s.sunk === SH_FLEET.length;
  const lost = !won && s.pings <= 0;
  // Build grid HTML
  let cellsHtml = "";
  for (let r = 0; r < SH_GRID_SIZE; r++) {
    for (let c = 0; c < SH_GRID_SIZE; c++) {
      const idx = r * SH_GRID_SIZE + c;
      const cell = s.board[idx];
      const reveal = cell.hit || won;
      const cls = cell.hit ? (cell.ship != null ? "is-hit" : "is-miss") : (reveal && cell.ship != null ? "is-revealed" : "");
      const ch = cell.hit ? (cell.ship != null ? "X" : "·") : (won && cell.ship != null ? "X" : " ");
      cellsHtml += `<button type="button" class="sh-cell ${cls}" data-sh-fire="${idx}" ${(cell.hit || won || lost) ? "disabled" : ""}>${ch}</button>`;
    }
  }
  const status = `┌── SONAR HUNT ─ 6×6 grid ─ Pings: ${String(s.pings).padStart(2)} ─ Sunk: ${s.sunk}/5 ─┐`;
  const fleetLine = s.ships.map((sh) => `  ${sh.name.padEnd(10)} (${sh.len}) ${sh.sunk ? "[SUNK]" : `[${sh.hits}/${sh.len} hits]`}`).join("\n");
  stage.innerHTML = `<pre class="bbs-game-screen">${status}
${fleetLine}
${won ? "\n   ★★★ ALL SUBS SUNK — VICTORY ★★★" : (lost ? "\n   ── PINGS EXHAUSTED — DEFEAT ──" : "")}

   Recent:
${s.log.map((l) => `  > ${l}`).join("\n")}</pre>
    <div class="sh-grid">${cellsHtml}</div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-sh-reset>[New hunt]</button>
      <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
    </div>`;
}
function _shFire(idx) {
  const s = state.shState; if (!s || s.sunk === SH_FLEET.length || s.pings <= 0) return;
  const cell = s.board[idx]; if (cell.hit) return;
  cell.hit = true; s.pings -= 1;
  if (cell.ship != null) {
    const ship = s.ships[cell.ship];
    ship.hits += 1;
    if (ship.hits >= ship.len) {
      ship.sunk = true; s.sunk += 1;
      s.pings += 3; // bonus pings on sink
      _shPush(`SUNK ${ship.name}! +3 bonus pings.`);
      if (s.sunk === SH_FLEET.length) { _bbsRecordGameScore("sonar-hunt", s.pings); _shPush(`★ Fleet destroyed. Final score: ${s.pings} pings remaining.`); }
    } else {
      _shPush(`HIT at row ${Math.floor(idx / SH_GRID_SIZE) + 1}, col ${(idx % SH_GRID_SIZE) + 1}.`);
    }
  } else {
    _shPush(`Miss. ${s.pings} pings left.`);
  }
  if (s.pings <= 0 && s.sunk < SH_FLEET.length) _shPush(`Out of pings.`);
  _shRender($("bbs-game-stage"));
}
function _shReset() { state.shState = null; _shLaunch($("bbs-game-stage")); }


/* ════════════════════════════════════════════════════════════════════
   GAME: Lighthouse Defense  (Tower Defense, turn-based)
   ════════════════════════════════════════════════════════════════════
   - The harbor has 4 lighthouse posts (LH1-LH4). Each can hold ONE
     turret: Beam (cheap, weak), Mortar (mid), Lance (strong).
   - 10 waves of attackers (Skiffs, Cutters, Frigates, Storm Surge).
     Each wave is a list of enemies that approach in rounds.
   - Each round: every turret fires at one enemy in range; survivors
     close one row. If they reach the dock, they damage the harbor.
   - You earn gold per kill to upgrade between waves. 5 dock HP. */
const LD_TURRETS = [
  { id: "beam",   name: "Signal Beam",     cost: 30, atk: 4,  range: 5 },
  { id: "mortar", name: "Coastal Mortar",  cost: 80, atk: 9,  range: 4 },
  { id: "lance",  name: "Plasma Lance",    cost: 180,atk: 22, range: 3 },
];
const LD_WAVE_TEMPLATES = [
  // wave # → list of {type, hp, atk, gold, speed}. Each entry = one enemy.
  [{ t: "Skiff",   hp: 6,  atk: 1, gold: 5,  spd: 1 }, { t: "Skiff", hp: 6, atk: 1, gold: 5, spd: 1 }],
  [{ t: "Skiff",   hp: 8,  atk: 1, gold: 6,  spd: 1 }, { t: "Skiff", hp: 8, atk: 1, gold: 6, spd: 1 }, { t: "Cutter", hp: 16, atk: 2, gold: 12, spd: 1 }],
  [{ t: "Cutter",  hp: 18, atk: 2, gold: 14, spd: 1 }, { t: "Cutter", hp: 18, atk: 2, gold: 14, spd: 1 }, { t: "Skiff", hp: 8, atk: 1, gold: 6, spd: 1 }],
  [{ t: "Surge",   hp: 24, atk: 3, gold: 22, spd: 2 }, { t: "Cutter", hp: 20, atk: 2, gold: 14, spd: 1 }],
  [{ t: "Frigate", hp: 38, atk: 4, gold: 38, spd: 1 }, { t: "Cutter", hp: 22, atk: 2, gold: 14, spd: 1 }],
  [{ t: "Cutter",  hp: 22, atk: 2, gold: 14, spd: 1 }, { t: "Cutter", hp: 22, atk: 2, gold: 14, spd: 1 }, { t: "Surge", hp: 28, atk: 3, gold: 22, spd: 2 }, { t: "Frigate", hp: 40, atk: 4, gold: 38, spd: 1 }],
  [{ t: "Frigate", hp: 48, atk: 4, gold: 38, spd: 1 }, { t: "Frigate", hp: 48, atk: 4, gold: 38, spd: 1 }],
  [{ t: "Surge",   hp: 36, atk: 3, gold: 24, spd: 2 }, { t: "Surge", hp: 36, atk: 3, gold: 24, spd: 2 }, { t: "Frigate", hp: 52, atk: 5, gold: 42, spd: 1 }],
  [{ t: "Frigate", hp: 60, atk: 5, gold: 50, spd: 1 }, { t: "Frigate", hp: 60, atk: 5, gold: 50, spd: 1 }, { t: "Surge", hp: 44, atk: 4, gold: 26, spd: 2 }],
  [{ t: "Kraken",  hp: 220, atk: 8, gold: 200, spd: 1 }],
];
function _ldLaunch(stage) {
  state.ldState = {
    posts: [null, null, null, null], // turret id at each post
    gold: 90, dockHp: 5, wave: 0, waveActive: false, enemies: [],
    log: [`Lighthouse Defense — defend the harbor. 4 turret posts, 10 waves. Start: 90 gold, 5 dock HP.`],
  };
  _ldRender(stage);
}
function _ldPush(l) {
  state.ldState.log.push(l);
  if (state.ldState.log.length > 8) state.ldState.log.shift();
}
function _ldRender(stage) {
  const s = state.ldState; if (!s) return;
  const lost = s.dockHp <= 0;
  const won = s.wave >= LD_WAVE_TEMPLATES.length && !s.waveActive && !lost;
  // Render lighthouse line: each post shows its turret + ammo
  const postsLine = s.posts.map((id, i) => {
    if (!id) return `  LH${i+1}: [ empty post ]`;
    const t = LD_TURRETS.find((x) => x.id === id);
    return `  LH${i+1}: ${t.name} (atk ${t.atk}, range ${t.range})`;
  }).join("\n");
  // Enemies in flight
  const enemyLine = s.enemies.length
    ? s.enemies.map((e, i) => `  • ${e.t.padEnd(8)} HP ${String(e.hp).padStart(3)}  ${String(e.dist).padStart(2)} rows away${e.spd > 1 ? " (fast)" : ""}`).join("\n")
    : "  (no enemies — between waves)";
  const screen = `┌── LIGHTHOUSE DEFENSE ─ Wave ${s.wave}/10 ─┐
│  Gold: ${String(s.gold).padStart(4)}    Dock HP: ${s.dockHp}/5                   │
└──────────────────────────────────────────┘

   POSTS:
${postsLine}

   APPROACHING:
${enemyLine}

   Log:
${s.log.map((l) => `  > ${l}`).join("\n")}
${won ? "\n   ★★★ HARBOR HELD — VICTORY ★★★" : (lost ? "\n   ── DOCK BREACHED — DEFEAT ──" : "")}`;

  let buyButtons = "";
  if (!s.waveActive && !lost && !won) {
    // Buy phase — let player choose turret + post
    const emptyPosts = s.posts.map((p, i) => p == null ? i : null).filter((x) => x != null);
    buyButtons = LD_TURRETS.flatMap((t) =>
      emptyPosts.map((p) => `<button type="button" class="button button-secondary" data-ld-buy="${t.id}:${p}" ${s.gold < t.cost ? "disabled" : ""}>${t.name} → LH${p+1} (${t.cost}g)</button>`)
    ).join("");
    buyButtons += `<button type="button" class="button button-primary" data-ld-startwave>[Start wave ${s.wave + 1}]</button>`;
  }
  if (s.waveActive && !lost) {
    buyButtons = `<button type="button" class="button button-primary" data-ld-tick>[Next round]</button>`;
  }
  stage.innerHTML = `<pre class="bbs-game-screen">${screen}</pre>
    <div class="bbs-game-controls">${buyButtons}</div>
    <div class="bbs-game-controls">
      <button type="button" class="button button-secondary" data-ld-reset>[New game]</button>
      <button type="button" class="button button-secondary" data-bbs-game-quit>[Quit]</button>
    </div>`;
}
function _ldBuy(turretId, post) {
  const s = state.ldState; const t = LD_TURRETS.find((x) => x.id === turretId);
  if (!t || s.gold < t.cost || s.posts[post]) return;
  s.gold -= t.cost; s.posts[post] = t.id;
  _ldPush(`Placed ${t.name} on LH${post + 1}.`);
  _ldRender($("bbs-game-stage"));
}
function _ldStartWave() {
  const s = state.ldState;
  const tpl = LD_WAVE_TEMPLATES[s.wave];
  if (!tpl) return;
  s.wave += 1;
  s.waveActive = true;
  s.enemies = tpl.map((e) => ({ ...e, dist: 8 + Math.floor(Math.random() * 3) }));
  _ldPush(`★ Wave ${s.wave} approaches — ${tpl.length} enemy(ies).`);
  _ldRender($("bbs-game-stage"));
}
function _ldTick() {
  const s = state.ldState;
  if (!s.waveActive) return;
  // Each turret fires at the closest in-range enemy
  for (let i = 0; i < 4; i++) {
    if (!s.posts[i]) continue;
    const t = LD_TURRETS.find((x) => x.id === s.posts[i]);
    const target = s.enemies.filter((e) => e.dist <= t.range && e.hp > 0).sort((a, b) => a.dist - b.dist)[0];
    if (!target) continue;
    target.hp -= t.atk;
    _ldPush(`LH${i+1} ${t.name} → ${target.t} for ${t.atk}.`);
    if (target.hp <= 0) { s.gold += target.gold; _ldPush(`${target.t} sunk! +${target.gold}g.`); }
  }
  // Drop dead enemies
  s.enemies = s.enemies.filter((e) => e.hp > 0);
  // Advance survivors
  for (const e of s.enemies) e.dist = Math.max(0, e.dist - e.spd);
  // Resolve enemies that reached the dock
  let breached = s.enemies.filter((e) => e.dist === 0);
  for (const e of breached) {
    s.dockHp -= e.atk;
    _ldPush(`${e.t} reaches the dock! -${e.atk} dock HP.`);
  }
  s.enemies = s.enemies.filter((e) => e.dist > 0);
  // End-of-wave check
  if (s.enemies.length === 0) {
    s.waveActive = false;
    _ldPush(`Wave cleared. ${s.dockHp} dock HP remaining.`);
    if (s.wave >= LD_WAVE_TEMPLATES.length) {
      _bbsRecordGameScore("lighthouse-def", s.dockHp * 100 + s.gold);
      _ldPush(`★ All 10 waves repelled. Score: ${s.dockHp * 100 + s.gold}.`);
    }
  }
  if (s.dockHp <= 0) {
    s.dockHp = 0; s.waveActive = false;
    _bbsRecordGameScore("lighthouse-def", -(10 - s.wave));
    _ldPush(`Dock breached. Game over.`);
  }
  _ldRender($("bbs-game-stage"));
}
function _ldReset() { state.ldState = null; _ldLaunch($("bbs-game-stage")); }


