function _bbsArtList() {
  const stored = _bbsLoadJson(BBS_ART_KEY, []);
  // User submissions first (newest at top), then seed.
  return [...stored, ...BBS_ART_SEED];
}
function renderBbsArt() {
  const tag = state.bbsArtTag || "all";
  const all = _bbsArtList();
  const items = tag === "all" ? all : all.filter((a) => a.tag === tag);
  // Tag filter pills
  const tagBar = document.getElementById("bbs-art-tags");
  if (tagBar) {
    tagBar.innerHTML = BBS_ART_TAGS.map((t) => {
      const count = t.id === "all" ? all.length : all.filter((a) => a.tag === t.id).length;
      return `<button type="button" class="bbs-art-tag ${t.id === tag ? "is-active" : ""}" data-bbs-art-tag="${escapeHtml(t.id)}">${escapeHtml(t.label)} <small>(${count})</small></button>`;
    }).join("");
  }
  // Banner
  const banner = $("bbs-art-banner");
  if (banner) banner.innerHTML = `— [ GALLERY · ${escapeHtml(BBS_ART_TAGS.find((t) => t.id === tag)?.label || "All")} · ${items.length} item${items.length === 1 ? "" : "s"} ] —`;
  // Grid
  const grid = $("bbs-art-grid");
  if (grid) {
    grid.innerHTML = items.length
      ? items.map((a) => `<button type="button" class="bbs-art-tile ${state.bbsArtId === a.id ? "is-active" : ""}" data-bbs-art-id="${escapeHtml(a.id)}" title="${escapeHtml(a.title)} — by ${escapeHtml(a.artist)}">
          <span class="bbs-art-tile-img"><img loading="lazy" src="${escapeHtml(a.url)}" alt="${escapeHtml(a.title)}" onerror="this.classList.add('failed');this.removeAttribute('src');" /></span>
          <span class="bbs-art-tile-meta">
            <strong>${escapeHtml(a.title)}</strong>
            <small>${escapeHtml(a.artist)} · ${escapeHtml((BBS_ART_TAGS.find((t) => t.id === a.tag) || {}).label || a.tag)}</small>
          </span>
        </button>`).join("")
      : '<div class="empty">No items match this filter. Switch tags above, or submit one below.</div>';
  }
  // Selected viewer (if any)
  const active = items.find((a) => a.id === state.bbsArtId) || items[0] || null;
  state.bbsArtId = active?.id || null;
  const wrap = document.getElementById("bbs-art-viewer-wrap");
  const banner2 = document.getElementById("bbs-art-viewer-banner");
  if (wrap && banner2) {
    if (!active) {
      wrap.hidden = true; banner2.hidden = true;
    } else {
      wrap.hidden = false; banner2.hidden = false;
      banner2.innerHTML = `— [ VIEWING · ${escapeHtml(active.title.toUpperCase())} ] —`;
      const img = document.getElementById("bbs-art-viewer-img");
      const title = document.getElementById("bbs-art-viewer-title");
      const desc = document.getElementById("bbs-art-viewer-desc");
      const attr = document.getElementById("bbs-art-viewer-attr");
      const src = document.getElementById("bbs-art-viewer-src");
      if (img) { img.src = active.url; img.alt = active.title; }
      if (title) title.textContent = active.title;
      if (desc) desc.textContent = active.description || "";
      if (attr) attr.textContent = [active.artist, active.license, active.bySysop ? "Seed" : "User submission"].filter(Boolean).join(" · ");
      if (src) { if (active.source) { src.href = active.source; src.hidden = false; src.textContent = "Source ↗"; } else { src.hidden = true; } }
    }
  }
}

/* ── POLLS ─────────────────────────────────────────────────────────── */
function renderBbsPolls() {
  const list = $("bbs-polls-list");
  if (!list) return;
  const votes = _bbsLoadJson(BBS_POLL_VOTES_KEY, {});
  list.innerHTML = BBS_POLLS.map((p) => {
    const totals = {};
    let total = 0;
    for (const opt of p.options) {
      const extra = votes[p.id] === opt.id ? 1 : 0;
      totals[opt.id] = (opt.base || 0) + extra;
      total += totals[opt.id];
    }
    const myVote = votes[p.id] || null;
    const optsHtml = p.options.map((opt) => {
      const count = totals[opt.id];
      const pct = total > 0 ? Math.round((count / total) * 100) : 0;
      const mine = myVote === opt.id;
      return `<button type="button" class="bbs-poll-opt ${mine ? "is-mine" : ""}" data-bbs-poll-id="${escapeHtml(p.id)}" data-bbs-poll-opt="${escapeHtml(opt.id)}" ${myVote ? "" : "title='Click to vote'"}>
        <span class="bbs-poll-opt-label">${mine ? "[✓] " : "[ ] "}${escapeHtml(opt.label)}</span>
        <span class="bbs-poll-opt-bar"><span class="bbs-poll-opt-fill" style="width:${pct}%"></span></span>
        <span class="bbs-poll-opt-count">${count} · ${pct}%</span>
      </button>`;
    }).join("");
    return `<article class="bbs-poll-card">
      <header class="bbs-poll-head">
        <strong>${escapeHtml(p.question)}</strong>
        <span class="muted small">closes ${escapeHtml(p.closes)} · ${total} vote${total === 1 ? "" : "s"}${myVote ? " · you voted" : ""}</span>
      </header>
      <div class="bbs-poll-opts">${optsHtml}</div>
    </article>`;
  }).join("");
}

