/* ── STATS ─────────────────────────────────────────────────────────── */
function renderBbsStats() {
  const grid = $("bbs-stats-grid");
  if (grid) {
    const totalTopics = COMMUNITY_FORUM_CHANNELS.reduce((n, b) => n + (b.topics || 0), 0);
    const totalPosts  = COMMUNITY_FORUM_CHANNELS.reduce((n, b) => n + (b.posts || 0), 0);
    const totalFiles  = BBS_FILES.length;
    const totalDls    = BBS_FILES.reduce((n, f) => n + (f.dls || 0), 0);
    const onlineNow   = BBS_WHOSON.length;
    const bulletins   = BBS_BULLETINS.length;
    grid.innerHTML = [
      statCard("Online now", onlineNow, "Callers + agents connected"),
      statCard("Topics", totalTopics, `${totalPosts} total posts`),
      statCard("Files", totalFiles, `${totalDls.toLocaleString()} total downloads`),
      statCard("Bulletins", bulletins, "SysOp announcements"),
      statCard("Boards", COMMUNITY_FORUM_CHANNELS.length, "Active message boards"),
      statCard("Uptime", "00d 14h 22m", "Since gateway start"),
      statCard("Calls today", "37", "Distinct sessions"),
      statCard("Polls", BBS_POLLS.length, "Open votes"),
    ].join("");
  }
  const top = $("bbs-stats-top");
  if (top) {
    // Top posters by post count across all threads. Honest count from
    // the static thread set we have; if backend persistence lands this
    // becomes a real /v1/community/forum/top route.
    const counts = {};
    for (const t of COMMUNITY_FORUM_THREADS) {
      for (const m of (t.messages || [])) counts[m.author] = (counts[m.author] || 0) + 1;
    }
    const ranked = Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, 8);
    if (!ranked.length) {
      top.innerHTML = '<div class="empty">No posts yet.</div>';
    } else {
      const header = `<div class="bbs-stats-top-row bbs-stats-top-row-head">
        <span class="bbs-sc-rank">RANK</span>
        <span class="bbs-sc-handle">HANDLE</span>
        <span class="bbs-sc-posts">POSTS</span>
      </div>`;
      top.innerHTML = header + ranked.map(([h, n], i) => `
        <div class="bbs-stats-top-row">
          <span class="bbs-sc-rank">#${i + 1}</span>
          <span class="bbs-sc-handle"><strong>${escapeHtml(h)}</strong></span>
          <span class="bbs-sc-posts">${n}</span>
        </div>`).join("");
    }
  }
}

/* ── Section-nav + per-module click delegation ─────────────────────── */
function bindBbsSectionEvents() {
  const page = document.getElementById("forum-page");
  if (!page || page.dataset.bbsBound === "1") return;
  page.dataset.bbsBound = "1";
  page.addEventListener("click", (event) => {
    // New sidebar nav (.bbs-side-btn) + lobby cards + legacy top nav (.bbs-nav-btn)
    // all use data-bbs-section, so one selector covers everything.
    const navBtn = event.target.closest("[data-bbs-section]");
    if (navBtn) { setBbsSection(navBtn.dataset.bbsSection); return; }
    // Chat
    const chatCh = event.target.closest("[data-bbs-chat-channel]");
    if (chatCh) { _bbsChatStore().channel = chatCh.dataset.bbsChatChannel; _bbsSaveJson(BBS_CHAT_KEY, state.bbsChat); renderBbsChat(); return; }
    if (event.target.closest("#bbs-chat-send")) { _bbsChatSubmit(); return; }
    // One-liners
    if (event.target.closest("#bbs-ol-post")) { _bbsOlPost(); return; }
    // Sanctuary (was: Aquarium)
    // Release X button inside a roster chip — handle BEFORE the chip click so
    // clicking X releases the pet instead of selecting it.
    const aqRelease = event.target.closest("[data-aq-release]");
    if (aqRelease) {
      event.stopPropagation();
      _bbsAqAct("release-pet", aqRelease.dataset.aqRelease);
      return;
    }
    const aqHabitat = event.target.closest("[data-aq-set-habitat]");
    if (aqHabitat) { _bbsAqAct("set-habitat", aqHabitat.dataset.aqSetHabitat); return; }
    const aqAdopt = event.target.closest("[data-aq-adopt]");
    if (aqAdopt) { _bbsAqAct("adopt", aqAdopt.dataset.aqAdopt); return; }
    const aqSelect = event.target.closest("[data-aq-select]");
    if (aqSelect) { _bbsAqAct("select-pet", aqSelect.dataset.aqSelect); return; }
    const aqAct = event.target.closest("[data-aq-act]");
    if (aqAct) { _bbsAqAct(aqAct.dataset.aqAct); return; }
    // Files
    const dirBtn = event.target.closest("[data-bbs-file-dir]");
    if (dirBtn) { state.bbsFileDir = dirBtn.dataset.bbsFileDir; renderBbsFiles(); return; }
    const fileBtn = event.target.closest("[data-bbs-file-name]");
    if (fileBtn) {
      if (typeof showToast === "function") showToast(`Stub: file "${fileBtn.dataset.bbsFileName}" is in the catalog but not hosted yet.`, { duration: 2400 });
      return;
    }
    // Mail
    const mailOpen = event.target.closest("[data-bbs-mail-open]");
    if (mailOpen) {
      const id = mailOpen.dataset.bbsMailOpen;
      state.bbsMailOpenId = state.bbsMailOpenId === id ? null : id;
      const m = (state.bbsMail || []).find((x) => x.id === id);
      if (m && !m.read) { m.read = true; _bbsSaveJson(BBS_MAIL_KEY, state.bbsMail); }
      renderBbsMail();
      return;
    }
    const mailDel = event.target.closest("[data-bbs-mail-delete]");
    if (mailDel) {
      const id = mailDel.dataset.bbsMailDelete;
      state.bbsMail = (state.bbsMail || []).filter((x) => x.id !== id);
      state.bbsMailOpenId = null;
      _bbsSaveJson(BBS_MAIL_KEY, state.bbsMail);
      renderBbsMail();
      return;
    }
    if (event.target.closest("#bbs-mail-send")) {
      const to = $("bbs-mail-to")?.value?.trim() || "self";
      const subj = $("bbs-mail-subj")?.value?.trim() || "(no subject)";
      const body = $("bbs-mail-body")?.value?.trim() || "";
      if (!body) { if (typeof showToast === "function") showToast("Body is empty.", { severity: "warn", duration: 1800 }); return; }
      const msg = { id: "m" + Date.now(), from: "you", to, subj, date: new Date().toISOString().replace("T"," ").slice(0,16), read: true, body };
      state.bbsMail = state.bbsMail || [];
      state.bbsMail.unshift(msg);
      _bbsSaveJson(BBS_MAIL_KEY, state.bbsMail);
      $("bbs-mail-to").value = ""; $("bbs-mail-subj").value = ""; $("bbs-mail-body").value = "";
      if (typeof showToast === "function") showToast(`Mail saved to local outbox · 1 message.`, { duration: 2200 });
      renderBbsMail();
      return;
    }
    // Games
    const gameBtn = event.target.closest("[data-bbs-game-play]");
    if (gameBtn) { bbsLaunchGame(gameBtn.dataset.bbsGamePlay); return; }
    if (event.target.closest("[data-bbs-game-quit]")) {
      state.bbsActiveGame = null; state.bbsBuoyState = null; state.bbsGuessState = null;
      const sec = $("bbs-game-active-section"); if (sec) sec.hidden = true;
      return;
    }
    const buoyBet = event.target.closest("[data-bbs-buoy-bet]");
    if (buoyBet) { _bbsPlayBuoy(buoyBet.dataset.bbsBuoyBet); return; }
    if (event.target.closest("[data-bbs-guess-submit]")) {
      const v = Number($("bbs-guess-input")?.value);
      _bbsPlayGuess(v);
      return;
    }
    // ── Sector Trader handlers ──
    const stMove = event.target.closest("[data-st-move]");
    if (stMove) { _stMove(Number(stMove.dataset.stMove)); return; }
    const stBuy = event.target.closest("[data-st-buy]");
    if (stBuy) { _stBuy(stBuy.dataset.stBuy, 1); return; }
    const stSell = event.target.closest("[data-st-sell]");
    if (stSell) { _stSell(stSell.dataset.stSell, 1); return; }
    const stBuyMax = event.target.closest("[data-st-buy-max]");
    if (stBuyMax) {
      const key = stBuyMax.dataset.stBuyMax;
      const sec = _stCurrentSector(); const p = state.stState.player;
      const comm = ST_COMMS.find((c) => c.key === key);
      const free = p.holds - _stCargoUsed(p);
      const maxByCargo = Math.floor(free / comm.weight);
      const maxByCash = Math.floor(p.credits / sec.prices[key]);
      const qty = Math.min(maxByCargo, maxByCash);
      if (qty > 0) _stBuy(key, qty);
      return;
    }
    const stSellAll = event.target.closest("[data-st-sell-all]");
    if (stSellAll) {
      const key = stSellAll.dataset.stSellAll;
      const have = state.stState.player.cargo[key] || 0;
      if (have > 0) _stSell(key, have);
      return;
    }
    if (event.target.closest("[data-st-refuel]")) { _stRefuel(); return; }
    if (event.target.closest("[data-st-repair]")) { _stRepair(); return; }
    if (event.target.closest("[data-st-reset]")) { _stReset(); return; }
    // ── Legend of the Black Buoy handlers ──
    const lbGo = event.target.closest("[data-lb-go]");
    if (lbGo) { _lbGo(lbGo.dataset.lbGo); return; }
    if (event.target.closest("[data-lb-hunt]")) { _lbHunt(); return; }
    const lbCb = event.target.closest("[data-lb-cb]");
    if (lbCb) { _lbCombat(lbCb.dataset.lbCb); return; }
    const lbInn = event.target.closest("[data-lb-inn]");
    if (lbInn) { _lbInn(lbInn.dataset.lbInn); return; }
    const lbTrain = event.target.closest("[data-lb-train]");
    if (lbTrain) { _lbTrain(lbTrain.dataset.lbTrain); return; }
    const lbBuyW = event.target.closest("[data-lb-buy-w]");
    if (lbBuyW) { _lbBuyWeapon(lbBuyW.dataset.lbBuyW); return; }
    const lbBuyA = event.target.closest("[data-lb-buy-a]");
    if (lbBuyA) { _lbBuyArmor(lbBuyA.dataset.lbBuyA); return; }
    if (event.target.closest("[data-lb-master]")) { _lbMaster(); return; }
    if (event.target.closest("[data-lb-reset]")) { _lbReset(); return; }
    // ── Fleet Realms handlers ──
    const frAct = event.target.closest("[data-fr-act]");
    if (frAct) { _frAct(frAct.dataset.frAct); return; }
    const frRaid = event.target.closest("[data-fr-raid]");
    if (frRaid) { _frAct("raid", frRaid.dataset.frRaid); return; }
    if (event.target.closest("[data-fr-reset]")) { _frReset(); return; }
    // ── Global War handlers ──
    const gwAttack = event.target.closest("[data-gw-attack]");
    if (gwAttack) {
      const [from, to] = gwAttack.dataset.gwAttack.split("-").map(Number);
      _gwAttack(from, to); return;
    }
    const gwReinf = event.target.closest("[data-gw-reinforce]");
    if (gwReinf) { _gwReinforce(Number(gwReinf.dataset.gwReinforce)); return; }
    if (event.target.closest("[data-gw-end]")) { _gwEndTurn(); return; }
    if (event.target.closest("[data-gw-reset]")) { _gwReset(); return; }
    // ── Overkill III handlers ──
    const ooAct = event.target.closest("[data-oo-act]");
    if (ooAct) { _ooAct(ooAct.dataset.ooAct); return; }
    if (event.target.closest("[data-oo-reset]")) { _ooReset(); return; }
    // ── Net Cast handlers ──
    const ncCast = event.target.closest("[data-nc-cast]");
    if (ncCast) { _ncCast(ncCast.dataset.ncCast); return; }
    const ncUp = event.target.closest("[data-nc-upgrade]");
    if (ncUp) { _ncUpgrade(ncUp.dataset.ncUpgrade); return; }
    if (event.target.closest("[data-nc-cashout]")) { _ncCashout(); return; }
    if (event.target.closest("[data-nc-rest]")) { _ncRest(); return; }
    if (event.target.closest("[data-nc-reset]")) { _ncReset(); return; }
    // ── Sonar Hunt handlers ──
    const shFire = event.target.closest("[data-sh-fire]");
    if (shFire) { _shFire(Number(shFire.dataset.shFire)); return; }
    if (event.target.closest("[data-sh-reset]")) { _shReset(); return; }
    // ── Lighthouse Defense handlers ──
    const ldBuy = event.target.closest("[data-ld-buy]");
    if (ldBuy) {
      const [tid, post] = ldBuy.dataset.ldBuy.split(":");
      _ldBuy(tid, Number(post));
      return;
    }
    if (event.target.closest("[data-ld-startwave]")) { _ldStartWave(); return; }
    if (event.target.closest("[data-ld-tick]")) { _ldTick(); return; }
    if (event.target.closest("[data-ld-reset]")) { _ldReset(); return; }
    // Art — tag filter, tile select, submit
    const artTag = event.target.closest("[data-bbs-art-tag]");
    if (artTag) {
      state.bbsArtTag = artTag.dataset.bbsArtTag;
      state.bbsArtId = null; // reset selection when filter changes
      renderBbsArt(); return;
    }
    const artBtn = event.target.closest("[data-bbs-art-id]");
    if (artBtn) { state.bbsArtId = artBtn.dataset.bbsArtId; renderBbsArt(); return; }
    if (event.target.closest("#bbs-art-submit-btn")) {
      const title = ($("bbs-art-title")?.value || "").trim();
      const artist = ($("bbs-art-artist")?.value || "").trim();
      const url = ($("bbs-art-url")?.value || "").trim();
      const tag = $("bbs-art-tag-select")?.value || "art";
      const desc = ($("bbs-art-desc")?.value || "").trim();
      if (!title || !url) {
        if (typeof showToast === "function") showToast("Title and Image URL are required.", { severity: "warn", duration: 2400 });
        return;
      }
      const stored = _bbsLoadJson(BBS_ART_KEY, []);
      stored.unshift({
        id: "user-" + Date.now(),
        title,
        artist: artist || "anonymous",
        url,
        source: "",
        license: "User submission",
        tag,
        description: desc,
        bySysop: false,
      });
      _bbsSaveJson(BBS_ART_KEY, stored.slice(0, 50));
      if ($("bbs-art-title")) $("bbs-art-title").value = "";
      if ($("bbs-art-artist")) $("bbs-art-artist").value = "";
      if ($("bbs-art-url")) $("bbs-art-url").value = "";
      if ($("bbs-art-desc")) $("bbs-art-desc").value = "";
      if (typeof showToast === "function") showToast(`★ Submitted "${title}".`, { duration: 2400 });
      renderBbsArt();
      return;
    }
    // Polls
    const pollOpt = event.target.closest("[data-bbs-poll-id][data-bbs-poll-opt]");
    if (pollOpt) {
      const votes = _bbsLoadJson(BBS_POLL_VOTES_KEY, {});
      const pid = pollOpt.dataset.bbsPollId;
      const oid = pollOpt.dataset.bbsPollOpt;
      // Toggle off if same; otherwise switch.
      if (votes[pid] === oid) delete votes[pid]; else votes[pid] = oid;
      _bbsSaveJson(BBS_POLL_VOTES_KEY, votes);
      renderBbsPolls();
      return;
    }
  });
  // Enter inside misc inputs submits the matching button.
  page.addEventListener("keydown", (event) => {
    if (event.key !== "Enter") return;
    const id = event.target?.id;
    if (id === "bbs-guess-input") { event.preventDefault(); page.querySelector("[data-bbs-guess-submit]")?.click(); return; }
    if (id === "bbs-chat-input")  { event.preventDefault(); _bbsChatSubmit(); return; }
    if (id === "bbs-ol-text")     { event.preventDefault(); _bbsOlPost(); return; }
  });
}

function wikiTextFromBlock(block) {
  if (!block) return "";
  if (typeof block === "string") return block;
  const pieces = [block.title, block.text, block.language, block.unit, block.caption, block.alt, block.variant];
  if (Array.isArray(block.items)) {
    pieces.push(...block.items.map((item) => (typeof item === "string" ? item : Object.values(item || {}).join(" "))));
  }
  if (Array.isArray(block.rows)) {
    pieces.push(...block.rows.flat().map((value) => String(value ?? "")));
  }
  if (Array.isArray(block.columns)) {
    pieces.push(...block.columns);
  }
  if (Array.isArray(block.nodes)) {
    pieces.push(...block.nodes);
  }
  if (Array.isArray(block.links)) {
    pieces.push(...block.links);
  }
  if (Array.isArray(block.bars)) {
    pieces.push(...block.bars.map((bar) => `${bar.label || ""} ${bar.note || ""} ${bar.value || ""}`));
  }
  if (Array.isArray(block.labels)) {
    pieces.push(...block.labels);
  }
  if (Array.isArray(block.values)) {
    pieces.push(...block.values.map((value) => String(value ?? "")));
  }
  return pieces.filter(Boolean).join(" ");
}

function wikiArticleSearchText(article) {
  return [
    article.title,
    article.summary,
    article.category,
    article.readTime,
    ...(article.tags || []),
    ...(article.sections || []),
    ...(article.body || []).map(wikiTextFromBlock),
  ].join(" ").toLowerCase();
}

function renderWikiMetrics(block) {
  const items = Array.isArray(block.items) ? block.items : [];
  return `
    <div class="wiki-metric-grid">
      ${items.map((item) => `
        <div class="wiki-metric">
          <strong>${escapeHtml(item.value)}</strong>
          <span>${escapeHtml(item.label)}</span>
          <small>${escapeHtml(item.note || "")}</small>
        </div>
      `).join("")}
    </div>
  `;
}

function renderWikiDiagram(block) {
  const nodes = Array.isArray(block.nodes) ? block.nodes : [];
  const links = Array.isArray(block.links) ? block.links : [];
  return `
    <figure class="wiki-flow-diagram">
      ${block.title ? `<figcaption>${escapeHtml(block.title)}</figcaption>` : ""}
      <div class="wiki-flow-row">
        ${nodes.map((node, index) => `
          <div class="wiki-flow-step">
            <b>${escapeHtml(node)}</b>
            ${links[index] ? `<span>${escapeHtml(links[index])}</span>` : ""}
          </div>
        `).join("")}
      </div>
    </figure>
  `;
}

