function renderWikiPicture(block) {
  const scene = wikiPictureScene(block.variant);
  const labels = Array.isArray(scene.labels) ? scene.labels : [];
  const accent = escapeHtml(scene.accent || "#32d0bd");
  const points = labels.map((label, index) => {
    const x = 134 + index * 156;
    const y = index % 2 === 0 ? 116 : 212;
    return `
      <g class="wiki-picture-node" transform="translate(${x} ${y})">
        <circle r="28"></circle>
        <text y="5" text-anchor="middle">${escapeHtml(label)}</text>
      </g>
    `;
  }).join("");
  return `
    <figure class="wiki-picture wiki-picture-${escapeHtml(block.variant || "default")}">
      <div class="wiki-picture-canvas" style="--wiki-picture-accent:${accent}">
        <svg viewBox="0 0 760 340" role="img" aria-label="${escapeHtml(block.alt || block.title || "Project wiki illustration")}">
          <rect width="760" height="340" rx="24"></rect>
          <path class="wiki-picture-water" d="M0 236 C82 198 136 252 220 218 C320 178 382 230 470 194 C574 150 646 190 760 156 L760 340 L0 340 Z"></path>
          <path class="wiki-picture-coast" d="M0 170 C84 124 144 150 220 112 C300 74 378 92 444 66 C524 34 602 54 760 22"></path>
          <circle class="wiki-picture-orbit" cx="594" cy="126" r="74"></circle>
          <path class="wiki-picture-grid" d="M40 72H720M40 148H720M40 224H720M132 46V298M288 46V298M444 46V298M600 46V298"></path>
          <path class="wiki-picture-line" d="M162 116 C236 72 300 266 418 212 C492 178 544 118 660 138"></path>
          ${points}
          <g class="wiki-picture-badge" transform="translate(34 32)">
            <rect width="156" height="34" rx="17"></rect>
            <text x="78" y="22" text-anchor="middle">${escapeHtml(scene.badge || "OMEGA")}</text>
          </g>
          <text class="wiki-picture-caption" x="38" y="314">${escapeHtml(scene.caption || "")}</text>
        </svg>
      </div>
      <figcaption>
        <span>${escapeHtml(block.title || "Project figure")}</span>
        ${block.caption ? `<small>${escapeHtml(block.caption)}</small>` : ""}
      </figcaption>
    </figure>
  `;
}

function renderWikiTable(block) {
  const columns = Array.isArray(block.columns) ? block.columns : [];
  const rows = Array.isArray(block.rows) ? block.rows : [];
  return `
    <div class="wiki-table-wrap">
      ${block.title ? `<div class="wiki-table-title">${escapeHtml(block.title)}</div>` : ""}
      <table class="wiki-table">
        <thead>
          <tr>${columns.map((column) => `<th>${escapeHtml(column)}</th>`).join("")}</tr>
        </thead>
        <tbody>
          ${rows.map((row) => `<tr>${row.map((cell) => `<td>${escapeHtml(cell)}</td>`).join("")}</tr>`).join("")}
        </tbody>
      </table>
    </div>
  `;
}

function renderWikiCode(block) {
  return `
    <figure class="wiki-code-block">
      <figcaption>
        <span>${escapeHtml(block.title || "Code example")}</span>
        <small>${escapeHtml(block.language || "text")}</small>
      </figcaption>
      <pre><code>${escapeHtml(block.text || "")}</code></pre>
    </figure>
  `;
}

function renderWikiBarChart(block) {
  const bars = Array.isArray(block.bars) ? block.bars : [];
  const max = Math.max(1, ...bars.map((bar) => Number(bar.value) || 0));
  return `
    <figure class="wiki-bar-chart">
      <figcaption>
        <span>${escapeHtml(block.title || "Chart")}</span>
        ${block.unit ? `<small>${escapeHtml(block.unit)}</small>` : ""}
      </figcaption>
      <div class="wiki-bar-stack">
        ${bars.map((bar) => {
          const value = Number(bar.value) || 0;
          const pct = Math.max(2, Math.min(100, (value / max) * 100));
          return `
            <div class="wiki-bar-row">
              <span>${escapeHtml(bar.label)}</span>
              <div class="wiki-bar-track"><i style="width:${pct.toFixed(2)}%"></i></div>
              <b>${escapeHtml(value)}</b>
              ${bar.note ? `<small>${escapeHtml(bar.note)}</small>` : ""}
            </div>
          `;
        }).join("")}
      </div>
    </figure>
  `;
}

function renderWikiLineChart(block) {
  const values = (Array.isArray(block.values) ? block.values : []).map((value) => Number(value) || 0);
  const labels = Array.isArray(block.labels) ? block.labels : [];
  if (!values.length) return "";
  const width = 640;
  const height = 220;
  const pad = 34;
  const max = Math.max(...values);
  const min = Math.min(...values);
  const range = Math.max(1, max - min);
  const points = values.map((value, index) => {
    const x = pad + (index * (width - pad * 2)) / Math.max(1, values.length - 1);
    const y = height - pad - ((value - min) / range) * (height - pad * 2);
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  });
  return `
    <figure class="wiki-line-chart">
      <figcaption>
        <span>${escapeHtml(block.title || "Trend")}</span>
        ${block.unit ? `<small>${escapeHtml(block.unit)}</small>` : ""}
      </figcaption>
      <svg viewBox="0 0 ${width} ${height}" role="img" aria-label="${escapeHtml(block.title || "Wiki line chart")}">
        <path class="wiki-chart-gridline" d="M${pad} ${pad}H${width - pad}M${pad} ${height / 2}H${width - pad}M${pad} ${height - pad}H${width - pad}" />
        <polyline class="wiki-line-path" points="${escapeHtml(points.join(" "))}" />
        ${points.map((point, index) => {
          const [x, y] = point.split(",");
          return `<circle class="wiki-line-dot" cx="${x}" cy="${y}" r="4"><title>${escapeHtml(labels[index] || `Point ${index + 1}`)}: ${escapeHtml(values[index])}</title></circle>`;
        }).join("")}
        <text x="${pad}" y="${height - 10}">${escapeHtml(labels[0] || "")}</text>
        <text x="${width - pad}" y="${height - 10}" text-anchor="end">${escapeHtml(labels[labels.length - 1] || "")}</text>
      </svg>
    </figure>
  `;
}

function renderWikiBlock(block, index) {
  if (typeof block === "string") {
    return `<p class="wiki-paragraph">${escapeHtml(block)}</p>`;
  }
  switch (block.type) {
    case "lead":
      return `<p class="wiki-lead">${escapeHtml(block.text)}</p>`;
    case "heading":
      return `<h4 class="wiki-section-heading">${escapeHtml(block.text)}</h4>`;
    case "paragraph":
      return `<p class="wiki-paragraph">${escapeHtml(block.text)}</p>`;
    case "steps":
      return `<ol class="wiki-step-list">${(block.items || []).map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ol>`;
    case "list":
      return `<ul class="wiki-bullet-list">${(block.items || []).map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>`;
    case "callout":
      return `<aside class="wiki-callout"><strong>${escapeHtml(block.title || "Note")}</strong><p>${escapeHtml(block.text || "")}</p></aside>`;
    case "metrics":
      return renderWikiMetrics(block);
    case "diagram":
      return renderWikiDiagram(block);
    case "picture":
      return renderWikiPicture(block);
    case "table":
      return renderWikiTable(block);
    case "code":
      return renderWikiCode(block);
    case "chart":
      return renderWikiBarChart(block);
    case "line-chart":
      return renderWikiLineChart(block);
    default:
      return `<p class="wiki-paragraph">${escapeHtml(block.text || block.title || `Wiki block ${index + 1}`)}</p>`;
  }
}

function renderWikiArticleBody(article) {
  const body = Array.isArray(article.body) && article.body.length
    ? article.body
    : (article.sections || []).map((section) => ({ type: "paragraph", text: section }));
  return body.map(renderWikiBlock).join("");
}

function wikiBlockTocLabel(block) {
  if (!block || typeof block === "string") return "";
  if (block.type === "lead") return "";
  if (block.type === "heading") return block.text || "";
  if (block.type === "metrics") return "Key facts";
  if (block.type === "picture") return block.title || "Project picture";
  if (block.type === "table") return block.title || "Reference table";
  if (block.type === "code") return block.title || "Code example";
  if (block.type === "diagram") return block.title || "System diagram";
  if (block.type === "chart" || block.type === "line-chart") return block.title || "Technical chart";
  if (block.type === "steps") return block.title || "Procedure";
  if (block.type === "callout") return block.title || "Implementation note";
  return block.title || "";
}

function renderWikiDocIndex(article) {
  const body = Array.isArray(article.body) && article.body.length ? article.body : [];
  const labels = body.map(wikiBlockTocLabel).filter(Boolean).slice(0, 9);
  if (!labels.length) return "";
  return `
    <nav class="wiki-doc-index" aria-label="On this wiki page">
      <strong>On this page</strong>
      <div>
        ${labels.map((label) => `<span>${escapeHtml(label)}</span>`).join("")}
      </div>
    </nav>
  `;
}

function renderWikiPage() {
  const query = String(state.wikiQuery || "").trim().toLowerCase();
  const category = state.wikiCategory || "all";
  const filtered = WIKI_ARTICLES.filter((article) => {
    const haystack = wikiArticleSearchText(article);
    return (category === "all" || article.category === category) && (!query || haystack.includes(query));
  });
  if (!filtered.some((article) => article.id === state.wikiArticleId)) {
    state.wikiArticleId = filtered[0]?.id || WIKI_ARTICLES[0]?.id || "";
  }
  const article = WIKI_ARTICLES.find((item) => item.id === state.wikiArticleId) || filtered[0] || WIKI_ARTICLES[0];
  if ($("wiki-search-input")) $("wiki-search-input").value = state.wikiQuery;
  if ($("wiki-category-select")) $("wiki-category-select").value = state.wikiCategory;
  if ($("wiki-summary")) {
    $("wiki-summary").innerHTML = [
      statCard("Pages", WIKI_ARTICLES.length, "Technical docs"),
      statCard("Visible", filtered.length, "Search results"),
      statCard("Updated", article?.updated || "-", "Selected article"),
      statCard("Category", article ? formatName(article.category) : "-", "Current topic"),
    ].join("");
  }
  if ($("wiki-article-list")) {
    $("wiki-article-list").innerHTML = filtered.map(
      (item) => `
        <button type="button" class="knowledge-list-item ${item.id === article?.id ? "is-active" : ""}" data-wiki-article="${escapeHtml(item.id)}">
          <strong>${escapeHtml(item.title)}</strong>
          <span>${escapeHtml(item.summary)}</span>
          <small>${escapeHtml(formatName(item.category))} | ${escapeHtml(item.readTime || "Quick read")} | Updated ${escapeHtml(item.updated)}</small>
          ${item.tags?.length ? `<span class="tag-row">${tagListHtml(item.tags.slice(0, 4))}</span>` : ""}
        </button>
      `,
    ).join("") || '<div class="empty">No wiki pages match that search.</div>';
  }
  if ($("wiki-article-detail")) {
    $("wiki-article-detail").innerHTML = article
      ? `
        <div class="wiki-doc-page">
          <header class="wiki-doc-header">
            <p class="eyebrow">${escapeHtml(formatName(article.category))}</p>
            <h3>${escapeHtml(article.title)}</h3>
            <p class="muted">${escapeHtml(article.summary)}</p>
            <div class="wiki-article-meta">
              <span>${escapeHtml(article.readTime || "Quick read")}</span>
              <span>Updated ${escapeHtml(article.updated)}</span>
              ${article.tags?.map((tag) => `<span>${escapeHtml(tag)}</span>`).join("") || ""}
            </div>
          </header>
          ${renderWikiDocIndex(article)}
          <div class="wiki-article-body">
            ${renderWikiArticleBody(article)}
          </div>
        </div>
      `
      : '<div class="empty">Select a wiki article.</div>';
  }
}

function renderBlogPage() {
  const filter = state.blogFilter || "all";
  const posts = AI_BLOG_POSTS.filter((post) => filter === "all" || String(post.status || "").toLowerCase() === filter);
  if (!posts.some((post) => post.id === state.blogPostId)) {
    state.blogPostId = posts[0]?.id || AI_BLOG_POSTS[0]?.id || "";
  }
  const activePost = AI_BLOG_POSTS.find((post) => post.id === state.blogPostId) || posts[0] || AI_BLOG_POSTS[0];
  const briefingItems = state.blogBriefing?.items || [];
  const sourceRows = state.blogBriefing?.sources || [];
  const sourceOk = sourceRows.filter((source) => source.status === "ok").length;
  if ($("blog-filter-select")) $("blog-filter-select").value = filter;
  if ($("blog-summary")) {
    $("blog-summary").innerHTML = [
      statCard("Posts", AI_BLOG_POSTS.length, "Editorial queue"),
      statCard("Queue", briefingItems.length, "Fresh source items"),
      statCard("Sources", `${sourceOk}/${sourceRows.length || "-"}`, "Last refresh"),
      statCard("Featured", activePost?.category || "-", "Selected story"),
    ].join("");
  }
  renderBlogBriefingPanel();
  if ($("blog-post-list")) {
    $("blog-post-list").innerHTML = posts.map(
      (post) => `
        <button type="button" class="blog-card ${post.id === activePost?.id ? "is-active" : ""}" data-blog-post="${escapeHtml(post.id)}">
          <span class="pill ${post.status === "Ready" ? "ok" : post.status === "Draft" ? "warn" : "planned"}">${escapeHtml(post.status || "Draft")}</span>
          <strong>${escapeHtml(post.title)}</strong>
          <span>${escapeHtml(post.dek)}</span>
          <small>${escapeHtml(post.author)} | ${escapeHtml(post.date)} | ${escapeHtml(post.read)}</small>
        </button>
      `,
    ).join("") || '<div class="empty">No blog posts match this filter.</div>';
  }
  if ($("blog-featured-post")) {
    $("blog-featured-post").innerHTML = activePost
      ? `
        <p class="eyebrow">${escapeHtml(activePost.category)}</p>
        <h3>${escapeHtml(activePost.title)}</h3>
        <p class="muted">${escapeHtml(activePost.dek)}</p>
        <div class="tag-row">
          <span class="mini-tag">${escapeHtml(activePost.status)}</span>
          <span class="mini-tag">${escapeHtml(activePost.read)}</span>
          <span class="mini-tag">${escapeHtml(activePost.author)}</span>
        </div>
        <div class="blog-body">
          ${activePost.content || ""}
        </div>
        ${blogSourceLinksHtml(activePost.sources)}
      `
      : '<div class="empty">Choose a post from the editorial queue.</div>';
  }
}

function renderBlogBriefingPanel() {
  const briefing = state.blogBriefing || { items: [], sources: [] };
  const items = briefing.items || [];
  const sources = briefing.sources || [];
  const status = $("blog-briefing-status");
  if (status) {
    if (state.blogRefreshing) {
      status.textContent = "Updating briefing sources now...";
    } else if (briefing.updated_at) {
      status.textContent = `Briefing queue updated ${shortTime(briefing.updated_at)} from ${sources.length || "configured"} sources.`;
    } else {
      status.textContent = "No briefing refresh has run yet. Use Update Sources to fetch recent items.";
    }
  }
  if ($("blog-source-summary")) {
    const ok = sources.filter((source) => source.status === "ok").length;
    const errors = sources.filter((source) => source.status === "error").length;
    const top = items[0];
    $("blog-source-summary").innerHTML = [
      statCard("Fresh Items", items.length, "Ranked by relevance"),
      statCard("Healthy", ok, "Sources responding"),
      statCard("Warnings", errors, "Skipped gracefully"),
      statCard("Top Signal", top?.matched_keywords?.[0] || "-", top?.source_name || "No queue yet"),
    ].join("");
  }
  // Column-head item count + draft count badges — give the two main
  // sections a current-state readout so the user can see at a glance
  // what they're looking at.
  if ($("blog-queue-count")) {
    const filtered = items.length;
    $("blog-queue-count").textContent = filtered ? `${filtered} item${filtered === 1 ? "" : "s"}` : "no items yet";
  }
  if ($("blog-draft-count")) {
    const dCount = (typeof AI_BLOG_POSTS !== "undefined" ? AI_BLOG_POSTS.length : 0);
    $("blog-draft-count").textContent = dCount ? `${dCount} draft${dCount === 1 ? "" : "s"}` : "no drafts yet";
  }
  if ($("blog-briefing-list")) {
    // Friendlier empty state — tell the user exactly which button to
    // press in case the explainer above is collapsed or skimmed past.
    // While a refresh is in flight, mention it so they don't double-click.
    const emptyHtml = state.blogRefreshing
      ? `<div class="empty"><strong>⏳ Updating sources now…</strong><br><span class="muted">Fetching NOAA, marine-tech, and ocean-research feeds. The queue will populate when each source responds.</span></div>`
      : `<div class="empty">
          <strong>No briefing items yet.</strong>
          <p class="muted" style="margin:6px 0 10px">Press <strong>↻ Update Sources</strong> above to fetch the latest items from every configured feed. Each story shows up here ranked by relevance, with a link to the original article and the source name underneath.</p>
          <button type="button" class="button button-primary" onclick="document.getElementById('btn-blog-refresh')?.click()">↻ Update Sources now</button>
        </div>`;
    $("blog-briefing-list").innerHTML = items.slice(0, 6).map((item) => `
      <article class="briefing-item">
        <div>
          <p class="eyebrow">${escapeHtml(item.source_name || item.source_id || "Source")} | ${escapeHtml(shortTime(item.published_at))}</p>
          <h3><a href="${escapeHtml(item.url || "#")}" target="_blank" rel="noopener noreferrer">${escapeHtml(item.title || "Untitled item")}</a></h3>
          <p>${escapeHtml(item.summary || "")}</p>
          <div class="tag-row">${tagListHtml(item.matched_keywords || [])}</div>
        </div>
        <strong title="Relevance score — higher means more on-topic for OMEGA-wave's brief">${escapeHtml(Number(item.score || 0).toFixed(0))}</strong>
      </article>
    `).join("") || emptyHtml;
  }
}

function blogSourceLinksHtml(sources = []) {
  if (!sources?.length) {
    return "";
  }
  return `
    <div class="blog-source-links">
      <p class="eyebrow">Sources</p>
      ${sources.map((source) => `
        <a href="${escapeHtml(source.url || "#")}" target="_blank" rel="noopener noreferrer">
          <strong>${escapeHtml(source.title || "Source")}</strong>
          <span>${escapeHtml(source.source || "")}${source.published_at ? ` | ${escapeHtml(shortTime(source.published_at))}` : ""}</span>
        </a>
      `).join("")}
    </div>
  `;
}

function renderMarketplacePage() {
  const filter = state.bountyFilter || "open";
  const items = MARKETPLACE_BOUNTIES.filter((bounty) => {
    if (filter === "all") return true;
    return bounty.status.toLowerCase() === filter || bounty.type.toLowerCase().replace(/\s+/g, "-") === filter;
  });
  if (!items.some((item) => item.id === state.bountyId)) {
    state.bountyId = items[0]?.id || MARKETPLACE_BOUNTIES[0]?.id || "";
  }
  const active = MARKETPLACE_BOUNTIES.find((item) => item.id === state.bountyId) || items[0] || MARKETPLACE_BOUNTIES[0];
  if ($("bounty-filter-select")) $("bounty-filter-select").value = filter;
  if ($("marketplace-summary")) {
    $("marketplace-summary").innerHTML = [
      statCard("Listings", MARKETPLACE_BOUNTIES.length, "Bounties and offers"),
      statCard("Open", MARKETPLACE_BOUNTIES.filter((item) => item.status === "Open").length, "Ready to claim"),
      statCard("Review", MARKETPLACE_BOUNTIES.filter((item) => item.status === "Review").length, "Needs feedback"),
      statCard("Rewards", MARKETPLACE_BOUNTIES.filter((item) => item.reward.startsWith("$")).length, "Cash-backed"),
    ].join("");
  }
  if ($("bounty-list")) {
    $("bounty-list").innerHTML = items.map(
      (item) => `
        <button type="button" class="bounty-card ${item.id === active?.id ? "is-active" : ""}" data-bounty-id="${escapeHtml(item.id)}">
          <span class="pill ${item.status === "Open" ? "ok" : item.status === "Review" ? "warn" : ""}">${escapeHtml(item.status)}</span>
          <strong>${escapeHtml(item.title)}</strong>
          <span>${escapeHtml(item.summary)}</span>
          <small>${escapeHtml(item.type)} | ${escapeHtml(item.reward)} | Due ${escapeHtml(item.due)}</small>
        </button>
      `,
    ).join("") || '<div class="empty">No marketplace listings match this filter.</div>';
  }
  if ($("bounty-detail")) {
    $("bounty-detail").innerHTML = active
      ? `
        <div class="community-detail-head">
          <div>
            <p class="eyebrow">${escapeHtml(active.type)}</p>
            <h3>${escapeHtml(active.title)}</h3>
          </div>
          <span class="pill ${active.status === "Open" ? "ok" : active.status === "Review" ? "warn" : ""}">${escapeHtml(active.status)}</span>
        </div>
        <p class="muted">${escapeHtml(active.summary)}</p>
        <div class="bounty-meta-grid">
          ${statCard("Reward", active.reward, "Listing value")}
          ${statCard("Due", active.due, "Target date")}
        </div>
        <div class="tag-row">${tagListHtml(active.skills)}</div>
      `
      : '<div class="empty">Select a listing to inspect the work package.</div>';
  }
}

async function fetchBlogPosts() {
  try {
    const res = await apiGet("/v1/community/blog/posts");
    AI_BLOG_POSTS = res || [];
    renderBlogPage();
  } catch (err) {
    console.error("Failed to fetch blog posts:", err);
  }
}

async function fetchBlogBriefing() {
  try {
    const res = await apiGet("/v1/community/blog/briefing");
    state.blogBriefing = res || { items: [], sources: [], updated_at: null };
    renderBlogPage();
    if (!state.blogAutoRefreshAttempted && !(state.blogBriefing.items || []).length && !state.blogBriefing.updated_at) {
      state.blogAutoRefreshAttempted = true;
      await refreshBlogBriefing();
    }
  } catch (err) {
    console.error("Failed to fetch briefing queue:", err);
  }
  // Pull the source catalog too — fresh from /v1/community/blog/sources
  // so the "Configured sources" details block shows the live set.
  fetchBlogSourceCatalog().catch((err) => console.warn("Failed to load briefing source catalog:", err));
}

async function fetchBlogSourceCatalog() {
  try {
    const res = await apiGet("/v1/community/blog/sources");
    state.blogSourceCatalog = (res && Array.isArray(res.sources)) ? res.sources : [];
    renderBlogSourceCatalog();
  } catch (err) {
    console.warn("Failed to fetch briefing source catalog:", err);
  }
}

/** Render the collapsed source-catalog details block. Shows every
 *  configured feed as a row with name, kind, topic, trust, and
 *  default-enabled state. Helps the operator answer "where is the
 *  Briefings page pulling from?" without leaving the page. */
function renderBlogSourceCatalog() {
  const list = document.getElementById("blog-source-catalog-list");
  const counter = document.getElementById("blog-source-catalog-count");
  const catalog = state.blogSourceCatalog || [];
  if (counter) {
    const enabled = catalog.filter((s) => s.default_enabled).length;
    const optional = catalog.length - enabled;
    counter.textContent = catalog.length
      ? `${catalog.length} configured · ${enabled} default-on${optional ? ` · ${optional} optional` : ""}`
      : "loading…";
  }
  if (!list) return;
  if (!catalog.length) {
    list.innerHTML = '<div class="empty">Loading source catalog…</div>';
    return;
  }
  list.innerHTML = catalog.map((src) => {
    const trustPct = src.trust != null ? Math.round(Number(src.trust) * 100) : null;
    const trustClass = trustPct == null ? "" : trustPct >= 90 ? "is-high" : trustPct >= 78 ? "is-med" : "is-low";
    const kindLabel = (src.kind || "feed").toUpperCase();
    return `<article class="blog-source-row">
      <div class="blog-source-row-head">
        <strong>${escapeHtml(src.name || src.id)}</strong>
        <span class="pill ${trustClass}" title="Trust weighting applied to items from this source">trust ${trustPct != null ? trustPct + "%" : "—"}</span>
        <span class="pill ${src.default_enabled ? "ok" : "warn"}" title="${src.default_enabled ? "Fetched by default on Update Sources" : "Off by default — needs include_optional=true to fetch"}">${src.default_enabled ? "default-on" : "optional"}</span>
        <small class="muted">${escapeHtml(kindLabel)}</small>
      </div>
      <p class="blog-source-row-topic">${escapeHtml(src.topic || "")}</p>
      ${src.note ? `<p class="blog-source-row-note muted small">↳ ${escapeHtml(src.note)}</p>` : ""}
      <a class="blog-source-row-url muted small" href="${escapeHtml(src.url || "#")}" target="_blank" rel="noopener noreferrer">${escapeHtml(src.url || "")}</a>
    </article>`;
  }).join("");
}

async function refreshBlogBriefing() {
  state.blogRefreshing = true;
  renderBlogPage();
  try {
    const res = await apiPost("/v1/community/blog/refresh", {});
    state.blogBriefing = res || { items: [], sources: [], updated_at: null };
  } catch (err) {
    console.error("Failed to update briefing sources:", err);
    alert("Failed to update briefing sources. Existing cached items are still available.");
  } finally {
    state.blogRefreshing = false;
    renderBlogPage();
  }
}

function renderCommunityPages() {
  // BBS section nav: wire once + restore last-active section.
  bindBbsSectionEvents();
  state.bbsSection = state.bbsSection || _bbsLoadJson(BBS_SECTION_PERSIST_KEY, "lobby");
  setBbsSection(state.bbsSection);
  renderWikiPage();
  fetchBlogPosts();
  fetchBlogBriefing();
  renderMarketplacePage();
}

function bindCommunityPages() {
  // Restore any SysOp status overrides (pin/lock/resolve) from a
  // previous session so moderation decisions survive a reload.
  try {
    const saved = localStorage.getItem(BBS_FORUM_MOD_KEY);
    if (saved) state.communityForumModeration = JSON.parse(saved) || {};
  } catch (_e) { state.communityForumModeration = {}; }
  $("forum-page")?.addEventListener("click", (event) => {
    const channelButton = event.target.closest("[data-forum-channel]");
    if (channelButton) {
      state.communityForumChannel = channelButton.dataset.forumChannel;
      renderForumPage();
      return;
    }
    // SysOp moderation toolbar (pin/lock/resolve/hot) — gated in the
    // handlers; clicks are no-ops for non-admins.
    const modButton = event.target.closest("[data-forum-mod]");
    if (modButton) {
      _bbsModerateThread(modButton.dataset.forumMod);
      return;
    }
    // SysOp per-post delete.
    const delButton = event.target.closest("[data-forum-post-del]");
    if (delButton) {
      _bbsDeleteLocalPost(delButton.dataset.forumPostDel);
      return;
    }
    const threadButton = event.target.closest("[data-forum-thread]");
    if (threadButton) {
      state.communityForumThread = threadButton.dataset.forumThread;
      renderForumPage();
    }
  });
  $("forum-post-button")?.addEventListener("click", () => {
    const input = $("forum-composer-input");
    const text = String(input?.value || "").trim();
    if (!text || !state.communityForumThread) {
      if ($("forum-status")) $("forum-status").textContent = "Write a reply before posting a local draft.";
      return;
    }
    // Locked topics reject member replies; the SysOp can always post.
    const activeThread = COMMUNITY_FORUM_THREADS.find((t) => t.id === state.communityForumThread);
    if (_forumThreadStatus(activeThread) === "Locked" && !_bbsIsSysop()) {
      if ($("forum-status")) $("forum-status").textContent = "This topic is locked by the SysOp — no new replies.";
      return;
    }
    // The SysOp posts under the operator handle + SYSOP role; everyone
    // else posts as a local-draft member.
    const sysop = _bbsIsSysop();
    const author = sysop ? _bbsAdminHandle() : "You";
    const role = sysop ? "SYSOP" : "Local draft";
    const posts = state.communityForumPosts[state.communityForumThread] || [];
    state.communityForumPosts[state.communityForumThread] = [
      ...posts,
      { author, role, time: "Now", body: text },
    ];
    input.value = "";
    if ($("forum-status")) {
      $("forum-status").textContent = sysop
        ? "Posted as SysOp (local to this browser session)."
        : "Local draft added to this browser session.";
    }
    renderForumPage();
  });
  $("wiki-search-input")?.addEventListener("input", (event) => {
    state.wikiQuery = event.target.value;
    renderWikiPage();
  });
  $("wiki-category-select")?.addEventListener("change", (event) => {
    state.wikiCategory = event.target.value;
    renderWikiPage();
  });
  $("wiki-page")?.addEventListener("click", (event) => {
    const articleButton = event.target.closest("[data-wiki-article]");
    if (articleButton) {
      state.wikiArticleId = articleButton.dataset.wikiArticle;
      renderWikiPage();
      requestAnimationFrame(() => {
        $("wiki-page")?.scrollTo?.({ top: 0, behavior: "auto" });
        $("wiki-article-detail")?.scrollIntoView?.({ block: "start", behavior: "auto" });
      });
    }
  });
  $("blog-filter-select")?.addEventListener("change", (event) => {
    state.blogFilter = event.target.value;
    renderBlogPage();
  });
  $("blog-page")?.addEventListener("click", (event) => {
    const postButton = event.target.closest("[data-blog-post]");
    if (postButton) {
      state.blogPostId = postButton.dataset.blogPost;
      renderBlogPage();
    }
  });
  $("btn-blog-generate")?.addEventListener("click", async (event) => {
    const btn = event.target;
    btn.disabled = true;
    btn.textContent = "Generating...";
    try {
      const res = await apiPost("/v1/community/blog/generate", {});
      await fetchBlogPosts();
      state.blogPostId = res.id;
      renderBlogPage();
    } catch (err) {
      console.error("Failed to generate story:", err);
      alert("Failed to generate Briefing story. See console for details.");
    } finally {
      btn.disabled = false;
      btn.textContent = "Draft New Story";
    }
  });
  $("btn-blog-refresh")?.addEventListener("click", async (event) => {
    const btn = event.target;
    btn.disabled = true;
    btn.textContent = "Updating...";
    try {
      await refreshBlogBriefing();
    } finally {
      btn.disabled = false;
      btn.textContent = "Update Sources";
    }
  });
  $("bounty-filter-select")?.addEventListener("change", (event) => {
    state.bountyFilter = event.target.value;
    renderMarketplacePage();
  });
  $("marketplace-page")?.addEventListener("click", (event) => {
    const bountyButton = event.target.closest("[data-bounty-id]");
    if (bountyButton) {
      state.bountyId = bountyButton.dataset.bountyId;
      renderMarketplacePage();
      return;
    }
    const actionButton = event.target.closest("[data-bounty-action]");
    if (actionButton && $("bounty-status")) {
      const action = actionButton.dataset.bountyAction === "watch" ? "Watching" : "Interest noted for";
      const active = MARKETPLACE_BOUNTIES.find((item) => item.id === state.bountyId);
      $("bounty-status").textContent = `${action} ${active?.title || "this listing"}.`;
    }
  });
}

function localHardwareCandidate(item, mappedNodeIds) {
  const nodeId = String(item.node_id || "");
  const deviceId = String(item.device_id || "");
  const site = String(item.site || "");
  const combined = `${nodeId} ${deviceId} ${site}`.toLowerCase();
  const localHint = ["tbeam", "t-beam", "lilygo", "asv", "prototype", "coprocessor", "serial", "com"].some((hint) => combined.includes(hint));
  return localHint || (!nodeId.includes(":real:") && !mappedNodeIds.has(nodeId));
}

function groupHardwareMeasurements(items) {
  const mappedNodeIds = new Set(state.features.map((feature) => feature.properties?.node_id).filter(Boolean));
  const groups = new Map();
  for (const item of items || []) {
    if (!localHardwareCandidate(item, mappedNodeIds)) {
      continue;
    }
    const nodeId = item.node_id || item.device_id || "unknown-local-device";
    if (!groups.has(nodeId)) {
      groups.set(nodeId, {
        node_id: nodeId,
        device_id: item.device_id || "",
        site: item.site || "",
        mapped: mappedNodeIds.has(nodeId),
        latest_at: item.recorded_at || item.sampled_at || "",
        metrics: [],
      });
    }
    const group = groups.get(nodeId);
    group.latest_at = [group.latest_at, item.recorded_at || item.sampled_at || ""].filter(Boolean).sort().pop() || group.latest_at;
    if (group.metrics.length < 10) {
      group.metrics.push(item);
    }
  }
  return [...groups.values()].sort((a, b) => new Date(b.latest_at || 0).getTime() - new Date(a.latest_at || 0).getTime());
}

function hardwareGroupByNode(nodeId) {
  const id = String(nodeId || "");
  return (state.hardwareFeed || []).find((group) => String(group.node_id) === id);
}

function hardwarePinByNode(nodeId) {
  const id = String(nodeId || "");
  return (state.hardwarePins || []).find((pin) => String(pin.node_id) === id);
}

function hardwareFeatureByNode(nodeId) {
  const id = String(nodeId || "");
  return state.features.find((feature) => String(feature.properties?.node_id || "") === id);
}

function buildHardwarePinPopup(pin) {
  const metrics = (pin.metrics || [])
    .slice(0, 5)
    .map((metric) => `<div><dt>${escapeHtml(telemetryLabel(metric.metric_name))}</dt><dd>${escapeHtml(formatValue(metric.value, metric.unit))}</dd></div>`)
    .join("");
  return `
    <div class="station-popup hardware-pin-popup">
      <div class="station-popup-head">
        <span class="pill warn">Temporary pin</span>
        <strong>${escapeHtml(pin.device_id || pin.node_id)}</strong>
      </div>
      <div class="station-popup-value">
        <span>Browser-only map anchor</span>
        <strong>${escapeHtml(Number(pin.lat).toFixed(4))}, ${escapeHtml(Number(pin.lon).toFixed(4))}</strong>
      </div>
      <dl class="station-popup-meta">
        <div><dt>Node</dt><dd>${escapeHtml(pin.node_id)}</dd></div>
        <div><dt>Pinned</dt><dd>${escapeHtml(shortTime(pin.pinned_at))}</dd></div>
        <div><dt>Meaning</dt><dd>Not saved, exported, or treated as sensor GPS.</dd></div>
        ${metrics}
      </dl>
    </div>
  `;
}

function renderHardwarePins() {
  if (!state.map || typeof L === "undefined") {
    return;
  }
  if (state.hardwarePinLayer) {
    state.hardwarePinLayer.removeFrom(state.map);
    state.hardwarePinLayer = null;
  }
  const pins = (state.hardwarePins || []).filter((pin) => Number.isFinite(Number(pin.lat)) && Number.isFinite(Number(pin.lon)));
  if (!pins.length) {
    renderMapStatusStrip();
    return;
  }
  const markers = pins.map((pin) => {
    const marker = L.marker([Number(pin.lat), Number(pin.lon)], {
      icon: L.divIcon({
        className: "",
        html: `<span class="hardware-pin-marker"></span>`,
        iconSize: [30, 30],
        iconAnchor: [15, 15],
      }),
      zIndexOffset: 440,
    });
    marker.bindTooltip(pin.device_id || pin.node_id || "Local hardware", { direction: "top", offset: [0, -14] });
    marker.bindPopup(buildHardwarePinPopup(pin), {
      className: "omega-station-popup",
      closeButton: true,
      maxWidth: 340,
      minWidth: 280,
    });
    return marker;
  });
  state.hardwarePinLayer = L.layerGroup(markers).addTo(state.map);
  renderMapStatusStrip();
}

function pinHardwareAtMapCenter(nodeId) {
  const group = hardwareGroupByNode(nodeId);
  if (!group || !state.map) {
    setStatus("That hardware feed is no longer available in the latest measurements.");
    return;
  }
  const center = state.map.getCenter();
  const nextPin = {
    node_id: group.node_id,
    device_id: group.device_id || "",
    lat: center.lat,
    lon: center.lng,
    pinned_at: new Date().toISOString(),
    metrics: (group.metrics || []).slice(0, 8).map((metric) => ({
      metric_name: metric.metric_name,
      value: metric.value,
      unit: metric.unit,
      recorded_at: metric.recorded_at || metric.sampled_at || "",
    })),
  };
  state.hardwarePins = [nextPin, ...(state.hardwarePins || []).filter((pin) => String(pin.node_id) !== String(group.node_id))].slice(0, 8);
  renderHardwarePins();
  renderHardwareFeed();
  setStatus(`${group.device_id || group.node_id} was pinned at the current map center as a temporary browser-only anchor.`);
}

function removeHardwarePin(nodeId) {
  const before = state.hardwarePins.length;
  state.hardwarePins = (state.hardwarePins || []).filter((pin) => String(pin.node_id) !== String(nodeId || ""));
  renderHardwarePins();
  renderHardwareFeed();
  if (before !== state.hardwarePins.length) {
    setStatus("Temporary hardware pin removed.");
  }
}

function clearHardwarePins() {
  state.hardwarePins = [];
  renderHardwarePins();
  renderHardwareFeed();
  setStatus("All temporary hardware pins were cleared. Real station coordinates are unchanged.");
}

async function focusHardwareNode(nodeId) {
  const feature = hardwareFeatureByNode(nodeId);
  if (feature?.geometry?.coordinates?.length >= 2) {
    await selectFeature(feature);
    return;
  }
  const pin = hardwarePinByNode(nodeId);
  if (pin && state.map) {
    state.map.setView([Number(pin.lat), Number(pin.lon)], Math.max(state.map.getZoom(), MAP_DETAIL_ZOOM), {
      animate: true,
    });
    setStatus(`${pin.device_id || pin.node_id} focused using its temporary browser-only pin.`);
    return;
  }
  setStatus("This local hardware feed has no real coordinate or temporary pin yet.");
}

function renderHardwareFeed() {
  const count = $("hardware-feed-count");
  const list = $("hardware-feed-list");
  if (!count || !list) {
    return;
  }
  const feed = state.hardwareFeed || [];
  count.textContent = feed.length ? `${feed.length} local` : "None";
  count.className = `pill ${feed.length ? "ok" : "warn"}`;
  if (!feed.length) {
    list.innerHTML = `<div class="empty">No local board measurements found in the latest gateway feed.</div>`;
    return;
  }
  list.innerHTML = feed
    .slice(0, 4)
    .map((group) => {
      const gnss = group.metrics.find((item) => item.metric_name === "gnss-status");
      const fix = group.metrics.find((item) => item.metric_name === "gnss-fix-type");
      const pin = hardwarePinByNode(group.node_id);
      const locationStatus = group.mapped
        ? "Mapped"
        : pin
          ? `Temporary browser pin: ${Number(pin.lat).toFixed(4)}, ${Number(pin.lon).toFixed(4)}`
        : gnss?.value
          ? `No map marker: GNSS ${gnss.value}`
          : "No map marker: coordinates unavailable";
      const metricChips = group.metrics
        .filter((item) => !["gnss-status", "gnss-fix-type"].includes(item.metric_name))
        .slice(0, 5)
        .map((item) => `<span>${escapeHtml(formatName(item.metric_name))}: ${escapeHtml(formatValue(item.value, item.unit))}</span>`)
        .join("");
      const fixText = fix ? ` | fix ${escapeHtml(formatValue(fix.value, fix.unit))}` : "";
      return `
        <article class="hardware-card">
          <header>
            <div>
              <strong>${escapeHtml(group.device_id || group.node_id)}</strong>
              <small class="muted">${escapeHtml(group.node_id)}</small>
            </div>
            <span class="pill ${group.mapped ? "ok" : "warn"}">${escapeHtml(group.mapped ? "Map" : "Unmapped")}</span>
          </header>
          <p class="muted">${escapeHtml(locationStatus)}${fixText} | latest ${escapeHtml(shortTime(group.latest_at))}</p>
          <div class="hardware-metrics">${metricChips || "<span>No numeric metrics in latest batch</span>"}</div>
          <div class="hardware-card-actions">
            <button type="button" class="button button-secondary" data-hardware-focus="${escapeHtml(group.node_id)}">${escapeHtml(group.mapped || pin ? "Focus" : "Locate")}</button>
            <button type="button" class="button button-secondary" data-hardware-pin="${escapeHtml(group.node_id)}">${escapeHtml(pin ? "Move Pin" : "Pin At Center")}</button>
            ${pin ? `<button type="button" class="button button-secondary" data-hardware-unpin="${escapeHtml(group.node_id)}">Remove Pin</button>` : ""}
          </div>
        </article>
      `;
    })
    .join("");
}

async function loadHardwareFeed() {
  if (!$("hardware-feed-list")) {
    return;
  }
  try {
    const payload = await api("/v1/measurements/latest", {
      data_scope: "real",
      limit: 250,
    });
    state.hardwareFeed = groupHardwareMeasurements(payload.items || []);
    renderHardwareFeed();
    renderHardwarePins();
    renderMapStatusStrip();
  } catch (error) {
    $("hardware-feed-count").textContent = "Error";
    $("hardware-feed-count").className = "pill bad";
    $("hardware-feed-list").innerHTML = `<div class="empty">Hardware feed failed: ${escapeHtml(error.message)}</div>`;
    renderMapStatusStrip();
  }
}

function renderStationTable() {
  if (!state.features.length) {
    $("station-table").innerHTML = `<div class="empty">No ${escapeHtml(dataScopeLabel())} are loaded.</div>`;
    return;
  }
  $("station-table").innerHTML = state.features
    .map((feature) => {
      const props = feature.properties || {};
      return `
        <button type="button" class="table-row station-row" data-node-id="${escapeHtml(props.node_id)}">
          <strong>${escapeHtml(props.label || props.site || props.node_id)}</strong>
          <span>${escapeHtml(formatValue(props.display_metric_value, props.display_metric_unit))}</span>
        </button>
      `;
    })
    .join("");
}

function updateMetricDownloadLink() {
  const href = `/v1/map/stations/export.csv?data_scope=${activeDataScope()}&metric_name=${encodeURIComponent(state.metric || "")}`;
  $("download-map-link").href = href;
  if ($("download-metric-csv-link")) {
    $("download-metric-csv-link").href = href;
  }
}

async function selectFeature(feature, options = {}) {
  state.selectedFeature = feature;
  const props = feature.properties || {};
  const entityId = featureEntityId(feature);
  if (options.openDrawer !== false) {
    state.selectedMapEntity = { type: "node", id: entityId };
    state.mapVizCollapsed = false;
  }
  // Sync the Inspect dashboard's site filter to the clicked station so that
  // when the operator navigates to Data > Inspect their live tiles are
  // already pivoted to this site's metrics.
  try {
    const nodeId = props.node_id;
    if (nodeId && typeof _inspectLiveSite !== "undefined") {
      _inspectLiveSite = String(nodeId);
      if (typeof _saveInspectLiveState === "function") _saveInspectLiveState();
      const siteSel = document.getElementById("inspect-live-site");
      if (siteSel && Array.from(siteSel.options).find((o) => o.value === nodeId)) {
        siteSel.value = nodeId;
      }
      if (typeof _refreshPickerLabelsForGroup === "function") {
        _refreshPickerLabelsForGroup("inspect");
      }
      if (typeof _refreshInspectLiveTiles === "function") {
        _refreshInspectLiveTiles();
      }
    }
  } catch {}
  $("station-freshness").textContent = props.freshness || "unknown";
  $("station-freshness").className = `pill ${props.freshness === "fresh" ? "ok" : "warn"}`;
  if ($("control-target-node")) {
    $("control-target-node").value = props.node_id || "";
  }
  if ($("mesh-target-node")) {
    $("mesh-target-node").value = props.node_id || "";
  }
  renderStationKpis(props.latest_metrics || []);
  renderMetricList(props.latest_metrics || []);
  renderSceneReport();
  renderContextDrawer();
  renderMapVisualizationDock();
  if (options.fit !== false && feature.geometry?.coordinates) {
    const focusZoom = Math.min(Math.max(state.map.getZoom(), MAP_DETAIL_ZOOM), MAP_MAX_ZOOM - 2);
    state.map.setView([feature.geometry.coordinates[1], feature.geometry.coordinates[0]], focusZoom, {
      animate: true,
    });
  }
  renderGlobeScene();
  try {
    const detail = await api("/v1/stations/detail", {
      node_id: props.node_id,
      device_id: props.device_id,
      metric_name: state.metric,
    });
    renderStationDetail(detail);
  } catch (error) {
    state.selectedDetail = null;
    $("station-chart").innerHTML = `<div class="empty">Station detail unavailable: ${escapeHtml(error.message)}</div>`;
    renderChartSuite();
    renderMapVisualizationDock();
  }
}

function renderStationKpis(metrics) {
  const important = ["water-temperature", "significant-wave-height", "wind-speed", "atmospheric-pressure"];
  const cards = important.map((name) => {
    const metric = metrics.find((item) => item.metric_name === name);
    return `<article class="kpi"><span>${escapeHtml(telemetryLabel(name))}</span><strong>${escapeHtml(metric ? formatValue(metric.value, metric.unit) : "-")}</strong></article>`;
  });
  $("station-kpis").innerHTML = cards.join("");
}

function renderMetricList(metrics) {
  if (!metrics.length) {
    $("station-metrics").innerHTML = `<div class="empty">No telemetry metrics found.</div>`;
    return;
  }
  const used = new Set();
  const sections = TELEMETRY_GROUPS.map((group) => {
    const rows = group.metrics
      .map((name) => metricByName(metrics, name))
      .filter(Boolean);
    rows.forEach((metric) => used.add(metric.metric_name));
    return { title: group.title, rows };
  }).filter((section) => section.rows.length);
  const otherRows = metrics.filter((metric) => !used.has(metric.metric_name)).slice(0, 8);
  if (otherRows.length) {
    sections.push({ title: "Other Sensor Readings", rows: otherRows });
  }
  $("station-metrics").innerHTML = sections
    .map((section) => `
      <section class="telemetry-group">
        <h4>${escapeHtml(section.title)}</h4>
        <div class="telemetry-readings">
          ${section.rows.map(renderTelemetryReading).join("")}
        </div>
      </section>
    `)
    .join("");
}

function renderTelemetryReading(metric) {
  return `
    <article class="telemetry-reading">
      <div>
        <strong>${escapeHtml(telemetryLabel(metric.metric_name))}</strong>
        <span>${escapeHtml(shortTime(metric.recorded_at || metric.sampled_at))}</span>
      </div>
      <b>${escapeHtml(formatValue(metric.value, metric.unit))}</b>
    </article>
  `;
}

function renderStationDetail(detail) {
  state.selectedDetail = detail;
  const history = detail.history || [];
  drawLineChart("station-chart", history, {
    title: `${formatName(detail.selected_metric || state.metric)} history`,
    valueKey: "value",
  });
  renderChartSuite();
  renderMapVisualizationDock();
}

async function loadQcReview() {
  if (!state.metric) {
    return;
  }
  const payload = await api("/v1/qc/summary", {
    metric_name: state.metric,
    data_scope: activeDataScope(),
    limit: 500,
  });
  state.qcReview = payload;
  renderQcReview();
  renderChartSuite();
}

function renderQcReview() {
  const review = state.qcReview;
  if (!review) {
    $("qc-review-summary").innerHTML = "";
    $("qc-review-list").innerHTML = `<div class="empty">Run QC Review to evaluate the active metric.</div>`;
    return;
  }
  const counts = review.summary?.flag_counts || {};
  $("qc-review-summary").innerHTML = [
    statCard("Stations", review.summary?.station_count ?? 0, "Evaluated"),
    statCard("PASS", counts.PASS ?? 0, "Valid readings"),
    statCard("SUSPECT", counts.SUSPECT ?? 0, "Needs review"),
    statCard("FAIL", counts.FAIL ?? 0, "Flagged"),
  ].join("");
  const items = review.items || [];
  if (!items.length) {
    $("qc-review-list").innerHTML = `<div class="empty">No QC items returned for ${escapeHtml(formatName(state.metric))}.</div>`;
    return;
  }
  $("qc-review-list").innerHTML = items
    .slice(0, 20)
    .map((item) => {
      const label = item.qc?.summary_label || "NOT_EVALUATED";
      const flagged = label !== "PASS";
      return `
        <button type="button" class="check-card ${flagged ? "is-fail" : "is-pass"}" data-node-id="${escapeHtml(item.node_id)}">
          <div>
            <strong>${escapeHtml(item.site || item.node_id)}</strong>
            <p class="muted">${escapeHtml(telemetryLabel(item.metric_name))} ${escapeHtml(formatValue(item.value, item.unit))} | ${escapeHtml(shortTime(item.recorded_at || item.sampled_at))}</p>
          </div>
          <div class="tool-card-actions">
            <span class="pill ${flagged ? "warn" : "ok"}">${escapeHtml(label)}</span>
          </div>
        </button>
      `;
    })
    .join("");
}

async function focusFirstQcFlag() {
  if (!state.qcReview) {
    await loadQcReview();
  }
  const flagged = (state.qcReview?.items || []).find((item) => item.qc?.summary_label && item.qc.summary_label !== "PASS");
  if (!flagged) {
    $("qc-review-list").insertAdjacentHTML("afterbegin", `<div class="empty">No flagged readings for ${escapeHtml(formatName(state.metric))}.</div>`);
    return;
  }
  const feature = state.features.find((item) => item.properties?.node_id === flagged.node_id);
  if (feature) {
    navigate("map");
    await selectFeature(feature);
  }
}

function downloadQcReview() {
  const review = state.qcReview || { status: "not-run", metric_name: state.metric };
  downloadJson(review, `omega-wave-qc-${state.metric || "metric"}-${new Date().toISOString().replace(/[:.]/g, "-")}.json`);
}

async function loadLayers() {
  const payload = await api("/v1/map/layers");
  state.layers = payload.items || [];
  populateBasemapSelect();
  renderChartLayerSelect();
  renderMapGisLayerSelect();
  renderEnvironmentalLayerSelect();
  renderLayerList();
  renderSceneReport();
  renderChartSuite();
  if (typeof renderLayerCatalog === "function") {
    renderLayerCatalog();
  }
  renderOceanLayerDock();
}

function layerProvider(layer) {
  return layer.tags?.provider || layer.source?.provider || "";
}

function isLiveAisLayer(layer) {
  return ["ais", "aisstream"].includes(layerProvider(layer));
}

function isMarineCadastreTransitLayer(layer) {
  return layerProvider(layer) === "marine-cadastre-ais" && layer?.tags?.theme === "ais-transit-counts";
}

function marineCadastreTransitYear(layerOrId) {
  const raw =
    typeof layerOrId === "string"
      ? String(layerOrId).match(/marine-cadastre-ais-transit-counts-(\d{4})$/)?.[1]
      : layerOrId?.tags?.year ?? String(layerOrId?.layer_id || "").match(/marine-cadastre-ais-transit-counts-(\d{4})$/)?.[1];
  const year = Number(raw);
  return Number.isFinite(year) ? year : null;
}

function marineCadastreTransitLayers({ newestFirst = false } = {}) {
  const layers = (state.layers || [])
    .filter(isMarineCadastreTransitLayer)
    .map((layer) => ({ layer, year: marineCadastreTransitYear(layer) }))
    .filter((item) => Number.isFinite(item.year))
    .sort((a, b) => a.year - b.year);
  if (newestFirst) layers.reverse();
  return layers.map((item) => item.layer);
}

function marineCadastreTransitLayerForYear(year) {
  const wanted = Number(year);
  if (!Number.isFinite(wanted)) return null;
  return marineCadastreTransitLayers().find((layer) => marineCadastreTransitYear(layer) === wanted) || null;
}

function removeActiveMarineCadastreTransitLayersExcept(layerId) {
  const cat = layerCatalogState();
  for (const entry of [...(cat.activeStack || [])]) {
    if (entry.layer_id === layerId) continue;
    const layer = (state.layers || []).find((item) => item.layer_id === entry.layer_id);
    if (isMarineCadastreTransitLayer(layer)) {
      layerCatalogRemove(entry.layer_id);
    }
  }
}

function layerTheme(layer) {
  return layer.tags?.theme || layer.tags?.scope || layer.category || "";
}

function layerMinUsefulZoom(layer) {
  const value = Number(layer.tags?.min_useful_zoom ?? layer.source?.min_useful_zoom);
  return Number.isFinite(value) ? value : null;
}

function layerRenderMinZoom(layer) {
  const configured = Number(layer.tags?.render_min_zoom ?? layer.source?.min_zoom);
  if (Number.isFinite(configured)) return configured;
  if (isChartLikeLayer(layer)) {
    return layerMinUsefulZoom(layer) ?? MAP_MIN_ZOOM;
  }
  return MAP_MIN_ZOOM;
}

function layerMaxNativeZoom(layer) {
  const value = Number(layer.tags?.max_native_zoom ?? layer.source?.max_native_zoom);
  return Number.isFinite(value) ? value : null;
}

function layerCoverageLabel(layer) {
  return layer.tags?.coverage_region || (layerProvider(layer) === "noaa" ? "United States coastal waters" : "Coverage varies by provider");
}

function layerFingerprint(layer) {
  if (layer.is_default) {
    return `default:${layer.layer_id}`;
  }
  const source = layer.source || {};
  return [
    layer.name,
    layer.category,
    layer.source_type,
    source.uploaded_from || source.url || source.service_url || layer.tags?.provider || "",
  ]
    .join("|")
    .toLowerCase();
}

function visibleChartLayers() {
  const seen = new Set();
  const layers = [];
  for (const layer of state.layers) {
    if (!["chart", "overlay", "obstacle", "reference"].includes(layer.category)) {
      continue;
    }
    const fingerprint = layerFingerprint(layer);
    if (seen.has(fingerprint)) {
      continue;
    }
    seen.add(fingerprint);
    if (layer.status === "hidden" && !layer.is_default) {
      continue;
    }
    layers.push(layer);
  }
  return layers.sort((a, b) => {
    const providerRank = (layer) => {
      const provider = layerProvider(layer);
      if (provider === "noaa") return 0;
      if (provider === "openseamap") return 1;
      if (provider === "nasa") return 2;
      if (layer.is_default) return 3;
      return 4;
    };
    return providerRank(a) - providerRank(b) || String(a.name).localeCompare(String(b.name));
  });
}

function renderChartLayerSelect() {
  const select = $("chart-layer-select");
  if (!select) {
    return;
  }
  const layers = visibleChartLayers();
  select.innerHTML = layers
    .map((layer) => {
      const provider = layerProvider(layer) || layer.source_type;
      return `<option value="${escapeHtml(layer.layer_id)}">${escapeHtml(layer.name)} - ${escapeHtml(formatName(provider))}</option>`;
    })
    .join("");
  if (state.contextLayer?.omegaLayerId && layers.some((layer) => layer.layer_id === state.contextLayer.omegaLayerId)) {
    select.value = state.contextLayer.omegaLayerId;
  }
  const duplicateCount = Math.max(0, state.layers.length - layers.length);
  const summary = $("layer-stack-summary");
  if (summary) {
    summary.textContent = `${layers.length} usable chart sources are available${duplicateCount ? `; ${duplicateCount} duplicate or hidden uploads are folded away from the main list.` : "."}`;
  }
}

function renderMapGisLayerSelect() {
  const select = $("map-gis-layer-select");
  if (!select) {
    return;
  }
  const layers = visibleChartLayers();
  if (!layers.length) {
    select.innerHTML = `<option value="">No GIS layers registered</option>`;
    select.disabled = true;
    return;
  }
  select.disabled = false;
  select.innerHTML = layers
    .map((layer) => {
      const provider = layerProvider(layer) || layer.source_type;
      const category = layer.category === "chart" ? "chart" : layer.category;
      return `<option value="${escapeHtml(layer.layer_id)}">${escapeHtml(layer.name)} - ${escapeHtml(formatName(provider || category))}</option>`;
    })
    .join("");
  if (state.contextLayer?.omegaLayerId && layers.some((layer) => layer.layer_id === state.contextLayer.omegaLayerId)) {
    select.value = state.contextLayer.omegaLayerId;
  }
}

function environmentalLayers() {
  return state.layers
    .filter((layer) => layer.source_type === "wms" && layer.tags?.provider === "nasa")
    .sort((a, b) => (a.name || "").localeCompare(b.name || ""));
}

function todayDateString() {
  const date = new Date();
  return date.toISOString().slice(0, 10);
}

function utcDateFromInput(value) {
  if (!value) {
    return null;
  }
  const date = new Date(`${value}T00:00:00Z`);
  return Number.isFinite(date.getTime()) ? date : null;
}

function dateStringFromUtc(date) {
  return date.toISOString().slice(0, 10);
}

function environmentalFrameIntervalMs() {
  const value = Number($("environmental-animation-speed")?.value || 1100);
  return Number.isFinite(value) ? Math.max(450, Math.min(5000, value)) : 1100;
}

function renderEnvironmentalLayerSelect() {
  const select = $("environmental-layer-select");
  if (!select) {
    return;
  }
  const layers = environmentalLayers();
  select.innerHTML = layers.length
    ? layers.map((layer) => `<option value="${escapeHtml(layer.layer_id)}">${escapeHtml(layer.name)}</option>`).join("")
    : `<option value="">No NASA environmental layers registered</option>`;
  const dateInput = $("environmental-animation-date");
  if (dateInput && !dateInput.value) {
    dateInput.value = todayDateString();
  }
  setEnvironmentalAnimationStatus(layers.length ? "Ready" : "No layers", layers.length ? "" : "warn");
  renderEnvironmentalTimeline();
}

function selectedEnvironmentalLayer() {
  const layerId = $("environmental-layer-select")?.value;
  return state.layers.find((layer) => layer.layer_id === layerId) || environmentalLayers()[0] || null;
}

function setEnvironmentalAnimationStatus(message, tone = "") {
  const target = $("environmental-animation-status");
  if (!target) {
    return;
  }
  target.textContent = message;
  target.classList.toggle("ok", tone === "ok");
  target.classList.toggle("warn", tone === "warn");
  target.classList.toggle("bad", tone === "bad");
}

function environmentalDateFrames() {
  const end = utcDateFromInput($("environmental-animation-date")?.value || todayDateString()) || new Date();
  const start = utcDateFromInput($("environmental-animation-start-date")?.value || "");
  const frameCount = Math.max(2, Math.min(365, Number($("environmental-animation-frames")?.value || 14) || 14));
  const stepDays = Math.max(1, Math.min(30, Number($("environmental-animation-step-days")?.value || 1) || 1));
  const frames = [];
  if (start && start <= end) {
    const current = new Date(start);
    while (current <= end && frames.length < frameCount) {
      frames.push(dateStringFromUtc(current));
      current.setUTCDate(current.getUTCDate() + stepDays);
    }
    const endString = dateStringFromUtc(end);
    if (frames[frames.length - 1] !== endString && frames.length < frameCount) {
      frames.push(endString);
    }
    return frames.length ? frames : [endString];
  }
  for (let index = frameCount - 1; index >= 0; index -= 1) {
    const date = new Date(end);
    date.setUTCDate(end.getUTCDate() - index * stepDays);
    frames.push(dateStringFromUtc(date));
  }
  return frames;
}

function renderEnvironmentalTimeline(activeFrame = null) {
  const target = $("environmental-animation-frame-list");
  if (!target) {
    return;
  }
  const frames = state.environmentalAnimationTimer && state.environmentalAnimationFrames.length ? state.environmentalAnimationFrames : environmentalDateFrames();
  const active = activeFrame || state.environmentalCurrentFrame;
  target.innerHTML =
    frames
      .map(
        (frame) =>
          `<button type="button" class="timeline-frame ${frame === active ? "is-active" : ""}" data-env-frame="${escapeHtml(frame)}">${escapeHtml(frame)}</button>`
      )
      .join("") || "No frames are available for this date range.";
}

function stopEnvironmentalAnimation() {
  if (state.environmentalAnimationTimer) {
    window.clearInterval(state.environmentalAnimationTimer);
    state.environmentalAnimationTimer = null;
  }
  state.environmentalAnimationIndex = 0;
  state.environmentalAnimationBusy = false;
  state.environmentalAnimationFrames = [];
  setEnvironmentalAnimationStatus("Stopped");
}

function setLeafletLayerOpacity(layer, opacity) {
  if (!layer) {
    return;
  }
  if (typeof layer.setOpacity === "function") {
    layer.setOpacity(opacity);
    return;
  }
  if (typeof layer.eachLayer === "function") {
    layer.eachLayer((childLayer) => setLeafletLayerOpacity(childLayer, opacity));
  }
}

function removeContextLayerWhenStale(layer) {
  if (!layer || layer === state.contextLayer || !state.map) {
    return;
  }
  try {
    layer.removeFrom(state.map);
  } catch (_error) {
    state.map.removeLayer?.(layer);
  }
}

async function applyEnvironmentalLayerAtDate(dateString = $("environmental-animation-date")?.value || todayDateString(), { navigateToMap = false } = {}) {
  const layer = selectedEnvironmentalLayer();
  if (!layer) {
    setEnvironmentalAnimationStatus("No layer", "bad");
    return;
  }
  const previousLayer = state.contextLayer;
  const configuredOpacity = Number(layer.style?.opacity ?? 0.7);
  const targetOpacity = Number.isFinite(configuredOpacity) ? configuredOpacity : 0.7;
  const leafletLayer = await createLeafletMapLayer(layer, {
    initialOpacity: 0,
    wmsParams: { time: dateString },
  });
  if (!leafletLayer) {
    setEnvironmentalAnimationStatus("Unavailable", "bad");
    return;
  }
  let transitioned = false;
  const finishTransition = () => {
    if (transitioned || leafletLayer !== state.contextLayer) {
      return;
    }
    transitioned = true;
    setLeafletLayerOpacity(leafletLayer, targetOpacity);
    if (previousLayer && previousLayer !== leafletLayer) {
      setLeafletLayerOpacity(previousLayer, 0);
      window.setTimeout(() => removeContextLayerWhenStale(previousLayer), 480);
    }
  };
  leafletLayer.on?.("tileerror", () => {
    setEnvironmentalAnimationStatus("Tile gaps", "warn");
    $("active-layer-summary").textContent = `${layer.name} has gaps for ${dateString}. NASA GIBS coverage varies by product, date, and cloud screening.`;
  });
  leafletLayer.once?.("load", finishTransition);
  leafletLayer.omegaLayerId = layer.layer_id;
  leafletLayer.addTo(state.map);
  state.contextLayer = leafletLayer;
  window.setTimeout(finishTransition, 900);
  state.environmentalCurrentFrame = dateString;
  const message = `${layer.name} applied for ${dateString}. View preserved.`;
  $("active-layer-summary").textContent = message;
  setEnvironmentalAnimationStatus(dateString, "ok");
  renderEnvironmentalTimeline(dateString);
  renderChartLayerSelect();
  renderMapGisLayerSelect();
  renderLayerList();
  if (navigateToMap) {
    navigate("map");
  }
}

async function stepEnvironmentalFrame(delta) {
  stopEnvironmentalAnimation();
  const frames = environmentalDateFrames();
  if (!frames.length) {
    setEnvironmentalAnimationStatus("No frames", "bad");
    return;
  }
  const current = state.environmentalCurrentFrame || $("environmental-animation-date")?.value || frames[frames.length - 1];
  const currentIndex = Math.max(0, frames.indexOf(current));
  const nextIndex = (currentIndex + delta + frames.length) % frames.length;
  await applyEnvironmentalLayerAtDate(frames[nextIndex], { navigateToMap: false });
}

async function playEnvironmentalAnimation() {
  const layer = selectedEnvironmentalLayer();
  if (!layer) {
    setEnvironmentalAnimationStatus("No layer", "bad");
    return;
  }
  stopEnvironmentalAnimation();
  state.environmentalAnimationFrames = environmentalDateFrames();
  state.environmentalAnimationIndex = 0;
  const renderFrame = async () => {
    if (state.environmentalAnimationBusy) {
      return;
    }
    state.environmentalAnimationBusy = true;
    const frame = state.environmentalAnimationFrames[state.environmentalAnimationIndex % state.environmentalAnimationFrames.length];
    state.environmentalAnimationIndex += 1;
    try {
      await applyEnvironmentalLayerAtDate(frame, { navigateToMap: false });
      setStatus(`Animating ${layer.name}: ${frame}`);
    } finally {
      state.environmentalAnimationBusy = false;
    }
  };
  await renderFrame();
  state.environmentalAnimationTimer = window.setInterval(() => {
    renderFrame().catch((error) => {
      stopEnvironmentalAnimation();
      showError(error);
    });
  }, environmentalFrameIntervalMs());
}

function renderLayerList() {
  const useful = visibleChartLayers().slice(0, MAX_LAYER_CARDS);
  $("layer-list").innerHTML = useful
    .map((layer) => `
      <article class="layer-card ${state.contextLayer?.omegaLayerId === layer.layer_id ? "is-active" : ""}">
        <div>
          <strong>${escapeHtml(layer.name)}</strong>
          <p class="muted">${escapeHtml(formatName(layerProvider(layer) || "local"))} | ${escapeHtml(formatName(layer.category))} | ${escapeHtml(String(layer.source_type || "").toUpperCase())}</p>
          <span class="muted">${escapeHtml(layerCoverageLabel(layer))}${layerMinUsefulZoom(layer) ? ` | best zoom ${escapeHtml(layerMinUsefulZoom(layer))}+` : ""}</span>
          <span class="muted">${escapeHtml(layer.tags?.coverage_note || layer.tags?.notes || layer.source?.summary || "Browser-renderable map layer.")}</span>
        </div>
        <button type="button" class="button button-secondary" data-layer-id="${escapeHtml(layer.layer_id)}">Apply</button>
      </article>
    `)
    .join("") || `<div class="empty">No chart layers are registered.</div>`;
}

const NO_DATA_KEY_THRESHOLD = 26;

// WMS tile layer that keys near-black no-data pixels to transparent. GIBS
// swath imagery (MODIS/VIIRS true colour) bakes its orbital gaps in as opaque
// black; keyed out, the gaps reveal the basemap instead of solid black wedges.
// Tiles route through the same-origin gateway proxy so the canvas stays
// untainted and getImageData can run.
function createNoDataKeyedWmsLayer(layer, wmsOptions) {
  const KeyedWmsLayer = L.TileLayer.WMS.extend({
    createTile(coords, done) {
      const size = this.getTileSize();
      const tile = document.createElement("canvas");
      tile.width = size.x;
      tile.height = size.y;
      const img = new Image();
      img.alt = "";
      img.addEventListener("load", () => {
        const ctx = tile.getContext("2d");
        try {
          ctx.drawImage(img, 0, 0, tile.width, tile.height);
          const frame = ctx.getImageData(0, 0, tile.width, tile.height);
          const px = frame.data;
          for (let i = 0; i < px.length; i += 4) {
            if (px[i] + px[i + 1] + px[i + 2] <= NO_DATA_KEY_THRESHOLD) {
              px[i + 3] = 0;
            }
          }
          ctx.putImageData(frame, 0, 0);
        } catch (_err) {
          // Tainted canvas or decode failure — show the raw tile unkeyed.
          try {
            ctx.clearRect(0, 0, tile.width, tile.height);
            ctx.drawImage(img, 0, 0, tile.width, tile.height);
          } catch (_err2) {
            /* leave the tile blank */
          }
        }
        done(null, tile);
      });
      img.addEventListener("error", () => done(new Error("WMS tile load failed"), tile));
      img.src = this.getTileUrl(coords);
      return tile;
    },
  });
  const proxyBase = `/v1/map/layers/${encodeURIComponent(layer.layer_id)}/proxy`;
  return new KeyedWmsLayer(proxyBase, { ...wmsOptions, uppercase: false });
}

async function createLeafletMapLayer(layer, options = {}) {
  let leafletLayer = null;
  const xyzOpacity = Number(options.initialOpacity ?? layer.style?.opacity ?? 0.82);
  const wmsOpacity = Number(options.initialOpacity ?? layer.style?.opacity ?? 0.7);
  const minZoom = layerRenderMinZoom(layer);
  const maxNativeZoom = layerMaxNativeZoom(layer);
  const rasterPane = paneForRasterLayer(layer);
  const noWrap = layer.source?.no_wrap === true || isChartLikeLayer(layer);
  if (layer.source_type === "xyz" && layer.source?.url) {
    const initialXyzParams = { ...(options.xyzParams || {}) };
    const integerTileGrid = layerRequiresIntegerTileGrid(layer);
    const isGlobalFishingWatchLayer = layerProvider(layer) === "global-fishing-watch";
    leafletLayer = L.tileLayer(layerTileTemplate(layer, initialXyzParams), {
      opacity: Number.isFinite(xyzOpacity) ? xyzOpacity : 0.82,
      attribution: layer.source.attribution || layer.name,
      noWrap,
      errorTileUrl: TRANSPARENT_TILE_DATA_URL,
      updateWhenIdle: integerTileGrid || isGlobalFishingWatchLayer,
      updateWhenZooming: !integerTileGrid && !isGlobalFishingWatchLayer,
      keepBuffer: isGlobalFishingWatchLayer ? 1 : layer.category === "overlay" ? 6 : 4,
      minZoom,
      maxZoom: MAP_MAX_ZOOM,
      ...(rasterPane ? { pane: rasterPane } : {}),
      ...(maxNativeZoom ? { maxNativeZoom } : {}),
    });
    leafletLayer.omegaXyzParams = initialXyzParams;
    leafletLayer.omegaSetParams = (nextParams = {}) => {
      leafletLayer.omegaXyzParams = { ...(nextParams || {}) };
      leafletLayer.setUrl(layerTileTemplate(layer, leafletLayer.omegaXyzParams));
      return leafletLayer;
    };
  } else if (layer.source_type === "wmts" && layer.source?.layer) {
    const wmtsParams = { ...(options.wmtsParams || {}) };
    const wmtsOpacity = Number(options.initialOpacity ?? layer.style?.opacity ?? 0.72);
    const tileLayer = createWmtsTileLayer(layer, wmtsParams, {
      opacity: 0,
      attribution: layer.source.attribution || layer.name,
      errorTileUrl: TRANSPARENT_TILE_DATA_URL,
      noWrap,
      updateWhenIdle: false,
      updateWhenZooming: true,
      keepBuffer: layer.category === "overlay" ? 6 : 4,
      minZoom,
      maxZoom: MAP_MAX_ZOOM,
      tileSize: Number(layer.source.tile_size ?? 256) || 256,
      ...(rasterPane ? { pane: rasterPane } : {}),
      ...(maxNativeZoom ? { maxNativeZoom } : {}),
    });
    const motionLayer = shouldCreateWmtsMotionLayer(layer)
      ? createWmtsMotionCanvasLayer(layer, {
          opacity: Number.isFinite(wmtsOpacity) ? wmtsOpacity * 0.56 : 0.4,
          opacityScale: 0.56,
          maxOpacity: 0.68,
        })
      : null;
    attachWmtsCoherentReveal(tileLayer, layer, Number.isFinite(wmtsOpacity) ? wmtsOpacity : 0.72);
    if (motionLayer) {
      const setTileParams = tileLayer.omegaSetParams.bind(tileLayer);
      leafletLayer = L.layerGroup([tileLayer, motionLayer]);
      leafletLayer.omegaTileLayer = tileLayer;
      leafletLayer.omegaMotionLayer = motionLayer;
      leafletLayer.omegaSetParams = (nextParams = {}) => {
        setTileParams(nextParams);
        return leafletLayer;
      };
    } else {
      leafletLayer = tileLayer;
      leafletLayer.omegaTileLayer = tileLayer;
      leafletLayer.omegaMotionLayer = null;
    }
  } else if (layer.source_type === "wms" && layer.source?.service_url) {
    const wmsOptions = {
      layers: layer.source.layers,
      format: layer.source.format || "image/png",
      transparent: layer.source.transparent !== false,
      version: layer.source.version || "1.3.0",
      uppercase: true,
      crs: crsForWmsLayer(layer),
      noWrap,
      updateWhenIdle: false,
      updateWhenZooming: true,
      keepBuffer: 4,
      minZoom,
      maxZoom: MAP_MAX_ZOOM,
      ...(rasterPane ? { pane: rasterPane } : {}),
      ...(maxNativeZoom ? { maxNativeZoom } : {}),
      opacity: Number.isFinite(wmsOpacity) ? wmsOpacity : 0.7,
      attribution: layer.source.attribution || layer.name,
      ...(options.wmsParams || {}),
    };
    leafletLayer = layer.tags?.key_black_nodata
      ? createNoDataKeyedWmsLayer(layer, wmsOptions)
      : L.tileLayer.wms(layerWmsBase(layer), { ...wmsOptions });
  } else if (layer.has_feature_collection || layer.source_type === "geojson") {
    const featureCollection = await api(`/v1/map/layers/${encodeURIComponent(layer.layer_id)}/features`);
    if (featureCollectionIsPointLike(featureCollection)) {
      leafletLayer = createDynamicFeatureCanvasLayer(featureCollection, layer, {
        opacity: Number(options.initialOpacity ?? layer.style?.opacity ?? 0.68),
        colorFor: (_value, fallbackFraction) => paletteColor(layer.style?.palette || "thermal", fallbackFraction),
      });
    } else {
      leafletLayer = L.geoJSON(featureCollection, {
        style: {
          color: layer.style?.stroke || layer.style?.color || "#7dd3fc",
          weight: Number(layer.style?.weight ?? 2),
          fillColor: layer.style?.fill || "#32d0bd",
          fillOpacity: Number(layer.style?.fillOpacity ?? 0.12),
        },
        pointToLayer(feature, latlng) {
          const color = layer.style?.stroke || layer.style?.color || "#7dd3fc";
          return L.marker(latlng, {
            icon: dataLayerMarkerIcon(layer, feature, color),
            keyboard: false,
          });
        },
      });
    }
  } else if (layer.source_type === "feature-endpoint" && layer.source?.endpoint) {
    let payload;
    const params = { ...(options.endpointParams || {}) };
    if (!params.bbox && state.map && layerUsesViewportBbox(layer)) {
      const b = state.map.getBounds();
      if (b) {
        const minLon = Math.max(-180, b.getWest());
        const maxLon = Math.min(180, b.getEast());
        const minLat = Math.max(-90, b.getSouth());
        const maxLat = Math.min(90, b.getNorth());
        params.bbox = `${minLon.toFixed(3)},${minLat.toFixed(3)},${maxLon.toFixed(3)},${maxLat.toFixed(3)}`;
      }
    }
    try {
      payload = await api(layer.source.endpoint, params);
    } catch (err) {
      console.warn("feature-endpoint fetch failed", layer.layer_id, err);
      return null;
    }
    const featureCollection = payload && payload.type === "FeatureCollection" ? payload : null;
    if (!featureCollection) {
      return null;
    }
    const colormap = layer.style?.colormap || {};
    const overrideMin = Number(options.endpointParams?.color_min);
    const overrideMax = Number(options.endpointParams?.color_max);
    const minVal = Number.isFinite(overrideMin) ? overrideMin : (Number.isFinite(Number(colormap.min)) ? Number(colormap.min) : null);
    const maxVal = Number.isFinite(overrideMax) ? overrideMax : (Number.isFinite(Number(colormap.max)) ? Number(colormap.max) : null);
    const palette = options.endpointParams?.palette || colormap.palette || "thermal";
    const colorFor = (value, fallbackFraction = 0.52) => {
      if (!Number.isFinite(value) || minVal === null || maxVal === null || maxVal === minVal) {
        return paletteColor(palette, fallbackFraction);
      }
      const fraction = Math.max(0, Math.min(1, (value - minVal) / (maxVal - minVal)));
      return paletteColor(palette, fraction);
    };
    if (featureCollectionIsPointLike(featureCollection)) {
      leafletLayer = createDynamicFeatureCanvasLayer(featureCollection, layer, {
        opacity: Number(options.initialOpacity ?? layer.style?.opacity ?? 0.68),
        palette,
        minVal,
        maxVal,
        colorFor,
      });
    } else {
      leafletLayer = L.geoJSON(featureCollection, {
        pointToLayer(feature, latlng) {
          const value = featureScalarValue(feature, layer);
          const color = colorFor(value);
          return L.marker(latlng, {
            icon: dataLayerMarkerIcon(layer, feature, color),
            keyboard: false,
          });
        },
        style(feature) {
          const value = featureScalarValue(feature, layer);
          return {
            color: colorFor(value),
            weight: 1.5,
            fillColor: colorFor(value),
            fillOpacity: Number(layer.style?.opacity ?? 0.55),
          };
        },
      });
    }
  }
  return leafletLayer;
}

async function applyLayer(layerId) {
  const layer = state.layers.find((item) => item.layer_id === layerId);
  if (!layer) {
    return;
  }
  clearLayer();
  const chartBasemapChanged = applyChartFallbackBasemap(layer);
  const leafletLayer = await createLeafletMapLayer(layer);
  if (!leafletLayer) {
    $("active-layer-summary").textContent = `${layer.name} is registered but does not expose a browser-renderable source yet.`;
    return;
  }
  leafletLayer.on?.("tileerror", () => {
    $("active-layer-summary").textContent = `${layer.name} missed one or more tiles. ${layer.tags?.coverage_note || "Coverage varies by provider, zoom, and location."}`;
  });
  let mapLayer = leafletLayer;
  const fallbackDefinition = layer.tags?.fallback_layer_id
    ? state.layers.find((item) => item.layer_id === layer.tags.fallback_layer_id)
    : null;
  if (fallbackDefinition) {
    const fallbackLayer = await createLeafletMapLayer(fallbackDefinition);
    if (fallbackLayer) {
      mapLayer = L.layerGroup([fallbackLayer, leafletLayer]);
    }
  }
  mapLayer.omegaLayerId = layer.layer_id;
  mapLayer.addTo(state.map);
  state.contextLayer = mapLayer;
  $("active-layer-summary").textContent = `${layer.name} applied. ${chartBasemapChanged ? "Esri Ocean is underneath it as global chart context. " : ""}Your map view was preserved; use Fit Overlay only when you want to move the camera.`;
  updateChartCoverageStatus(layer);
  renderChartLayerSelect();
  renderMapGisLayerSelect();
  renderLayerList();
}

function clearLayer({ stopAnimation = true } = {}) {
  if (stopAnimation) {
    stopEnvironmentalAnimation();
  }
  if (state.contextLayer) {
    state.contextLayer.removeFrom(state.map);
    state.contextLayer = null;
  }
  state.environmentalCurrentFrame = null;
  $("active-layer-summary").textContent = "No additional chart layer selected.";
  renderChartLayerSelect();
  renderMapGisLayerSelect();
  renderLayerList();
}

const LAYER_CATALOG_RECENT_KEY = "omega-wave.layer-catalog.recent.v1";
const LAYER_CATALOG_ACTIVE_KEY = "omega-wave.layer-catalog.active.v1";

function layerCatalogState() {
  state.layerCatalog = state.layerCatalog || {
    search: "",
    filter: "all",
    expanded: true,
    activeStack: [],
    recent: [],
  };
  return state.layerCatalog;
}

const LAYER_CATALOG_TYPE_RULES = {
  basemap: (layer) => layer.category === "basemap",
  charts: (layer) =>
    layer.category === "chart" || ["noaa", "openseamap"].includes(layerProvider(layer)),
  "ocean-physics": (layer) => {
    if (layerProvider(layer) !== "copernicus-marine") return false;
    const theme = layer.tags?.theme || "";
    return ["wind", "current", "waves", "sea-temperature", "sea-salinity", "sea-level"].includes(theme);
  },
  biogeochemistry: (layer) => {
    if (layerProvider(layer) !== "copernicus-marine") return false;
    const theme = layer.tags?.theme || "";
    return ["chlorophyll", "oxygen", "ph", "nitrate"].includes(theme);
  },
  satellite: (layer) => layerProvider(layer) === "nasa",
  vessels: (layer) =>
    ["argo", "ioos-glider-dac", "global-fishing-watch", "marine-cadastre-ais", "ais", "aisstream"].includes(layerProvider(layer)),
  bathymetry: (layer) =>
    layer.category === "bathymetry" || ["bathymetry", "depth"].includes(layer.tags?.theme || ""),
  custom: (layer) => layer.tags?.local === true || layer.tags?.scope === "demo" || !layer.is_default,
};

function loadLayerCatalogPersistedState() {
  const cat = layerCatalogState();
  try {
    cat.recent = JSON.parse(window.localStorage?.getItem(LAYER_CATALOG_RECENT_KEY) || "[]") || [];
  } catch (_err) {
    cat.recent = [];
  }
  try {
    cat.persistedActive = JSON.parse(window.localStorage?.getItem(LAYER_CATALOG_ACTIVE_KEY) || "[]") || [];
  } catch (_err) {
    cat.persistedActive = [];
  }
}

function persistLayerCatalogState() {
  const cat = layerCatalogState();
  // A layer_id is unique in the active stack. Dedupe in place so any stray
  // duplicate (e.g. from a concurrent add) is healed and never persisted.
  const seenIds = new Set();
  cat.activeStack = (cat.activeStack || []).filter((entry) => {
    if (!entry || seenIds.has(entry.layer_id)) return false;
    seenIds.add(entry.layer_id);
    return true;
  });
  try {
    window.localStorage?.setItem(LAYER_CATALOG_RECENT_KEY, JSON.stringify(cat.recent.slice(0, 12)));
    const compact = cat.activeStack.map(({ layer_id, opacity, params }) => ({
      layer_id,
      opacity,
      params: params || {},
    }));
    window.localStorage?.setItem(LAYER_CATALOG_ACTIVE_KEY, JSON.stringify(compact));
  } catch (_err) {}
}

function layerContextControlSpecs(layer) {
  const specs = [];
  const tags = layer.tags || {};
  const style = layer.style || {};
  if (tags.time_dimension) {
    const fmt = tags.time_dimension.format || "ISO8601";
    specs.push({
      key: "time",
      kind: fmt === "YYYY-MM-DD" ? "date" : "datetime-local",
      label: "Time",
      hint: fmt === "YYYY-MM-DD" ? "Daily product (UTC date)" : "Datetime (UTC)",
    });
    specs.push({
      key: "__animate",
      kind: "animate",
      label: "Animate over time",
      hint:
        tags.animation_scope === "full-extent" && tags.time_extent_start
          ? `Cycle provider history since ${String(tags.time_extent_start).slice(0, 10)}`
          : "Loop the most-recent frames",
    });
  }
  if (isMarineCadastreTransitLayer(layer)) {
    const transitLayers = marineCadastreTransitLayers({ newestFirst: true });
    specs.push({
      key: "archive_year",
      kind: "select",
      label: "AIS archive year",
      value: marineCadastreTransitYear(layer),
      options: transitLayers.map((item) => {
        const year = marineCadastreTransitYear(item);
        return { value: year, label: `${year} transit counts` };
      }),
      hint: "Switches the active MarineCadastre raster year without stacking layers",
    });
    specs.push({
      key: "__animate",
      kind: "animate",
      label: "Animate years",
      hint: "Cycle the MarineCadastre AIS transit-count archive from 2019 through 2025",
    });
  }
  if (tags.depth_dimension) {
    const range = tags.depth_dimension;
    specs.push({
      key: "depth",
      kind: "number",
      label: "Depth (m)",
      min: range.min_m ?? 0,
      max: range.max_m ?? 5500,
      step: 10,
      hint: `Surface = 0 m, deepest = ${range.max_m ?? 5500} m`,
    });
  }
  if (layer.layer_id?.startsWith("erddap-")) {
    specs.push({
      key: "window_hours",
      kind: "select",
      label: "Time window",
      options: [
        { value: 24, label: "Last 24h" },
        { value: 72, label: "Last 3 days" },
        { value: 168, label: "Last 7 days" },
        { value: 720, label: "Last 30 days" },
        { value: 2160, label: "Last 90 days" },
      ],
      hint: "Recent activity window",
    });
    specs.push({
      key: "row_limit",
      kind: "select",
      label: "Max rows",
      options: [
        { value: 100, label: "100 (fast)" },
        { value: 500, label: "500" },
        { value: 2000, label: "2000" },
        { value: 5000, label: "5000 (slow)" },
      ],
      hint: "Server-side row cap",
    });
  }
  if (isLiveAisLayer(layer)) {
    specs.push({
      key: "limit",
      kind: "select",
      label: "Max vessels",
      options: [
        { value: 100, label: "100 (fast)" },
        { value: 250, label: "250" },
        { value: 500, label: "500" },
        { value: 1000, label: "1000 (busy)" },
      ],
      hint: "Maximum live AIS positions per refresh",
    });
    specs.push({
      key: "timeout_s",
      kind: "select",
      label: "Listen time",
      options: [
        { value: 3, label: "3 seconds" },
        { value: 6, label: "6 seconds" },
        { value: 10, label: "10 seconds" },
      ],
      hint: "Backend websocket snapshot duration",
    });
  }
  if (style.colormap) {
    const cm = style.colormap;
    const unit = cm.unit ? ` (${cm.unit})` : "";
    specs.push({
      key: "color_min",
      kind: "number",
      label: `Min${unit}`,
      step: 0.1,
      hint: `Default ${cm.min}`,
    });
    specs.push({
      key: "color_max",
      kind: "number",
      label: `Max${unit}`,
      step: 0.1,
      hint: `Default ${cm.max}`,
    });
    specs.push({
      key: "palette",
      kind: "select",
      label: "Palette",
      options: [
        { value: "thermal", label: "Thermal (cool→hot)" },
        { value: "viridis", label: "Viridis" },
        { value: "haline", label: "Haline (salinity)" },
        { value: "ice", label: "Ice (cold)" },
        { value: "algae", label: "Algae (chlorophyll)" },
      ],
      hint: "Color scheme for the value range",
    });
  }
  if (style.vector_style) {
    specs.push({
      key: "vector_arrows",
      kind: "select",
      label: "Vector style",
      options: [
        { value: "arrows", label: "Arrows" },
        { value: "particles", label: "Particles" },
        { value: "dots", label: "Dots only" },
      ],
      hint: "Render direction with arrows or animated particles",
    });
  }
  if (layerProvider(layer) === "global-fishing-watch") {
    specs.push({
      key: "window_days",
      kind: "number",
      label: "Window (days)",
      min: 1,
      max: 366,
      step: 1,
      hint: `Default ${Number(layer.tags?.default_window_days || 31)}`,
    });
  }
  if (layer.source_type === "feature-endpoint" || layer.source_type === "wms" || layer.source_type === "wmts" || layer.source_type === "xyz") {
    specs.push({
      key: "__refresh",
      kind: "refresh",
      label: layer.layer_id?.startsWith("erddap-")
        ? "Refresh (current viewport)"
        : isLiveAisLayer(layer)
        ? "Refresh live vessels"
        : "Refresh",
    });
  }
  return specs;
}

function bumpLayerCatalogRecent(layerId) {
  const cat = layerCatalogState();
  cat.recent = [layerId, ...cat.recent.filter((id) => id !== layerId)].slice(0, 12);
}

function isCatalogLayerHidden(layer) {
  return layer.status === "hidden" && !layer.is_default;
}

function layerCatalogVisible() {
  const cat = layerCatalogState();
  const search = (cat.search || "").trim().toLowerCase();
  const filter = cat.filter || "all";
  const typeRule = LAYER_CATALOG_TYPE_RULES[filter] || null;
  const layers = (state.layers || []).filter((layer) => {
    if (filter === "all" && layer.category === "basemap") return false;
    if (typeRule && !typeRule(layer)) return false;
    if (!search && filter === "all" && layer.status === "hidden") return false;
    if (search) {
      const haystack = [
        layer.name,
        layer.layer_id,
        layer.category,
        layerProvider(layer),
        layerTheme(layer),
        layer.tags?.notes || "",
      ]
        .join(" ")
        .toLowerCase();
      if (!haystack.includes(search)) return false;
    }
    return true;
  });
  const recentSet = new Set(cat.recent);
  return layers.sort((a, b) => {
    const ra = recentSet.has(a.layer_id) ? cat.recent.indexOf(a.layer_id) : 999;
    const rb = recentSet.has(b.layer_id) ? cat.recent.indexOf(b.layer_id) : 999;
    if (ra !== rb) return ra - rb;
    const order = { basemap: 0, chart: 1, overlay: 2, bathymetry: 3, obstacle: 4, reference: 5 };
    const oa = order[a.category] ?? 9;
    const ob = order[b.category] ?? 9;
    return oa - ob || String(a.name).localeCompare(String(b.name));
  });
}

function layerCatalogActiveEntry(layerId) {
  return layerCatalogState().activeStack.find((entry) => entry.layer_id === layerId) || null;
}

function isGlobalRasterLayer(layer) {
  return (
    layer?.source_type === "wms" ||
    layer?.source_type === "wmts" ||
    layer?.tags?.map_delivery === "global-wmts-raster" ||
    layer?.tags?.map_delivery === "gfw-4wings-heatmap"
  );
}

function layerRequiresIntegerTileGrid(layer) {
  return layer?.source_type === "xyz" && layerProvider(layer) === "global-fishing-watch";
}

function layerUsesViewportBbox(layer) {
  return layer?.layer_id?.startsWith("erddap-") || isLiveAisLayer(layer);
}

function hasActiveIntegerTileGridLayer() {
  const cat = layerCatalogState();
  return (cat.activeStack || []).some((entry) => {
    const layer = (state.layers || []).find((item) => item.layer_id === entry.layer_id);
    return layerRequiresIntegerTileGrid(layer);
  });
}

function snapMapZoomForIntegerTileGrid(layer = null) {
  if (!state.map) return false;
  if (layer && !layerRequiresIntegerTileGrid(layer)) return false;
  if (!layer && !hasActiveIntegerTileGridLayer()) return false;
  const zoom = Number(state.map.getZoom());
  if (!Number.isFinite(zoom)) return false;
  const minZoom = Math.ceil(Number(state.map.getMinZoom?.() ?? MAP_MIN_ZOOM));
  const maxZoom = Math.floor(Number(state.map.getMaxZoom?.() ?? MAP_MAX_ZOOM));
  const snapped = Math.max(minZoom, Math.min(maxZoom, Math.round(zoom)));
  if (!Number.isFinite(snapped) || Math.abs(snapped - zoom) < 0.001) {
    return false;
  }
  state.map.setZoom(snapped, { animate: false });
  return true;
}

function shouldCreateWmtsMotionLayer(layer) {
  if (layerProvider(layer) === "copernicus-marine" && layer?.tags?.map_delivery === "global-wmts-raster") {
    return false;
  }
  return layer?.source_type === "wmts" && layer?.tags?.allow_visual_continuity === true;
}

function layerRenderSurfaceLabel(layer) {
  if (layer?.tags?.map_delivery === "cached-wmts-chart") return "cached NOAA chart tiles";
  if (layer?.tags?.map_delivery === "global-wmts-raster") return "global WMTS raster";
  if (layer?.tags?.map_delivery === "gfw-4wings-heatmap") return "4Wings heatmap tiles";
  if (layer?.tags?.map_delivery === "arcgis-cache") return "cached ArcGIS tiles";
  if (isLiveAisLayer(layer)) return "live AIS feed";
  if (layer?.source_type === "wms") return "global WMS raster";
  if (layer?.source_type === "feature-endpoint") return "sampled feature feed";
  if (layer?.source_type === "geojson") return "vector geometry";
  return String(layer?.source_type || "layer").toUpperCase();
}

function activeGlobalRasterOverlayLayers() {
  const cat = layerCatalogState();
  return (cat.activeStack || [])
    .map((entry) => (state.layers || []).find((item) => item.layer_id === entry.layer_id))
    .filter((layer) => layer?.category === "overlay" && isGlobalRasterLayer(layer));
}

function activeCopernicusRasterFieldId() {
  const layer = activeGlobalRasterOverlayLayers().find(
    (item) => layerProvider(item) === "copernicus-marine" && item?.tags?.map_delivery === "global-wmts-raster"
  );
  const fieldId = layer?.tags?.field_id;
  return COPERNICUS_OVERLAY_MODES.includes(fieldId) ? fieldId : "";
}

function activeChartOverlayLayers() {
  const cat = layerCatalogState();
  return (cat.activeStack || [])
    .map((entry) => (state.layers || []).find((item) => item.layer_id === entry.layer_id))
    .filter((layer) => isChartLikeLayer(layer));
}

function activeGlobalRasterOverlayLabel(layers = activeGlobalRasterOverlayLayers()) {
  if (!layers.length) return "";
  if (layers.length === 1) return layers[0].name || layerRenderSurfaceLabel(layers[0]);
  const first = layers[0].name || layerRenderSurfaceLabel(layers[0]);
  return `${first} + ${layers.length - 1}`;
}

function hasActiveGlobalRasterOverlay() {
  return activeGlobalRasterOverlayLayers().length > 0;
}

function hasActiveChartOverlay() {
  return activeChartOverlayLayers().length > 0;
}

function applyLeafletOpacityForCatalog(leafletLayer, opacity) {
  if (!leafletLayer) return;
  if (leafletLayer.omegaDeferReveal) {
    leafletLayer.omegaTargetOpacity = opacity;
    opacity = leafletLayer.omegaWmtsReady ? opacity : 0;
  }
  if (typeof leafletLayer.setOpacity === "function") {
    leafletLayer.setOpacity(opacity);
    return;
  }
  if (typeof leafletLayer.setStyle === "function") {
    leafletLayer.setStyle({ opacity, fillOpacity: opacity });
    return;
  }
  if (leafletLayer.eachLayer) {
    leafletLayer.eachLayer((child) => applyLeafletOpacityForCatalog(child, opacity));
  }
}

function layerTimeStepHours(layer) {
  const explicit = Number(layer?.source?.time_step_hours ?? layer?.tags?.time_step_hours);
  if (Number.isFinite(explicit) && explicit > 0) return explicit;
  const datasetId = String(layer?.source?.dataset_id || "");
  const hourly = datasetId.match(/PT(\d+(?:\.\d+)?)H/i);
  if (hourly) {
    const value = Number(hourly[1]);
    if (Number.isFinite(value) && value > 0) return value;
  }
  const daily = datasetId.match(/P(\d+(?:\.\d+)?)D/i);
  if (daily) {
    const value = Number(daily[1]);
    if (Number.isFinite(value) && value > 0) return value * 24;
  }
  return null;
}

function alignDateToStepHours(date, stepHours) {
  const hours = Number(stepHours);
  if (!Number.isFinite(hours) || hours <= 0) return date;
  const stepMs = Math.max(60 * 1000, hours * 60 * 60 * 1000);
  return new Date(Math.floor(date.getTime() / stepMs) * stepMs);
}

function parseLayerTimeDate(value) {
  if (!value) return null;
  const normalized = String(value)
    .trim()
    .replace(/\.(\d{3})\d*(Z|[+-]\d\d:\d\d)$/i, ".$1$2");
  const parsed = new Date(normalized);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function formatLayerFrameTime(date, format) {
  if (!(date instanceof Date) || Number.isNaN(date.getTime())) return null;
  return format === "YYYY-MM-DD"
    ? date.toISOString().slice(0, 10)
    : date.toISOString().replace(/\.\d+Z$/, "Z");
}

function pushUniqueLayerFrame(frames, seen, date, format) {
  const formatted = formatLayerFrameTime(date, format);
  if (!formatted || seen.has(formatted)) return false;
  seen.add(formatted);
  frames.push(formatted);
  return true;
}

function buildFullExtentAnimationFrames(layer, frameCount, stepHours, lagHours, format) {
  const tags = layer.tags || {};
  const dim = tags.time_dimension || {};
  const start = parseLayerTimeDate(tags.time_extent_start || dim.extent_start || layer.source?.time_extent_start);
  const explicitEnd = parseLayerTimeDate(tags.time_extent_end || dim.extent_end || layer.source?.time_extent_end);
  const end = explicitEnd || alignDateToStepHours(new Date(Date.now() - lagHours * 60 * 60 * 1000), stepHours);
  if (!start || !end || end.getTime() <= start.getTime()) return [];

  const frames = [];
  const seen = new Set();
  const spanMs = end.getTime() - start.getTime();
  for (let i = 0; i < frameCount; i += 1) {
    const fraction = frameCount <= 1 ? 1 : i / (frameCount - 1);
    let frameDate = i === 0
      ? new Date(start)
      : i === frameCount - 1
        ? new Date(end)
        : alignDateToStepHours(new Date(start.getTime() + spanMs * fraction), stepHours);
    if (frameDate.getTime() < start.getTime()) frameDate = new Date(start);
    if (frameDate.getTime() > end.getTime()) frameDate = new Date(end);
    pushUniqueLayerFrame(frames, seen, frameDate, format);
  }
  return frames;
}

function addUtcMonths(date, deltaMonths) {
  return new Date(Date.UTC(
    date.getUTCFullYear(),
    date.getUTCMonth() + deltaMonths,
    1,
    date.getUTCHours(),
    0,
    0
  ));
}

function buildMonthlyArchiveAnimationFrames(layer, frameCount, stepMonths, lagHours, format) {
  const tags = layer.tags || {};
  const dim = tags.time_dimension || {};
  const start = parseLayerTimeDate(tags.time_extent_start || dim.extent_start || layer.source?.time_extent_start);
  const explicitEnd = parseLayerTimeDate(tags.time_extent_end || dim.extent_end || layer.source?.time_extent_end);
  const stepHours = layerTimeStepHours(layer) || adaptiveFrameProfile(layer).stepHours || 24;
  const runtimeEnd = alignDateToStepHours(new Date(Date.now() - lagHours * 60 * 60 * 1000), stepHours);
  const rawEnd = explicitEnd && explicitEnd.getTime() < runtimeEnd.getTime() ? explicitEnd : runtimeEnd;
  if (!rawEnd || Number.isNaN(rawEnd.getTime())) return [];
  const monthStep = Math.max(1, Math.min(12, Number(stepMonths) || 1));
  const end = new Date(Date.UTC(rawEnd.getUTCFullYear(), rawEnd.getUTCMonth(), 1, rawEnd.getUTCHours(), 0, 0));
  const frames = [];
  const seen = new Set();
  for (let i = frameCount - 1; i >= 0; i -= 1) {
    const frameDate = addUtcMonths(end, -i * monthStep);
    if (start && frameDate.getTime() < start.getTime()) {
      continue;
    }
    pushUniqueLayerFrame(frames, seen, alignDateToStepHours(frameDate, stepHours), format);
  }
  return frames;
}

function adaptiveFrameProfile(layer) {
  const tags = layer.tags || {};
  const dim = tags.time_dimension || {};
  const format = dim.format || "ISO8601";
  if (layer.source_type === "wmts") {
    const stepHours = layerTimeStepHours(layer) || (format === "YYYY-MM-DD" ? 24 : 1);
    const tagCount = Number(tags.animation_frame_count);
    const count = Number.isFinite(tagCount) && tagCount >= 2 ? tagCount : format === "YYYY-MM-DD" ? 8 : 6;
    return { count, stepHours };
  }
  if (layer.source_type === "wms") {
    if (format === "YYYY-MM-DD") return { count: 30, stepHours: 24 };
    const stepHours = layerTimeStepHours(layer) || 1;
    return { count: stepHours >= 24 ? 14 : 24, stepHours };
  }
  if (layer.source_type === "xyz") {
    const stepHours = layerTimeStepHours(layer) || (format === "YYYY-MM-DD" ? 24 : 6);
    const tagCount = Number(tags.animation_frame_count);
    const count = Number.isFinite(tagCount) && tagCount >= 2 ? tagCount : 12;
    return { count, stepHours };
  }
  if (layer.source_type === "feature-endpoint") {
    if (layer.layer_id?.startsWith("erddap-")) return { count: 7, stepHours: 24 };
    if (format === "YYYY-MM-DD") return { count: 14, stepHours: 24 };
    return { count: 12, stepHours: 6 };
  }
  return { count: 7, stepHours: format === "YYYY-MM-DD" ? 24 : 6 };
}

function buildLayerAnimationFrames(layer, opts = {}) {
  const dim = layer.tags?.time_dimension || {};
  const format = dim.format || "ISO8601";
  const profile = adaptiveFrameProfile(layer);
  const frameCount = Math.max(
    2,
    Math.min(60, Number(opts.frameCount ?? layer.tags?.animation_frame_count ?? profile.count) || profile.count)
  );
  const stepHours = Number(opts.stepHours ?? profile.stepHours) || profile.stepHours;
  const lagHours = Number(opts.lagHours ?? layer.tags?.default_lag_hours ?? 0) || 0;
  const scope = opts.scope || layer.tags?.animation_scope || "recent";
  if (scope === "monthly-archive") {
    const monthlyFrames = buildMonthlyArchiveAnimationFrames(
      layer,
      frameCount,
      opts.stepMonths ?? COPERNICUS_TIMELINE_MODES.monthly.stepMonths,
      lagHours,
      format
    );
    if (monthlyFrames.length >= 2) return monthlyFrames;
  }
  if (scope === "full-extent") {
    const fullExtentFrames = buildFullExtentAnimationFrames(layer, frameCount, stepHours, lagHours, format);
    if (fullExtentFrames.length >= 2) return fullExtentFrames;
  }
  const end = alignDateToStepHours(new Date(Date.now() - lagHours * 60 * 60 * 1000), stepHours);
  const frames = [];
  for (let i = frameCount - 1; i >= 0; i -= 1) {
    const t = new Date(end.getTime() - i * stepHours * 60 * 60 * 1000);
    const formatted = formatLayerFrameTime(t, format);
    if (formatted) frames.push(formatted);
  }
  return frames;
}

function defaultLayerTimeParam(layer) {
  const dim = layer.tags?.time_dimension || null;
  if (!dim) return null;
  const format = dim.format || "ISO8601";
  const lagHours = Number(layer.tags?.default_lag_hours ?? (format === "YYYY-MM-DD" ? 24 : 0)) || 0;
  const stepHours = layerTimeStepHours(layer) || adaptiveFrameProfile(layer).stepHours || 1;
  const date = alignDateToStepHours(new Date(Date.now() - lagHours * 60 * 60 * 1000), stepHours);
  return format === "YYYY-MM-DD" ? date.toISOString().slice(0, 10) : date.toISOString().replace(/\.\d+Z$/, "Z");
}

function _detachAnimationFrameLayers(animation, keepLayer = null) {
  if (!animation) return;
  if (animation.crossfadeRaf) {
    try { window.cancelAnimationFrame(animation.crossfadeRaf); } catch (_err) {}
    animation.crossfadeRaf = null;
  }
  animation.crossfadeToken = (animation.crossfadeToken || 0) + 1;
  if (!state.map) return;
  if (animation.pendingLayer && animation.pendingLayer !== keepLayer) {
    try { animation.pendingLayer.removeFrom(state.map); } catch (_err) {}
    animation.pendingLayer = null;
  }
  if (animation.frameLayers) {
    for (const fl of animation.frameLayers) {
      if (fl && fl !== keepLayer) {
        try { fl.removeFrom(state.map); } catch (_err) {}
      }
    }
    animation.frameLayers = null;
  }
}

function stopLayerAnimation(layerId) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry || !entry.animation) return;
  if (entry.animation.timer) {
    window.clearInterval(entry.animation.timer);
  }
  _detachAnimationFrameLayers(entry.animation, entry.leafletLayer);
  entry.animation.playing = false;
  entry.animation.timer = null;
  renderLayerCatalog();
  renderGlobeScene();
}

function waitForWmtsLayerReady(leafletLayer, timeoutMs = 14000) {
  return new Promise((resolve) => {
    if (!leafletLayer) {
      resolve(false);
      return;
    }
    if (!leafletLayer.omegaDeferReveal || leafletLayer.omegaWmtsReady) {
      resolve(true);
      return;
    }
    let settled = false;
    let timeout = null;
    const settle = (value) => {
      if (settled) return;
      settled = true;
      if (timeout) {
        window.clearTimeout(timeout);
      }
      if (typeof leafletLayer.off === "function") {
        leafletLayer.off("load", onLoad);
        leafletLayer.off("tileload", onTile);
        leafletLayer.off("tileerror", onTile);
      }
      resolve(Boolean(value));
    };
    const checkReady = () => {
      window.setTimeout(() => {
        if (leafletLayer.omegaWmtsReady) {
          settle(true);
        }
      }, 0);
    };
    const onLoad = () => checkReady();
    const onTile = () => checkReady();
    if (typeof leafletLayer.on === "function") {
      leafletLayer.on("load", onLoad);
      leafletLayer.on("tileload", onTile);
      leafletLayer.on("tileerror", onTile);
    }
    timeout = window.setTimeout(() => settle(Boolean(leafletLayer.omegaWmtsReady)), Math.max(2500, timeoutMs));
    checkReady();
  });
}

async function _startWmsAnimation(layerId, layer, frames, intervalMs) {
  // For tile WMS layers, swap entry.leafletLayer from a re-creation path to a single
  // L.tileLayer.wms instance whose `time` parameter we can update via setParams. Leaflet
  // handles tile fade-in transitions so the result is smooth.
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry) return;
  const old = entry.leafletLayer;
  entry.params = { ...(entry.params || {}), time: frames[0] };
  const fresh = await createLeafletMapLayer(
    layer,
    layer.source_type === "wmts"
      ? { wmtsParams: buildWmtsParamsForLayer(entry, layer) }
      : { wmsParams: { time: frames[0] } }
  );
  if (!fresh) return;
  fresh.omegaCatalogId = layerId;
  fresh.addTo(state.map);
  applyLeafletOpacityForCatalog(fresh, entry.opacity);
  if (old) {
    try { old.removeFrom(state.map); } catch (_err) {}
  }
  entry.leafletLayer = fresh;
  entry.animation = { playing: true, frames, index: 0, intervalMs, timer: null, mode: "wms-setparams" };
  entry.animation.timer = window.setInterval(() => {
    const e = layerCatalogActiveEntry(layerId);
    if (!e || !e.animation || !e.animation.playing || !e.leafletLayer) {
      if (e?.animation?.timer) window.clearInterval(e.animation.timer);
      return;
    }
    e.animation.index = (e.animation.index + 1) % e.animation.frames.length;
    const frame = e.animation.frames[e.animation.index];
    e.params = { ...(e.params || {}), time: frame };
    try {
      if (typeof e.leafletLayer.omegaSetParams === "function") {
        e.leafletLayer.omegaSetParams(buildWmtsParamsForLayer(e, layer));
      } else if (typeof e.leafletLayer.setParams === "function") {
        e.leafletLayer.setParams({ time: frame });
      }
    } catch (err) {
      console.warn("wms setParams failed:", err);
    }
    renderGlobeScene();
    const meta = document.querySelector(`.layer-catalog-row[data-layer-id="${layerId}"] .anim-pill`);
    if (meta) meta.textContent = `▶ ${frame}`;
  }, intervalMs);
  renderLayerCatalog();
}

async function _startWmtsFrameSwapAnimation(layerId, layer, frames, intervalMs, opts = {}) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry || !state.map) return;
  const previousLiveLayer = entry.leafletLayer;
  const frameLayers = new Array(frames.length).fill(null);
  const readyFrames = new Set();
  const failedFrames = new Set();
  const transitionMs = 0;
  const requireCompleteBuffer =
    opts.requireCompleteBuffer === true ||
    (layerProvider(layer) === "copernicus-marine" && opts.scope === "monthly-archive");
  entry.animation = {
    playing: true,
    frames,
    index: 0,
    currentIndex: -1,
    intervalMs,
    transitionMs,
    timer: null,
    mode: "wmts-buffered",
    frameLayers,
    readyFrames,
    failedFrames,
    pendingLayer: null,
    pendingFrame: null,
    bufferComplete: false,
    requireCompleteBuffer,
    bufferingStartedAt: Date.now(),
    crossfadeRaf: null,
    crossfadeToken: 0,
    crossfading: false,
  };
  entry.busy = true;
  renderLayerCatalog();
  setStatus(`${layer.name} is buffering ${frames.length} real WMTS data frames.`);

  const animationStillCurrent = (e) =>
    Boolean(e?.animation?.playing && e.animation.mode === "wmts-buffered" && e.animation.frames === frames);

  const readyIndexes = (e = layerCatalogActiveEntry(layerId)) => {
    if (!animationStillCurrent(e)) return [];
    return frames
      .map((_, index) => index)
      .filter((index) => {
        const frameLayer = e.animation.frameLayers?.[index];
        return (
          e.animation.readyFrames?.has(index) &&
          frameLayer &&
          (!frameLayer.omegaDeferReveal || frameLayer.omegaWmtsReady)
        );
      });
  };

  const updateAnimationPill = (e, text = "") => {
    const meta = document.querySelector(`.layer-catalog-row[data-layer-id="${layerId}"] .anim-pill`);
    if (!meta || !animationStillCurrent(e)) return;
    const readyCount = readyIndexes(e).length;
    meta.textContent = text || `buffer ${readyCount}/${frames.length}`;
  };

  const crossfadeToIndex = (e, nextIndex) => {
    if (!animationStillCurrent(e)) return false;
    const nextLayer = e.animation.frameLayers?.[nextIndex];
    if (!nextLayer || (nextLayer.omegaDeferReveal && !nextLayer.omegaWmtsReady)) {
      return false;
    }
    const previousIndex = Number(e.animation.currentIndex);
    const previousLayer = previousIndex >= 0 ? e.animation.frameLayers?.[previousIndex] : e.leafletLayer;
    if (previousLayer === nextLayer && previousIndex === nextIndex) {
      return true;
    }
    if (e.animation.crossfadeRaf) {
      try { window.cancelAnimationFrame(e.animation.crossfadeRaf); } catch (_err) {}
      e.animation.crossfadeRaf = null;
    }
    e.animation.crossfadeToken = (e.animation.crossfadeToken || 0) + 1;
    e.animation.crossfading = false;
    e.params = { ...(e.params || {}), time: frames[nextIndex] };
    e.animation.index = nextIndex;
    if (typeof nextLayer.bringToFront === "function") {
      try { nextLayer.bringToFront(); } catch (_err) {}
    }
    if (previousLayer && previousLayer !== nextLayer) {
      applyLeafletOpacityForCatalog(previousLayer, 0);
      if (!e.animation.frameLayers?.includes(previousLayer) && state.map) {
        try { previousLayer.removeFrom(state.map); } catch (_err) {}
      }
    }
    applyLeafletOpacityForCatalog(nextLayer, Number(e.opacity ?? 0.75));
    e.leafletLayer = nextLayer;
    e.animation.currentIndex = nextIndex;
    renderGlobeScene();
    updateAnimationPill(e, `frame ${nextIndex + 1}/${frames.length} ${frames[nextIndex]}`);
    return true;
  };

  const advanceBufferedFrame = () => {
    const e = layerCatalogActiveEntry(layerId);
    if (!animationStillCurrent(e) || e.animation.crossfading) return;
    const ready = readyIndexes(e);
    if (ready.length < 2) return;
    const currentIndex = Number(e.animation.currentIndex);
    const currentReadyPosition = ready.indexOf(currentIndex);
    const nextIndex = ready[(currentReadyPosition + 1 + ready.length) % ready.length] ?? ready[0];
    crossfadeToIndex(e, nextIndex);
  };

  const maybeStartBufferedPlayback = () => {
    const e = layerCatalogActiveEntry(layerId);
    if (!animationStillCurrent(e)) return;
    const ready = readyIndexes(e);
    if (!ready.length) {
      updateAnimationPill(e);
      return;
    }
    if (e.animation.requireCompleteBuffer && !e.animation.bufferComplete) {
      updateAnimationPill(e, `buffer ${ready.length}/${frames.length}`);
      return;
    }
    if (Number(e.animation.currentIndex) < 0 && !e.animation.crossfading) {
      crossfadeToIndex(e, ready[0]);
    }
    if (!e.animation.timer && ready.length >= 2) {
      e.animation.timer = window.setInterval(advanceBufferedFrame, intervalMs);
      setStatus(`${layer.name} is playing real WMTS data frames from a ${ready.length}/${frames.length} frame buffer.`);
    }
    updateAnimationPill(e);
  };

  const markReady = (index) => {
    const e = layerCatalogActiveEntry(layerId);
    if (!animationStillCurrent(e)) return;
    e.animation.readyFrames.add(index);
    e.animation.failedFrames.delete(index);
    maybeStartBufferedPlayback();
  };

  const buildBufferedFrame = async (frame, index) => {
    const e = layerCatalogActiveEntry(layerId);
    if (!animationStillCurrent(e)) return null;
    const params = buildWmtsParamsForLayer({ ...e, params: { ...(e.params || {}), time: frame } }, layer);
    let fresh = null;
    try {
      fresh = await createLeafletMapLayer(layer, { wmtsParams: params, initialOpacity: e.opacity });
      const current = layerCatalogActiveEntry(layerId);
      if (!fresh || !animationStillCurrent(current) || !state.map) return null;
      fresh.omegaCatalogId = layerId;
      fresh.omegaFrameTime = frame;
      current.animation.frameLayers[index] = fresh;
      applyLeafletOpacityForCatalog(fresh, 0);
      const lateReady = () => {
        window.setTimeout(() => {
          if (fresh.omegaWmtsReady) {
            markReady(index);
          }
        }, 0);
      };
      if (typeof fresh.on === "function") {
        fresh.on("load", lateReady);
        fresh.on("tileload", lateReady);
      }
      fresh.addTo(state.map);
      const ready = await waitForWmtsLayerReady(fresh, Math.max(9000, intervalMs * frames.length));
      const latest = layerCatalogActiveEntry(layerId);
      if (!animationStillCurrent(latest)) {
        if (state.map) {
          try { fresh.removeFrom(state.map); } catch (_err) {}
        }
        return null;
      }
      if (ready) {
        markReady(index);
      } else {
        latest.animation.failedFrames.add(index);
        updateAnimationPill(latest);
      }
      return fresh;
    } catch (err) {
      console.warn("wmts buffered frame failed:", err);
      const latest = layerCatalogActiveEntry(layerId);
      if (animationStillCurrent(latest)) {
        latest.animation.failedFrames.add(index);
        updateAnimationPill(latest);
      }
      if (fresh && state.map) {
        try { fresh.removeFrom(state.map); } catch (_innerErr) {}
      }
      return null;
    }
  };

  let nextFrameIndex = 0;
  const maxConcurrent = Math.max(1, Math.min(8, Number(opts.maxConcurrent ?? 6) || 6));
  const preloadWorker = async () => {
    while (nextFrameIndex < frames.length) {
      const index = nextFrameIndex;
      nextFrameIndex += 1;
      await buildBufferedFrame(frames[index], index);
    }
  };
  const preloadTasks = Array.from(
    { length: Math.min(maxConcurrent, frames.length) },
    () => preloadWorker()
  );
  const minimumReady = Math.min(3, frames.length);
  const preloadDeadline = Date.now() + Math.max(9000, Math.min(18000, frames.length * 3600));
  while (Date.now() < preloadDeadline) {
    const current = layerCatalogActiveEntry(layerId);
    if (!animationStillCurrent(current)) return;
    const ready = readyIndexes(current).length;
    const settled = ready + (current.animation.failedFrames?.size || 0);
    if (ready >= minimumReady || settled >= frames.length) {
      break;
    }
    await new Promise((resolve) => window.setTimeout(resolve, 250));
  }
  const current = layerCatalogActiveEntry(layerId);
  if (!animationStillCurrent(current)) return;
  if (current.animation.requireCompleteBuffer) {
    updateAnimationPill(current, `buffer ${readyIndexes(current).length}/${frames.length}`);
  } else {
    current.busy = false;
    maybeStartBufferedPlayback();
  }
  if (readyIndexes(current).length < 2) {
    setStatus(`${layer.name} has not buffered enough complete WMTS frames for smooth playback yet; keeping the current raster visible.`);
  }
  Promise.allSettled(preloadTasks).then(() => {
    const latest = layerCatalogActiveEntry(layerId);
    if (!animationStillCurrent(latest)) return;
    latest.animation.bufferComplete = true;
    latest.busy = false;
    maybeStartBufferedPlayback();
    const ready = readyIndexes(latest).length;
    if (ready >= 2) {
      setStatus(
        latest.animation.requireCompleteBuffer
          ? `${layer.name} finished buffering ${ready}/${frames.length} real WMTS data frames before starting playback.`
          : `${layer.name} buffered ${ready}/${frames.length} real WMTS data frames for no-pulse playback.`
      );
    }
  });
  if (!readyIndexes(current).length && previousLiveLayer) {
    current.leafletLayer = previousLiveLayer;
    applyLeafletOpacityForCatalog(previousLiveLayer, current.opacity);
  }
  renderLayerCatalog();
}

async function _startFeatureEndpointAnimation(layerId, layer, frames, intervalMs) {
  // For GeoJSON feature-endpoint layers we pre-fetch every frame in parallel,
  // build a Leaflet layer per frame, add them all to the map but visually hide
  // every frame except the current one. Playback is then a pure show/hide swap
  // (no fetch, no DOM thrash).
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry || !state.map) return;
  entry.busy = true;
  entry.animation = { playing: true, frames, index: 0, intervalMs, timer: null, mode: "feature-prefetch", frameLayers: null };
  renderLayerCatalog();

  const baseParams = { ...(entry.params || {}) };
  delete baseParams.time;
  // Auto-pass viewport bbox once so all frames share it.
  if (!baseParams.bbox && layer.layer_id?.startsWith("erddap-")) {
    const b = state.map.getBounds();
    if (b) {
      baseParams.bbox = `${b.getWest().toFixed(3)},${b.getSouth().toFixed(3)},${b.getEast().toFixed(3)},${b.getNorth().toFixed(3)}`;
    }
  }

  const builds = await Promise.allSettled(
    frames.map((time) =>
      createLeafletMapLayer(layer, { endpointParams: { ...baseParams, time } })
    )
  );

  const frameLayers = builds.map((result, index) => {
    if (result.status !== "fulfilled" || !result.value) return null;
    const fl = result.value;
    fl.omegaCatalogId = layerId;
    fl.omegaFrameIndex = index;
    fl.addTo(state.map);
    applyLeafletOpacityForCatalog(fl, index === 0 ? entry.opacity : 0);
    return fl;
  });

  // Replace the original single layer with the first frame layer (so stack opacity
  // mutations affect the visible frame).
  if (entry.leafletLayer) {
    try { entry.leafletLayer.removeFrom(state.map); } catch (_err) {}
  }
  entry.leafletLayer = frameLayers[0] || entry.leafletLayer;

  if (!entry.animation || !entry.animation.playing) {
    for (const fl of frameLayers) if (fl) { try { fl.removeFrom(state.map); } catch (_err) {} }
    entry.busy = false;
    return;
  }
  entry.animation.frameLayers = frameLayers;
  entry.busy = false;

  entry.animation.timer = window.setInterval(() => {
    const e = layerCatalogActiveEntry(layerId);
    if (!e || !e.animation || !e.animation.playing || !e.animation.frameLayers) {
      if (e?.animation?.timer) window.clearInterval(e.animation.timer);
      return;
    }
    const prevIdx = e.animation.index;
    e.animation.index = (e.animation.index + 1) % e.animation.frames.length;
    const prevLayer = e.animation.frameLayers[prevIdx];
    const nextLayer = e.animation.frameLayers[e.animation.index];
    if (prevLayer) applyLeafletOpacityForCatalog(prevLayer, 0);
    if (nextLayer) applyLeafletOpacityForCatalog(nextLayer, e.opacity);
    if (nextLayer) {
      e.leafletLayer = nextLayer;
    }
    renderGlobeScene();
    const meta = document.querySelector(`.layer-catalog-row[data-layer-id="${layerId}"] .anim-pill`);
    if (meta) meta.textContent = `▶ ${e.animation.frames[e.animation.index]}`;
  }, intervalMs);
  renderLayerCatalog();
}

function waitForTileLayerSettle(tileLayer, timeoutMs = 10000) {
  return new Promise((resolve) => {
    if (!tileLayer || typeof tileLayer.on !== "function") {
      resolve(false);
      return;
    }
    let settled = false;
    let loaded = 0;
    let started = 0;
    const finish = (value) => {
      if (settled) return;
      settled = true;
      try {
        tileLayer.off("tileloadstart", onStart);
        tileLayer.off("tileload", onLoad);
        tileLayer.off("tileerror", onError);
        tileLayer.off("load", onLayerLoad);
      } catch (_err) {}
      resolve(Boolean(value));
    };
    const onStart = () => {
      started += 1;
    };
    const onLoad = () => {
      loaded += 1;
      if (started >= 4 && loaded >= Math.max(2, Math.ceil(started * 0.55))) {
        finish(true);
      }
    };
    const onError = () => {
      if (started >= 4 && loaded >= Math.max(1, Math.ceil(started * 0.35))) {
        finish(true);
      }
    };
    const onLayerLoad = () => finish(true);
    tileLayer.on("tileloadstart", onStart);
    tileLayer.on("tileload", onLoad);
    tileLayer.on("tileerror", onError);
    tileLayer.on("load", onLayerLoad);
    window.setTimeout(() => finish(loaded > 0), Math.max(1500, timeoutMs));
  });
}

async function _startXyzFrameSwapAnimation(layerId, layer, frames, intervalMs) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry || !state.map) return;
  entry.busy = true;
  entry.animation = { playing: true, frames, index: 0, intervalMs, timer: null, mode: "xyz-buffered", frameLayers: null };
  renderLayerCatalog();
  setStatus(`${layer.name} is buffering ${frames.length} heatmap frames.`);

  const baseParams = { ...(entry.params || {}) };
  delete baseParams.time;
  const builds = await Promise.allSettled(
    frames.map((time) =>
      createLeafletMapLayer(layer, { xyzParams: { ...baseParams, time } })
    )
  );
  const frameLayers = builds.map((result, index) => {
    if (result.status !== "fulfilled" || !result.value) return null;
    const fl = result.value;
    fl.omegaCatalogId = layerId;
    fl.omegaFrameIndex = index;
    fl.addTo(state.map);
    applyLeafletOpacityForCatalog(fl, index === 0 ? entry.opacity : 0);
    return fl;
  });
  await Promise.allSettled(
    frameLayers
      .filter(Boolean)
      .slice(0, 8)
      .map((fl) => waitForTileLayerSettle(fl, 9000))
  );

  if (entry.leafletLayer) {
    try { entry.leafletLayer.removeFrom(state.map); } catch (_err) {}
  }
  entry.leafletLayer = frameLayers[0] || entry.leafletLayer;

  if (!entry.animation || !entry.animation.playing) {
    for (const fl of frameLayers) if (fl) { try { fl.removeFrom(state.map); } catch (_err) {} }
    entry.busy = false;
    return;
  }
  entry.animation.frameLayers = frameLayers;
  entry.busy = false;
  entry.animation.timer = window.setInterval(() => {
    const e = layerCatalogActiveEntry(layerId);
    if (!e || !e.animation || !e.animation.playing || !e.animation.frameLayers) {
      if (e?.animation?.timer) window.clearInterval(e.animation.timer);
      return;
    }
    const prevIdx = e.animation.index;
    e.animation.index = (e.animation.index + 1) % e.animation.frames.length;
    const prevLayer = e.animation.frameLayers[prevIdx];
    const nextLayer = e.animation.frameLayers[e.animation.index];
    if (prevLayer) applyLeafletOpacityForCatalog(prevLayer, 0);
    if (nextLayer) {
      applyLeafletOpacityForCatalog(nextLayer, e.opacity);
      e.leafletLayer = nextLayer;
    }
    renderGlobeScene();
    const meta = document.querySelector(`.layer-catalog-row[data-layer-id="${layerId}"] .anim-pill`);
    if (meta) meta.textContent = `> ${e.animation.frames[e.animation.index]}`;
  }, intervalMs);
  renderLayerCatalog();
}

async function _startXyzSetParamsAnimation(layerId, layer, frames, intervalMs) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry || !state.map) return;
  if (!entry.leafletLayer) {
    const fresh = await createLeafletMapLayer(layer, {
      xyzParams: buildXyzParamsForLayer(entry, layer),
    });
    if (!fresh) return;
    fresh.omegaCatalogId = layerId;
    fresh.addTo(state.map);
    applyLeafletOpacityForCatalog(fresh, entry.opacity);
    entry.leafletLayer = fresh;
  }
  const initialIndex = layerProvider(layer) === "global-fishing-watch" ? frames.length - 1 : 0;
  entry.params = { ...(entry.params || {}), time: frames[initialIndex] };
  if (typeof entry.leafletLayer.omegaSetParams === "function") {
    entry.leafletLayer.omegaSetParams(buildXyzParamsForLayer(entry, layer));
  }
  entry.animation = {
    playing: true,
    frames,
    index: initialIndex,
    intervalMs,
    timer: null,
    mode: "xyz-setparams",
    frameLayers: null,
  };
  setStatus(`${layer.name} is animating one heatmap layer at a time so the basemap stays stable.`);
  entry.animation.timer = window.setInterval(() => {
    const e = layerCatalogActiveEntry(layerId);
    if (!e || !e.animation || !e.animation.playing) {
      if (e?.animation?.timer) window.clearInterval(e.animation.timer);
      return;
    }
    e.animation.index = (e.animation.index + 1) % e.animation.frames.length;
    e.params = { ...(e.params || {}), time: e.animation.frames[e.animation.index] };
    if (typeof e.leafletLayer?.omegaSetParams === "function") {
      e.leafletLayer.omegaSetParams(buildXyzParamsForLayer(e, layer));
    }
    renderGlobeScene();
    const meta = document.querySelector(`.layer-catalog-row[data-layer-id="${layerId}"] .anim-pill`);
    if (meta) meta.textContent = `> ${e.animation.frames[e.animation.index]}`;
  }, intervalMs);
  renderLayerCatalog();
}

function updateArchiveAnimationPill(layerId, text) {
  const selectors = [
    `.layer-catalog-row[data-layer-id="${layerId}"] .anim-pill`,
    "#context-panel .anim-pill",
  ];
  for (const meta of document.querySelectorAll(selectors.join(","))) {
    meta.textContent = text;
  }
}

function updateArchiveYearControls(layerId, year) {
  for (const control of document.querySelectorAll(`[data-layer-param="${layerId}"][data-param-key="archive_year"]`)) {
    control.value = String(year);
  }
}

async function switchMarineCadastreTransitYear(layerId, year, { keepContextOpen = true } = {}) {
  const currentEntry = layerCatalogActiveEntry(layerId);
  const currentLayer = (state.layers || []).find((item) => item.layer_id === layerId);
  const targetLayer = marineCadastreTransitLayerForYear(year);
  if (!currentEntry || !isMarineCadastreTransitLayer(currentLayer) || !targetLayer) {
    return null;
  }
  const targetYear = marineCadastreTransitYear(targetLayer);
  if (targetLayer.layer_id === layerId) {
    currentEntry.params = { ...(currentEntry.params || {}), archive_year: targetYear };
    persistLayerCatalogState();
    renderLayerCatalog();
    renderContextPanel();
    return currentEntry;
  }
  const opacity = Number(currentEntry.opacity ?? currentLayer.style?.opacity ?? 0.72);
  stopLayerAnimation(layerId);
  layerCatalogRemove(layerId);
  const nextEntry = await layerCatalogAdd(targetLayer.layer_id, {
    opacity,
    autoFocus: false,
    autoAnimate: false,
  });
  const activeEntry = nextEntry || layerCatalogActiveEntry(targetLayer.layer_id);
  if (activeEntry) {
    activeEntry.params = { ...(activeEntry.params || {}), archive_year: targetYear };
    persistLayerCatalogState();
    if (keepContextOpen) {
      openContextTab(`layer:${targetLayer.layer_id}`);
    }
    setStatus(`MarineCadastre AIS transit-count archive switched to ${targetYear}.`);
    renderLayerCatalog();
    renderMapOverlayLayer();
  }
  return activeEntry;
}

async function _startMarineCadastreTransitAnimation(layerId, layer) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry || !state.map || !isMarineCadastreTransitLayer(layer)) return;
  const archiveLayers = marineCadastreTransitLayers();
  if (archiveLayers.length < 2) {
    setStatus("MarineCadastre AIS transit counts need at least two archive years to animate.");
    return;
  }
  stopLayerAnimation(layerId);
  const years = archiveLayers.map((item) => marineCadastreTransitYear(item));
  const startYear = Number(entry.params?.archive_year ?? marineCadastreTransitYear(layer));
  const startIndex = Math.max(0, years.indexOf(startYear));
  const intervalMs = Math.max(700, Math.min(8000, Number(layer.tags?.animation_interval_ms) || 2400));
  entry.busy = true;
  entry.params = { ...(entry.params || {}), archive_year: years[startIndex] };
  entry.animation = {
    playing: true,
    frames: years.map(String),
    index: startIndex,
    intervalMs,
    timer: null,
    mode: "layer-family",
    frameLayers: null,
    frameLayerIds: archiveLayers.map((item) => item.layer_id),
  };
  renderLayerCatalog();
  setStatus(`MarineCadastre AIS archive is buffering ${archiveLayers.length} yearly vessel-density rasters.`);

  const builds = await Promise.allSettled(
    archiveLayers.map((archiveLayer) => createLeafletMapLayer(archiveLayer, { initialOpacity: entry.opacity }))
  );
  const latest = layerCatalogActiveEntry(layerId);
  if (!latest || !latest.animation?.playing || latest.animation.mode !== "layer-family") {
    return;
  }
  const frameLayers = builds.map((result, index) => {
    if (result.status !== "fulfilled" || !result.value || !state.map) return null;
    const frameLayer = result.value;
    frameLayer.omegaCatalogId = layerId;
    frameLayer.omegaFrameYear = years[index];
    frameLayer.addTo(state.map);
    applyLeafletOpacityForCatalog(frameLayer, index === startIndex ? latest.opacity : 0);
    return frameLayer;
  });
  await Promise.allSettled(
    frameLayers
      .filter(Boolean)
      .map((frameLayer) => waitForTileLayerSettle(frameLayer, 8000))
  );
  const current = layerCatalogActiveEntry(layerId);
  if (!current || !current.animation?.playing || current.animation.mode !== "layer-family") {
    for (const frameLayer of frameLayers) {
      if (frameLayer && state.map) {
        try { frameLayer.removeFrom(state.map); } catch (_err) {}
      }
    }
    return;
  }
  const oldLayer = current.leafletLayer;
  current.animation.frameLayers = frameLayers;
  current.busy = false;
  current.leafletLayer = frameLayers[startIndex] || current.leafletLayer;
  if (oldLayer && oldLayer !== current.leafletLayer && state.map) {
    try { oldLayer.removeFrom(state.map); } catch (_err) {}
  }
  current.animation.timer = window.setInterval(() => {
    const active = layerCatalogActiveEntry(layerId);
    if (!active || !active.animation?.playing || active.animation.mode !== "layer-family") {
      if (active?.animation?.timer) window.clearInterval(active.animation.timer);
      return;
    }
    const previousIndex = active.animation.index;
    active.animation.index = (active.animation.index + 1) % active.animation.frames.length;
    const nextIndex = active.animation.index;
    const previousLayer = active.animation.frameLayers?.[previousIndex];
    const nextLayer = active.animation.frameLayers?.[nextIndex];
    if (previousLayer) applyLeafletOpacityForCatalog(previousLayer, 0);
    if (nextLayer) {
      applyLeafletOpacityForCatalog(nextLayer, active.opacity);
      active.leafletLayer = nextLayer;
    }
    const year = active.animation.frames[nextIndex];
    active.params = { ...(active.params || {}), archive_year: Number(year) };
    updateArchiveAnimationPill(layerId, `year ${year}`);
    updateArchiveYearControls(layerId, year);
    renderGlobeScene();
  }, intervalMs);
  persistLayerCatalogState();
  renderLayerCatalog();
  renderContextPanel();
  setStatus("MarineCadastre AIS archive is cycling yearly vessel-density rasters without stacking active layers.");
}

async function startLayerAnimation(layerId, opts = {}) {
  const entry = layerCatalogActiveEntry(layerId);
  const layer = (state.layers || []).find((item) => item.layer_id === layerId);
  if (!entry || !layer || !layer.tags?.time_dimension) return;
  stopLayerAnimation(layerId);
  const frames = buildLayerAnimationFrames(layer, opts);
  if (frames.length < 2) {
    setStatus(`${layer.name} does not expose enough time frames for animation in the selected timeline.`);
    renderLayerCatalog();
    return;
  }
  const defaultIntervalMs = layer.source_type === "wmts" ? 1800 : layer.source_type === "wms" ? 2600 : layer.source_type === "xyz" ? 750 : 250;
  const intervalMs = Math.max(120, Math.min(8000, Number(opts.intervalMs ?? defaultIntervalMs)));
  if (layer.source_type === "wms") {
    await _startWmsAnimation(layerId, layer, frames, intervalMs);
  } else if (layer.source_type === "wmts") {
    await _startWmtsFrameSwapAnimation(layerId, layer, frames, intervalMs, opts);
  } else if (layer.source_type === "xyz") {
    if (layerProvider(layer) === "global-fishing-watch") {
      await _startXyzSetParamsAnimation(layerId, layer, frames, intervalMs);
    } else {
      await _startXyzFrameSwapAnimation(layerId, layer, frames, intervalMs);
    }
  } else if (layer.source_type === "feature-endpoint") {
    await _startFeatureEndpointAnimation(layerId, layer, frames, intervalMs);
  }
}

function toggleLayerAnimation(layerId) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry) return;
  const layer = (state.layers || []).find((item) => item.layer_id === layerId);
  if (isMarineCadastreTransitLayer(layer)) {
    if (entry.animation?.playing) {
      stopLayerAnimation(layerId);
      renderContextPanel();
    } else {
      _startMarineCadastreTransitAnimation(layerId, layer).catch((err) => console.warn(err));
    }
    return;
  }
  // Raster overlays (WMS + WMTS) use the buffered time-lapse engine — a
  // pre-loaded time range played back smoothly with a scrubber — instead of
  // the legacy per-frame refetch loop.
  if (
    layer &&
    (layer.source_type === "wms" || layer.source_type === "wmts") &&
    typeof window.toggleTimelapseForLayer === "function"
  ) {
    window.toggleTimelapseForLayer(layerId);
    if (typeof renderContextPanel === "function") renderContextPanel();
    return;
  }
  if (entry.animation?.playing) {
    stopLayerAnimation(layerId);
  } else {
    // Restart with the same frame-count/cadence the layer uses when it
    // auto-animates on add, so manual and automatic playback are consistent.
    const opts = layer ? layerAutoAnimationOptions(layer) : {};
    startLayerAnimation(layerId, opts).catch((err) => console.warn(err));
  }
}

function paletteColor(palette, fraction) {
  // Single source of truth for overlay palettes: interpolate the same colour
  // stops the scalar field viz uses (overlayPaletteStops), so a layer's
  // markers, the heat field, and the legend swatch all read identical colours.
  return interpolateColor(overlayPaletteStops(palette), fraction);
}

function layerCatalogDefaultParams(layer) {
  const params = {};
  const tags = layer.tags || {};
  if (tags.time_dimension) {
    const defaultTime = defaultLayerTimeParam(layer);
    if (defaultTime) params.time = defaultTime;
  }
  if (tags.depth_dimension) {
    params.depth = 0;
  }
  if (layerProvider(layer) === "global-fishing-watch") {
    params.window_days = Number(tags.default_window_days) || 31;
  }
  if (isMarineCadastreTransitLayer(layer)) {
    const year = marineCadastreTransitYear(layer);
    if (Number.isFinite(year)) {
      params.archive_year = year;
    }
  }
  if (layer.layer_id?.startsWith("erddap-")) {
    params.window_hours = Number(tags.default_window_hours) || 168;
  }
  if (isLiveAisLayer(layer)) {
    params.limit = 500;
    params.timeout_s = 6;
    params.cache_ttl_s = Number(tags.refresh_interval_s) || 15;
  }
  return params;
}

function buildEndpointParamsForLayer(entry, layer) {
  const params = { ...(entry.params || {}) };
  if (layerUsesViewportBbox(layer) && !params.bbox && state.map) {
    const b = state.map.getBounds();
    if (b) {
      const minLon = Math.max(-180, b.getWest());
      const maxLon = Math.min(180, b.getEast());
      const minLat = Math.max(-90, b.getSouth());
      const maxLat = Math.min(90, b.getNorth());
      params.bbox = `${minLon.toFixed(3)},${minLat.toFixed(3)},${maxLon.toFixed(3)},${maxLat.toFixed(3)}`;
    }
  }
  return params;
}

function buildWmsParamsForLayer(entry, layer) {
  const params = {};
  if (layer.tags?.time_dimension && entry.params?.time) {
    params.time = entry.params.time;
  }
  return params;
}

function buildXyzParamsForLayer(entry, layer) {
  const params = {};
  if (layer.tags?.time_dimension && entry.params?.time) {
    params.time = entry.params.time;
  }
  if (layerProvider(layer) === "global-fishing-watch") {
    params.window_days = Number(entry.params?.window_days || layer.tags?.default_window_days || 31);
  }
  return params;
}

function wmtsDepthToElevation(depth, fallback) {
  const value = Number(depth);
  if (!Number.isFinite(value)) return fallback || "";
  if (Math.abs(value) <= 1 && fallback) return String(fallback);
  return String(-Math.abs(value));
}

function wmtsStyleForLayer(entry, layer) {
  let style = layer.source?.style || "";
  const palette = entry.params?.palette;
  if (palette && style.includes("cmap:")) {
    style = style.replace(/cmap:[^,]+/, `cmap:${palette}`);
  }
  const vectorMode = entry.params?.vector_arrows;
  if (style.includes("vectorStyle:")) {
    const vectorStyle = vectorMode
      ? vectorMode === "dots"
        ? "solid"
        : vectorMode === "particles"
          ? "vector"
          : "solidAndVector"
      : "solid";
    style = style.replace(/vectorStyle:[^,]+/, `vectorStyle:${vectorStyle}`);
  }
  return style;
}

function buildWmtsParamsForLayer(entry, layer) {
  const params = {};
  if (layer.tags?.time_dimension && entry.params?.time) {
    params.time = entry.params.time;
  }
  const elevation = wmtsDepthToElevation(entry.params?.depth, layer.source?.default_elevation);
  if (elevation) {
    params.elevation = elevation;
  }
  const style = wmtsStyleForLayer(entry, layer);
  if (style) {
    params.style = style;
  }
  return params;
}

async function layerCatalogRefetch(layerId) {
  const entry = layerCatalogActiveEntry(layerId);
  const layer = (state.layers || []).find((item) => item.layer_id === layerId);
  if (!entry || !layer || !state.map) return;
  entry.busy = true;
  renderLayerCatalog();
  const oldLayer = entry.leafletLayer;
  let createOptions = {};
  if (layer.source_type === "feature-endpoint") {
    createOptions = { endpointParams: buildEndpointParamsForLayer(entry, layer) };
  } else if (layer.source_type === "wms") {
    createOptions = { wmsParams: buildWmsParamsForLayer(entry, layer) };
  } else if (layer.source_type === "wmts") {
    createOptions = { wmtsParams: buildWmtsParamsForLayer(entry, layer) };
  } else if (layer.source_type === "xyz") {
    createOptions = { xyzParams: buildXyzParamsForLayer(entry, layer) };
  }
  let nextLayer;
  try {
    nextLayer = await createLeafletMapLayer(layer, createOptions);
  } catch (err) {
    console.warn("layerCatalogRefetch failed:", err);
    entry.busy = false;
    entry.lastError = String(err?.message || err);
    renderLayerCatalog();
    return;
  }
  if (!nextLayer) {
    entry.busy = false;
    entry.lastError = `No data returned for ${layer.name}.`;
    setStatus(`${layer.name} refresh returned no data.`);
    renderLayerCatalog();
    return;
  }
  nextLayer.omegaCatalogId = layerId;
  nextLayer.addTo(state.map);
  applyLeafletOpacityForCatalog(nextLayer, entry.opacity);
  if (oldLayer) {
    try {
      oldLayer.removeFrom(state.map);
    } catch (_err) {}
  }
  entry.leafletLayer = nextLayer;
  entry.busy = false;
  entry.lastError = null;
  queueRasterLayerTileWarmup(layer, entry);
  persistLayerCatalogState();
  renderLayerCatalog();
  renderMapOverlayLayer();
}

function layerCatalogSetParam(layerId, key, value) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry) return;
  entry.params = entry.params || {};
  entry.params[key] = value;
  persistLayerCatalogState();
  layerCatalogRefetch(layerId).catch((err) => console.warn(err));
}

function chartFallbackBasemapId(layer) {
  const explicit = layer?.tags?.chart_fallback_basemap_id;
  if (typeof explicit === "string" && explicit) return explicit;
  return layer?.category === "chart" && layerProvider(layer) === "noaa" ? "basemap-ocean" : null;
}

function chartCompanionLayerIds(layer) {
  const raw = layer?.tags?.companion_layer_ids;
  const ids = Array.isArray(raw) ? raw.filter((id) => typeof id === "string" && id) : [];
  if (typeof layer?.tags?.fallback_layer_id === "string" && layer.tags.fallback_layer_id) {
    ids.push(layer.tags.fallback_layer_id);
  }
  return [...new Set(ids.filter((id) => id !== layer?.layer_id))];
}

function applyChartFallbackBasemap(layer) {
  const basemapId = chartFallbackBasemapId(layer);
  if (!basemapId || state.basemapLayerId === basemapId) return false;
  if (!(state.layers || []).some((item) => item.layer_id === basemapId && item.category === "basemap")) return false;
  // Remember the basemap so removing the last chart layer can restore it.
  if (!state.chartFallbackPriorBasemap) {
    state.chartFallbackPriorBasemap = state.basemapLayerId;
  }
  setBasemapById(basemapId);
  return true;
}

async function applyChartFallbackContext(layer, options = {}) {
  const addedCompanions = [];
  if (options.chartFallback === false || !state.map) return addedCompanions;
  if (layer?.category !== "chart" && layerProvider(layer) !== "noaa") return addedCompanions;
  const basemapChanged = applyChartFallbackBasemap(layer);
  if (options.companions === false) {
    return addedCompanions;
  }
  const companionIds = chartCompanionLayerIds(layer);
  for (const companionId of companionIds) {
    const companion = (state.layers || []).find((item) => item.layer_id === companionId);
    if (!companion || layerCatalogActiveEntry(companionId)) {
      continue;
    }
    await layerCatalogAdd(companionId, {
      opacity: Number(companion.style?.opacity ?? 0.75),
      autoFocus: false,
      autoAnimate: false,
      companions: false,
      chartFallback: false,
    });
    // Track companions this activation turned on in a global set, so removal
    // can take them back down without disturbing layers the user added itself.
    if (layerCatalogActiveEntry(companionId)) {
      addedCompanions.push(companionId);
      if (!Array.isArray(state.chartAutoCompanions)) state.chartAutoCompanions = [];
      if (!state.chartAutoCompanions.includes(companionId)) {
        state.chartAutoCompanions.push(companionId);
      }
    }
  }
  if (basemapChanged || addedCompanions.length) {
    setStatus(`${layer.name} is using Esri Ocean plus seamarks as persistent chart context outside NOAA tile coverage.`);
  }
  return addedCompanions;
}

function startLayerLiveRefresh(layerId, layer) {
  const entry = layerCatalogActiveEntry(layerId);
  const intervalS = Number(layer?.tags?.refresh_interval_s || 0);
  if (!entry || !Number.isFinite(intervalS) || intervalS <= 0) return;
  if (entry.liveTimer) {
    try { window.clearInterval(entry.liveTimer); } catch (_err) {}
    entry.liveTimer = null;
  }
  const intervalMs = Math.max(5000, Math.min(120000, intervalS * 1000));
  entry.liveTimer = window.setInterval(() => {
    const current = layerCatalogActiveEntry(layerId);
    if (!current) {
      window.clearInterval(entry.liveTimer);
      entry.liveTimer = null;
      return;
    }
    if (current.busy || current.animation?.playing) return;
    layerCatalogRefetch(layerId).catch((err) => console.warn("live layer refresh failed:", err));
  }, intervalMs);
}

function requestLayerAutoAnimation(layerId, layer) {
  const run = () => {
    const entry = layerCatalogActiveEntry(layerId);
    if (!entry || entry.animation?.playing) {
      return;
    }
    startLayerAnimation(layerId, layerAutoAnimationOptions(layer)).catch((err) => console.warn("auto-animate failed:", err));
  };
  run();
  window.setTimeout(run, 750);
}

async function layerCatalogAdd(layerId, options = {}) {
  if (!state.map) return null;
  const layer = (state.layers || []).find((item) => item.layer_id === layerId);
  if (!layer) return null;
  if (layer.category === "basemap") {
    setBasemapById(layerId);
    bumpLayerCatalogRecent(layerId);
    persistLayerCatalogState();
    renderLayerCatalog();
    return null;
  }
  const cat = layerCatalogState();
  if (cat.activeStack.some((entry) => entry.layer_id === layerId)) {
    return null;
  }
  if (isMarineCadastreTransitLayer(layer)) {
    removeActiveMarineCadastreTransitLayersExcept(layerId);
  }
  const params = options.params ? { ...options.params } : layerCatalogDefaultParams(layer);
  const stagingEntry = { layer_id: layerId, params };
  await applyChartFallbackContext(layer, options);
  // Was: snapMapZoomForIntegerTileGrid(layer) — that integer-snapped the
  // user's current zoom every time an overlay was added (e.g. activating
  // a Copernicus / NASA WMTS layer at zoom 4.3 jerked the map to zoom 4).
  // The zoomend listener already snaps when the USER changes zoom; we
  // don't need to do it on add. Slightly blurry tiles at fractional zoom
  // is a much smaller annoyance than the map jumping by itself.
  if (shouldFocusLayerOnCatalogAdd(layer, options)) {
    focusMapForLayer(layer);
  }
  let createOptions = {};
  if (layer.source_type === "feature-endpoint") {
    createOptions = { endpointParams: buildEndpointParamsForLayer(stagingEntry, layer) };
  } else if (layer.source_type === "wms") {
    createOptions = { wmsParams: buildWmsParamsForLayer(stagingEntry, layer) };
  } else if (layer.source_type === "wmts") {
    createOptions = { wmtsParams: buildWmtsParamsForLayer(stagingEntry, layer) };
  } else if (layer.source_type === "xyz") {
    createOptions = { xyzParams: buildXyzParamsForLayer(stagingEntry, layer) };
  }
  const leafletLayer = await createLeafletMapLayer(layer, createOptions);
  if (!leafletLayer) {
    setStatus(`${layer.name} is registered but no browser-renderable source is available.`);
    return null;
  }
  // Re-check after the await: a concurrent add of the same layer could have
  // registered it while createLeafletMapLayer was in flight (the top-of-
  // function guard alone leaves a race window that duplicates the stack).
  if (cat.activeStack.some((entry) => entry.layer_id === layerId)) {
    try { leafletLayer.removeFrom?.(state.map); } catch (_err) {}
    return cat.activeStack.find((entry) => entry.layer_id === layerId) || null;
  }
  const opacity = Number(options.opacity ?? layer.style?.opacity ?? 0.75);
  leafletLayer.omegaCatalogId = layerId;
  leafletLayer.addTo(state.map);
  applyLeafletOpacityForCatalog(leafletLayer, opacity);
  cat.activeStack.unshift({ layer_id: layerId, opacity, params, leafletLayer });
  const activeEntry = cat.activeStack[0];
  queueRasterLayerTileWarmup(layer, activeEntry);
  if (isLiveAisLayer(layer)) {
    startLayerLiveRefresh(layerId, layer);
  }
  bumpLayerCatalogRecent(layerId);
  persistLayerCatalogState();
  renderLayerCatalog();
  renderMapOverlayLayer();
  syncGlobeTimelapseToPrimary();
  if (shouldFocusLayerOnCatalogAdd(layer, options)) {
    focusMapForLayer(layer);
  }
  const autoplayRaster =
    options.autoAnimate !== false &&
    Boolean(layer.tags?.time_dimension) &&
    (layer.source_type === "wms" || layer.source_type === "wmts") &&
    layerProvider(layer) !== "copernicus-marine";
  if (autoplayRaster && typeof window.startTimelapse === "function") {
    // Time-aware raster overlays autoplay through the buffered time-lapse
    // engine; its controls take over the time bar while it runs.
    window.startTimelapse(layerId);
  } else if (layerShouldAutoAnimateOnAdd(layer, options)) {
    requestLayerAutoAnimation(layerId, layer);
  }
  if (
    options.bindDataOverlay !== false &&
    layerProvider(layer) === "copernicus-marine" &&
    COPERNICUS_OVERLAY_MODES.includes(layer.tags?.field_id) &&
    state.mapOverlayMode !== layer.tags.field_id
  ) {
    state.overlayVisualization = layer.tags?.field_kind === "vector" ? "particles" : state.overlayVisualization;
    state.copernicusWindCoverage = "global";
    // The numeric field subset can take tens of seconds to fetch. Don't block
    // the layer-add on it — the WMTS heatmap tiles already render, and
    // setMapOverlayMode drives its own loading state for the vector/particle
    // overlay as it streams in.
    setMapOverlayMode(layer.tags.field_id).catch((err) => {
      console.warn("Copernicus overlay field load failed", layer.layer_id, err);
    });
  }
  return activeEntry;
}

function layerShouldAutoAnimateOnAdd(layer, options = {}) {
  // Time-aware overlays loop automatically on add unless a caller explicitly
  // opts out with autoAnimate:false (e.g. the Copernicus monthly-archive path).
  if (!layer?.tags?.time_dimension || options.autoAnimate === false) {
    return false;
  }
  if (layer.tags?.auto_animate === false || layer.tags?.auto_animate === "false") {
    return false;
  }
  // Copernicus WMTS animates through the dedicated overlay-mode pipeline
  // (setMapOverlayMode / cached numeric frames), not the per-layer engine.
  if (layer.source_type === "wmts" && layerProvider(layer) === "copernicus-marine") {
    return false;
  }
  if (layerProvider(layer) === "global-fishing-watch") {
    return false;
  }
  // WMS overlays animate via the explicit buffered time-lapse engine (Play
  // button / Time-lapse), not the legacy auto-loop, so do not auto-start them.
  // feature-endpoint (sensor) layers are NOT auto-animated: each animation frame
  // is its own full-viewport canvas, so auto-looping every active sensor network
  // multiplies canvas memory. They animate on demand via the time controls.
  return layer.source_type === "wmts" || (layer.source_type === "xyz" && layerProvider(layer) === "global-fishing-watch");
}

function layerAutoAnimationOptions(layer) {
  if (layer?.source_type === "wmts") {
    const frameCount = Number(layer.tags?.animation_frame_count);
    const scope = layer.tags?.animation_scope || "recent";
    return {
      frameCount: Number.isFinite(frameCount) && frameCount >= 2 ? frameCount : 6,
      intervalMs: scope === "full-extent" ? 1200 : 1400,
      scope,
    };
  }
  if (layer?.source_type === "xyz" && layerProvider(layer) === "global-fishing-watch") {
    const frameCount = Number(layer.tags?.animation_frame_count);
    const intervalMs = Number(layer.tags?.animation_interval_ms);
    return {
      frameCount: Number.isFinite(frameCount) && frameCount >= 2 ? Math.min(frameCount, 6) : 6,
      intervalMs: Number.isFinite(intervalMs) && intervalMs >= 120 ? intervalMs : 2400,
      scope: "recent",
    };
  }
  if (layer?.source_type === "wms") {
    return { frameCount: 6, intervalMs: 2600 };
  }
  return {};
}

async function startCopernicusMonthlyArchivePlayback({ force = false } = {}) {
  if (!state.map || !COPERNICUS_OVERLAY_MODES.includes(state.mapOverlayMode)) {
    return null;
  }
  const fieldId = state.mapOverlayMode;
  let layer = activeCopernicusCatalogLayer(fieldId);
  if (!layer) {
    const candidate = copernicusCatalogLayerForField(fieldId);
    if (!candidate) {
      $("map-overlay-summary").textContent = `No Copernicus WMTS raster is registered for ${mapOverlayModeLabel().toLowerCase()} archive playback.`;
      return null;
    }
    await layerCatalogAdd(candidate.layer_id, {
      autoFocus: false,
      autoAnimate: false,
      bindDataOverlay: false,
    });
    layer = activeCopernicusCatalogLayer(fieldId);
  }
  if (!layer) {
    return null;
  }
  const entry = layerCatalogActiveEntry(layer.layer_id);
  if (!force && entry?.animation?.playing && entry.animation.mode === "wmts-buffered") {
    renderMapOverlayLayer();
    return entry;
  }
  const profile = copernicusTimelineProfile("monthly");
  await startLayerAnimation(layer.layer_id, {
    scope: "monthly-archive",
    frameCount: profile.frameCount,
    stepMonths: profile.stepMonths,
    intervalMs: profile.intervalMs,
    maxConcurrent: 3,
    requireCompleteBuffer: true,
  });
  clearCopernicusNumericFieldState();
  renderMapOverlayLayer();
  return layerCatalogActiveEntry(layer.layer_id);
}

function layerCatalogRemove(layerId) {
  const cat = layerCatalogState();
  const index = cat.activeStack.findIndex((entry) => entry.layer_id === layerId);
  if (index < 0) return;
  const [entry] = cat.activeStack.splice(index, 1);
  if (entry.animation?.timer) {
    try { window.clearInterval(entry.animation.timer); } catch (_err) {}
  }
  if (entry.liveTimer) {
    try { window.clearInterval(entry.liveTimer); } catch (_err) {}
    entry.liveTimer = null;
  }
  _detachAnimationFrameLayers(entry.animation);
  if (window.timelapseIsActive?.(layerId) && typeof window.stopTimelapse === "function") {
    window.stopTimelapse();
  }
  if (entry.leafletLayer && state.map) {
    try {
      entry.leafletLayer.removeFrom(state.map);
    } catch (_err) {}
  }
  const layer = (state.layers || []).find((item) => item.layer_id === layerId);
  const fieldId = layer?.tags?.field_id;
  if (COPERNICUS_OVERLAY_MODES.includes(fieldId) && state.mapOverlayMode === fieldId) {
    clearMapOverlay();
    state.copernicusWindField = null;
    state.copernicusWindState = "idle";
    state.copernicusFieldLoadedId = null;
    state.copernicusWindLoadedCoverage = null;
    state.copernicusWindFetchedAt = 0;
  }
  // Reverse the chart-fallback context: take down auto-added companion layers
  // that no active chart still wants, then restore the basemap once no chart
  // layer that forces a fallback basemap remains active.
  if (Array.isArray(state.chartAutoCompanions) && state.chartAutoCompanions.length) {
    const wanted = new Set();
    for (const other of cat.activeStack) {
      const otherLayer = (state.layers || []).find((item) => item.layer_id === other.layer_id);
      if (otherLayer) {
        for (const cid of chartCompanionLayerIds(otherLayer)) wanted.add(cid);
      }
    }
    const orphaned = [];
    const keep = [];
    for (const companionId of state.chartAutoCompanions) {
      if (!layerCatalogActiveEntry(companionId)) continue;
      if (wanted.has(companionId)) keep.push(companionId);
      else orphaned.push(companionId);
    }
    state.chartAutoCompanions = keep;
    for (const companionId of orphaned) layerCatalogRemove(companionId);
  }
  const removedFallbackBasemap = layer ? chartFallbackBasemapId(layer) : null;
  if (removedFallbackBasemap && state.chartFallbackPriorBasemap) {
    const anotherFallbackActive = cat.activeStack.some((other) => {
      const otherLayer = (state.layers || []).find((item) => item.layer_id === other.layer_id);
      return otherLayer && chartFallbackBasemapId(otherLayer);
    });
    if (!anotherFallbackActive) {
      if (state.basemapLayerId === removedFallbackBasemap) {
        setBasemapById(state.chartFallbackPriorBasemap);
      }
      state.chartFallbackPriorBasemap = null;
    }
  }
  persistLayerCatalogState();
  renderLayerCatalog();
  renderMapOverlayLayer();
  syncGlobeTimelapseToPrimary();
}

function layerCatalogSetOpacity(layerId, value) {
  const entry = layerCatalogActiveEntry(layerId);
  if (!entry) return;
  entry.opacity = Math.max(0, Math.min(1, Number(value) || 0));
  applyLeafletOpacityForCatalog(entry.leafletLayer, entry.opacity);
  persistLayerCatalogState();
  renderGlobeScene();
}

function layerCatalogClearOverlays() {
  const cat = layerCatalogState();
  for (const entry of [...cat.activeStack]) {
    if (entry.animation?.timer) {
      try { window.clearInterval(entry.animation.timer); } catch (_err) {}
    }
    if (entry.liveTimer) {
      try { window.clearInterval(entry.liveTimer); } catch (_err) {}
      entry.liveTimer = null;
    }
    _detachAnimationFrameLayers(entry.animation);
    if (entry.leafletLayer && state.map) {
      try {
        entry.leafletLayer.removeFrom(state.map);
      } catch (_err) {}
    }
  }
  cat.activeStack = [];
  state.chartAutoCompanions = [];
  // No chart layers remain — restore the basemap they had overridden.
  if (state.chartFallbackPriorBasemap) {
    const priorBasemap = state.chartFallbackPriorBasemap;
    state.chartFallbackPriorBasemap = null;
    if ((state.layers || []).some((item) => item.layer_id === priorBasemap && item.category === "basemap")) {
      setBasemapById(priorBasemap);
    }
  }
  persistLayerCatalogState();
  // Stop the buffered time-lapse engine too — it runs its own loop and frame
  // layers outside the per-layer animation state cleared above.
  if (typeof window.stopTimelapse === "function") {
    window.stopTimelapse();
  }
  clearMapOverlay();
  renderLayerCatalog();
  renderMapOverlayLayer();
}

