function _runForumOutcome(name) {
  // The forum's channel rows are buttons or links inside #forum-channel-list.
  // Click the row whose text matches the requested channel.
  const channelMap = {
    "field-ops": "Field Ops",
    "data-apis": "Data APIs",
    "hardware-lab": "Hardware Lab",
    "visualizations": "Visualizations",
  };
  if (name === "mark-read") {
    document.querySelectorAll("#forum-thread-list .thread-unread-dot, #forum-thread-list .unread")
      .forEach((el) => el.remove?.());
    setStatus("Marked all threads in this channel as read (local only).");
    return;
  }
  const want = channelMap[name];
  if (!want) return;
  const rows = document.querySelectorAll("#forum-channel-list [data-channel-id], #forum-channel-list .channel-row, #forum-channel-list button, #forum-channel-list li");
  for (const r of rows) {
    if (r.textContent && r.textContent.includes(want)) {
      r.click?.();
      setStatus(`Jumped to ${want} channel.`);
      return;
    }
  }
  setStatus(`Channel "${want}" isn't loaded yet.`);
}

