// ----- Operator activity feed ------------------------------------------
// Tracks the last 30 things that happened — recipe runs, watch adds,
// ingests, page jumps. Surfaces as a clock-icon popover from the
// header so operators can "rewind" their session.
const _ACTIVITY_KEY = "omega-activity-feed-v1";
const _ACTIVITY_MAX = 30;
function _loadActivity() {
  try { const raw = localStorage.getItem(_ACTIVITY_KEY); if (!raw) return []; const a = JSON.parse(raw); return Array.isArray(a) ? a : []; } catch { return []; }
}
function _saveActivity(list) { try { localStorage.setItem(_ACTIVITY_KEY, JSON.stringify(list.slice(0, _ACTIVITY_MAX))); } catch {} }
function logActivity(kind, text, meta) {
  const list = _loadActivity();
  // De-dupe: if the previous activity is the same kind+text within 30s,
  // don't push a duplicate — bump its timestamp instead. Avoids flooding
  // the feed with "Navigated to Data" rows when the user quickly tabs
  // between pages.
  if (list.length > 0) {
    const prev = list[0];
    const sameWithin = prev.kind === kind && prev.text === text && Date.now() - prev.ts < 30000;
    if (sameWithin) {
      prev.ts = Date.now();
      _saveActivity(list);
      _refreshActivityDot();
      return;
    }
  }
  list.unshift({ kind, text, meta: meta || null, ts: Date.now() });
  _saveActivity(list);
  _refreshActivityDot();
}
function _refreshActivityDot() {
  const btn = document.getElementById("activity-feed-button");
  if (!btn) return;
  const list = _loadActivity();
  const recent = list.filter((a) => Date.now() - a.ts < 5 * 60 * 1000);
  let badge = btn.querySelector(".activity-feed-dot");
  if (!badge) {
    badge = document.createElement("span");
    badge.className = "activity-feed-dot";
    btn.appendChild(badge);
  }
  badge.style.display = recent.length > 0 ? "" : "none";
}
function _renderActivityPopover() {
  const existing = document.getElementById("activity-feed-popover");
  if (existing) { existing.remove(); return; }
  const list = _loadActivity();
  const pop = document.createElement("div");
  pop.id = "activity-feed-popover";
  pop.className = "activity-feed-popover";
  pop.innerHTML = `
    <header><strong>🕒 Recent activity</strong><button type="button" class="activity-feed-close" aria-label="Close">×</button></header>
    ${list.length === 0
      ? `<p class="muted small">No activity yet — fire a recipe or load some data.</p>`
      : `<ul class="activity-feed-list">${list.slice(0, 15).map((a) => {
          const ago = _ago(Date.now() - a.ts);
          // Text-letter prefix is cleaner than emoji and reads in any
          // typeface. CSS colors the .activity-feed-item[data-activity-kind]
          // border-left to communicate kind visually instead.
          const letter = { recipe: "R", watch: "!", ingest: "I", page: ">", chip: "·" }[a.kind] || "·";
          return `<li class="activity-feed-item" data-activity-kind="${a.kind}"><span class="activity-feed-icon">${letter}</span><div class="activity-feed-body"><div class="activity-feed-text">${a.text}</div><div class="activity-feed-ago muted small">${ago}</div></div></li>`;
        }).join("")}</ul>
        <footer><button type="button" class="button button-secondary button-small" id="activity-feed-clear">Clear history</button></footer>`}
  `;
  document.body.appendChild(pop);
  // Position next to the trigger button
  const btn = document.getElementById("activity-feed-button");
  if (btn) {
    const r = btn.getBoundingClientRect();
    pop.style.top = `${r.bottom + 6}px`;
    pop.style.right = `${Math.max(8, window.innerWidth - r.right)}px`;
  }
  pop.querySelector(".activity-feed-close")?.addEventListener("click", () => pop.remove());
  pop.querySelector("#activity-feed-clear")?.addEventListener("click", () => {
    _saveActivity([]);
    _refreshActivityDot();
    pop.remove();
  });
  // Click an activity item to "rewind" — navigate to the captured page if
  // it was a navigation event, or re-run the recipe if it was a recipe.
  pop.querySelectorAll(".activity-feed-item").forEach((li, idx) => {
    const item = list[idx];
    if (!item) return;
    li.style.cursor = "pointer";
    li.title = "Click to revisit";
    li.addEventListener("click", () => {
      if (item.kind === "page" && item.meta?.page && typeof navigate === "function") {
        navigate(item.meta.page);
        pop.remove();
      } else if (item.kind === "recipe" && item.meta?.recipeId) {
        // Try to re-run the recipe chip
        const chip = document.querySelector(`[data-graphs-recipe="${item.meta.recipeId}"], [data-map-recipe="${item.meta.recipeId}"], [data-plan-recipe="${item.meta.recipeId}"], [data-mesh-recipe="${item.meta.recipeId}"], [data-watch-recipe="${item.meta.recipeId}"], [data-hw-recipe="${item.meta.recipeId}"]`);
        if (chip) chip.click();
        pop.remove();
      }
    });
  });
  // Click-outside dismiss
  setTimeout(() => {
    const onAway = (e) => {
      if (!pop.contains(e.target) && e.target.id !== "activity-feed-button") {
        pop.remove();
        document.removeEventListener("click", onAway);
      }
    };
    document.addEventListener("click", onAway);
  }, 0);
}
function _ago(ms) {
  const s = Math.round(ms / 1000);
  if (s < 60) return `${s}s ago`;
  const m = Math.round(s / 60);
  if (m < 60) return `${m}m ago`;
  const h = Math.round(m / 60);
  if (h < 24) return `${h}h ago`;
  return `${Math.round(h / 24)}d ago`;
}
/**
 * Strip leading emoji + whitespace from chip text labels. The portal
 * was built with emoji prefixes on every outcome/recipe/starter chip
 * ("🔥 Hottest SST", "🌊 Compare wave heights", "📍 Drop pins") which
 * the operator asked to remove in favor of clean text. CSS can't
 * regex on text content, so we do a one-time scrub at init plus a
 * mutation observer for dynamic chips.
 *
 * Targets emoji at the START of the visible text only — leaves any
 * mid-text emoji alone in case it's intentional. Caches via dataset
 * so we don't re-process the same element on every observer tick.
 */
/* Move the Inspect panel's live-status + Query/Chart tool buttons out
 * of the panel-head into the panel-outcomes chip row. The panel-head's
 * h3 + subtitle are already hidden (panel-context-bar handles the
 * title), so the head's only payload was the tools on the right —
 * which can co-exist with the action chips on the same 40h row. Saves
 * 44h of vertical chrome on every Inspect render.
 */
function _hoistInspectToolsIntoOutcomes() {
  try {
    const head = document.querySelector('.data-browser-panel > .panel-head');
    const outcomes = document.querySelector('.data-browser-panel > .panel-outcomes');
    const tools = head && head.querySelector('.inspect-panel-tools');
    if (!head || !outcomes || !tools) return;
    if (tools._hoisted) return;
    tools._hoisted = true;
    tools.classList.add('hoisted-from-head');
    outcomes.appendChild(tools);
    // Only mark the head as fully empty if there's nothing substantive
    // left to show. The new .viz-workflow ol with onboarding steps is
    // substantive content — when present, keep the head visible.
    const hasWorkflow = head.querySelector('.viz-workflow');
    if (!hasWorkflow) head.classList.add('is-empty');
  } catch (e) {
    // Non-fatal: leave the tools where they were if anything goes wrong.
  }
}

function _stripEmojiFromChips() {
  // Match Unicode emoji properties (Emoji + variation selectors + ZWJ
  // sequences). Safe for modern browsers; falls back gracefully.
  let leadingEmojiRe;
  try {
    leadingEmojiRe = new RegExp("^(\\p{Extended_Pictographic}|\\u{1F1E6}-\\u{1F1FF}|[\\u2600-\\u27BF])(\\uFE0F|\\u200D[\\p{Extended_Pictographic}\\u2600-\\u27BF\\uFE0F])*\\s*", "u");
  } catch {
    // Older engine — bail without breaking. Better than throwing.
    return;
  }
  const selectors = [
    ".outcome-chip",
    ".recipe-chip",
    ".recipe-rail-label",
    ".copilot-starter-chip",
    ".map-today-card .map-today-stat span",
    ".workspace-tab",
    ".category-chip",
    ".data-view-picker-item",
    ".live-tile-icon",
    // Panel chrome: panel titles + section eyebrows often have emoji
    // ("🔬 Inspect", "📊 Stats", "🛠 Tool Directory") — these were not
    // chips so they slipped past the earlier scrub.
    ".panel-title",
    ".panel-head h3",
    ".panel-head h2",
    "h3.panel-title",
    ".tile-category-chip",
    ".inspect-panel-title-row h3",
    ".system-check-panel summary",
    ".system-check-fold > summary",
    ".stats-panel-fold > summary",
    ".runtime-notes-fold > summary",
    // Inspect-style toolbar buttons ("⚙ Query", "📈 Chart") that
    // aren't .outcome-chip but still ship a leading emoji.
    ".inspect-tool-btn",
    ".cmd-palette-item",
    ".community-action",
  ];
  for (const el of document.querySelectorAll(selectors.join(","))) {
    if (el.dataset._emojiStripped === "1") continue;
    // Walk first text node and trim leading emoji
    const node = Array.from(el.childNodes).find((n) => n.nodeType === Node.TEXT_NODE && n.textContent && leadingEmojiRe.test(n.textContent));
    if (node) {
      node.textContent = node.textContent.replace(leadingEmojiRe, "");
    } else if (leadingEmojiRe.test(el.textContent || "")) {
      // Whole textContent is leading-emoji form — fall back to a full
      // replace on the element's text. Safer when text is wrapped in
      // spans by JS rendering.
      el.textContent = (el.textContent || "").replace(leadingEmojiRe, "");
    }
    el.dataset._emojiStripped = "1";
  }
}

function _initActivityFeed() {
  // Inject the trigger button into the header (left of the metric/scope row)
  const header = document.querySelector(".app-header, header") || document.body;
  if (!document.getElementById("activity-feed-button")) {
    const btn = document.createElement("button");
    btn.id = "activity-feed-button";
    btn.type = "button";
    btn.className = "activity-feed-button";
    btn.title = "Recent activity (recipes, watches, ingests, navigations)";
    btn.setAttribute("aria-label", "Recent activity");
    btn.textContent = "🕒";
    // Place near top-right
    document.body.appendChild(btn);
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      _renderActivityPopover();
    });
  }
  _refreshActivityDot();
  // Hook recipe runs + recipe-completion via _runRecipeChip wrapper —
  // but to keep changes small, wrap nav clicks here.
  for (const navBtn of document.querySelectorAll(".nav-button[data-page]")) {
    if (navBtn._activityHooked) continue;
    navBtn._activityHooked = true;
    navBtn.addEventListener("click", () => {
      const page = navBtn.dataset.page;
      // Build the label from the nav-button's accessible name, NOT
      // textContent (which now includes the live badge digits).
      const label = (navBtn.getAttribute("aria-label") || navBtn.getAttribute("title") || page).trim();
      logActivity("page", `Navigated to ${label}`, { page });
    });
  }
}

// ----- Global page-jump hotkeys -----------------------------------------
// Gmail/GitHub-style two-key combos: `g` then a letter jumps to a page.
// `g m` → Map · `g d` → Data · `g a` → Analyze (graphs) · `g p` → Plan
// `g c` → Control · `g s` → Mesh (Signals) · `g h` → Hardware
// `g f` → Forum · `g w` → Wiki · `g b` → Briefings · `g k` → Market
// `g x` → Settings (admin)
// `?` → cheat sheet overlay
// Suppressed while typing in inputs / contenteditable.
const _PAGE_HOTKEYS = {
  m: "map", d: "inspect", l: "library", a: "graphs", p: "command", c: "control",
  s: "comms", h: "hardware", f: "forum", w: "wiki", b: "blog",
  k: "marketplace", x: "settings",
};
let _gPending = false;
let _gPendingTimer = null;
function _isTextInput(t) {
  if (!t) return false;
  if (t.isContentEditable) return true;
  const tn = t.tagName;
  return tn === "INPUT" || tn === "TEXTAREA" || tn === "SELECT";
}
function _showHotkeyCheatSheet() {
  if (document.getElementById("hotkey-cheat-sheet")) return;
  const overlay = document.createElement("div");
  overlay.id = "hotkey-cheat-sheet";
  overlay.className = "hotkey-cheat-sheet";
  overlay.innerHTML = `
    <div class="hotkey-cheat-card">
      <header><strong>⌨ Keyboard shortcuts</strong><button type="button" class="hotkey-cheat-close" aria-label="Close">×</button></header>
      <div class="hotkey-cheat-grid">
        <div class="hotkey-cheat-section"><h4>Navigation</h4>
          <ul>
            <li><kbd>g</kbd>+<kbd>m</kbd> Map</li>
            <li><kbd>g</kbd>+<kbd>d</kbd> Data</li>
            <li><kbd>g</kbd>+<kbd>p</kbd> Plan</li>
            <li><kbd>g</kbd>+<kbd>a</kbd> Analyze</li>
            <li><kbd>g</kbd>+<kbd>c</kbd> Control</li>
            <li><kbd>g</kbd>+<kbd>s</kbd> Mesh (Signals)</li>
            <li><kbd>g</kbd>+<kbd>h</kbd> Hardware</li>
            <li><kbd>g</kbd>+<kbd>x</kbd> Admin</li>
            <li><kbd>g</kbd>+<kbd>f</kbd> Forum</li>
            <li><kbd>g</kbd>+<kbd>w</kbd> Wiki</li>
            <li><kbd>g</kbd>+<kbd>b</kbd> Briefings</li>
            <li><kbd>g</kbd>+<kbd>k</kbd> Market</li>
          </ul>
        </div>
        <div class="hotkey-cheat-section"><h4>Power tools</h4>
          <ul>
            <li><kbd>Ctrl</kbd>+<kbd>K</kbd> Command palette</li>
            <li><kbd>Ctrl</kbd>+<kbd>Shift</kbd>+<kbd>H</kbd> Toggle Honu</li>
            <li><kbd>?</kbd> This cheat sheet</li>
            <li><kbd>Esc</kbd> Dismiss popovers</li>
          </ul>
        </div>
      </div>
      <p class="muted small">Hotkeys are suppressed while typing.</p>
    </div>
  `;
  document.body.appendChild(overlay);
  const close = () => overlay.remove();
  overlay.querySelector(".hotkey-cheat-close")?.addEventListener("click", close);
  overlay.addEventListener("click", (e) => { if (e.target === overlay) close(); });
  document.addEventListener("keydown", function onEsc(ev) {
    if (ev.key === "Escape") { close(); document.removeEventListener("keydown", onEsc); }
  });
}
function _initGlobalHotkeys() {
  document.addEventListener("keydown", (event) => {
    if (_isTextInput(event.target)) return;
    if (event.ctrlKey || event.metaKey || event.altKey) return;
    const key = event.key.toLowerCase();
    if (event.key === "?" && event.shiftKey) {
      event.preventDefault();
      _showHotkeyCheatSheet();
      return;
    }
    if (key === "g" && !_gPending) {
      _gPending = true;
      clearTimeout(_gPendingTimer);
      _gPendingTimer = setTimeout(() => { _gPending = false; }, 1500);
      return;
    }
    if (_gPending) {
      _gPending = false;
      clearTimeout(_gPendingTimer);
      const target = _PAGE_HOTKEYS[key];
      if (target) {
        event.preventDefault();
        // Use the actual navigate() pipeline so URL + state stay synced
        document.querySelector(`[data-page="${target}"].nav-button`)?.click();
        if (typeof showToast === "function") {
          const label = (document.querySelector(`[data-page="${target}"].nav-button`)?.textContent || target).trim().slice(0, 30);
          showToast(`→ ${label}`, { duration: 1500 });
        }
      }
    }
  });
}

// ----- Toast notifications ----------------------------------------------
// Dismissable cards that confirm async actions (recipes, ingests, etc.)
// without forcing the operator to watch the status line. Each toast can
// carry up to 2 action buttons. Auto-dismiss after `duration` ms unless
// the user hovers or it has an action.
function _ensureToastHost() {
  let host = document.getElementById("toast-host");
  if (!host) {
    host = document.createElement("div");
    host.id = "toast-host";
    host.className = "toast-host";
    host.setAttribute("aria-live", "polite");
    host.setAttribute("aria-atomic", "false");
    document.body.appendChild(host);
  }
  return host;
}
function showToast(text, opts = {}) {
  const host = _ensureToastHost();
  const toast = document.createElement("div");
  toast.className = "toast";
  if (opts.severity === "alert") toast.classList.add("is-alert");
  else if (opts.severity === "warn") toast.classList.add("is-warn");
  const head = document.createElement("div");
  head.className = "toast-head";
  const t = document.createElement("div");
  t.className = "toast-text";
  t.textContent = text;
  head.appendChild(t);
  const close = document.createElement("button");
  close.type = "button";
  close.className = "toast-close";
  close.textContent = "×";
  close.title = "Dismiss";
  close.addEventListener("click", () => dismiss());
  head.appendChild(close);
  toast.appendChild(head);
  const actions = Array.isArray(opts.actions) ? opts.actions.slice(0, 2) : [];
  if (actions.length) {
    const ar = document.createElement("div");
    ar.className = "toast-actions";
    for (const a of actions) {
      const b = document.createElement("button");
      b.type = "button";
      b.className = "toast-action";
      b.textContent = a.label;
      b.addEventListener("click", () => {
        try { a.onClick?.(); } catch {}
        dismiss();
      });
      ar.appendChild(b);
    }
    toast.appendChild(ar);
  }
  host.appendChild(toast);
  const duration = opts.duration ?? (actions.length ? 9000 : 5000);
  let timer = setTimeout(dismiss, duration);
  toast.addEventListener("mouseenter", () => { clearTimeout(timer); });
  toast.addEventListener("mouseleave", () => { timer = setTimeout(dismiss, 2500); });
  function dismiss() {
    clearTimeout(timer);
    toast.classList.add("is-leaving");
    setTimeout(() => toast.remove(), 220);
  }
  return { dismiss };
}

// ----- Recipe runner (Plan / Mesh / Watches / Hardware) ---------------
// Recipes are multi-step automated workflows: fetch data → synthesize a
// result → pivot the UI. The visual signal that a recipe is running
// (.is-running class on the chip) is set + cleared by _runRecipeChip.
// NOTE: distinct from the existing inspect-page _runRecipe(id) helper —
// that one looks up a registered RESEARCH_RECIPES entry by id; this one
// just executes a passed callback while showing chip-level state.
// localStorage key for "recently used recipes" — surfaced at the top
// of the recipes modal so operators can re-run their most-used recipes
// without scrolling through 66 entries.
const _RECENT_RECIPES_KEY = "omega-recent-recipes-v1";
const _RECENT_RECIPES_MAX = 8;
function _loadRecentRecipes() {
  try { const raw = localStorage.getItem(_RECENT_RECIPES_KEY); if (!raw) return []; const a = JSON.parse(raw); return Array.isArray(a) ? a : []; } catch { return []; }
}
function _saveRecentRecipes(list) { try { localStorage.setItem(_RECENT_RECIPES_KEY, JSON.stringify(list.slice(0, _RECENT_RECIPES_MAX))); } catch {} }
function _pushRecentRecipe(recipeKey, label) {
  if (!recipeKey) return;
  const list = _loadRecentRecipes().filter((r) => r.recipeKey !== recipeKey);
  list.unshift({ recipeKey, label: String(label || "").trim(), ts: Date.now() });
  _saveRecentRecipes(list);
}

async function _runRecipeChip(chip, fn) {
  if (!chip || chip._recipeRunning) return;
  chip._recipeRunning = true;
  chip.classList.add("is-running");
  const original = chip.textContent;
  let recipeId = "";
  let recipeModalKey = "";
  for (const k of Object.keys(chip.dataset || {})) {
    if (k.endsWith("Recipe")) {
      recipeId = `${k.replace(/Recipe$/, "")}/${chip.dataset[k]}`;
      // Build the same {group}:{id} key the recipes modal uses, so a
      // chip run shows up at the top next time the user opens it.
      const k2 = k.replace(/Recipe$/, "");
      const groupMap = { graphs: "graphs", inspect: "inspect", watch: "watches", plan: "plan", mesh: "mesh", hw: "hardware", map: "map", control: "control", find: "find", pinboard: "pinboard" };
      const grp = groupMap[k2] || k2;
      recipeModalKey = `${grp}:${chip.dataset[k]}`;
      break;
    }
  }
  const t0 = Date.now();
  try {
    await fn();
    if (recipeId && typeof logActivity === "function") logActivity("recipe", `Ran ${recipeId}: ${original}`, { recipeId });
    if (recipeModalKey) _pushRecentRecipe(recipeModalKey, original);
    // Subtle success toast — silent if the recipe finished fast (under
    // 600ms feels instantaneous, no toast needed). Only toast on slower
    // runs where the user might wonder if it worked.
    const elapsed = Date.now() - t0;
    if (elapsed >= 600 && typeof showToast === "function") {
      showToast(`✓ ${original} (${(elapsed / 1000).toFixed(1)}s)`, { duration: 2200 });
    }
  } catch (err) {
    const msg = err?.message || String(err);
    if (typeof showToast === "function") {
      showToast(`Recipe failed: ${msg}`, { severity: "alert", duration: 6000 });
    } else if (typeof setStatus === "function") {
      setStatus(`Recipe failed: ${msg}`);
    } else {
      console.warn("recipe failed", err);
    }
  }
  finally {
    chip.classList.remove("is-running");
    chip._recipeRunning = false;
    chip.textContent = original;
  }
}

async function _fetchLatest(metricName, limit = 200) {
  const r = await fetch(`/v1/measurements/latest?metric_name=${encodeURIComponent(metricName)}&data_scope=real&limit=${limit}`, { cache: "no-store" });
  if (!r.ok) throw new Error(`HTTP ${r.status}`);
  const j = await r.json();
  return (j?.items || []).filter((it) => typeof it.value === "number" && it.node_id);
}

function _bindPlanRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-plan-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.planRecipe;
      if (id === "route-to-biggest-waves" || id === "route-to-hottest-sst") {
        const metric = id === "route-to-biggest-waves" ? "significant-wave-height" : "sea-surface-temperature";
        const items = await _fetchLatest(metric, 200);
        if (!items.length) { setStatus(`Recipe: no ${metric} data yet — try "Load public ocean feeds" first.`); return; }
        items.sort((a, b) => b.value - a.value);
        const top = items[0];
        // Look up lat/lon for that node via /v1/map/stations.geojson
        const sr = await fetch("/v1/map/stations.geojson?data_scope=real", { cache: "no-store" });
        const sj = await sr.json();
        const feat = (sj?.features || []).find((f) => f?.properties?.node_id === top.node_id);
        const coords = feat?.geometry?.coordinates;
        if (!coords) { setStatus(`Recipe: site ${top.node_id} has no geometry; can't route to it.`); return; }
        // The first 3 fleet nodes are typically the "origin candidates". Use the
        // nearest one as origin; fall back to a default offshore origin near
        // SF if no fleet node has geometry.
        const fleetFeats = (sj?.features || []).filter((f) => {
          const at = String(f?.properties?.asset_type || "").toLowerCase();
          return at.includes("shore") || at.includes("asv") || at.includes("relay");
        });
        let origin = { lat: 37.7000, lon: -122.5000 };
        if (fleetFeats.length) {
          // Nearest by chord distance
          fleetFeats.sort((a, b) => {
            const [alon, alat] = a.geometry.coordinates;
            const [blon, blat] = b.geometry.coordinates;
            const da = Math.hypot(alon - coords[0], alat - coords[1]);
            const db = Math.hypot(blon - coords[0], blat - coords[1]);
            return da - db;
          });
          const [olon, olat] = fleetFeats[0].geometry.coordinates;
          origin = { lat: olat, lon: olon };
        }
        // Pre-fill the route form
        const setVal = (id, v) => { const e = document.getElementById(id); if (e) { e.value = String(v); e.dispatchEvent(new Event("input", { bubbles: true })); } };
        setVal("origin-lat", origin.lat.toFixed(6));
        setVal("origin-lon", origin.lon.toFixed(6));
        setVal("destination-lat", coords[1].toFixed(6));
        setVal("destination-lon", coords[0].toFixed(6));
        const tail = top.node_id.split(":").pop();
        const verb = id === "route-to-biggest-waves" ? "biggest waves" : "hottest SST";
        setStatus(`Recipe: ${verb} at ${tail} (${top.value.toFixed(2)}). Origin set to nearest fleet site.`);
        // Trigger the actual route plan
        document.getElementById("route-form")?.requestSubmit?.();
        return;
      }
      if (id === "route-to-storm-alert") {
        // Use NHC active-storms feed and surface the first storm
        try {
          const r = await fetch("/v1/external/nhc/active-storms/data", { cache: "no-store" });
          const j = await r.json();
          const features = j?.features || j?.storms || [];
          if (!features.length) { setStatus("Recipe: no active NHC storms right now (clear seas)."); return; }
          const storm = features[0];
          const coords = storm?.geometry?.coordinates || storm?.coords;
          const name = storm?.properties?.name || storm?.name || "active storm";
          if (!coords) { setStatus(`Recipe: ${name} has no position fix yet.`); return; }
          // Mark this position as a destination for the operator to plan AROUND
          const setVal = (id, v) => { const e = document.getElementById(id); if (e) { e.value = String(v); e.dispatchEvent(new Event("input", { bubbles: true })); } };
          setVal("destination-lat", Number(coords[1]).toFixed(6));
          setVal("destination-lon", Number(coords[0]).toFixed(6));
          setStatus(`Recipe: ${name} at (${Number(coords[1]).toFixed(2)}, ${Number(coords[0]).toFixed(2)}) marked. Use Avoid land + obstacle to route around it.`);
        } catch (e) {
          setStatus(`Recipe: NHC fetch failed (${e.message}). Try again when network is up.`);
        }
        return;
      }
      if (id === "route-to-anomaly") {
        // Look at watches; find the one with highest |deviation %|
        const watches = (typeof _loadWatches === "function" ? _loadWatches() : []);
        if (!watches.length) { setStatus("Recipe: no watches set. Add one from any tile's 🚨 button, then try again."); return; }
        watches.sort((a, b) => Math.abs(b.lastDeviationPct || 0) - Math.abs(a.lastDeviationPct || 0));
        const top = watches[0];
        const sr = await fetch("/v1/map/stations.geojson?data_scope=real", { cache: "no-store" });
        const sj = await sr.json();
        const feat = (sj?.features || []).find((f) => f?.properties?.node_id === top.nodeId);
        const coords = feat?.geometry?.coordinates;
        if (!coords) { setStatus(`Recipe: watch site ${top.nodeId} has no geometry — can't route to it.`); return; }
        const setVal = (id, v) => { const e = document.getElementById(id); if (e) { e.value = String(v); e.dispatchEvent(new Event("input", { bubbles: true })); } };
        setVal("destination-lat", coords[1].toFixed(6));
        setVal("destination-lon", coords[0].toFixed(6));
        const tail = top.nodeId.split(":").pop();
        setStatus(`Recipe: most-drifted watch is ${top.metric} at ${tail} (${((top.lastDeviationPct || 0) * 100).toFixed(0)}% off). Destination set.`);
        return;
      }
      if (id === "route-to-nearest-station") {
        // Read current origin lat/lon. Compute distance to every station.
        // Pick the closest one. Plan route from origin to that station.
        const origLat = parseFloat(document.getElementById("origin-lat")?.value);
        const origLon = parseFloat(document.getElementById("origin-lon")?.value);
        if (!Number.isFinite(origLat) || !Number.isFinite(origLon)) {
          setStatus("Recipe: set an Origin first (Pick Origin on the map).");
          return;
        }
        const sr = await fetch("/v1/map/stations.geojson?data_scope=real", { cache: "no-store" });
        const sj = await sr.json();
        const feats = (sj?.features || []).filter((f) => f?.geometry?.coordinates);
        if (!feats.length) { setStatus("Recipe: no stations available — try loading public feeds first."); return; }
        // Haversine-light: equirectangular distance is fine for picking nearest
        const dist = (lat1, lon1, lat2, lon2) => {
          const dLat = (lat2 - lat1) * Math.PI / 180;
          const dLon = (lon2 - lon1) * Math.PI / 180;
          const x = dLon * Math.cos(((lat1 + lat2) / 2) * Math.PI / 180);
          return Math.sqrt(x * x + dLat * dLat) * 6371;  // km
        };
        let best = null;
        for (const f of feats) {
          const [lon, lat] = f.geometry.coordinates;
          const d = dist(origLat, origLon, lat, lon);
          if (!best || d < best.d) best = { feature: f, d, lat, lon };
        }
        const tail = (best.feature.properties?.node_id || "").split(":").pop();
        const setVal = (id, v) => { const e = document.getElementById(id); if (e) { e.value = String(v); e.dispatchEvent(new Event("input", { bubbles: true })); } };
        setVal("destination-lat", best.lat.toFixed(6));
        setVal("destination-lon", best.lon.toFixed(6));
        setStatus(`Recipe: nearest station is ${tail} at ${best.d.toFixed(1)} km. Destination set.`);
        if (typeof showToast === "function") showToast(`📍 Nearest: ${tail} (${best.d.toFixed(1)} km)`);
        return;
      }
      if (id === "copy-route-as-gpx") {
        const origLat = parseFloat(document.getElementById("origin-lat")?.value);
        const origLon = parseFloat(document.getElementById("origin-lon")?.value);
        const destLat = parseFloat(document.getElementById("destination-lat")?.value);
        const destLon = parseFloat(document.getElementById("destination-lon")?.value);
        if (![origLat, origLon, destLat, destLon].every(Number.isFinite)) {
          setStatus("Recipe: set both Origin and Destination first.");
          return;
        }
        const now = new Date().toISOString();
        const gpx = `<?xml version="1.0" encoding="UTF-8"?>
<gpx version="1.1" creator="OMEGA-wave" xmlns="http://www.topografix.com/GPX/1/1">
  <metadata>
    <name>OMEGA-wave Plan Route</name>
    <time>${now}</time>
  </metadata>
  <rte>
    <name>Origin → Destination</name>
    <rtept lat="${origLat}" lon="${origLon}"><name>Origin</name></rtept>
    <rtept lat="${destLat}" lon="${destLon}"><name>Destination</name></rtept>
  </rte>
</gpx>`;
        const blob = new Blob([gpx], { type: "application/gpx+xml" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `omega-route-${new Date().toISOString().slice(0, 10)}.gpx`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(() => URL.revokeObjectURL(url), 500);
        setStatus("Recipe: route exported as GPX.");
        if (typeof showToast === "function") showToast("📥 Route exported as GPX");
        return;
      }
    }));
  }
}

function _bindMeshRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-mesh-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.meshRecipe;
      if (id === "diagnose-worst-link") {
        const r = await fetch("/v1/mesh/neighbors", { cache: "no-store" });
        if (!r.ok) { setStatus("Recipe: /v1/mesh/neighbors unreachable — is the gateway running?"); return; }
        const j = await r.json();
        const ns = j?.items || j?.neighbors || [];
        if (!ns.length) { setStatus("Recipe: no neighbors known to the mesh yet — bring up a LoRa node first."); return; }
        ns.sort((a, b) => (a.rssi ?? 0) - (b.rssi ?? 0));
        const worst = ns[0];
        const id2 = worst.node_id || worst.id || "(unknown)";
        const rssi = Number.isFinite(worst.rssi) ? `${worst.rssi} dBm` : "—";
        setStatus(`Recipe: worst link is ${id2} @ ${rssi}. Loading routes…`);
        const tgt = document.getElementById("mesh-target-node-input") || document.querySelector('[id*="mesh"][id*="target"]');
        if (tgt) { tgt.value = id2; tgt.dispatchEvent(new Event("input", { bubbles: true })); }
        return;
      }
      if (id === "ping-all") {
        const r = await fetch("/v1/mesh/neighbors", { cache: "no-store" });
        const j = await r.json();
        const ns = j?.items || j?.neighbors || [];
        if (!ns.length) { setStatus("Recipe: no neighbors known — nothing to ping."); return; }
        setStatus(`Recipe: would queue status_snapshot to ${ns.length} neighbors. (Confirm in operator outbox before send.)`);
        return;
      }
      if (id === "clear-stale-outbox") {
        const r = await fetch("/v1/mesh/outbox", { cache: "no-store" });
        const j = await r.json();
        const items = j?.items || [];
        const hourAgo = Date.now() - 3600 * 1000;
        const stale = items.filter((it) => {
          const t = it.created_at ? Date.parse(it.created_at) : NaN;
          return Number.isFinite(t) && t < hourAgo;
        });
        setStatus(stale.length ? `Recipe: ${stale.length}/${items.length} outbox entries are >1h old.` : "Recipe: no stale outbox entries (every queued message is <1h old).");
        return;
      }
      if (id === "map-mesh") {
        if (typeof navigate === "function") navigate("map");
        setStatus("Recipe: switched to Map — neighbors render as markers; LoRa routes follow as polylines.");
        return;
      }
      if (id === "copy-routes-table") {
        try {
          const r = await fetch("/v1/mesh/routes", { cache: "no-store" });
          if (!r.ok) { setStatus(`Recipe: routes unreachable — HTTP ${r.status}.`); return; }
          const j = await r.json();
          const routes = j?.routes || j?.items || [];
          if (!routes.length) { setStatus("Recipe: no mesh routes known."); return; }
          const lines = ["# OMEGA Mesh Routes", `_${new Date().toISOString()}_`, "", "| Destination | Bearer | Cost | Next hop |", "|---|---|---|---|"];
          for (const r of routes.slice(0, 50)) {
            lines.push(`| ${r.destination || r.dest || "—"} | ${r.bearer || r.transport || "—"} | ${r.cost ?? "—"} | ${r.next_hop || r.via || "—"} |`);
          }
          await navigator.clipboard.writeText(lines.join("\n"));
          setStatus(`Recipe: copied ${routes.length} route${routes.length === 1 ? "" : "s"} as Markdown.`);
          if (typeof showToast === "function") showToast(`📋 Copied ${routes.length} route${routes.length === 1 ? "" : "s"}`);
        } catch (e) { setStatus(`Recipe: routes copy failed — ${e.message}.`); }
        return;
      }
      if (id === "show-best-link") {
        try {
          const r = await fetch("/v1/mesh/neighbors", { cache: "no-store" });
          if (!r.ok) { setStatus(`Recipe: neighbors unreachable — HTTP ${r.status}.`); return; }
          const j = await r.json();
          const neighbors = j?.neighbors || j?.items || [];
          const withRssi = neighbors.filter((n) => typeof n.rssi === "number");
          if (!withRssi.length) { setStatus("Recipe: no LoRa neighbors with RSSI data."); return; }
          withRssi.sort((a, b) => b.rssi - a.rssi);  // higher RSSI = better
          const best = withRssi[0];
          setStatus(`Recipe: best link is ${best.node_id || best.id || "unknown"} at ${best.rssi} dBm.`);
          if (typeof showToast === "function") showToast(`⭐ Best link: ${best.node_id || best.id} (${best.rssi} dBm)`);
        } catch (e) { setStatus(`Recipe: best-link query failed — ${e.message}.`); }
        return;
      }
      if (id === "count-bearers") {
        try {
          const r = await fetch("/v1/mesh/interfaces", { cache: "no-store" });
          if (!r.ok) { setStatus(`Recipe: interfaces unreachable — HTTP ${r.status}.`); return; }
          const j = await r.json();
          const items = j?.interfaces || j?.items || [];
          const counts = { lora: 0, halow: 0, acoustic: 0, other: 0 };
          for (const it of items) {
            const t = (it.bearer || it.type || it.kind || "").toLowerCase();
            if (t.includes("lora")) counts.lora += 1;
            else if (t.includes("halow") || t.includes("802.11ah")) counts.halow += 1;
            else if (t.includes("janus") || t.includes("acoustic")) counts.acoustic += 1;
            else counts.other += 1;
          }
          const msg = `${counts.lora} LoRa · ${counts.halow} HaLow · ${counts.acoustic} acoustic · ${counts.other} other`;
          setStatus(`Recipe: ${msg}.`);
          if (typeof showToast === "function") showToast(`📊 ${msg}`);
        } catch (e) { setStatus(`Recipe: bearer count failed — ${e.message}.`); }
        return;
      }
    }));
  }
}

function _bindWatchRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-watch-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.watchRecipe;
      const bulkWatch = async (metric, thresholdPct, label) => {
        const items = await _fetchLatest(metric, 200);
        if (!items.length) { setStatus(`Recipe: no ${metric} sites currently reporting. Load public feeds first.`); return; }
        // Dedupe by node_id, take freshest
        const byNode = new Map();
        for (const it of items) {
          const prev = byNode.get(it.node_id);
          if (!prev || (it.sampled_at && it.sampled_at > prev.sampled_at)) byNode.set(it.node_id, it);
        }
        const existing = (typeof _loadWatches === "function" ? _loadWatches() : []);
        const existingKeys = new Set(existing.map((w) => `${w.metric}::${w.nodeId}`));
        let added = 0;
        for (const it of byNode.values()) {
          if (existingKeys.has(`${metric}::${it.node_id}`)) continue;
          const tail = it.node_id.split(":").pop();
          if (typeof _addAnomalyWatch === "function") {
            _addAnomalyWatch(it.node_id, tail, metric, it.value, it.unit || "", thresholdPct);
            added += 1;
          }
        }
        const msg = `${label}: added ${added} new watch${added === 1 ? "" : "es"} (${byNode.size} sites total, ${byNode.size - added} already watched).`;
        setStatus(`Recipe: ${msg}`);
        if (added > 0 && typeof showToast === "function") {
          showToast(`✅ ${msg}`, {
            actions: [
              { label: "View Watches", onClick: () => {
                if (typeof setWorkspace === "function") setWorkspace("inspect", "watches");
              }},
            ],
          });
        }
      };
      if (id === "watch-all-sst") return bulkWatch("sea-surface-temperature", 0.10, "Every SST site");
      if (id === "watch-all-waves") return bulkWatch("significant-wave-height", 0.15, "Every wave-height site");
      if (id === "watch-top-anomalies") {
        // Pull every numeric metric, find top 5 deviants vs median
        const r = await fetch("/v1/measurements/latest?data_scope=real&limit=1000", { cache: "no-store" });
        const j = await r.json();
        const items = (j?.items || []).filter((it) => typeof it.value === "number" && it.node_id);
        if (!items.length) { setStatus("Recipe: no numeric data to sweep."); return; }
        const groups = new Map();
        for (const it of items) {
          const k = `${it.node_id}::${it.metric_name}`;
          const prev = groups.get(k);
          if (!prev || (it.sampled_at && it.sampled_at > prev.sampled_at)) groups.set(k, it);
        }
        const byMetric = new Map();
        for (const it of groups.values()) {
          const a = byMetric.get(it.metric_name) || [];
          a.push(it.value);
          byMetric.set(it.metric_name, a);
        }
        const median = (a) => { const s = [...a].sort((x, y) => x - y); return s[Math.floor(s.length / 2)]; };
        const ranked = [];
        for (const it of groups.values()) {
          const med = median(byMetric.get(it.metric_name) || [it.value]);
          if (med === 0) continue;
          ranked.push({ ...it, drift: Math.abs((it.value - med) / med), median: med });
        }
        ranked.sort((a, b) => b.drift - a.drift);
        const top = ranked.slice(0, 5);
        const existing = (typeof _loadWatches === "function" ? _loadWatches() : []);
        const existingKeys = new Set(existing.map((w) => `${w.metric}::${w.nodeId}`));
        let added = 0;
        for (const it of top) {
          if (existingKeys.has(`${it.metric_name}::${it.node_id}`)) continue;
          const tail = it.node_id.split(":").pop();
          if (typeof _addAnomalyWatch === "function") {
            _addAnomalyWatch(it.node_id, tail, it.metric_name, it.median, it.unit || "", 0.15);
            added += 1;
          }
        }
        const msg = `Watched top ${added} of ${top.length} drifters (baseline = current median across sites).`;
        setStatus(`Recipe: ${msg}`);
        if (added > 0 && typeof showToast === "function") {
          showToast(`🚨 ${msg}`, {
            severity: "alert",
            actions: [
              { label: "View Watches", onClick: () => { if (typeof setWorkspace === "function") setWorkspace("inspect", "watches"); }},
            ],
          });
        }
        return;
      }
      if (id === "watch-storm-alerts") return bulkWatch("alert-severity-index", 0.50, "Storm-alert sites");
      if (id === "watch-all-winds") return bulkWatch("wind-speed", 0.25, "Every wind-speed site");
      if (id === "watch-all-currents") return bulkWatch("current-speed", 0.20, "Every current-speed site");
      if (id === "watch-clear-stale") {
        // Remove watches whose baseline timestamp is > 24h old
        const all = (typeof _loadWatches === "function" ? _loadWatches() : []);
        const cutoff = Date.now() - 24 * 3600 * 1000;
        const kept = all.filter((w) => {
          if (!w.baselineAt) return true; // unknown — keep
          const t = Date.parse(w.baselineAt);
          return Number.isFinite(t) && t >= cutoff;
        });
        const dropped = all.length - kept.length;
        if (dropped === 0) {
          setStatus("Recipe: no watches have stale baselines (>24h).");
          return;
        }
        if (typeof _saveWatches === "function") _saveWatches(kept);
        if (typeof _renderWatchesList === "function") _renderWatchesList();
        setStatus(`Recipe: cleared ${dropped} stale watch${dropped === 1 ? "" : "es"} (>24h baseline).`);
        if (typeof showToast === "function") showToast(`🧹 Cleared ${dropped} stale watch${dropped === 1 ? "" : "es"}`);
        return;
      }
      if (id === "watch-rearm-all") {
        // Re-baseline every watch from the latest reading
        const all = (typeof _loadWatches === "function" ? _loadWatches() : []);
        if (!all.length) { setStatus("Recipe: no watches to re-arm."); return; }
        let updated = 0;
        for (const w of all) {
          try {
            const r = await fetch(`/v1/measurements/latest?node_id=${encodeURIComponent(w.nodeId)}&metric_name=${encodeURIComponent(w.metric)}&limit=1`, { cache: "no-store" });
            if (!r.ok) continue;
            const j = await r.json();
            const it = (j?.items || [])[0];
            if (it && typeof it.value === "number") {
              w.baseline = it.value;
              w.baselineAt = it.sampled_at || new Date().toISOString();
              w.lastValue = it.value;
              w.lastSeverity = "ok";
              w.lastDeviationPct = 0;
              updated += 1;
            }
          } catch (e) {}
        }
        if (typeof _saveWatches === "function") _saveWatches(all);
        if (typeof _renderWatchesList === "function") _renderWatchesList();
        setStatus(`Recipe: re-armed ${updated} of ${all.length} watch${all.length === 1 ? "" : "es"}.`);
        if (typeof showToast === "function") showToast(`↺ Re-armed ${updated} watch${updated === 1 ? "" : "es"}`);
        return;
      }
      if (id === "watch-export-csv") {
        const all = (typeof _loadWatches === "function" ? _loadWatches() : []);
        if (!all.length) { setStatus("Recipe: no watches to export."); return; }
        const rows = [["metric", "node_id", "baseline", "unit", "threshold_pct", "baseline_at", "last_value", "last_severity", "last_deviation_pct"]];
        for (const w of all) {
          rows.push([
            w.metric || "",
            w.nodeId || "",
            (typeof w.baseline === "number" ? w.baseline : "").toString(),
            w.unit || "",
            (typeof w.thresholdPct === "number" ? w.thresholdPct : 0.10).toString(),
            w.baselineAt || "",
            (typeof w.lastValue === "number" ? w.lastValue : "").toString(),
            w.lastSeverity || "",
            (typeof w.lastDeviationPct === "number" ? w.lastDeviationPct.toFixed(4) : "").toString(),
          ]);
        }
        const csv = rows.map((r) => r.map((c) => /[",\n]/.test(c) ? `"${c.replace(/"/g, '""')}"` : c).join(",")).join("\n");
        const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `omega-watches-${new Date().toISOString().slice(0, 10)}.csv`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(() => URL.revokeObjectURL(url), 500);
        setStatus(`Recipe: exported ${all.length} watch${all.length === 1 ? "" : "es"} as CSV.`);
        if (typeof showToast === "function") showToast(`📥 Exported ${all.length} watch${all.length === 1 ? "" : "es"}`);
        return;
      }
    }));
  }
}

function _bindGraphsRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-graphs-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.graphsRecipe;
      // All recipes pivot the Chart Builder. Make sure we're there.
      if (typeof navigate === "function" && document.body.dataset.page !== "graphs") navigate("graphs");
      await new Promise((r) => setTimeout(r, 200));
      if (typeof setWorkspace === "function") setWorkspace("graphs", "builder");
      await new Promise((r) => setTimeout(r, 300));
      const setSelect = (id, value) => {
        const el = document.getElementById(id);
        if (!el) return false;
        const opt = Array.from(el.options).find((o) => o.value === value || o.textContent?.trim() === value);
        if (opt) {
          el.value = opt.value;
          el.dispatchEvent(new Event("change", { bubbles: true }));
          return true;
        }
        return false;
      };
      const setVizTool = (vizType) => {
        const tool = document.querySelector(`.viz-tool[data-viz-type="${vizType}"]`);
        if (tool) { tool.click(); return true; }
        return false;
      };
      if (id === "compare-sst") {
        setVizTool("station-bars");
        setSelect("visualization-metric-select", "sea-surface-temperature");
        setStatus("Recipe: Station Bars across all sites for sea-surface-temperature.");
        setTimeout(() => document.getElementById("render-visualization-button")?.click(), 200);
        return;
      }
      if (id === "compare-waves") {
        setVizTool("station-bars");
        setSelect("visualization-metric-select", "significant-wave-height");
        setStatus("Recipe: Station Bars across all sites for significant-wave-height.");
        setTimeout(() => document.getElementById("render-visualization-button")?.click(), 200);
        return;
      }
      if (id === "wave-histogram") {
        setVizTool("histogram");
        setSelect("visualization-metric-select", "significant-wave-height");
        setStatus("Recipe: Histogram of significant-wave-height across sites.");
        setTimeout(() => document.getElementById("render-visualization-button")?.click(), 200);
        return;
      }
      if (id === "trend-top-anomaly") {
        const watches = (typeof _loadWatches === "function" ? _loadWatches() : []);
        if (!watches.length) {
          setStatus("Recipe: no watches set. Add one (any tile's 🚨 button), then try again.");
          return;
        }
        watches.sort((a, b) => Math.abs(b.lastDeviationPct || 0) - Math.abs(a.lastDeviationPct || 0));
        const top = watches[0];
        setVizTool("trend");
        setSelect("visualization-metric-select", top.metric);
        setSelect("visualization-station-select", top.nodeId);
        setSelect("visualization-range-select", "720");  // 30 days in hours
        const tail = top.nodeId.split(":").pop();
        setStatus(`Recipe: trend of ${top.metric} at ${tail} (most-drifted watch, ${((top.lastDeviationPct || 0) * 100).toFixed(0)}% off baseline).`);
        setTimeout(() => document.getElementById("render-visualization-button")?.click(), 250);
        return;
      }
      // Time-window quick presets
      if (id === "window-24h" || id === "window-7d" || id === "window-30d") {
        const hours = id === "window-24h" ? 24 : id === "window-7d" ? 168 : 720;
        const label = id === "window-24h" ? "24 hours" : id === "window-7d" ? "7 days" : "30 days";
        setSelect("visualization-range-select", String(hours));
        setStatus(`Recipe: chart window set to last ${label}.`);
        setTimeout(() => document.getElementById("render-visualization-button")?.click(), 200);
        return;
      }
      if (id === "overlay-sst-wave") {
        // Render SST trend, then pin wave-height as overlay
        setVizTool("trend");
        setSelect("visualization-metric-select", "sea-surface-temperature");
        document.getElementById("render-visualization-button")?.click();
        await new Promise((r) => setTimeout(r, 400));
        // Now pin and switch to wave height for overlay
        document.getElementById("visualization-add-series-button")?.click();
        await new Promise((r) => setTimeout(r, 200));
        setSelect("visualization-metric-select", "significant-wave-height");
        document.getElementById("render-visualization-button")?.click();
        setStatus("Recipe: SST trend with wave-height overlay (pinned as series).");
        return;
      }
      if (id === "depth-profile-top") {
        // Find site with the most depth-tagged readings
        try {
          const r = await fetch("/v1/measurements/latest?data_scope=real&limit=1000", { cache: "no-store" });
          const j = await r.json();
          const items = (j?.items || []).filter((it) => typeof it.depth_m === "number" || /depth/i.test(it.metric_name || ""));
          if (!items.length) {
            setStatus("Recipe: no depth-tagged readings — load Argo / glider data first or pick depth-profile manually.");
            return;
          }
          const counts = new Map();
          for (const it of items) counts.set(it.node_id, (counts.get(it.node_id) || 0) + 1);
          const topNode = Array.from(counts.entries()).sort((a, b) => b[1] - a[1])[0][0];
          setVizTool("depth-profile");
          setSelect("visualization-station-select", topNode);
          setTimeout(() => document.getElementById("render-visualization-button")?.click(), 250);
          const tail = topNode.split(":").pop();
          setStatus(`Recipe: depth profile for ${tail} (${counts.get(topNode)} depth-tagged readings).`);
        } catch (e) {
          setStatus("Recipe: depth-profile lookup failed — pick the viz tool manually.");
        }
        return;
      }
      if (id === "qc-flag-summary") {
        setVizTool("qc-flags");
        setTimeout(() => document.getElementById("render-visualization-button")?.click(), 200);
        setStatus("Recipe: QC Flags summary — pass / suspect / fail breakdown.");
        return;
      }
      if (id === "copy-chart-snapshot") {
        // Build Markdown snapshot of the current chart config
        const vizType = document.querySelector(".viz-tool.is-active strong")?.textContent?.trim() || "Trend";
        const metric = document.getElementById("visualization-metric-select")?.selectedOptions?.[0]?.textContent?.trim() || "—";
        const station = document.getElementById("visualization-station-select")?.selectedOptions?.[0]?.textContent?.trim() || "All sites";
        const range = document.getElementById("visualization-range-select")?.selectedOptions?.[0]?.textContent?.trim() || "default";
        const rows = window.state?.vizActiveRows || [];
        let statsBlock = "";
        if (Array.isArray(rows) && rows.length) {
          const vals = rows.map((r) => r.value).filter((v) => typeof v === "number");
          if (vals.length) {
            const mean = vals.reduce((s, x) => s + x, 0) / vals.length;
            const min = Math.min(...vals);
            const max = Math.max(...vals);
            const sd = Math.sqrt(vals.reduce((s, x) => s + (x - mean) ** 2, 0) / vals.length);
            statsBlock = `\n\n**Stats (n=${vals.length}):**\n- Mean: ${mean.toFixed(3)}\n- Min: ${min.toFixed(3)}\n- Max: ${max.toFixed(3)}\n- Stdev: ${sd.toFixed(3)}\n`;
          }
        }
        const md = `# OMEGA-wave Chart Snapshot\n_${new Date().toISOString()}_\n\n- **Visualization:** ${vizType}\n- **Metric:** ${metric}\n- **Site:** ${station}\n- **Window:** ${range}\n- **Row count:** ${Array.isArray(rows) ? rows.length : 0}${statsBlock}`;
        try {
          await navigator.clipboard.writeText(md);
          setStatus("Recipe: chart snapshot copied to clipboard.");
          if (typeof showToast === "function") showToast("📋 Chart snapshot copied");
        } catch (e) {
          setStatus("Recipe: clipboard write blocked.");
        }
        return;
      }
      if (id === "save-preset") {
        const name = prompt("Name this chart preset:", "My chart");
        if (!name) { setStatus("Recipe: preset save cancelled."); return; }
        const preset = {
          name,
          vizType: document.querySelector(".viz-tool.is-active")?.dataset.vizType || "trend",
          metric: document.getElementById("visualization-metric-select")?.value || "",
          station: document.getElementById("visualization-station-select")?.value || "",
          range: document.getElementById("visualization-range-select")?.value || "",
          savedAt: new Date().toISOString(),
        };
        try {
          const all = JSON.parse(localStorage.getItem("omega-chart-presets") || "[]");
          const existingIdx = all.findIndex((p) => p.name === name);
          if (existingIdx >= 0) all[existingIdx] = preset; else all.push(preset);
          localStorage.setItem("omega-chart-presets", JSON.stringify(all));
          setStatus(`Recipe: saved preset "${name}".`);
          if (typeof showToast === "function") showToast(`💾 Saved chart preset "${name}"`);
        } catch (e) {
          setStatus(`Recipe: preset save failed — ${e.message}.`);
        }
        return;
      }
      if (id === "load-preset") {
        let all = [];
        try { all = JSON.parse(localStorage.getItem("omega-chart-presets") || "[]"); } catch (e) {}
        if (!all.length) {
          setStatus("Recipe: no saved presets yet. Use 'Save preset' to create one.");
          return;
        }
        const choice = prompt(`Load which preset?\n\n${all.map((p, i) => `${i + 1}. ${p.name} (${p.vizType}, ${p.metric || "all"})`).join("\n")}\n\nEnter a number:`, "1");
        const idx = parseInt(choice || "0", 10) - 1;
        if (Number.isNaN(idx) || idx < 0 || idx >= all.length) {
          setStatus("Recipe: invalid preset choice.");
          return;
        }
        const p = all[idx];
        setVizTool(p.vizType);
        if (p.metric) setSelect("visualization-metric-select", p.metric);
        if (p.station) setSelect("visualization-station-select", p.station);
        if (p.range) setSelect("visualization-range-select", p.range);
        setTimeout(() => document.getElementById("render-visualization-button")?.click(), 250);
        setStatus(`Recipe: loaded preset "${p.name}".`);
        if (typeof showToast === "function") showToast(`📂 Loaded "${p.name}"`);
        return;
      }
    }));
  }
}

// ----- Inspect (inspect:browse) smart recipes -------------------------------
// These pivot the Inspect tile dashboard to data-driven extremes:
// hottest/coldest SST, biggest wave, strongest current, quietest site,
// pin top 5, copy snapshot. They use live measurements from /v1/measurements/latest
// so the answer is always grounded in real gateway data.
function _bindInspectRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-inspect-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.inspectRecipe;
      // Helper: find the single best (max/min) reading for a metric across sites
      const findExtreme = async (metric, comparator, label) => {
        const r = await fetch(`/v1/measurements/latest?data_scope=real&limit=500&metric_name=${encodeURIComponent(metric)}`, { cache: "no-store" });
        if (!r.ok) throw new Error(`Could not load ${metric}`);
        const j = await r.json();
        const items = (j?.items || []).filter((it) => typeof it.value === "number" && it.node_id);
        if (!items.length) {
          setStatus(`Recipe: no ${metric} sites currently reporting. Try Load Public Feeds first.`);
          return null;
        }
        // Dedupe by node_id, take freshest
        const byNode = new Map();
        for (const it of items) {
          const prev = byNode.get(it.node_id);
          if (!prev || (it.sampled_at && it.sampled_at > prev.sampled_at)) byNode.set(it.node_id, it);
        }
        const list = Array.from(byNode.values());
        list.sort(comparator);
        return list[0];
      };
      const pivotToSite = async (top, label) => {
        if (!top) return;
        const tail = (top.node_id || "").split(":").pop();
        const valueStr = typeof top.value === "number"
          ? `${top.value.toFixed(2)}${top.unit ? " " + top.unit : ""}`
          : String(top.value);
        // Set the inspect site filter to this node
        if (typeof setWorkspace === "function" && document.body.dataset.page !== "inspect") {
          if (typeof navigate === "function") navigate("inspect");
          await new Promise((r) => setTimeout(r, 200));
        }
        if (typeof setWorkspace === "function") setWorkspace("inspect", "browse");
        await new Promise((r) => setTimeout(r, 250));
        const siteSelect = document.getElementById("inspect-live-site");
        if (siteSelect) {
          const opt = Array.from(siteSelect.options).find((o) => o.value === top.node_id);
          if (opt) {
            siteSelect.value = top.node_id;
            siteSelect.dispatchEvent(new Event("change", { bubbles: true }));
          }
        }
        setStatus(`Recipe: ${label} → ${tail} (${valueStr}).`);
        if (typeof showToast === "function") {
          showToast(`✅ ${label}: ${tail} at ${valueStr}`, {
            actions: [
              { label: "Chart it", onClick: () => {
                if (typeof setWorkspace === "function") setWorkspace("graphs", "builder");
              }},
              { label: "Add watch", onClick: () => {
                if (typeof _addAnomalyWatch === "function") {
                  _addAnomalyWatch(top.node_id, tail, top.metric_name, top.value, top.unit || "", 0.10);
                }
              }},
            ],
          });
        }
      };
      if (id === "hottest-sst") {
        const top = await findExtreme("sea-surface-temperature", (a, b) => b.value - a.value, "Hottest SST");
        return pivotToSite(top, "Hottest SST");
      }
      if (id === "coldest-sst") {
        const top = await findExtreme("sea-surface-temperature", (a, b) => a.value - b.value, "Coldest SST");
        return pivotToSite(top, "Coldest SST");
      }
      if (id === "biggest-wave") {
        const top = await findExtreme("significant-wave-height", (a, b) => b.value - a.value, "Biggest wave");
        return pivotToSite(top, "Biggest wave");
      }
      if (id === "strongest-current") {
        const top = await findExtreme("current-speed", (a, b) => b.value - a.value, "Strongest current");
        return pivotToSite(top, "Strongest current");
      }
      if (id === "quietest-site") {
        // Quietest = site with lowest stdev across its numeric metrics
        const r = await fetch("/v1/measurements/latest?data_scope=real&limit=1000", { cache: "no-store" });
        if (!r.ok) { setStatus("Recipe: latest measurements unavailable."); return; }
        const j = await r.json();
        const items = (j?.items || []).filter((it) => typeof it.value === "number" && it.node_id);
        if (!items.length) { setStatus("Recipe: no numeric data — load public feeds first."); return; }
        const bySite = new Map();
        for (const it of items) {
          const key = `${it.node_id}::${it.metric_name}`;
          const prev = bySite.get(key);
          if (!prev || (it.sampled_at && it.sampled_at > prev.sampled_at)) bySite.set(key, it);
        }
        const perSite = new Map();
        for (const it of bySite.values()) {
          const a = perSite.get(it.node_id) || [];
          a.push(it.value);
          perSite.set(it.node_id, a);
        }
        const variance = (a) => {
          if (a.length < 2) return Infinity;
          const m = a.reduce((s, x) => s + x, 0) / a.length;
          // Coefficient-of-variation-ish: stdev / abs(mean) so different
          // magnitudes are comparable
          const sd = Math.sqrt(a.reduce((s, x) => s + (x - m) * (x - m), 0) / a.length);
          return Math.abs(m) > 0.001 ? sd / Math.abs(m) : Infinity;
        };
        const ranked = Array.from(perSite.entries())
          .map(([node_id, vals]) => ({ node_id, count: vals.length, cv: variance(vals) }))
          .filter((x) => Number.isFinite(x.cv) && x.count >= 2)
          .sort((a, b) => a.cv - b.cv);
        if (!ranked.length) { setStatus("Recipe: not enough numeric metrics per site to score variance."); return; }
        const top = ranked[0];
        const tail = top.node_id.split(":").pop();
        if (typeof setWorkspace === "function") setWorkspace("inspect", "browse");
        await new Promise((r) => setTimeout(r, 200));
        const siteSelect = document.getElementById("inspect-live-site");
        if (siteSelect) {
          const opt = Array.from(siteSelect.options).find((o) => o.value === top.node_id);
          if (opt) {
            siteSelect.value = top.node_id;
            siteSelect.dispatchEvent(new Event("change", { bubbles: true }));
          }
        }
        setStatus(`Recipe: Quietest site → ${tail} (CV=${top.cv.toFixed(3)} across ${top.count} metrics).`);
        if (typeof showToast === "function") {
          showToast(`✅ Quietest: ${tail} (CV=${top.cv.toFixed(3)})`);
        }
        return;
      }
      if (id === "pin-top-5") {
        // Pin top 5 visible tiles to the pinboard
        const tiles = Array.from(document.querySelectorAll("#inspect-live-tiles .live-tile")).slice(0, 5);
        if (!tiles.length) { setStatus("Recipe: no tiles visible to pin."); return; }
        let pinned = 0;
        for (const tile of tiles) {
          const btn = tile.querySelector("[data-pin-tile], .pin-tile-button, [data-action='pin']");
          if (btn) {
            btn.click();
            pinned += 1;
          } else if (typeof _addPinFromTile === "function") {
            _addPinFromTile(tile);
            pinned += 1;
          }
        }
        setStatus(`Recipe: Pinned ${pinned} tile${pinned === 1 ? "" : "s"} to the Pinboard.`);
        if (typeof showToast === "function" && pinned > 0) {
          showToast(`📌 Pinned ${pinned} tile${pinned === 1 ? "" : "s"}`, {
            actions: [{ label: "Open Pinboard", onClick: () => {
              if (typeof setWorkspace === "function") setWorkspace("graphs", "pinboard");
            }}],
          });
        }
        return;
      }
      if (id === "copy-snapshot") {
        // Build a Markdown summary of currently-visible tiles
        const tiles = Array.from(document.querySelectorAll("#inspect-live-tiles .live-tile"));
        if (!tiles.length) { setStatus("Recipe: no tiles visible to snapshot."); return; }
        const lines = ["# OMEGA-wave Inspect Snapshot", `_${new Date().toISOString()}_`, "", "| Metric | Value | Site | Age |", "|---|---|---|---|"];
        for (const tile of tiles.slice(0, 30)) {
          const metric = tile.querySelector(".live-tile-metric, .live-tile-label")?.textContent?.trim() || "—";
          const value = tile.querySelector(".live-tile-value")?.textContent?.trim() || "—";
          const site = tile.querySelector(".live-tile-site, [data-site]")?.textContent?.trim() || tile.dataset.site || "—";
          const age = tile.querySelector(".live-tile-meta, .live-tile-age")?.textContent?.trim() || "—";
          lines.push(`| ${metric} | ${value} | ${site} | ${age} |`);
        }
        const md = lines.join("\n");
        try {
          await navigator.clipboard.writeText(md);
          setStatus(`Recipe: Copied ${tiles.length} tile${tiles.length === 1 ? "" : "s"} as Markdown to clipboard.`);
          if (typeof showToast === "function") showToast(`📋 Snapshot copied (${tiles.length} tile${tiles.length === 1 ? "" : "s"})`);
        } catch (e) {
          setStatus("Recipe: clipboard write blocked. Use Ctrl+C from this output instead.");
        }
        return;
      }
    }));
  }
}

// ----- Pinboard (graphs:pinboard) smart recipes ----------------------------
function _bindPinboardRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-pinboard-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.pinboardRecipe;
      if (id === "snapshot-everything") {
        const btn = document.getElementById("pinboard-save-current-button");
        if (btn) { btn.click(); setStatus("Recipe: snapshot saved — name it in the prompt."); return; }
        setStatus("Recipe: pinboard save button not found.");
        return;
      }
      if (id === "copy-as-markdown") {
        // Use localStorage pin format (matches the existing save format)
        let pins = [];
        try { pins = JSON.parse(localStorage.getItem("omega-pinboard") || "[]"); } catch (e) {}
        if (!pins.length) { setStatus("Recipe: no saved workspaces to copy."); return; }
        const lines = ["# OMEGA-wave Pinboard", `_${new Date().toISOString()}_`, ""];
        for (const p of pins) {
          lines.push(`- **${p.name || "Untitled"}** (${p.savedAt || "—"}) — ${p.summary || ""}`);
        }
        try {
          await navigator.clipboard.writeText(lines.join("\n"));
          setStatus(`Recipe: copied ${pins.length} pin${pins.length === 1 ? "" : "s"} as Markdown.`);
          if (typeof showToast === "function") showToast(`📋 Copied ${pins.length} pin${pins.length === 1 ? "" : "s"}`);
        } catch (e) { setStatus("Recipe: clipboard write blocked."); }
        return;
      }
      if (id === "count-pins") {
        let pins = [], presets = [];
        try { pins = JSON.parse(localStorage.getItem("omega-pinboard") || "[]"); } catch (e) {}
        try { presets = JSON.parse(localStorage.getItem("omega-chart-presets") || "[]"); } catch (e) {}
        const tiles = document.querySelectorAll(".live-tile[data-pinned], .pinned-tile").length;
        const msg = `${pins.length} workspace${pins.length === 1 ? "" : "s"} · ${presets.length} chart preset${presets.length === 1 ? "" : "s"} · ${tiles} pinned tile${tiles === 1 ? "" : "s"}`;
        setStatus(`Recipe: ${msg}.`);
        if (typeof showToast === "function") showToast(`🔢 ${msg}`);
        return;
      }
    }));
  }
}

// ----- Find (library:find) smart recipes -----------------------------------
function _bindFindRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-find-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.findRecipe;
      const placeInput = document.getElementById("finder-place-input");
      const metricInput = document.getElementById("finder-metric-input");
      if (id === "copy-query-link") {
        const params = new URLSearchParams();
        if (placeInput?.value) params.set("place", placeInput.value);
        if (metricInput?.value) params.set("metric", metricInput.value);
        if (!params.toString()) { setStatus("Recipe: nothing to copy — pick a place or metric first."); return; }
        const url = `${location.origin}/portal#library:find?${params.toString()}`;
        try {
          await navigator.clipboard.writeText(url);
          setStatus("Recipe: query link copied to clipboard.");
          if (typeof showToast === "function") showToast("📋 Query link copied");
        } catch (e) { setStatus("Recipe: clipboard write blocked."); }
        return;
      }
      if (id === "route-to-best-provider") {
        const btn = document.querySelector('[data-find-outcome="suggest"]') || document.getElementById("finder-suggest-button");
        if (btn) btn.click();
        await new Promise((r) => setTimeout(r, 1500));
        const firstMatch = document.querySelector(".finder-match-card, .finder-result-row, [data-finder-provider]");
        if (firstMatch) {
          firstMatch.click();
          setStatus("Recipe: Suggest run, top match opened.");
          if (typeof showToast === "function") showToast("⚡ Top match loaded");
        } else {
          setStatus("Recipe: Suggest run but no matches surfaced.");
        }
        return;
      }
      if (id === "export-matches-csv") {
        const matches = document.querySelectorAll(".finder-match-card, .finder-result-row, [data-finder-provider]");
        if (!matches.length) { setStatus("Recipe: no matches to export. Run Suggest first."); return; }
        const rows = [["provider", "score", "summary"]];
        for (const m of matches) {
          const name = m.querySelector("strong, .finder-provider-name")?.textContent?.trim() || (m.dataset.finderProvider || "—");
          const score = m.querySelector(".finder-score, [data-score]")?.textContent?.trim() || "—";
          const summary = m.querySelector(".finder-summary, p")?.textContent?.trim().replace(/\s+/g, " ").slice(0, 200) || "";
          rows.push([name, score, summary]);
        }
        const csv = rows.map((r) => r.map((c) => /[",\n]/.test(c) ? `"${c.replace(/"/g, '""')}"` : c).join(",")).join("\n");
        const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `omega-find-matches-${new Date().toISOString().slice(0, 10)}.csv`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(() => URL.revokeObjectURL(url), 500);
        setStatus(`Recipe: exported ${matches.length} match${matches.length === 1 ? "" : "es"} as CSV.`);
        if (typeof showToast === "function") showToast(`📥 Exported ${matches.length} matches`);
        return;
      }
    }));
  }
}

// ----- Global Recipes catalog modal --------------------------------------
// Opens a single discoverable list of every recipe in the portal, grouped
// by page, with one-click run. Solves "I love the recipes but where are
// they all?" by giving every recipe a single home — accessible via the
// header Recipes button or the [r] hotkey.
// ----- Examples fold onboarding ----------------------------------------
// On first visit, auto-open the .viz-examples-fold / .usage-examples-fold
// on the active workspace so new operators see the workflow examples.
// Once they explicitly close one, mark it as "seen" in localStorage and
// never auto-open it again. Returning users don't get the pop-up.
const _EXAMPLES_SEEN_KEY = "omega-examples-seen-v1";
function _loadExamplesSeen() {
  try { const raw = localStorage.getItem(_EXAMPLES_SEEN_KEY); if (!raw) return {}; const a = JSON.parse(raw); return (a && typeof a === "object") ? a : {}; } catch { return {}; }
}
function _markExamplesSeen(key) {
  if (!key) return;
  const seen = _loadExamplesSeen();
  seen[key] = Date.now();
  try { localStorage.setItem(_EXAMPLES_SEEN_KEY, JSON.stringify(seen)); } catch {}
}
function _foldKey(fold) {
  // Build a stable key per fold: combine the closest workspace section
  // (if any) with the fold's index inside it. Two folds in the same
  // workspace will get distinct keys (workspace + nth-of-type).
  const section = fold.closest("[data-workspace-section]");
  const ws = section ? section.dataset.workspaceSection : "global";
  const siblings = section ? [...section.querySelectorAll(".viz-examples-fold, .usage-examples-fold")] : [fold];
  const idx = Math.max(0, siblings.indexOf(fold));
  return `${ws}#${idx}`;
}
function _initExamplesFoldOnboarding() {
  const folds = document.querySelectorAll(".viz-examples-fold, .usage-examples-fold");
  for (const fold of folds) {
    const key = _foldKey(fold);
    // Wire the "seen" listener now so it survives workspace switches.
    fold.addEventListener("toggle", () => {
      if (!fold.open) _markExamplesSeen(key);
    });
  }
  // Defer the auto-open check to the next frame so initWorkspaces has
  // had a chance to set hidden=true/false on each workspace section.
  // Otherwise we'd open every fold globally because all sections are
  // un-hidden during the initial DOM parse.
  requestAnimationFrame(() => {
    const seen = _loadExamplesSeen();
    for (const fold of folds) {
      const key = _foldKey(fold);
      if (seen[key]) continue;
      const section = fold.closest("[data-workspace-section]");
      const isActiveWorkspace = !section || !section.hidden;
      if (isActiveWorkspace) fold.open = true;
    }
  });
  // Re-check on workspace switches so the first time the operator
  // visits a section (e.g. switches from inspect:browse to library:find),
  // its examples auto-open if unseen.
  document.addEventListener("workspace:changed", () => {
    const seen = _loadExamplesSeen();
    for (const fold of folds) {
      const key = _foldKey(fold);
      if (seen[key]) continue;
      const section = fold.closest("[data-workspace-section]");
      if (section && !section.hidden) fold.open = true;
    }
  });
}

function _initRecipesCatalog() {
  const modal = document.getElementById("recipes-modal");
  const btn = document.getElementById("recipes-book-button");
  if (!modal || !btn) return;
  const searchEl = document.getElementById("recipes-modal-search");
  const listEl = document.getElementById("recipes-modal-list");

  function _gatherRecipes() {
    // Walk all .recipe-chip[data-*-recipe] in the DOM and group by page.
    // The recipe rail's aria-label tells us the group name; we infer the
    // page from the parent workspace-section attribute or sensible defaults.
    const out = new Map();
    const groupOrder = ["Observe", "Plan", "Control", "Analyze", "Inspect", "Library", "Mesh", "Hardware", "Other"];
    for (const name of groupOrder) out.set(name, []);
    for (const chip of document.querySelectorAll(".recipe-chip")) {
      const rail = chip.closest(".recipe-rail, .floating-map-recipe-rail");
      const railLabel = rail ? (rail.getAttribute("aria-label") || "") : "";
      let group = "Other";
      let recipeKey = null;
      if (chip.dataset.graphsRecipe) { group = "Analyze"; recipeKey = `graphs:${chip.dataset.graphsRecipe}`; }
      else if (chip.dataset.inspectRecipe) { group = "Inspect"; recipeKey = `inspect:${chip.dataset.inspectRecipe}`; }
      else if (chip.dataset.watchRecipe) { group = "Inspect"; recipeKey = `watches:${chip.dataset.watchRecipe}`; }
      else if (chip.dataset.planRecipe) { group = "Plan"; recipeKey = `plan:${chip.dataset.planRecipe}`; }
      else if (chip.dataset.meshRecipe) { group = "Mesh"; recipeKey = `mesh:${chip.dataset.meshRecipe}`; }
      else if (chip.dataset.hwRecipe) { group = "Hardware"; recipeKey = `hardware:${chip.dataset.hwRecipe}`; }
      else if (chip.dataset.mapRecipe) { group = "Observe"; recipeKey = `map:${chip.dataset.mapRecipe}`; }
      else if (chip.dataset.controlRecipe) { group = "Control"; recipeKey = `control:${chip.dataset.controlRecipe}`; }
      else if (chip.dataset.findRecipe) { group = "Library"; recipeKey = `find:${chip.dataset.findRecipe}`; }
      else if (chip.dataset.pinboardRecipe) { group = "Analyze"; recipeKey = `pinboard:${chip.dataset.pinboardRecipe}`; }
      if (!recipeKey) continue;
      const label = (chip.textContent || "").trim().replace(/\s+/g, " ");
      const tip = chip.getAttribute("title") || "";
      const arr = out.get(group) || [];
      // Dedupe: chips can be duplicated by clones (page-context-bar etc).
      // Use the recipeKey as the dedupe key.
      if (!arr.some((r) => r.recipeKey === recipeKey)) {
        arr.push({ label, tip, recipeKey, chipEl: chip, railLabel });
        out.set(group, arr);
      }
    }
    return out;
  }

  function _renderRecipesModal(filter) {
    if (!listEl) return;
    const grouped = _gatherRecipes();
    // Build a {recipeKey → {label, tip, group}} lookup so the
    // "Recently used" section can show the rich label + description
    // for keys we've seen run, even if they don't currently match the
    // filter.
    const allByKey = new Map();
    for (const [groupName, items] of grouped) {
      for (const r of items) allByKey.set(r.recipeKey, { ...r, groupName });
    }
    const filterText = (filter || "").trim().toLowerCase();
    const sections = [];

    // Recently used — shown when there's no filter, at the top, so the
    // operator's most common recipes are 1 click away. Hidden when
    // filtering so the search results aren't shadowed.
    if (!filterText) {
      const recent = _loadRecentRecipes().filter((r) => allByKey.has(r.recipeKey));
      if (recent.length) {
        const recentHtml = recent.map((r) => {
          const meta = allByKey.get(r.recipeKey);
          const label = meta?.label || r.label || r.recipeKey;
          const tip = meta?.tip || "";
          return `
            <button type="button" class="recipes-modal-item recipes-modal-recent-item" data-recipe-key="${escapeHtml(r.recipeKey)}" title="${escapeHtml(tip || label)}">
              <span class="recipes-modal-item-label">${escapeHtml(label)}</span>
              ${tip && tip !== label ? `<span class="recipes-modal-item-desc">${escapeHtml(tip.length > 70 ? tip.slice(0, 67) + "…" : tip)}</span>` : ""}
            </button>
          `;
        }).join("");
        sections.push(`
          <section class="recipes-modal-group recipes-modal-recent">
            <h3 class="recipes-modal-group-title">⏱ Recently used <span class="recipes-group-count">${recent.length} recipe${recent.length === 1 ? "" : "s"}</span></h3>
            <div class="recipes-modal-group-list">${recentHtml}</div>
          </section>
        `);
      }
    }

    for (const [groupName, items] of grouped) {
      const filtered = filterText
        ? items.filter((r) => r.label.toLowerCase().includes(filterText) || r.tip.toLowerCase().includes(filterText))
        : items;
      if (!filtered.length) continue;
      const itemHtml = filtered.map((r) => `
        <button type="button" class="recipes-modal-item" data-recipe-key="${escapeHtml(r.recipeKey)}" title="${escapeHtml(r.tip || r.label)}">
          <span class="recipes-modal-item-label">${escapeHtml(r.label)}</span>
          ${r.tip && r.tip !== r.label ? `<span class="recipes-modal-item-desc">${escapeHtml(r.tip.length > 70 ? r.tip.slice(0, 67) + "…" : r.tip)}</span>` : ""}
        </button>
      `).join("");
      sections.push(`
        <section class="recipes-modal-group">
          <h3 class="recipes-modal-group-title">${escapeHtml(groupName)} <span class="recipes-group-count">${filtered.length} recipe${filtered.length === 1 ? "" : "s"}</span></h3>
          <div class="recipes-modal-group-list">${itemHtml}</div>
        </section>
      `);
    }
    if (!sections.length) {
      listEl.innerHTML = `<div class="recipes-modal-empty">No recipes match "${escapeHtml(filterText)}". Try a different keyword.</div>`;
      return;
    }
    listEl.innerHTML = sections.join("");
    // Wire click → run the underlying chip
    for (const item of listEl.querySelectorAll(".recipes-modal-item")) {
      item.addEventListener("click", () => {
        const key = item.dataset.recipeKey;
        if (!key) return;
        const [group, id] = key.split(":");
        // Map group → data-attribute name and chip selector
        const attrMap = {
          graphs: "graphs-recipe", inspect: "inspect-recipe", watches: "watch-recipe",
          plan: "plan-recipe", mesh: "mesh-recipe", hardware: "hw-recipe", map: "map-recipe",
          control: "control-recipe", find: "find-recipe", pinboard: "pinboard-recipe",
        };
        const attr = attrMap[group];
        if (!attr) return;
        const chip = document.querySelector(`.recipe-chip[data-${attr}="${id}"]`);
        if (chip) {
          modal.hidden = true;
          chip.click();
        }
      });
    }
  }

  function _updateCount() {
    const countEl = document.getElementById("recipes-modal-count");
    if (!countEl) return;
    const grouped = _gatherRecipes();
    let total = 0;
    for (const [, items] of grouped) total += items.length;
    countEl.textContent = total > 0 ? `· ${total} recipes available` : "";
  }

  function _openCatalog() {
    modal.hidden = false;
    _renderRecipesModal("");
    _updateCount();
    if (searchEl) {
      searchEl.value = "";
      setTimeout(() => searchEl.focus(), 80);
    }
  }
  function _closeCatalog() { modal.hidden = true; }

  btn.addEventListener("click", _openCatalog);
  modal.querySelectorAll("[data-modal-dismiss]").forEach((el) => el.addEventListener("click", _closeCatalog));
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && !modal.hidden) _closeCatalog();
    // Hotkey: r (when not in input) opens the recipes catalog
    if (e.key === "r" && !modal.hidden) return;
    if (e.key === "r" && !e.metaKey && !e.ctrlKey && !e.altKey) {
      const tag = (document.activeElement?.tagName || "").toLowerCase();
      if (tag === "input" || tag === "textarea" || tag === "select") return;
      // Allow contenteditable to consume r
      if (document.activeElement?.isContentEditable) return;
      e.preventDefault();
      _openCatalog();
    }
  });
  if (searchEl) {
    searchEl.addEventListener("input", () => _renderRecipesModal(searchEl.value));
    // Enter inside the search input runs the FIRST visible recipe.
    // Lets the user type a search and just hit Enter without grabbing
    // the mouse — common keyboard-first power-user pattern.
    searchEl.addEventListener("keydown", (e) => {
      if (e.key === "Enter") {
        e.preventDefault();
        const first = listEl?.querySelector(".recipes-modal-item");
        if (first) first.click();
      } else if (e.key === "ArrowDown") {
        e.preventDefault();
        const first = listEl?.querySelector(".recipes-modal-item");
        if (first) first.focus();
      }
    });
    // Inside the list: arrow keys to navigate, Enter to run, Esc back
    // to search.
    listEl?.addEventListener("keydown", (e) => {
      if (!(e.target instanceof HTMLElement)) return;
      if (!e.target.classList.contains("recipes-modal-item")) return;
      const items = [...listEl.querySelectorAll(".recipes-modal-item")];
      const idx = items.indexOf(e.target);
      if (idx < 0) return;
      if (e.key === "ArrowDown") {
        e.preventDefault();
        items[Math.min(items.length - 1, idx + 1)]?.focus();
      } else if (e.key === "ArrowUp") {
        e.preventDefault();
        if (idx === 0) searchEl.focus();
        else items[idx - 1]?.focus();
      } else if (e.key === "Enter") {
        e.preventDefault();
        e.target.click();
      }
    });
  }
}

// ----- Live nav-button status badges ---------------------------------
// Shows at-a-glance health on the nav rail so the operator doesn't need
// to navigate INTO a page to discover something's degraded. Refreshes
// every 5s reusing the existing endpoints; failures are silent.
function _setNavBadge(page, text, severity) {
  const btn = document.querySelector(`.nav-button[data-page="${page}"]`);
  if (!btn) return;
  let badge = btn.querySelector(":scope > .nav-badge");
  if (!badge) {
    badge = document.createElement("span");
    badge.className = "nav-badge";
    btn.appendChild(badge);
  }
  if (text == null || text === "" || text === 0 || text === "0") {
    badge.classList.add("is-hidden");
    return;
  }
  badge.classList.remove("is-hidden", "is-warn", "is-alert");
  if (severity === "warn") badge.classList.add("is-warn");
  else if (severity === "alert") badge.classList.add("is-alert");
  badge.textContent = String(text);
}

async function _refreshNavBadges() {
  // Inspect page: count fresh tiles (samples ≤ 1h) across all metrics.
  // Show count when fresh exists; hide otherwise — the standing warn-
  // colored "·" dot on stale-only data was confusing operators because
  // it stayed lit any time the gateway hadn't received a sample in the
  // last hour (very common when the Pi is offline or during dev). If
  // the user wants to know about staleness, they can click into Inspect.
  try {
    const r = await fetch("/v1/measurements/latest?data_scope=real&limit=500", { cache: "no-store" });
    const j = await r.json();
    const items = j?.items || [];
    const now = Date.now();
    const fresh = items.filter((it) => {
      if (!it.sampled_at) return false;
      const t = Date.parse(it.sampled_at);
      return Number.isFinite(t) && now - t < 3600 * 1000;
    });
    const keys = new Set(fresh.map((it) => `${it.metric_name}::${it.node_id}`));
    if (keys.size > 0) _setNavBadge("inspect", keys.size, null);
    else _setNavBadge("inspect", "", null);  // no fresh data: hide badge
  } catch { _setNavBadge("inspect", "", null); }

  // Watches: count alerting (severity warning|critical) from localStorage
  try {
    const watches = (typeof _loadWatches === "function" ? _loadWatches() : []);
    const alerting = watches.filter((w) => w.lastSeverity === "warning" || w.lastSeverity === "critical").length;
    if (alerting > 0) {
      // Don't have a "watches" nav button — the data button's badge already
      // represents the data page. We'll instead OVERRIDE the data badge to
      // alert if any watches are alerting, which is the more urgent signal.
      _setNavBadge("inspect", alerting, "alert");
    }
  } catch {}

  // Mesh (comms): count active neighbors
  try {
    const r = await fetch("/v1/mesh/neighbors", { cache: "no-store" });
    if (r.ok) {
      const j = await r.json();
      const ns = j?.items || j?.neighbors || [];
      // Only set if neighbors > 0 (zero is the silent default — bg is fine)
      _setNavBadge("comms", ns.length, ns.length === 0 ? "warn" : null);
    }
  } catch {}

  // Hardware: show adapter count if registered
  try {
    const r = await fetch("/v1/adapters", { cache: "no-store" });
    if (r.ok) {
      const j = await r.json();
      const ns = j?.items || j?.adapters || [];
      if (ns.length > 0) _setNavBadge("hardware", ns.length, null);
    }
  } catch {}
}

let _navBadgeTimer = null;
function _startNavBadgeRefresh() {
  if (_navBadgeTimer) clearInterval(_navBadgeTimer);
  _refreshNavBadges();
  _navBadgeTimer = setInterval(_refreshNavBadges, 5000);
}

function _ensureMapRecipeRail() {
  // Smart-map recipe rail used to inject as a floating chip strip at the
  // bottom-left of every page. Those chips were duplicative on the Observe
  // page (the header 🍳 Recipes button + the [r] keyboard hotkey already
  // expose every chip via the command palette and the Recipes modal), and
  // they were pure clutter on every OTHER page — Inspect, Library, Forum,
  // Wiki, Briefings, etc. all had a "Smart map: Fleet Anomaly Storms…"
  // strip floating in the lower-left even though those pages don't show
  // an interactive map.
  //
  // Kept as a no-op so any callers (renderMapOverlayControls etc.) don't
  // crash. If you want a floating quick-action rail again, use the
  // header Recipes modal or the Cmd+K command palette — both are
  // page-aware and don't waste fixed screen space.
  // Defensive cleanup: if a stale rail was injected by an older bundle,
  // remove it so the page is clean even before a hard refresh.
  const stale = document.getElementById("floating-map-recipe-rail");
  if (stale) stale.remove();
}

// "Today" snapshot card — top-right of the map page. Floating, fixed-
// position, refreshes every 60s with live counts (active stations,
// fresh measurements, active storms, alerting watches). Click → Inspect.
function _ensureMapTodayCard() {
  if (document.getElementById("map-today-card")) return;
  const card = document.createElement("aside");
  card.id = "map-today-card";
  card.className = "map-today-card";
  card.setAttribute("aria-label", "Today's at-a-glance snapshot");
  card.innerHTML = `
    <header class="map-today-head">
      <span class="map-today-eyebrow muted small">TODAY</span>
      <strong id="map-today-date"></strong>
      <button type="button" id="map-today-refresh" class="map-today-refresh" title="Refresh now" aria-label="Refresh today snapshot">↻</button>
    </header>
    <div id="map-today-stats" class="map-today-stats">
      <button type="button" class="map-today-stat" data-today-action="inspect" title="Open Inspect to see live readings">
        <span class="muted small">Stations live (1h)</span>
        <strong id="map-today-fresh">—</strong>
      </button>
      <button type="button" class="map-today-stat" data-today-action="all-data" title="Fit the map to every site with data">
        <span class="muted small">Reporting today</span>
        <strong id="map-today-reporting">—</strong>
      </button>
      <button type="button" class="map-today-stat" data-today-action="watches" title="Open the Watches page">
        <span class="muted small">Active watches</span>
        <strong id="map-today-watches">—</strong>
      </button>
      <button type="button" class="map-today-stat" data-today-action="storms" title="Zoom map to NHC active storms">
        <span class="muted small">NHC storms</span>
        <strong id="map-today-storms">—</strong>
      </button>
    </div>
    <p id="map-today-headline" class="map-today-headline muted small"></p>
  `;
  document.body.appendChild(card);
  card.addEventListener("click", (ev) => {
    const stat = ev.target.closest(".map-today-stat");
    if (!stat) return;
    const action = stat.dataset.todayAction;
    if (action === "inspect" && typeof navigate === "function") navigate("inspect");
    else if (action === "watches" && typeof navigate === "function") navigate("inspect");
    else if (action === "all-data") {
      const chip = document.querySelector(".recipe-chip[data-map-recipe='zoom-to-data']");
      if (chip) chip.click();
    } else if (action === "storms") {
      const chip = document.querySelector(".recipe-chip[data-map-recipe='show-storms']");
      if (chip) chip.click();
    }
  });
  const refreshBtn = document.getElementById("map-today-refresh");
  if (refreshBtn) refreshBtn.addEventListener("click", (ev) => { ev.stopPropagation(); _refreshMapTodayCard(); });
}

async function _refreshMapTodayCard() {
  const dateEl = document.getElementById("map-today-date");
  const freshEl = document.getElementById("map-today-fresh");
  const reportingEl = document.getElementById("map-today-reporting");
  const watchesEl = document.getElementById("map-today-watches");
  const stormsEl = document.getElementById("map-today-storms");
  const headlineEl = document.getElementById("map-today-headline");
  if (!dateEl) return;
  // Date
  const now = new Date();
  dateEl.textContent = now.toLocaleDateString(undefined, { weekday: "short", month: "short", day: "numeric" });
  // Measurements
  try {
    const r = await fetch("/v1/measurements/latest?data_scope=real&limit=500", { cache: "no-store" });
    const j = await r.json();
    const items = j?.items || [];
    const t0 = now.getTime();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
    const freshKeys = new Set();
    const reportingKeys = new Set();
    let latestFresh = null;
    for (const it of items) {
      if (!it.sampled_at) continue;
      const ts = Date.parse(it.sampled_at);
      if (!Number.isFinite(ts)) continue;
      if (ts >= todayStart) reportingKeys.add(it.node_id || it.station_id || it.source_id || "?");
      if (t0 - ts < 3600 * 1000) {
        freshKeys.add(it.node_id || it.station_id || it.source_id || "?");
        if (!latestFresh || ts > latestFresh.ts) latestFresh = { ts, item: it };
      }
    }
    freshEl.textContent = freshKeys.size > 0 ? freshKeys.size : "—";
    reportingEl.textContent = reportingKeys.size > 0 ? reportingKeys.size : "—";
    if (latestFresh && headlineEl) {
      const m = latestFresh.item;
      const ago = Math.max(1, Math.round((t0 - latestFresh.ts) / 60000));
      let valNum = (typeof m.value === "number") ? m.value : Number(m.value);
      let valStr;
      if (Number.isFinite(valNum)) {
        // Round to 2 sig fig when small, else 1 decimal — never 7 trailing digits.
        valStr = Math.abs(valNum) >= 10 ? valNum.toFixed(1) : valNum.toFixed(2);
      } else {
        valStr = m.value != null ? String(m.value) : "—";
      }
      const value = m.unit ? `${valStr} ${m.unit}` : valStr;
      const metric = (m.metric_name || "").replace(/[-_]/g, " ");
      const site = m.node_id || m.station_id || "";
      headlineEl.textContent = `Latest: ${metric} ${value}${site ? " · " + site : ""} · ${ago}m ago`;
    } else if (headlineEl) {
      headlineEl.textContent = "No fresh measurements yet — gateway may be idle.";
    }
  } catch (err) {
    if (freshEl) freshEl.textContent = "?";
    if (reportingEl) reportingEl.textContent = "?";
  }
  // Watches + Fleet alerts — combined "Active alerts" count. Watches are
  // user-defined drift triggers from localStorage; fleet alerts come from
  // the gateway's /v1/fleet/node-profiles + station readiness eval. Show
  // the union so the operator doesn't have to check two badges.
  try {
    const watches = (typeof _loadWatches === "function" ? _loadWatches() : []);
    const watchAlerts = watches.filter((w) => w.lastSeverity === "warning" || w.lastSeverity === "critical").length;
    const fleetAlerts = Array.isArray(window.state?.alerts) ? window.state.alerts.length : (Array.isArray(state?.alerts) ? state.alerts.length : 0);
    const total = watchAlerts + fleetAlerts;
    watchesEl.textContent = total > 0 ? total : "—";
    const card = document.getElementById("map-today-card");
    if (card) card.classList.toggle("has-alert", total > 0);
    if (watchesEl.parentElement) {
      // Tooltip explaining the split so users know the breakdown
      watchesEl.parentElement.title = total > 0
        ? `${watchAlerts} watch drift + ${fleetAlerts} fleet alert${fleetAlerts === 1 ? "" : "s"} — click to review`
        : `${watches.length} watch${watches.length === 1 ? "" : "es"} configured — none alerting`;
    }
  } catch {}
  // Storms
  try {
    const r = await fetch("/v1/external/nhc/active-storms/data", { cache: "no-store" });
    const j = await r.json();
    const storms = j?.items || j?.storms || j?.features || [];
    stormsEl.textContent = storms.length > 0 ? storms.length : "—";
  } catch { stormsEl.textContent = "—"; }
}

let _mapTodayTimer = null;
function _startMapTodayCardRefresh() {
  _ensureMapTodayCard();
  _refreshMapTodayCard();
  if (_mapTodayTimer) clearInterval(_mapTodayTimer);
  _mapTodayTimer = setInterval(() => {
    // Only refresh when actually on the map page (saves battery on other pages)
    if (document.body.dataset.page === "map") _refreshMapTodayCard();
  }, 60000);
}

function _bindMapRecipeChips() {
  _ensureMapRecipeRail();
  _startMapTodayCardRefresh();
  for (const chip of document.querySelectorAll(".recipe-chip[data-map-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.mapRecipe;
      const leafletMap = window._map || window.map || (state && state.leafletMap);
      const fitTo = (coords) => {
        if (!coords.length) return false;
        const lats = coords.map((c) => c[0]);
        const lons = coords.map((c) => c[1]);
        if (leafletMap && typeof leafletMap.fitBounds === "function" && window.L) {
          leafletMap.fitBounds([[Math.min(...lats), Math.min(...lons)], [Math.max(...lats), Math.max(...lons)]], { padding: [40, 40] });
          return true;
        }
        return false;
      };
      // Make sure we're on the map page first
      if (typeof navigate === "function" && document.body.dataset.page !== "map") navigate("map");
      await new Promise((r) => setTimeout(r, 300));
      if (id === "zoom-to-fleet" || id === "zoom-to-data") {
        const r = await fetch("/v1/map/stations.geojson?data_scope=real", { cache: "no-store" });
        const j = await r.json();
        const feats = j?.features || [];
        const want = id === "zoom-to-fleet"
          ? feats.filter((f) => /shore|asv|relay/i.test(String(f?.properties?.asset_type || "")))
          : feats;
        const coords = want
          .map((f) => f?.geometry?.coordinates)
          .filter((c) => Array.isArray(c) && Number.isFinite(c[0]) && Number.isFinite(c[1]))
          .map((c) => [c[1], c[0]]);
        if (!coords.length) { setStatus(`Recipe: no ${id === "zoom-to-fleet" ? "fleet sites" : "data sites"} to zoom to yet.`); return; }
        const ok = fitTo(coords);
        setStatus(ok
          ? `Recipe: zoomed to ${coords.length} ${id === "zoom-to-fleet" ? "fleet" : "data"} sites.`
          : `Recipe: found ${coords.length} sites, but the map instance isn't ready — try opening the Map page first.`);
        return;
      }
      if (id === "zoom-to-anomaly") {
        const watches = (typeof _loadWatches === "function" ? _loadWatches() : []);
        if (!watches.length) { setStatus("Recipe: no watches set. Watch a metric first (any tile's 🚨 button)."); return; }
        watches.sort((a, b) => Math.abs(b.lastDeviationPct || 0) - Math.abs(a.lastDeviationPct || 0));
        const top = watches[0];
        const sr = await fetch("/v1/map/stations.geojson?data_scope=real", { cache: "no-store" });
        const sj = await sr.json();
        const feat = (sj?.features || []).find((f) => f?.properties?.node_id === top.nodeId);
        const coords = feat?.geometry?.coordinates;
        if (!coords) { setStatus(`Recipe: watch site ${top.nodeId} has no geometry.`); return; }
        if (leafletMap && typeof leafletMap.setView === "function") {
          leafletMap.setView([coords[1], coords[0]], 9);
        }
        const tail = top.nodeId.split(":").pop();
        setStatus(`Recipe: centered on ${tail} (${top.metric} drifted ${((top.lastDeviationPct || 0) * 100).toFixed(0)}%).`);
        return;
      }
      if (id === "show-storms") {
        try {
          const r = await fetch("/v1/external/nhc/active-storms/data", { cache: "no-store" });
          const j = await r.json();
          const feats = j?.features || j?.storms || [];
          if (!feats.length) { setStatus("Recipe: no active NHC storms right now — clear seas."); return; }
          const coords = feats.map((s) => {
            const c = s?.geometry?.coordinates || s?.coords;
            return c ? [Number(c[1]), Number(c[0])] : null;
          }).filter(Boolean);
          if (!coords.length) { setStatus(`Recipe: ${feats.length} active storms but none have a position fix.`); return; }
          const ok = fitTo(coords);
          setStatus(ok ? `Recipe: ${feats.length} active storm${feats.length === 1 ? "" : "s"} surfaced on map.` : `Recipe: ${feats.length} storms found but map not ready.`);
        } catch (e) { setStatus(`Recipe: NHC unreachable (${e.message}).`); }
        return;
      }
      if (id === "show-density") {
        // Activate AIS density layer via the existing layer-catalog API if
        // available, else show a helpful status.
        if (typeof layerCatalogActivateByName === "function") {
          try {
            await layerCatalogActivateByName("vessel-density");
            setStatus("Recipe: AIS vessel density overlay enabled.");
            if (typeof showToast === "function") showToast("🚢 AIS density layer on");
            return;
          } catch (e) {}
        }
        // Fallback: open the Layers dropdown so the operator can find it
        const ldd = document.querySelector('[data-dropdown-toggle="layers"]');
        if (ldd) ldd.click();
        setStatus("Recipe: pick a vessel density layer from the Layers menu.");
        return;
      }
      if (id === "show-bathymetry") {
        if (typeof layerCatalogActivateByName === "function") {
          try {
            await layerCatalogActivateByName("bathymetry");
            setStatus("Recipe: bathymetry overlay enabled.");
            if (typeof showToast === "function") showToast("🌊 Bathymetry layer on");
            return;
          } catch (e) {}
        }
        const ldd = document.querySelector('[data-dropdown-toggle="layers"]');
        if (ldd) ldd.click();
        setStatus("Recipe: pick the Bathymetry layer from the Layers menu.");
        return;
      }
      if (id === "reset-view") {
        if (typeof state !== "undefined" && state.map) {
          try {
            state.map.setView([20, 0], 2);
            setStatus("Recipe: map view reset to world bounds.");
            if (typeof showToast === "function") showToast("↺ Map reset");
          } catch (e) {
            setStatus(`Recipe: reset failed — ${e.message}.`);
          }
        } else {
          setStatus("Recipe: map not ready.");
        }
        return;
      }
    }));
  }
}

function _bindHwRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-hw-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.hwRecipe;
      if (id === "verify-stack") {
        const steps = [];
        try {
          const r1 = await fetch("/v1/gateway/status", { cache: "no-store" });
          steps.push(r1.ok ? "✅ gateway/status OK" : `❌ gateway/status ${r1.status}`);
        } catch { steps.push("❌ gateway/status unreachable"); }
        try {
          const r2 = await fetch("/v1/adapters", { cache: "no-store" });
          const j = await r2.json();
          const n = (j?.items || j?.adapters || []).length;
          steps.push(n ? `✅ ${n} adapter${n === 1 ? "" : "s"} registered` : "⚠️ 0 adapters registered (no bridge hardware connected)");
        } catch { steps.push("❌ /v1/adapters unreachable"); }
        try {
          const r3 = await fetch("/v1/mesh/interfaces", { cache: "no-store" });
          const j = await r3.json();
          const n = (j?.items || j?.interfaces || []).length;
          steps.push(n ? `✅ ${n} mesh interface${n === 1 ? "" : "s"}` : "⚠️ 0 mesh interfaces");
        } catch { steps.push("❌ /v1/mesh/interfaces unreachable"); }
        const summary = steps.join(" · ");
        setStatus(`Bridge verify: ${summary}`);
        const failed = steps.filter((s) => s.startsWith("❌"));
        const warns = steps.filter((s) => s.startsWith("⚠️"));
        const sev = failed.length ? "alert" : warns.length ? "warn" : null;
        if (typeof showToast === "function") {
          showToast(`Bridge verify: ${summary}`, { severity: sev, duration: 12000 });
        }
        return;
      }
      if (id === "lora-relay-smoke") {
        // Pre-select T3S3 firmware target + jump to flasher
        if (typeof setWorkspace === "function") setWorkspace("hardware", "firmware");
        setTimeout(() => {
          const target = document.getElementById("firmware-target-select");
          if (target) {
            const opt = Array.from(target.options).find((o) => /t3s3|relay/i.test(o.value + " " + o.textContent));
            if (opt) target.value = opt.value;
          }
          setStatus("LoRa relay smoke: target pre-selected. Plug board, pick serial port, Probe → Flash.");
        }, 200);
        return;
      }
      if (id === "supreme-setup") {
        if (typeof setWorkspace === "function") setWorkspace("hardware", "firmware");
        setTimeout(() => {
          const target = document.getElementById("firmware-target-select");
          if (target) {
            const opt = Array.from(target.options).find((o) => /supreme|t-?beam/i.test(o.value + " " + o.textContent));
            if (opt) target.value = opt.value;
          }
          setStatus("Supreme env-pod: target pre-selected. Verify GPS + PMU on first probe.");
        }, 200);
        return;
      }
      if (id === "halow-pair") {
        if (typeof setWorkspace === "function") setWorkspace("hardware", "halow");
        setStatus("HaLow pair bringup: defaults will populate the AP/STA form on switch.");
        return;
      }
      if (id === "probe-all-ports") {
        try {
          const r = await fetch("/v1/firmware/ports", { cache: "no-store" });
          if (!r.ok) { setStatus(`Recipe: port probe failed — HTTP ${r.status}.`); return; }
          const j = await r.json();
          const ports = j?.items || j?.ports || [];
          if (!ports.length) { setStatus("Recipe: no serial ports detected — connect a board first."); return; }
          // Probe each port for a status_snapshot response
          let responding = 0;
          const probes = [];
          for (const p of ports) {
            try {
              const pr = await fetch(`/v1/firmware/probe?port=${encodeURIComponent(p.device || p.port || p)}`, { cache: "no-store" });
              if (pr.ok) {
                const pj = await pr.json();
                if (pj?.snapshot || pj?.status_snapshot) responding += 1;
                probes.push(`${p.device || p}: ${pj?.snapshot ? "✅ responding" : pj?.error || "— no snapshot"}`);
              } else {
                probes.push(`${p.device || p}: HTTP ${pr.status}`);
              }
            } catch (e) {
              probes.push(`${p.device || p}: ${e.message}`);
            }
          }
          setStatus(`Recipe: probed ${ports.length} port${ports.length === 1 ? "" : "s"}, ${responding} responding to status_snapshot.`);
          if (typeof showToast === "function") {
            showToast(`🔍 ${responding}/${ports.length} ports responded`, {
              actions: [{ label: "View Firmware", onClick: () => { if (typeof setWorkspace === "function") setWorkspace("hardware", "firmware"); }}],
            });
          }
        } catch (e) { setStatus(`Recipe: port probe failed — ${e.message}.`); }
        return;
      }
      if (id === "show-firmware-status") {
        if (typeof setWorkspace === "function") setWorkspace("hardware", "firmware");
        setStatus("Recipe: opened firmware status. Each target shows build / serial / port readiness.");
        return;
      }
      if (id === "copy-runtime-snapshot") {
        // Build Markdown summary of current runtime state
        try {
          const r = await fetch("/v1/gateway/runtime/status", { cache: "no-store" });
          if (!r.ok) { setStatus(`Recipe: runtime status unavailable — HTTP ${r.status}.`); return; }
          const j = await r.json();
          const lines = ["# OMEGA-wave Runtime Snapshot", `_${new Date().toISOString()}_`, ""];
          lines.push(`- **Mode:** ${j.mode || "unknown"}`);
          lines.push(`- **Status:** ${j.status || "unknown"}`);
          lines.push(`- **Selected role:** ${j.selected?.role?.label || j.selected?.role?.role_id || "none"}`);
          lines.push(`- **Selected port:** ${j.selected?.serial_port || "none"}`);
          lines.push(`- **Running roles:** ${(j.items || []).filter((i) => i.runtime?.status === "running").length} of ${(j.items || []).length}`);
          if (j.selected?.launch_command_text) {
            lines.push("", "## Launch command", "```", j.selected.launch_command_text, "```");
          }
          const md = lines.join("\n");
          await navigator.clipboard.writeText(md);
          setStatus("Recipe: runtime snapshot copied to clipboard.");
          if (typeof showToast === "function") showToast("📋 Runtime snapshot copied");
        } catch (e) {
          setStatus(`Recipe: snapshot failed — ${e.message}.`);
        }
        return;
      }
    }));
  }
}

function _bindControlRecipeChips() {
  for (const chip of document.querySelectorAll(".recipe-chip[data-control-recipe]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => _runRecipeChip(chip, async () => {
      const id = chip.dataset.controlRecipe;
      if (id === "select-newest-device") {
        // Pick the device that reported most recently
        const items = document.querySelectorAll(".cockpit-device, .cockpit-device-card");
        if (!items.length) { setStatus("Recipe: no devices in cockpit roster."); return; }
        // Each card has a "data-last-seen" or text with relative time
        let bestEl = null;
        let bestT = -Infinity;
        for (const it of items) {
          const ts = parseInt(it.dataset.lastSeenMs || "0", 10) || 0;
          if (ts > bestT) { bestT = ts; bestEl = it; }
        }
        if (!bestEl) bestEl = items[0];
        bestEl.click();
        setStatus(`Recipe: selected newest device (${bestEl.querySelector(".cockpit-device-name, strong")?.textContent || "unknown"}).`);
        return;
      }
      if (id === "select-asv") {
        const asv = document.querySelector(".cockpit-device[data-type='asv'], .cockpit-device-card[data-type='asv']")
          || Array.from(document.querySelectorAll(".cockpit-device, .cockpit-device-card")).find((el) => /asv/i.test(el.textContent));
        if (!asv) { setStatus("Recipe: no ASV in cockpit roster."); return; }
        asv.click();
        setStatus("Recipe: selected first ASV.");
        return;
      }
      if (id === "copy-telemetry-snapshot") {
        const groups = document.querySelectorAll(".cockpit-deck-panel .instrument-group");
        if (!groups.length) { setStatus("Recipe: no telemetry visible — select a device first."); return; }
        const lines = ["# Cockpit Telemetry Snapshot", `_${new Date().toISOString()}_`, ""];
        for (const g of groups) {
          const h3 = g.querySelector("h3")?.textContent?.trim() || "Group";
          lines.push(`## ${h3}`);
          const rows = g.querySelectorAll(".telemetry-row, .sensor-reading");
          for (const r of rows) {
            const label = r.querySelector("span:not(.unit), strong, .telemetry-label")?.textContent?.trim() || "—";
            const value = r.querySelector("b, strong:last-child, .telemetry-value")?.textContent?.trim() || "—";
            lines.push(`- **${label}:** ${value}`);
          }
          lines.push("");
        }
        try {
          await navigator.clipboard.writeText(lines.join("\n"));
          setStatus("Recipe: telemetry snapshot copied to clipboard.");
          if (typeof showToast === "function") showToast("📋 Telemetry copied");
        } catch (e) {
          setStatus(`Recipe: clipboard write failed — ${e.message}.`);
        }
        return;
      }
      if (id === "show-fleet-on-map") {
        // Same as map-recipe zoom-to-fleet, but accessible from Control
        if (typeof navigate === "function") navigate("map");
        await new Promise((r) => setTimeout(r, 300));
        const chip = document.querySelector(".recipe-chip[data-map-recipe='zoom-to-fleet']");
        if (chip) chip.click();
        return;
      }
    }));
  }
}

function _bindControlOutcomeChips() {
  for (const chip of document.querySelectorAll(".outcome-chip[data-control-outcome]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => {
      const out = chip.dataset.controlOutcome;
      switch (out) {
        case "refresh-devices": {
          // The cockpit roster pulls via loadCockpit on a timer; force one now.
          if (typeof loadCockpit === "function") {
            loadCockpit().then(() => setStatus("Device roster refreshed.")).catch((e) => setStatus(`Refresh failed: ${e.message}`));
          } else { setStatus("Device roster updates automatically every 5s."); }
          break;
        }
        case "reload-telemetry": {
          // Telemetry comes from loadCockpit -> renderCockpitDeviceTelemetry on
          // each refresh tick; force a fresh fetch.
          if (typeof loadCockpit === "function") {
            loadCockpit().then(() => setStatus("Telemetry reloaded.")).catch((e) => setStatus(`Reload failed: ${e.message}`));
          } else { setStatus("Telemetry updates automatically when a device is selected."); }
          break;
        }
        case "locate-on-map": {
          const name = document.getElementById("cockpit-status-name")?.textContent?.trim();
          if (!name || name === "No device selected") { setStatus("Select a device in the left rail first."); break; }
          if (typeof navigate === "function") navigate("map");
          setStatus(`Centering on ${name}…`);
          break;
        }
        case "copy-urn": {
          const sub = document.getElementById("cockpit-status-class")?.textContent?.trim();
          const name = document.getElementById("cockpit-status-name")?.textContent?.trim();
          if (!name || name === "No device selected") { setStatus("Select a device in the left rail first."); break; }
          const urn = sub && sub !== "—" ? sub : name;
          try {
            navigator.clipboard?.writeText(urn);
            setStatus(`Copied: ${urn}`);
          } catch { setStatus("Clipboard blocked — selection: " + urn); }
          break;
        }
        case "cmd-sample-interval": {
          const p = document.getElementById("control-parameter");
          const v = document.getElementById("control-value");
          if (p) p.value = "sample_interval_s";
          if (v) v.value = "60";
          setStatus("Pre-filled: sample_interval_s = 60. Set Target Node and Queue.");
          break;
        }
        case "cmd-status-snapshot": {
          const p = document.getElementById("control-parameter");
          const v = document.getElementById("control-value");
          if (p) p.value = "command";
          if (v) v.value = "\"status_snapshot\"";
          setStatus("Pre-filled: command = status_snapshot. Set Target Node and Queue.");
          break;
        }
        case "cmd-route-beacon": {
          const p = document.getElementById("control-parameter");
          const v = document.getElementById("control-value");
          if (p) p.value = "command";
          if (v) v.value = "\"request_route_beacon\"";
          setStatus("Pre-filled: command = request_route_beacon. Set Target Node and Queue.");
          break;
        }
        case "cmd-show-queue": {
          document.getElementById("control-command-list")?.scrollIntoView({ behavior: "smooth", block: "center" });
          break;
        }
        case "acoustic-broadcast-test": {
          const scope = document.getElementById("janus-scope-select");
          const note = document.getElementById("janus-cargo-note");
          if (scope) scope.value = "broadcast";
          if (note) note.value = "Portal broadcast test — please ACK.";
          setStatus("Pre-filled: broadcast test message.");
          break;
        }
        case "acoustic-link-budget": {
          const f = document.getElementById("acoustic-frequency");
          const t = document.getElementById("acoustic-temperature");
          const d = document.getElementById("acoustic-depth");
          const r = document.getElementById("acoustic-range");
          if (f) f.value = "10";
          if (t) t.value = "10";
          if (d) d.value = "0.1";
          if (r) r.value = "5";
          setStatus("Pre-filled propagation model: 10 kHz · 10°C · 100 m · 5 km. Analyze to see budget.");
          break;
        }
        case "acoustic-refresh": {
          if (typeof loadComms === "function") {
            loadComms().then(() => setStatus("Acoustic links + messages refreshed.")).catch((e) => setStatus(`Refresh failed: ${e.message}`));
          } else { setStatus("Acoustic data updates automatically."); }
          break;
        }
        case "acoustic-scroll-model": {
          document.getElementById("acoustic-form")?.scrollIntoView({ behavior: "smooth", block: "start" });
          break;
        }
      }
    });
  }
}

