function _bindShareOutcomeChips() {
  for (const chip of document.querySelectorAll(".outcome-chip[data-share-outcome]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", async () => {
      switch (chip.dataset.shareOutcome) {
        case "refresh": document.getElementById("refresh-remote-access-button")?.click(); break;
        case "copy-local": {
          const url = `http://127.0.0.1:${location.port || 8091}/portal-assets/portal.html`;
          await _copyText(url, "Local portal URL");
          break;
        }
        case "copy-lan": {
          // Best-effort: ask the gateway for its inferred LAN URL.
          try {
            const r = await fetch("/v1/network/remote-access");
            const j = await r.json();
            const lan = (j?.urls || []).find((u) => u.kind === "lan");
            if (lan?.url) await _copyText(lan.url, "LAN URL");
            else setStatus("No LAN URL discovered — check Sharing panel.");
          } catch (err) { setStatus(`LAN URL lookup failed: ${err.message}`); }
          break;
        }
        case "copy-public": {
          try {
            const r = await fetch("/v1/network/remote-access");
            const j = await r.json();
            const pub = (j?.urls || []).find((u) => u.kind === "public" || u.kind === "tunnel");
            if (pub?.url) await _copyText(pub.url, "Public URL");
            else setStatus("No public tunnel URL active — start one with omega_gateway_online.ps1.");
          } catch (err) { setStatus(`Public URL lookup failed: ${err.message}`); }
          break;
        }
      }
    });
  }
}
async function _copyText(text, label) {
  try { await navigator.clipboard.writeText(text); setStatus(`${label} copied: ${text}`); }
  catch { prompt(`Copy this ${label}:`, text); }
}

