function _bindInspectEmptyStateActions() {
  const ingest = document.getElementById("inspect-empty-ingest-public");
  if (ingest && !ingest._bound) {
    ingest._bound = true;
    ingest.addEventListener("click", async () => {
      ingest.textContent = "📡 Loading…";
      ingest.disabled = true;
      try {
        const headers = state?.ownerKey ? { "X-OMEGA-API-Key": state.ownerKey, "Content-Type": "application/json" } : { "Content-Type": "application/json" };
        const r = await fetch("/v1/real-data/public/ingest", { method: "POST", headers, body: "{}" });
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        const j = await r.json();
        setStatus(`Public feeds ingested: ${j?.measurements_ingested || j?.added_count || "ok"}. Refreshing tiles…`);
        setTimeout(() => { if (typeof _refreshInspectLiveTiles === "function") _refreshInspectLiveTiles(); }, 1000);
      } catch (err) {
        setStatus(`Ingest failed: ${err.message}. May need owner key set.`);
      } finally {
        ingest.textContent = "📡 Load public ocean feeds";
        ingest.disabled = false;
      }
    });
  }
  document.getElementById("inspect-empty-providers")?.addEventListener("click", () => {
    if (typeof setWorkspace === "function") setWorkspace("library", "providers");
  });
  document.getElementById("inspect-empty-honu")?.addEventListener("click", () => {
    document.getElementById("copilot-launcher")?.click();
    setTimeout(() => {
      const input = document.getElementById("copilot-input");
      if (input) {
        input.value = "The gateway has no telemetry yet. What's the fastest way to get data flowing — public feeds, a provider refresh, or something else?";
        document.getElementById("copilot-panel")?.classList.add("has-conversation");
        document.getElementById("copilot-form")?.requestSubmit?.();
      }
    }, 300);
  });
}

function _bindDiagnosticsOutcomeChips() {
  for (const chip of document.querySelectorAll(".outcome-chip[data-diag-outcome]")) {
    if (chip._bound) continue;
    chip._bound = true;
    chip.addEventListener("click", () => {
      switch (chip.dataset.diagOutcome) {
        case "preflight":   document.getElementById("run-preflight-button")?.click(); break;
        case "system-check": document.getElementById("run-system-check-button")?.click(); break;
        case "tool-finder": if (typeof openToolFinder === "function") openToolFinder(""); break;
        case "logs": setStatus("Live logs aren't exposed over HTTP for safety. SSH and run `journalctl -u omega-wave -f`."); break;
      }
    });
  }
  // Hide-passing toggle: same behavior on settings:diagnostics chip AND
  // on hardware:halow chip — both share the body[data-diag-passing] state.
  for (const btnId of ["diag-show-passing-toggle", "halow-show-passing-toggle"]) {
    const t = document.getElementById(btnId);
    if (!t || t._bound) continue;
    t._bound = true;
    if (!document.body.dataset.diagPassing) document.body.dataset.diagPassing = "hide";
    const syncT = () => {
      const hidden = document.body.dataset.diagPassing === "hide";
      t.classList.toggle("is-active", !hidden);
      t.textContent = hidden ? "👁 Show all" : "👁 Hide passing";
    };
    syncT();
    t.addEventListener("click", () => {
      document.body.dataset.diagPassing = document.body.dataset.diagPassing === "hide" ? "all" : "hide";
      // Sync both toggles
      for (const otherId of ["diag-show-passing-toggle", "halow-show-passing-toggle"]) {
        const o = document.getElementById(otherId);
        if (!o) continue;
        const hidden = document.body.dataset.diagPassing === "hide";
        o.classList.toggle("is-active", !hidden);
        o.textContent = hidden ? "👁 Show all" : "👁 Hide passing";
      }
    });
  }
  // Legacy single-toggle binding (no-op if the loop above already bound it)
  const togBtn = document.getElementById("diag-show-passing-toggle");
  if (togBtn && !togBtn._bound) {
    togBtn._bound = true;
    // Set the default to hide-passing
    if (!document.body.dataset.diagPassing) document.body.dataset.diagPassing = "hide";
    const sync = () => {
      const hidden = document.body.dataset.diagPassing === "hide";
      togBtn.classList.toggle("is-active", !hidden);
      togBtn.textContent = hidden ? "👁 Show all" : "👁 Hide passing";
      togBtn.title = hidden
        ? "PASS cards are hidden — click to reveal them"
        : "All cards visible — click to hide PASS cards";
    };
    sync();
    togBtn.addEventListener("click", () => {
      document.body.dataset.diagPassing = document.body.dataset.diagPassing === "hide" ? "all" : "hide";
      sync();
    });
  }
}

