async function _runAdminOutcome(name) {
  switch (name) {
    case "reload":
      try {
        await fetch("/v1/config/reload-credentials", { method: "POST", headers: state?.ownerKey ? { "X-OMEGA-API-Key": state.ownerKey } : {} });
        setStatus("Credentials reloaded from /etc/omega-wave.env.");
        document.getElementById("reload-credentials-button")?.click();
      } catch (err) { setStatus(`Reload failed: ${err.message}`); }
      break;
    case "check-providers":
      try {
        const r = await fetch("/v1/external/providers/status");
        const j = await r.json();
        const ok = (j?.providers || []).filter((p) => p.status === "cached" || p.map_ready).length;
        setStatus(`Provider health: ${ok}/${(j?.providers || []).length} cached or map-ready.`);
      } catch (err) { setStatus(`Health check failed: ${err.message}`); }
      break;
    case "diagnostics":
      if (typeof setWorkspace === "function") setWorkspace("settings", "diagnostics");
      break;
    case "copy-portal-url": {
      const url = `${window.location.origin}/portal-assets/portal.html`;
      try {
        await navigator.clipboard.writeText(url);
        setStatus(`Portal URL copied: ${url}`);
      } catch {
        prompt("Copy this URL:", url);
      }
      break;
    }
  }
}

async function _runWatchOutcome(name) {
  switch (name) {
    case "recheck":
      await _runAllWatchChecks().catch(() => {});
      break;
    case "show-critical": {
      // Hide watch list items with severity "clear"
      document.querySelectorAll(".watches-list .watch-item").forEach((li) => {
        const isClear = li.classList.contains("watch-severity-clear");
        li.style.display = isClear ? "none" : "";
      });
      break;
    }
    case "watch-stale":
    case "watch-waves": {
      const metric = name === "watch-stale" ? "sea-surface-temperature" : "significant-wave-height";
      // Find the freshest sample for this metric and queue a watch
      try {
        const r = await fetch(`/v1/measurements/latest?metric_name=${encodeURIComponent(metric)}&data_scope=real&limit=20`, { cache: "no-store" });
        const j = await r.json();
        const items = (j?.items || []).filter((it) => typeof it.value === "number" && it.metric_name === metric);
        if (!items.length) {
          setStatus(`No recent ${metric} samples to watch.`);
          return;
        }
        // Pick the most recently sampled
        items.sort((a, b) => Date.parse(b.sampled_at || 0) - Date.parse(a.sampled_at || 0));
        const sample = items[0];
        const nodeTail = (sample.node_id || "").split(":").pop();
        const unit = sample.unit && sample.unit !== "1" ? sample.unit : "";
        const cfg = INSPECT_LIVE_METRIC_CONFIG[metric] || {};
        _addWatch({
          nodeId: sample.node_id,
          label: `${nodeTail} · ${cfg.label || metric}`,
          metric,
          baselineValue: sample.value,
          thresholdPct: 0.10,
          unit,
        });
      } catch (err) {
        setStatus(`Add-watch failed: ${err.message}`);
      }
      break;
    }
    case "clear-all": {
      if (!confirm("Remove every watch? This cannot be undone.")) return;
      _saveWatches([]);
      _renderWatchesList();
      _refreshAlertsBadgeFromWatches();
      break;
    }
  }
}

function _initWatchesQuickAdd() {
  const form = document.getElementById("watches-quickadd-form");
  if (!form || form._bound) return;
  form._bound = true;
  // Mirror Chart Builder's metric + station dropdowns into our own selects.
  // Use a polling approach since those selects populate asynchronously.
  const metricTarget = document.getElementById("watches-quickadd-metric");
  const nodeTarget = document.getElementById("watches-quickadd-node");
  const tryMirror = () => {
    const metricSrc = document.getElementById("visualization-metric-select");
    const nodeSrc = document.getElementById("visualization-station-select");
    if (metricSrc?.options?.length && metricTarget && metricTarget.options.length <= 1) {
      metricTarget.innerHTML = `<option value="">Metric…</option>` + Array.from(metricSrc.options).map((o) => `<option value="${o.value}">${o.textContent}</option>`).join("");
    }
    if (nodeSrc?.options?.length && nodeTarget && nodeTarget.options.length <= 1) {
      nodeTarget.innerHTML = `<option value="">Station…</option>` + Array.from(nodeSrc.options).map((o) => `<option value="${o.value}">${o.textContent}</option>`).join("");
    }
    return metricTarget?.options.length > 1 && nodeTarget?.options.length > 1;
  };
  if (!tryMirror()) {
    let attempts = 0;
    const t = setInterval(() => {
      if (tryMirror() || ++attempts > 20) clearInterval(t);
    }, 500);
  }

  form.addEventListener("submit", async (e) => {
    e.preventDefault();
    const metric = metricTarget?.value;
    const nodeRaw = nodeTarget?.value;
    const threshold = Number(document.getElementById("watches-quickadd-threshold")?.value) / 100;
    if (!metric || !nodeRaw) {
      setStatus("Pick a metric and station first.");
      return;
    }
    // station-select values are "node_id|device_id" — split off the node part
    const nodeId = nodeRaw.split("|")[0];
    const nodeLabel = nodeTarget.options[nodeTarget.selectedIndex]?.textContent || nodeId;
    const metricLabel = metricTarget.options[metricTarget.selectedIndex]?.textContent || metric;
    try {
      // Fetch a current sample as the baseline
      const since = new Date(Date.now() - 30 * 24 * 3600 * 1000).toISOString();
      const r = await fetch(`/v1/measurements?metric_name=${encodeURIComponent(metric)}&node_id=${encodeURIComponent(nodeId)}&start_at=${encodeURIComponent(since)}&data_scope=real&limit=1`, { cache: "no-store" });
      const j = await r.json();
      const sample = j?.items?.[0];
      if (!sample || typeof sample.value !== "number") {
        setStatus(`No recent numeric samples for ${metricLabel} at ${nodeLabel}. Cannot set baseline.`);
        return;
      }
      const baseline = sample.value;
      const unit = sample.unit && sample.unit !== "1" ? sample.unit : "";
      _addWatch({
        nodeId,
        label: `${nodeLabel} · ${metricLabel}`,
        metric,
        baselineValue: baseline,
        thresholdPct: threshold,
        unit,
      });
      form.reset();
      document.getElementById("watches-quickadd-threshold").value = "10";
    } catch (err) {
      setStatus(`Quick-add watch failed: ${err.message}`);
    }
  });
}

function _addWatch(opts) {
  // Wraps the existing watch creation flow with a known signature.
  const watches = _loadWatches();
  const id = `watch-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
  const watch = {
    id, nodeId: opts.nodeId, label: opts.label, metric: opts.metric,
    baseline: opts.baselineValue, thresholdPct: opts.thresholdPct, unit: opts.unit || "",
    createdAt: Date.now(), lastValue: opts.baselineValue, lastCheckedAt: Date.now(),
    lastSeverity: "clear", lastDeviationPct: 0,
  };
  watches.push(watch);
  _saveWatches(watches);
  setStatus(`🚨 Anomaly watch set: ${opts.label} · ${opts.metric} ${opts.baselineValue.toFixed(2)}${opts.unit ? ` ${opts.unit}` : ""} ± ${Math.round(opts.thresholdPct * 100)}%`);
  _renderWatchesList();
  return watch;
}

function _renderWatchesList() {
  const host = document.getElementById("watches-list");
  if (!host) return;
  // First render of this session: kick off a backend fetch in the
  // background. The fetch will call _renderWatchesList again when it
  // returns with fresh data; for now we render from whatever the
  // legacy cache holds so the panel isn't empty during the round-trip.
  if (!_watchesBackendReady) {
    _refreshWatchesFromBackend();
  }
  const watches = _loadWatches();
  if (!watches.length) {
    host.classList.add("empty");
    host.innerHTML = `<div class="empty-state" data-empty="watches">
      <p class="muted small">No anomaly watches yet. Add one from any pin's detail panel — the 🚨 button next to the trend chart sets a watch on that station's current metric value. The lighthouse Alerts badge will glow amber or red when one of your watches breaks its threshold.</p>
      <div class="empty-state-actions">
        <button type="button" class="button button-secondary" data-empty-jump="pinpoint">📍 Drop pins to start watching</button>
      </div>
    </div>`;
    _bindEmptyStateActions(host);
    return;
  }
  host.classList.remove("empty");
  host.innerHTML = `<ul class="watches-list-ul">${watches.map((w) => {
    const severity = w.lastSeverity || "clear";
    const dev = Number.isFinite(w.lastDeviationPct) ? `${(w.lastDeviationPct * 100).toFixed(1)}%` : "—";
    // Defensive formatting — corrupted localStorage entries shouldn't
    // crash the whole watches list rendering with TypeError on undefined.
    const baselineFmt = Number.isFinite(w.baseline) ? w.baseline.toFixed(2) : "—";
    const thresholdFmt = Number.isFinite(w.thresholdPct) ? Math.round(w.thresholdPct * 100) : "—";
    const checkedFmt = w.lastCheckedAt ? new Date(w.lastCheckedAt).toLocaleTimeString() : "never";
    return `<li class="watch-item watch-severity-${severity}">
      <div class="watch-icon">${severity === "critical" ? "🔴" : severity === "warning" ? "🟡" : "🟢"}</div>
      <div class="watch-body">
        <strong>${_escResearch(w.label || w.metric || "Untitled watch")}</strong>
        <span class="muted small">${_escResearch(w.metric || "?")} · baseline <strong>${baselineFmt}${w.unit ? ` ${_escResearch(w.unit)}` : ""}</strong> ± ${thresholdFmt}%</span>
        <span class="muted small">Last: <strong>${Number.isFinite(w.lastValue) ? w.lastValue.toFixed(2) : "—"}${w.unit ? ` ${_escResearch(w.unit)}` : ""}</strong> (${dev} deviation) · checked ${checkedFmt}</span>
      </div>
      <div class="watch-sparkline live-tile-sparkline" data-watch-spark="${_escResearch(w.id)}" data-spark-for="${_escResearch(w.metric)}" data-spark-node="${_escResearch(w.nodeId)}"></div>
      <button type="button" class="watch-chart" data-watch-chart-metric="${_escResearch(w.metric)}" data-watch-chart-node="${_escResearch(w.nodeId)}" title="Open quick chart for this metric+site">📊</button>
      <button type="button" class="watch-recheck" data-watch-recheck="${_escResearch(w.id)}" title="Re-fetch and re-evaluate">↺</button>
      <button type="button" class="watch-remove" data-watch-remove="${_escResearch(w.id)}" title="Remove watch">×</button>
    </li>`;
  }).join("")}</ul>`;
  host.querySelectorAll("[data-watch-remove]").forEach((b) => b.addEventListener("click", () => _removeWatch(b.dataset.watchRemove)));
  host.querySelectorAll("[data-watch-recheck]").forEach((b) => b.addEventListener("click", () => _runWatchCheck(b.dataset.watchRecheck).catch(showError)));
  host.querySelectorAll("[data-watch-chart-metric]").forEach((b) => b.addEventListener("click", () => {
    if (typeof _openQuickChart === "function") _openQuickChart(b.dataset.watchChartMetric, b.dataset.watchChartNode);
  }));
  // Fetch + draw sparkline for each watch (reuses the Inspect sparkline cache
  // and drawer — that's why the container has both .watch-sparkline +
  // .live-tile-sparkline classes and the data-spark-for/-node attrs).
  host.querySelectorAll("[data-watch-spark]").forEach((sparkHost) => {
    const metric = sparkHost.dataset.sparkFor;
    const node = sparkHost.dataset.sparkNode;
    if (metric && node && typeof _fetchAndDrawSparkline === "function") {
      _fetchAndDrawSparkline(metric, node);
    }
  });
}

async function _runWatchCheck(watchId) {
  // Backend mode: ask the gateway to evaluate the watch now and
  // re-fetch the list. This shares logic with the periodic scheduler
  // — the result here is identical to what would fire on the 60s tick.
  try {
    await api(`/v1/watches/${encodeURIComponent(watchId)}/evaluate-now`, {}, { method: "POST" });
    await _refreshWatchesFromBackend();
    return;
  } catch (err) {
    // If the backend isn't reachable, fall through to the legacy
    // client-side computation so the page still has a "recheck"
    // affordance offline.
    if (typeof console !== "undefined") {
      console.warn("Watch evaluate-now failed, falling back to client-side check:", err);
    }
  }
  // Legacy fallback (client computes deviation locally from the
  // metric series; kept so disconnected use still works).
  const watches = _loadWatches();
  const watch = watches.find((w) => w.id === watchId);
  if (!watch) return;
  try {
    const byMetric = await _researchFetchStationSeries(watch.nodeId);
    const points = byMetric.get(watch.metric);
    if (!points || !points.length) {
      watch.lastSeverity = "clear"; watch.lastValue = null; watch.lastDeviationPct = 0;
    } else {
      const current = points[0].value;
      const dev = watch.baseline !== 0 ? Math.abs((current - watch.baseline) / watch.baseline) : 0;
      watch.lastValue = current; watch.lastDeviationPct = dev;
      if (dev >= watch.thresholdPct * 2) watch.lastSeverity = "critical";
      else if (dev >= watch.thresholdPct) watch.lastSeverity = "warning";
      else watch.lastSeverity = "clear";
    }
    watch.lastCheckedAt = Date.now();
    _renderWatchesList();
    _refreshAlertsBadgeFromWatches();
  } catch (err) { setStatus(`Watch check failed for ${watch.label}: ${err.message}`); }
}

async function _runAllWatchChecks() {
  // Backend handles this via the 60s scheduled evaluator. Still
  // expose a one-shot manual run for the UI button.
  await _refreshWatchesFromBackend();
  const watches = _loadWatches();
  for (const w of watches) { try { await _runWatchCheck(w.id); } catch {} }
}

function _refreshAlertsBadgeFromWatches() {
  const badge = document.getElementById("alerts-badge");
  if (!badge) return;
  const watches = _loadWatches();
  let worst = "clear";
  for (const w of watches) {
    if (w.lastSeverity === "critical") { worst = "critical"; break; }
    if (w.lastSeverity === "warning" && worst === "clear") worst = "warning";
  }
  badge.dataset.severity = worst;
  badge.classList.toggle("is-clear", worst === "clear");
}

// ──────────────────────────────────────────────────────────────────
//   NOTIFICATIONS BELL — header badge + dropdown panel.
//   Backed by /v1/notifications. Polls the unread-count endpoint
//   every 30s for the badge. Click opens a dropdown with the
//   recent list + per-row mark-read / dismiss actions.
// ──────────────────────────────────────────────────────────────────
const _NOTIF_POLL_MS = 30000;
let _notifEventSource = null;          // live SSE stream when available
let _notifSSEFailedOnce = false;       // sticky: pin to polling after a confirmed SSE failure
let _notifPollTimer = null;
let _notifBellBound = false;
let _notifCache = [];

/** Light pull — only the count. Called by the timer; cheap. */
async function _refreshNotificationsCount() {
  if (typeof api !== "function") return;
  try {
    const resp = await api("/v1/notifications/unread-count");
    const count = Number(resp?.unread_count ?? 0);
    const badge = document.getElementById("notifications-bell-count");
    if (!badge) return;
    if (count > 0) {
      badge.hidden = false;
      badge.textContent = count > 99 ? "99+" : String(count);
    } else {
      badge.hidden = true;
    }
  } catch {
    // Backend unreachable / pre-restart — keep the badge hidden, don't toast.
  }
}

/** Full pull — list + cache + render. Called on bell click + refresh. */
async function _refreshNotificationsList() {
  if (typeof api !== "function") return;
  try {
    const resp = await api("/v1/notifications?limit=50");
    _notifCache = Array.isArray(resp?.items) ? resp.items : [];
    _renderNotificationsList();
    // Update the badge from the same response (saves a roundtrip).
    const count = Number(resp?.unread_count ?? 0);
    const badge = document.getElementById("notifications-bell-count");
    if (badge) {
      if (count > 0) { badge.hidden = false; badge.textContent = count > 99 ? "99+" : String(count); }
      else { badge.hidden = true; }
    }
  } catch (err) {
    const list = document.getElementById("notifications-list");
    if (list) list.innerHTML = `<p class="notifications-empty">Notifications unavailable: ${err && err.message ? err.message : err}</p>`;
  }
}

function _renderNotificationsList() {
  const list = document.getElementById("notifications-list");
  if (!list) return;
  if (_notifCache.length === 0) {
    list.innerHTML = `<p class="notifications-empty">No notifications yet. Watches that fire and command failures will show up here.</p>`;
    return;
  }
  list.innerHTML = _notifCache.map((n) => {
    const ts = _shortRelativeTime(n.created_at);
    const severityClass = `is-${n.severity || "info"}`;
    const unreadClass = n.is_unread ? "is-unread" : "";
    const iconForKind = ({
      "watch.fired": "🚨",
      "command.ack_timeout": "⏱",
      "command.failed": "❌",
      "command.sent": "📤",
      "system": "ℹ️",
    })[n.kind] || "•";
    const dataLine = _notifDataLine(n);
    return `<article class="notifications-item ${severityClass} ${unreadClass}" data-notif-id="${escapeHtml(n.notification_id)}">
      <div class="notifications-item-icon" aria-hidden="true">${iconForKind}</div>
      <div class="notifications-item-body">
        <div class="notifications-item-head">
          <strong class="notifications-item-title">${escapeHtml(n.title || "(no title)")}</strong>
          <span class="notifications-item-time muted small">${escapeHtml(ts)}</span>
        </div>
        <p class="notifications-item-text">${escapeHtml(n.body || "")}</p>
        ${dataLine ? `<p class="notifications-item-meta muted small">${dataLine}</p>` : ""}
      </div>
      <div class="notifications-item-actions">
        ${_notifKindActions(n)}
        ${n.is_unread ? `<button type="button" class="notifications-item-action" data-notif-act="read" title="Mark read">✓</button>` : ""}
        <button type="button" class="notifications-item-action" data-notif-act="dismiss" title="Dismiss">×</button>
      </div>
    </article>`;
  }).join("");
}

/** Kind-specific "primary" action buttons (Retry for command failures,
 *  Open Watch for fired watches). These complement the universal
 *  read/dismiss icons by giving the operator a one-click recovery /
 *  drill-down path for the alert. Returns "" when the kind has no
 *  bespoke action so the icons render in their usual position. */
function _notifKindActions(n) {
  const d = n.data || {};
  if (n.kind === "command.ack_timeout" || n.kind === "command.failed") {
    const commandId = d.command_id || n.source_id;
    if (!commandId) return "";
    return `<button type="button" class="notifications-item-action notifications-item-action-primary"
              data-notif-act="retry-command" data-command-id="${escapeHtml(commandId)}"
              title="Re-queue this command with the same parameters">↺ Retry</button>`;
  }
  if (n.kind === "watch.fired") {
    const watchId = d.watch_id || n.source_id;
    if (!watchId) return "";
    return `<button type="button" class="notifications-item-action notifications-item-action-primary"
              data-notif-act="open-watch" data-watch-id="${escapeHtml(watchId)}"
              title="Open this watch in the Watches panel">→ Open watch</button>`;
  }
  if (n.kind === "control.applied") {
    // 13/N: deep-link into the Recent Applies panel, pre-filtering by
    // (node, device, profile). source_id format is "node|device|profile".
    const node = d.node_id || "";
    const device = d.device_id || "";
    const profile = d.profile_id || "";
    if (!node || !profile) return "";
    const args = [node, device, profile].map(encodeURIComponent).join("|");
    return `<button type="button" class="notifications-item-action notifications-item-action-primary"
              data-notif-act="open-config-history" data-history-args="${escapeHtml(args)}"
              title="Open this device's apply history">→ Open history</button>`;
  }
  return "";
}

/** Build a tiny meta line from the notification's structured data — useful
 *  context (metric, value, target) without paying the cost of a deep-link. */
function _notifDataLine(n) {
  const d = n.data || {};
  const bits = [];
  if (d.metric) bits.push(`metric: ${escapeHtml(String(d.metric))}`);
  if (d.value !== undefined && d.value !== null) bits.push(`value: ${escapeHtml(String(d.value))}`);
  if (d.target_node_id) bits.push(`target: ${escapeHtml(String(d.target_node_id))}`);
  if (d.profile_id) bits.push(`profile: ${escapeHtml(String(d.profile_id))}`);
  return bits.join(" · ");
}

/** Relative-time string ("5 min ago", "2h ago", "May 28 12:34") for the
 *  notification header. ISO input. */
function _shortRelativeTime(iso) {
  if (!iso) return "";
  const t = Date.parse(iso);
  if (!Number.isFinite(t)) return iso;
  const diff = (Date.now() - t) / 1000;
  if (diff < 60) return "just now";
  if (diff < 3600) return `${Math.floor(diff / 60)} min ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return new Date(t).toLocaleString();
}

async function _markNotificationRead(notificationId) {
  try {
    await api(`/v1/notifications/${encodeURIComponent(notificationId)}/read`, {}, { method: "POST" });
    // Optimistic local update
    const n = _notifCache.find((x) => x.notification_id === notificationId);
    if (n) { n.is_unread = false; n.read_at = new Date().toISOString(); }
    _renderNotificationsList();
    _refreshNotificationsCount();
  } catch (err) {
    if (typeof setStatus === "function") setStatus(`Could not mark notification read: ${err.message || err}`);
  }
}

async function _dismissNotification(notificationId) {
  try {
    await api(`/v1/notifications/${encodeURIComponent(notificationId)}/dismiss`, {}, { method: "POST" });
    _notifCache = _notifCache.filter((n) => n.notification_id !== notificationId);
    _renderNotificationsList();
    _refreshNotificationsCount();
  } catch (err) {
    if (typeof setStatus === "function") setStatus(`Could not dismiss notification: ${err.message || err}`);
  }
}

/** Retry a command from its ack_timeout / failed notification. Calls the
 *  backend retry endpoint (which creates a brand-new control_command
 *  copying target/profile/params), marks the source notification read,
 *  and surfaces the new command_id via setStatus so the operator can
 *  follow up. The original command + notification stay intact (the new
 *  command has its own lifecycle + future notifications). */
async function _retryCommandFromNotification(notificationId, commandId) {
  if (!commandId) {
    if (typeof setStatus === "function") setStatus("Cannot retry — command_id missing from notification.");
    return;
  }
  try {
    const resp = await api(
      `/v1/control/commands/${encodeURIComponent(commandId)}/retry`,
      {},
      { method: "POST" },
    );
    // Mark the original notification read so it stops nagging.
    if (notificationId) await _markNotificationRead(notificationId);
    const newId = (resp && resp.command_id) || "(unknown)";
    if (typeof setStatus === "function") {
      setStatus(`Retry queued — new command_id: ${newId}`);
    }
  } catch (err) {
    if (typeof setStatus === "function") {
      setStatus(`Could not retry command: ${err.message || err}`);
    }
  }
}

/** Deep-link from a watch.fired notification into the Watches panel.
 *  Navigates to the Inspect page, switches to the watches workspace
 *  section, then scrolls + briefly highlights the matching row.
 *  Closes the notifications panel so the operator's context shifts
 *  fully to the watch. */
function _openConfigHistoryFromNotification(packed) {
  // 13/N: deep-link from a control.applied bell row to the Recent
  // Applies panel pre-filtered to that (node, device, profile)
  // triple. `packed` is "node|device|profile" with URL-encoded parts
  // (so a literal "|" inside any of them survives).
  if (!packed) return;
  const parts = packed.split("|").map(decodeURIComponent);
  if (parts.length !== 3) return;
  const [node, device, profile] = parts;
  // Navigate to the Control page if we're not there.
  const tab = document.querySelector('[data-page="control"]');
  if (tab) tab.click();
  // Find the panel and populate the filter inputs.
  setTimeout(() => {
    const nodeInput = document.getElementById("device-config-history-node-filter");
    const deviceInput = document.getElementById("device-config-history-device-filter");
    const profileInput = document.getElementById("device-config-history-profile-filter");
    if (nodeInput) nodeInput.value = node;
    if (deviceInput) deviceInput.value = device;
    if (profileInput) profileInput.value = profile;
    // Refresh.
    if (typeof loadDeviceConfigHistory === "function") loadDeviceConfigHistory();
    // Scroll to the panel.
    const panel = document.getElementById("instrument-device-config-history");
    if (panel) {
      panel.scrollIntoView({behavior: "smooth", block: "start"});
      panel.classList.add("audit-pivot-highlight");
      setTimeout(() => panel.classList.remove("audit-pivot-highlight"), 2400);
    }
  }, 150);
  // Close the bell.
  if (typeof _closeNotificationsPanel === "function") _closeNotificationsPanel();
}

function _openWatchFromNotification(watchId) {
  if (!watchId) {
    if (typeof setStatus === "function") setStatus("Cannot open watch — watch_id missing from notification.");
    return;
  }
  if (typeof navigate === "function") navigate("inspect");
  if (typeof setWorkspace === "function") setWorkspace("inspect", "watches");
  _closeNotificationsPanel();
  // Let the DOM update after the navigate + workspace switch, then
  // find the matching row. We retry briefly because the watches list
  // may render asynchronously after a backend refresh.
  let attempts = 0;
  const tryHighlight = () => {
    attempts += 1;
    const list = document.getElementById("watches-list");
    if (!list) {
      if (attempts < 10) setTimeout(tryHighlight, 100);
      return;
    }
    // Watch rows don't carry a single data-watch-id, but every child
    // button has data-watch-remove="<id>" — find the parent <li>.
    const safeId = (typeof CSS !== "undefined" && CSS.escape) ? CSS.escape(watchId) : watchId.replace(/"/g, "\\\"");
    const button = list.querySelector(`[data-watch-remove="${safeId}"]`);
    const row = button ? button.closest(".watch-item") : null;
    if (!row) {
      if (attempts < 10) setTimeout(tryHighlight, 100);
      return;
    }
    row.scrollIntoView({ behavior: "smooth", block: "center" });
    row.classList.add("watch-item-highlight");
    setTimeout(() => row.classList.remove("watch-item-highlight"), 2000);
  };
  setTimeout(tryHighlight, 50);
}

async function _markAllNotificationsRead() {
  try {
    await api("/v1/notifications/read-all", {}, { method: "POST" });
    for (const n of _notifCache) { n.is_unread = false; n.read_at = new Date().toISOString(); }
    _renderNotificationsList();
    _refreshNotificationsCount();
  } catch (err) {
    if (typeof setStatus === "function") setStatus(`Could not mark all read: ${err.message || err}`);
  }
}

function _openNotificationsPanel() {
  const panel = document.getElementById("notifications-panel");
  const bell = document.getElementById("notifications-bell");
  if (!panel || !bell) return;
  panel.hidden = false;
  bell.setAttribute("aria-expanded", "true");
  _refreshNotificationsList();
}

function _closeNotificationsPanel() {
  const panel = document.getElementById("notifications-panel");
  const bell = document.getElementById("notifications-bell");
  if (!panel || !bell) return;
  panel.hidden = true;
  bell.setAttribute("aria-expanded", "false");
}

// ── Current user / session state ─────────────────────────────────────
// On load: fetch /v1/auth/me + /v1/auth/bootstrap-status. If the
// gateway requires auth AND we're not signed in, redirect to /login
// (which handles the "no users yet → bootstrap" path too). If we ARE
// signed in, populate the header user-display chip + bind the
// dropdown's logout button.
//
// Stays out of the way when owner_auth_disabled (demo mode): no
// redirect, no chip. The chip also hides cleanly when the auth
// surface isn't reachable (e.g. very old gateway) — the rest of the
// portal continues to work.

let _userSessionLoaded = false;
let _userSessionState = null;    // {user, session} | {user: null}

// BBS sysop alias: every "SYSOP" label / author in the BBS data is
// replaced at render time with the current logged-in admin's handle.
// Non-admin sysops (e.g. "HONU" for sanctuary) stay as-is. Falls back
// to "SYSOP" when nobody is logged in or the user isn't admin.
function _bbsAdminHandle() {
  const u = _userSessionState && _userSessionState.user;
  if (!u || u.role !== "admin") return "SYSOP";
  const raw = (u.display_name && u.display_name.trim()) || u.username || "";
  return raw ? raw.toUpperCase() : "SYSOP";
}
function _bbsRelabelSysop(value) {
  // Replace standalone "SYSOP" tokens (word-boundary or start/end of
  // string) with the admin handle. Preserves prefixes/suffixes like
  // "SYSOP  May 28" → "JDCAPONE  May 28".
  if (value == null) return value;
  const handle = _bbsAdminHandle();
  if (handle === "SYSOP") return value;
  // Match only whole-word SYSOP so partial matches (e.g. "SYSOPNAME")
  // are left alone.
  return String(value).replace(/\bSYSOP\b/g, handle);
}

// True when the logged-in user is an admin — gates all the elevated
// BBS moderation powers (pin / lock / resolve / delete, sysop-authored
// posts). Non-admins + logged-out browsers see the BBS read-only with
// the normal member composer. The forum is localStorage-backed +
// per-browser today, so this is a client-side gate; when a server-
// backed forum lands, the same check maps onto API authorization.
function _bbsIsSysop() {
  const u = _userSessionState && _userSessionState.user;
  return !!(u && u.role === "admin");
}

async function _safeFetchAuthState() {
  // Returns {me, status} or null on hard failure. Each call is wrapped
  // so a fetch failure on one half doesn't block the other.
  let me = null;
  let status = null;
  try {
    const resp = await fetch("/v1/auth/me", { credentials: "same-origin" });
    if (resp.ok) me = await resp.json();
  } catch {}
  try {
    const resp = await fetch("/v1/auth/bootstrap-status", { credentials: "same-origin" });
    if (resp.ok) status = await resp.json();
  } catch {}
  if (me === null && status === null) return null;
  return { me, status };
}

async function _initUserSessionState() {
  if (_userSessionLoaded) return _userSessionState;
  _userSessionLoaded = true;
  const state = await _safeFetchAuthState();
  if (!state) {
    // Couldn't reach the auth endpoints at all — leave the chip
    // hidden + don't redirect. The rest of the portal will surface
    // its own errors on the next gateway call.
    _userSessionState = null;
    return null;
  }
  const user = state.me && state.me.user;
  const authRequired = state.status && state.status.auth_required !== false;
  // Decide on redirect FIRST so we don't paint the header for a
  // user who's about to be redirected away.
  if (!user && authRequired) {
    // Avoid redirect loops if we're already on /login somehow.
    if (!/^\/login(?:[\/?#]|$)/.test(window.location.pathname)) {
      window.location.href = "/login?next=" + encodeURIComponent(
        window.location.pathname + window.location.search + window.location.hash
      );
      return null;
    }
  }
  _userSessionState = { user, session: state.me && state.me.session, status: state.status };
  // Auth resolves async — if the BBS already painted as a plain member
  // (before the session loaded), re-render it now so the SysOp powers
  // appear without a manual reload. Guarded by DOM presence so this is
  // a no-op on every other page.
  try {
    if (typeof renderForumPage === "function" && document.getElementById("forum-thread-detail")) {
      renderForumPage();
    }
  } catch (_e) {}
  return _userSessionState;
}

function _renderUserDisplay(state) {
  const btn = document.getElementById("user-display");
  const panel = document.getElementById("user-display-panel");
  if (!btn || !panel) return;
  const user = state && state.user;
  if (!user) {
    // No user OR auth not required → keep the chip hidden.
    btn.hidden = true;
    panel.hidden = true;
    return;
  }
  // Populate the chip + dropdown content.
  const nameEl = document.getElementById("user-display-name");
  const fullEl = document.getElementById("user-display-fullname");
  const metaEl = document.getElementById("user-display-meta");
  if (nameEl) nameEl.textContent = user.display_name || user.username || "operator";
  if (fullEl) fullEl.textContent = user.display_name ? `${user.display_name} (${user.username})` : user.username;
  if (metaEl) {
    const role = user.role || "operator";
    const lastLogin = user.last_login_at ? new Date(user.last_login_at).toLocaleString() : "never";
    metaEl.textContent = `role: ${role} · last login: ${lastLogin}`;
  }
  btn.hidden = false;
}

function _bindUserDisplay() {
  const btn = document.getElementById("user-display");
  if (!btn || btn.dataset.bound === "1") return;
  btn.dataset.bound = "1";

  btn.addEventListener("click", (event) => {
    event.stopPropagation();
    const panel = document.getElementById("user-display-panel");
    if (!panel) return;
    if (panel.hidden) {
      panel.hidden = false;
      btn.setAttribute("aria-expanded", "true");
    } else {
      panel.hidden = true;
      btn.setAttribute("aria-expanded", "false");
    }
  });

  // Close on outside-click + Esc.
  document.addEventListener("click", (event) => {
    const panel = document.getElementById("user-display-panel");
    if (!panel || panel.hidden) return;
    if (event.target.closest("#user-display-panel") || event.target.closest("#user-display")) return;
    panel.hidden = true;
    btn.setAttribute("aria-expanded", "false");
  });
  document.addEventListener("keydown", (event) => {
    if (event.key !== "Escape") return;
    const panel = document.getElementById("user-display-panel");
    if (panel && !panel.hidden) {
      panel.hidden = true;
      btn.setAttribute("aria-expanded", "false");
    }
  });

  const logoutBtn = document.getElementById("user-display-logout");
  if (logoutBtn) {
    logoutBtn.addEventListener("click", async () => {
      logoutBtn.disabled = true;
      logoutBtn.textContent = "Logging out…";
      try {
        await fetch("/v1/auth/logout", { method: "POST", credentials: "same-origin" });
      } catch {}
      // After logout, send them to /login. If auth_required=false in
      // demo mode this is still fine — /login is reachable everywhere
      // and presents the right state for the gateway it's hitting.
      window.location.href = "/login";
    });
  }

  // ── Change password form toggle + submit ───────────────────────
  const changeBtn = document.getElementById("user-display-change-password");
  const cpForm = document.getElementById("user-display-change-password-form");
  const cpCancel = document.getElementById("user-display-change-password-cancel");
  const cpStatus = document.getElementById("user-cp-status");
  const cpCurrent = document.getElementById("user-cp-current");
  const cpNew = document.getElementById("user-cp-new");
  const cpConfirm = document.getElementById("user-cp-confirm");

  function _cpReset() {
    if (cpForm) cpForm.hidden = true;
    if (changeBtn) changeBtn.hidden = false;
    if (logoutBtn) logoutBtn.hidden = false;
    if (cpStatus) { cpStatus.textContent = ""; cpStatus.classList.remove("is-error", "is-ok"); }
    if (cpCurrent) cpCurrent.value = "";
    if (cpNew) cpNew.value = "";
    if (cpConfirm) cpConfirm.value = "";
  }

  if (changeBtn && cpForm) {
    changeBtn.addEventListener("click", () => {
      cpForm.hidden = false;
      changeBtn.hidden = true;
      if (logoutBtn) logoutBtn.hidden = true;
      if (cpCurrent) cpCurrent.focus();
    });
  }
  if (cpCancel) {
    cpCancel.addEventListener("click", _cpReset);
  }
  if (cpForm) {
    cpForm.addEventListener("submit", async (event) => {
      event.preventDefault();
      if (!cpStatus) return;
      cpStatus.classList.remove("is-error", "is-ok");
      const current = (cpCurrent && cpCurrent.value) || "";
      const next = (cpNew && cpNew.value) || "";
      const confirm = (cpConfirm && cpConfirm.value) || "";
      if (!current || !next || !confirm) {
        cpStatus.classList.add("is-error");
        cpStatus.textContent = "All three fields are required.";
        return;
      }
      if (next.length < 8) {
        cpStatus.classList.add("is-error");
        cpStatus.textContent = "New password must be at least 8 characters.";
        return;
      }
      if (next !== confirm) {
        cpStatus.classList.add("is-error");
        cpStatus.textContent = "New password and confirm do not match.";
        return;
      }
      const submitBtn = cpForm.querySelector('button[type="submit"]');
      if (submitBtn) submitBtn.disabled = true;
      cpStatus.textContent = "Updating…";
      try {
        const resp = await fetch("/v1/auth/password", {
          method: "POST",
          credentials: "same-origin",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ current_password: current, new_password: next }),
        });
        const ct = resp.headers.get("content-type") || "";
        const body = ct.includes("application/json") ? await resp.json().catch(() => null) : null;
        if (!resp.ok) {
          const detail = (body && body.detail) || `HTTP ${resp.status}`;
          cpStatus.classList.add("is-error");
          cpStatus.textContent = typeof detail === "string" ? detail : JSON.stringify(detail);
          if (submitBtn) submitBtn.disabled = false;
          return;
        }
        cpStatus.classList.add("is-ok");
        const revoked = (body && body.other_sessions_revoked) || 0;
        cpStatus.textContent = revoked > 0
          ? `Password updated. ${revoked} other session${revoked === 1 ? "" : "s"} logged out.`
          : "Password updated.";
        // Auto-collapse after a short success message so the dropdown
        // doesn't grow a stuck "success" pill the next time it opens.
        setTimeout(_cpReset, 2200);
      } catch (err) {
        cpStatus.classList.add("is-error");
        cpStatus.textContent = err && err.message ? err.message : "Request failed.";
        if (submitBtn) submitBtn.disabled = false;
      }
    });
  }
}

async function _initUserDisplayPanel() {
  const state = await _initUserSessionState();
  if (!state) return;   // either redirecting or auth surface unreachable
  _renderUserDisplay(state);
  _bindUserDisplay();
  // Best-effort: also init the users admin panel if we're on the
  // Settings page + the current session is admin. It's a no-op on
  // any other page (the DOM elements just won't exist).
  _initUsersPanel(state).catch(() => {});
  _initLoginSecurityPanel(state).catch(() => {});
  // 23/N: Audit Trail panel — same workspace, NOT admin-gated (any
  // authenticated operator can view audit). No-op when the DOM
  // section doesn't exist (other pages).
  _initAuditTrailPanel().catch(() => {});
}

// ── Multi-user login: Login Security panel (Settings → Login Security) ──
// Lists currently-blocked IPs from GET /v1/auth/rate-limit + lets an
// admin unblock a specific IP or clear all. Hidden + admin-only
// notice for non-admin sessions.

async function _initLoginSecurityPanel(sessionState) {
  const panel = document.getElementById("login-security-panel");
  if (!panel) return;
  const gate = document.getElementById("login-security-admin-gate");
  const list = document.getElementById("login-security-list");
  const refreshBtn = document.getElementById("login-security-refresh");
  const clearBtn = document.getElementById("login-security-clear-all");
  // Same admin-gate convention as the Users panel: show for sessions
  // with role=admin OR for callers with no /v1/auth/me user (loopback
  // / owner_key flow, which bypass admin gate at the API).
  const user = sessionState && sessionState.user;
  const isAdmin = !user || user.role === "admin";
  if (!isAdmin) {
    if (gate) gate.hidden = false;
    if (list) list.style.display = "none";
    if (refreshBtn) refreshBtn.style.display = "none";
    if (clearBtn) clearBtn.style.display = "none";
    return;
  }
  if (refreshBtn && !refreshBtn.dataset.bound) {
    refreshBtn.dataset.bound = "1";
    refreshBtn.addEventListener("click", () => _loadLoginSecurityList());
  }
  if (clearBtn && !clearBtn.dataset.bound) {
    clearBtn.dataset.bound = "1";
    clearBtn.addEventListener("click", _handleLoginSecurityClearAll);
  }
  await _loadLoginSecurityList();
}

async function _loadLoginSecurityList() {
  const list = document.getElementById("login-security-list");
  if (!list) return;
  list.classList.add("empty");
  list.textContent = "Loading rate-limited IPs…";
  try {
    const resp = await fetch("/v1/auth/rate-limit", { credentials: "same-origin" });
    if (!resp.ok) {
      list.textContent = resp.status === 403
        ? "Admin access required."
        : `Could not load: ${resp.statusText}`;
      return;
    }
    const body = await resp.json();
    const items = body.items || [];
    if (items.length === 0) {
      list.textContent = "No IPs are currently rate-limited. Nothing to do.";
      return;
    }
    list.classList.remove("empty");
    list.innerHTML = items.map(_renderLoginSecurityRow).join("");
    list.querySelectorAll("[data-rl-unblock]").forEach((btn) => {
      btn.addEventListener("click", () => _handleLoginSecurityUnblock(btn.dataset.rlUnblock));
    });
  } catch (err) {
    list.textContent = `Could not load: ${(err && err.message) || err}`;
  }
}

function _renderLoginSecurityRow(row) {
  // Format the cooldown end + remaining time. Both come from the
  // server so clocks don't drift between operator + gateway.
  const until = row.until || "?";
  const retry = Number(row.retry_after_s) || 0;
  const retryStr = retry < 60
    ? `${retry}s`
    : retry < 3600
      ? `${Math.floor(retry / 60)} min`
      : `${(retry / 3600).toFixed(1)} h`;
  return `<article class="rl-row" data-rl-ip="${escapeHtml(row.ip_address)}">
    <div class="rl-row-head">
      <div>
        <strong class="rl-row-ip">${escapeHtml(row.ip_address)}</strong>
        <div class="muted small">Retry in <strong>${escapeHtml(retryStr)}</strong> · cooldown ends ${escapeHtml(until)}</div>
      </div>
      <div class="rl-row-actions">
        <button type="button" class="button button-secondary" data-rl-unblock="${escapeHtml(row.ip_address)}">Unblock</button>
      </div>
    </div>
  </article>`;
}

async function _handleLoginSecurityUnblock(ip) {
  if (!ip) return;
  if (!window.confirm(`Unblock ${ip}? They'll be able to attempt login immediately.`)) return;
  try {
    const resp = await fetch("/v1/auth/rate-limit/unblock", {
      method: "POST",
      credentials: "same-origin",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ip_address: ip }),
    });
    const body = await resp.json().catch(() => null);
    if (!resp.ok) {
      alert(`Unblock failed: ${(body && body.detail) || resp.statusText}`);
      return;
    }
    if (typeof setStatus === "function" && body) {
      setStatus(body.unblocked ? `Unblocked ${ip}.` : `${ip} wasn't blocked.`);
    }
    await _loadLoginSecurityList();
  } catch (err) {
    alert(`Unblock failed: ${(err && err.message) || err}`);
  }
}

async function _handleLoginSecurityClearAll() {
  if (!window.confirm("Drop EVERY IP cooldown? Use only when the rate-limiter is widely misconfigured.")) return;
  try {
    const resp = await fetch("/v1/auth/rate-limit", {
      method: "DELETE", credentials: "same-origin",
    });
    const body = await resp.json().catch(() => null);
    if (!resp.ok) {
      alert(`Clear failed: ${(body && body.detail) || resp.statusText}`);
      return;
    }
    if (typeof setStatus === "function" && body) {
      setStatus(`Cleared ${body.cleared_count} IP cooldown(s).`);
    }
    await _loadLoginSecurityList();
  } catch (err) {
    alert(`Clear failed: ${(err && err.message) || err}`);
  }
}

// ── 23/N: Audit Trail panel (Settings → Login Security) ─────────────
// Renders the GET /v1/audit/admin-actions feed as a chronological
// list with action-family badges and operator filters. Visible to
// any authenticated session — NOT admin-gated (audit visibility is
// the point). State is held in a module-level object so the family
// chips and window selector can refire the load without each
// handler needing to know about the others.

const _AUDIT_TRAIL_STATE = {
  familyPrefix: "",     // "" | "user-mgmt-" | "rate-limit-"
  windowMinutes: 1440,  // matches the default <select> option
};

async function _initAuditTrailPanel() {
  const panel = document.getElementById("audit-trail-panel");
  if (!panel) return;
  const refreshBtn = document.getElementById("audit-trail-refresh");
  const windowSel = document.getElementById("audit-trail-window");
  const familyChips = panel.querySelectorAll("[data-audit-family]");
  if (refreshBtn && !refreshBtn.dataset.bound) {
    refreshBtn.dataset.bound = "1";
    refreshBtn.addEventListener("click", () => _loadAuditTrailList());
  }
  if (windowSel && !windowSel.dataset.bound) {
    windowSel.dataset.bound = "1";
    windowSel.addEventListener("change", () => {
      _AUDIT_TRAIL_STATE.windowMinutes = Number(windowSel.value) || 1440;
      _loadAuditTrailList();
    });
  }
  familyChips.forEach((chip) => {
    if (chip.dataset.bound) return;
    chip.dataset.bound = "1";
    chip.addEventListener("click", () => {
      familyChips.forEach((c) => c.classList.remove("is-active"));
      chip.classList.add("is-active");
      _AUDIT_TRAIL_STATE.familyPrefix = chip.dataset.auditFamily || "";
      _loadAuditTrailList();
    });
  });
  await _loadAuditTrailList();
}

async function _loadAuditTrailList() {
  const list = document.getElementById("audit-trail-list");
  if (!list) return;
  list.classList.add("empty");
  list.textContent = "Loading audit trail…";
  try {
    const params = new URLSearchParams();
    if (_AUDIT_TRAIL_STATE.familyPrefix) {
      params.set("source_id_prefix", _AUDIT_TRAIL_STATE.familyPrefix);
    }
    params.set("since_minutes", String(_AUDIT_TRAIL_STATE.windowMinutes));
    params.set("limit", "200");
    const url = `/v1/audit/admin-actions?${params.toString()}`;
    const resp = await fetch(url, { credentials: "same-origin" });
    if (!resp.ok) {
      list.textContent = resp.status === 401
        ? "You must be signed in to view the audit trail."
        : `Could not load: ${resp.statusText}`;
      return;
    }
    const body = await resp.json();
    const items = body.items || [];
    if (items.length === 0) {
      const family = _AUDIT_TRAIL_STATE.familyPrefix
        ? ` for ${_AUDIT_TRAIL_STATE.familyPrefix.replace(/-$/, "")}`
        : "";
      list.textContent = `No admin actions${family} in the selected window.`;
      return;
    }
    list.classList.remove("empty");
    list.innerHTML = items.map(_renderAuditTrailRow).join("");
    // 24/N: bind pivot buttons.
    list.querySelectorAll("[data-audit-pivot]").forEach((btn) => {
      btn.addEventListener("click", () => {
        _handleAuditPivot(btn.dataset.auditPivotTarget, btn.dataset.auditPivot);
      });
    });
    // 25/N: insert sticky-header date dividers when the window is
    // 7d or longer (the 24h default is dense enough not to need them).
    if (_AUDIT_TRAIL_STATE.windowMinutes >= 10080) {
      _injectAuditDateDividers(list);
    }
  } catch (err) {
    list.textContent = `Could not load: ${(err && err.message) || err}`;
  }
}

function _renderAuditTrailRow(row) {
  // The audit-row data shape:
  //   - source_id: "user-mgmt-user-create" | "rate-limit-unblock" | ...
  //   - data.action: short label ("user-create", "unblock")
  //   - data.detail: human-readable summary
  //   - data.admin_username, data.admin_kind: who did it
  //   - data.target_username (user-mgmt only)
  //   - created_at: ISO timestamp
  const d = row.data || {};
  const action = d.action || "?";
  const family = (row.source_id || "").startsWith("user-mgmt-")
    ? "user-mgmt"
    : (row.source_id || "").startsWith("rate-limit-")
      ? "rate-limit"
      : "other";
  const who = d.admin_username
    ? escapeHtml(d.admin_username)
    : `(${escapeHtml(d.admin_kind || "unknown")})`;
  const adminKind = d.admin_kind ? escapeHtml(d.admin_kind) : "unknown";
  const target = d.target_username ? escapeHtml(d.target_username) : "";
  const detail = d.detail ? escapeHtml(String(d.detail)) : "";
  const when = row.created_at
    ? escapeHtml(String(row.created_at).replace("T", " ").replace("Z", " UTC"))
    : "";
  // 24/N: per-row "Pivot to" link. user-mgmt rows jump to the target
  // user in the Users panel; rate-limit rows jump to the IP in the
  // Login Security panel. We render as a button so the click handler
  // can scroll + highlight without a full page reload.
  let pivotHtml = "";
  if (family === "user-mgmt" && d.target_username) {
    pivotHtml = `<button type="button" class="audit-row-pivot" data-audit-pivot="user" data-audit-pivot-target="${escapeHtml(d.target_username)}" title="Jump to ${escapeHtml(d.target_username)} in the Users panel">→ Users</button>`;
  } else if (family === "rate-limit" && d.detail) {
    // detail for rate-limit-unblock is the IP; rate-limit-clear-all
    // detail is "N cooldown(s)" so guard against that.
    const looksLikeIp = /^[\d.:a-fA-F]+$/.test(d.detail);
    if (looksLikeIp) {
      pivotHtml = `<button type="button" class="audit-row-pivot" data-audit-pivot="ip" data-audit-pivot-target="${escapeHtml(d.detail)}" title="Jump to ${escapeHtml(d.detail)} in Login Security">→ Login Security</button>`;
    }
  }
  return `<article class="audit-row" data-audit-family="${escapeHtml(family)}" data-audit-when="${escapeHtml(row.created_at || "")}">
    <div class="audit-row-head">
      <div class="audit-row-action">
        <span class="audit-row-family-badge audit-row-family-${escapeHtml(family)}">${escapeHtml(family)}</span>
        <strong>${escapeHtml(action)}</strong>
      </div>
      <div class="audit-row-when muted small">${when}</div>
    </div>
    <div class="audit-row-detail">${detail}</div>
    <div class="audit-row-meta muted small">
      <span>by <strong>${who}</strong> <span class="muted">(${adminKind})</span></span>
      ${target ? `<span>· target: <strong>${target}</strong></span>` : ""}
      ${pivotHtml}
    </div>
  </article>`;
}

function _handleAuditPivot(target, kind) {
  // 24/N: pivot from an audit row to the relevant panel + highlight
  // the matched item. The target panel is on the same workspace tab
  // (settings:login-security has rate-limit; user-mgmt is at
  // settings:users) — both already render before the audit list, so
  // the pivot is just a scroll + highlight.
  if (kind === "user") {
    // Open the Users tab + scroll to the row.
    const tab = document.querySelector('[data-workspace-tab="settings:users"]');
    if (tab) tab.click();
    setTimeout(() => {
      const row = Array.from(document.querySelectorAll(".user-row")).find((el) => {
        const name = el.querySelector(".user-row-name");
        return name && name.textContent.trim().includes(target);
      });
      if (row) {
        row.scrollIntoView({behavior: "smooth", block: "center"});
        row.classList.add("audit-pivot-highlight");
        setTimeout(() => row.classList.remove("audit-pivot-highlight"), 2400);
      }
    }, 100);
  } else if (kind === "ip") {
    // Stay on the Login Security tab + scroll to the rate-limit row.
    setTimeout(() => {
      const row = document.querySelector(`[data-rl-ip="${CSS.escape(target)}"]`);
      if (row) {
        row.scrollIntoView({behavior: "smooth", block: "center"});
        row.classList.add("audit-pivot-highlight");
        setTimeout(() => row.classList.remove("audit-pivot-highlight"), 2400);
      } else if (typeof setStatus === "function") {
        setStatus(`No active cooldown for ${target} — it may have already expired.`);
      }
    }, 100);
  }
}

function _injectAuditDateDividers(host) {
  // 25/N: insert sticky-header date dividers between rows from
  // different UTC days. Runs after the list renders. Keeps a 24h
  // window clean (just one or zero dividers) and makes 7d/30d
  // visually scannable.
  const rows = Array.from(host.querySelectorAll(".audit-row[data-audit-when]"));
  let lastDay = "";
  rows.forEach((row) => {
    const when = row.dataset.auditWhen || "";
    const day = when.slice(0, 10);  // YYYY-MM-DD
    if (!day) return;
    if (day !== lastDay) {
      const divider = document.createElement("div");
      divider.className = "audit-date-divider";
      divider.textContent = day;
      host.insertBefore(divider, row);
      lastDay = day;
    }
  });
}

// ── Multi-user login: admin Users panel (Settings → Users) ──────────
// Lists every user, lets the admin add/edit/disable/reset-password/
// delete via the 6/N endpoints. Hides itself + shows a friendly
// "admin only" notice for non-admin sessions.

async function _initUsersPanel(sessionState) {
  const panel = document.getElementById("users-panel");
  if (!panel) return;   // not on the Settings page
  const gate = document.getElementById("users-admin-gate");
  const list = document.getElementById("users-list");
  const addFold = document.getElementById("users-add-fold");
  // Admin gate: if the current session is non-admin, hide list +
  // form, show the friendly notice. owner_key + loopback callers
  // bypass the role check at the API; they SEE the panel because
  // /v1/auth/me returned null (kind: loopback isn't a session).
  // To keep the UI honest, show the panel to anyone whose
  // /v1/auth/me returned no user (legacy/loopback access path) OR
  // whose role is 'admin'.
  const user = sessionState && sessionState.user;
  const isAdmin = !user || user.role === "admin";
  if (!isAdmin) {
    if (gate) gate.hidden = false;
    if (list) list.style.display = "none";
    if (addFold) addFold.style.display = "none";
    return;
  }
  // Wire refresh + add-user submit + initial load.
  const refreshBtn = document.getElementById("users-refresh");
  if (refreshBtn && !refreshBtn.dataset.bound) {
    refreshBtn.dataset.bound = "1";
    refreshBtn.addEventListener("click", () => _loadUsersAdminList());
  }
  const addForm = document.getElementById("users-add-form");
  if (addForm && !addForm.dataset.bound) {
    addForm.dataset.bound = "1";
    addForm.addEventListener("submit", _handleAddUserSubmit);
  }
  await _loadUsersAdminList();
}

async function _loadUsersAdminList() {
  const list = document.getElementById("users-list");
  if (!list) return;
  list.classList.add("empty");
  list.textContent = "Loading users…";
  try {
    const resp = await fetch("/v1/users", { credentials: "same-origin" });
    if (!resp.ok) {
      const detail = await resp.text();
      list.textContent = resp.status === 403
        ? "Admin access required to list users."
        : `Could not load users: ${detail || resp.statusText}`;
      return;
    }
    const body = await resp.json();
    const users = body.items || [];
    if (users.length === 0) {
      list.textContent = "No users yet. Add one below.";
      return;
    }
    list.classList.remove("empty");
    list.innerHTML = users.map(_renderUserAdminRow).join("");
    _bindUserAdminRowActions(users);
  } catch (err) {
    list.textContent = `Could not load users: ${(err && err.message) || err}`;
  }
}

function _renderUserAdminRow(u) {
  const lastLogin = u.last_login_at ? new Date(u.last_login_at).toLocaleString() : "never";
  const roleBadge = `<span class="user-row-role role-${escapeHtml(u.role)}">${escapeHtml(u.role)}</span>`;
  const disabledBadge = u.disabled
    ? `<span class="user-row-disabled">disabled</span>`
    : "";
  const display = u.display_name
    ? `${escapeHtml(u.display_name)} <span class="muted small">(${escapeHtml(u.username)})</span>`
    : `<strong>${escapeHtml(u.username)}</strong>`;
  return `<article class="user-row" data-user-id="${u.id}" data-user-username="${escapeHtml(u.username)}" data-user-role="${escapeHtml(u.role)}" data-user-disabled="${u.disabled ? '1' : '0'}">
    <div class="user-row-head">
      <div>${display} ${roleBadge} ${disabledBadge}</div>
      <div class="user-row-actions">
        <button type="button" class="button button-secondary" data-user-act="reset-pw" title="Reset this user's password (revokes their sessions)">Reset password</button>
        <button type="button" class="button button-secondary" data-user-act="toggle-disabled" title="${u.disabled ? 'Re-enable login' : 'Disable login (sessions die immediately)'}">${u.disabled ? 'Enable' : 'Disable'}</button>
        <button type="button" class="button button-secondary" data-user-act="change-role" title="Change this user's role">Change role</button>
        <button type="button" class="button button-secondary" data-user-act="delete" title="Permanently delete this user">Delete</button>
      </div>
    </div>
    <div class="muted small">last login: ${escapeHtml(lastLogin)} · created ${escapeHtml(u.created_at || '')}</div>
  </article>`;
}

function _bindUserAdminRowActions(users) {
  const list = document.getElementById("users-list");
  if (!list) return;
  list.querySelectorAll("[data-user-act]").forEach((btn) => {
    btn.addEventListener("click", async () => {
      const row = btn.closest(".user-row");
      if (!row) return;
      const userId = Number(row.dataset.userId);
      const username = row.dataset.userUsername;
      const currentRole = row.dataset.userRole;
      const disabled = row.dataset.userDisabled === "1";
      const act = btn.dataset.userAct;
      try {
        if (act === "reset-pw") {
          const pw = window.prompt(`New password for ${username} (8+ chars). Their active sessions will be logged out.`);
          if (!pw) return;
          if (pw.length < 8) { alert("Password must be at least 8 characters."); return; }
          const resp = await fetch(`/v1/users/${userId}/password`, {
            method: "POST", credentials: "same-origin",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ password: pw }),
          });
          if (!resp.ok) throw new Error((await resp.json()).detail || resp.statusText);
          const body = await resp.json();
          alert(`Password reset. ${body.sessions_revoked} session(s) revoked.`);
        } else if (act === "toggle-disabled") {
          const verb = disabled ? "re-enable" : "disable";
          if (!window.confirm(`${verb.charAt(0).toUpperCase() + verb.slice(1)} user ${username}?`)) return;
          const resp = await fetch(`/v1/users/${userId}`, {
            method: "PUT", credentials: "same-origin",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ disabled: !disabled }),
          });
          if (!resp.ok) throw new Error((await resp.json()).detail || resp.statusText);
        } else if (act === "change-role") {
          const next = window.prompt(`New role for ${username} (admin | operator | viewer). Current: ${currentRole}`, currentRole);
          if (!next) return;
          if (!["admin", "operator", "viewer"].includes(next)) {
            alert("Role must be admin, operator, or viewer.");
            return;
          }
          const resp = await fetch(`/v1/users/${userId}`, {
            method: "PUT", credentials: "same-origin",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ role: next }),
          });
          if (!resp.ok) throw new Error((await resp.json()).detail || resp.statusText);
        } else if (act === "delete") {
          if (!window.confirm(`PERMANENTLY DELETE ${username}? Their sessions will be revoked + they can no longer log in.`)) return;
          const resp = await fetch(`/v1/users/${userId}`, {
            method: "DELETE", credentials: "same-origin",
          });
          if (!resp.ok && resp.status !== 204) {
            const body = await resp.json().catch(() => null);
            throw new Error((body && body.detail) || resp.statusText);
          }
        } else {
          return;
        }
        // Re-render after any successful action so the badges + last-login refresh.
        await _loadUsersAdminList();
      } catch (err) {
        alert(`Action failed: ${(err && err.message) || err}`);
      }
    });
  });
}

async function _handleAddUserSubmit(event) {
  event.preventDefault();
  const status = document.getElementById("users-add-status");
  const username = document.getElementById("users-add-username").value.trim();
  const display_name = document.getElementById("users-add-display-name").value.trim() || null;
  const role = document.getElementById("users-add-role").value;
  const password = document.getElementById("users-add-password").value;
  if (status) status.textContent = "Creating user…";
  try {
    const resp = await fetch("/v1/users", {
      method: "POST", credentials: "same-origin",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username, password, role, display_name }),
    });
    const body = await resp.json().catch(() => null);
    if (!resp.ok) {
      const detail = (body && body.detail) || resp.statusText;
      if (status) {
        status.textContent = `Failed: ${detail}`;
        status.style.color = "var(--err, #ff7a7a)";
      }
      return;
    }
    if (status) {
      status.textContent = `Created ${body.username} (${body.role}).`;
      status.style.color = "var(--ok, #8df5b1)";
    }
    document.getElementById("users-add-username").value = "";
    document.getElementById("users-add-display-name").value = "";
    document.getElementById("users-add-password").value = "";
    document.getElementById("users-add-role").value = "operator";
    await _loadUsersAdminList();
  } catch (err) {
    if (status) {
      status.textContent = `Failed: ${(err && err.message) || err}`;
      status.style.color = "var(--err, #ff7a7a)";
    }
  }
}

if (typeof document !== "undefined") {
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", () => { _initUserDisplayPanel(); });
  } else {
    setTimeout(() => { _initUserDisplayPanel(); }, 0);
  }
}

function _bindNotificationsBell() {
  if (_notifBellBound) return;
  const bell = document.getElementById("notifications-bell");
  if (!bell) return;    // template not loaded yet
  _notifBellBound = true;
  bell.addEventListener("click", (event) => {
    event.stopPropagation();
    const panel = document.getElementById("notifications-panel");
    if (!panel) return;
    if (panel.hidden) _openNotificationsPanel();
    else _closeNotificationsPanel();
  });
  document.getElementById("notifications-close")?.addEventListener("click", _closeNotificationsPanel);
  document.getElementById("notifications-mark-all")?.addEventListener("click", _markAllNotificationsRead);
  document.getElementById("notifications-refresh")?.addEventListener("click", _refreshNotificationsList);
  // Per-item delegated clicks
  document.getElementById("notifications-list")?.addEventListener("click", (event) => {
    const btn = event.target.closest("[data-notif-act]");
    if (!btn) return;
    const item = btn.closest("[data-notif-id]");
    if (!item) return;
    const id = item.dataset.notifId;
    const act = btn.dataset.notifAct;
    if (act === "read") _markNotificationRead(id);
    else if (act === "dismiss") _dismissNotification(id);
    else if (act === "retry-command") _retryCommandFromNotification(id, btn.dataset.commandId);
    else if (act === "open-watch") _openWatchFromNotification(btn.dataset.watchId);
    else if (act === "open-config-history") _openConfigHistoryFromNotification(btn.dataset.historyArgs);
  });
  // Close on outside-click + Esc
  document.addEventListener("click", (event) => {
    const panel = document.getElementById("notifications-panel");
    if (!panel || panel.hidden) return;
    if (event.target.closest("#notifications-panel") || event.target.closest("#notifications-bell")) return;
    _closeNotificationsPanel();
  });
  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape") {
      const panel = document.getElementById("notifications-panel");
      if (panel && !panel.hidden) _closeNotificationsPanel();
    }
  });
  // Initial fetch so the badge populates immediately.
  _refreshNotificationsCount();
  // Prefer live SSE; fall back to 30s polling if EventSource isn't
  // available (older browsers, opted-out clients, gateway pre-restart).
  _startNotificationStream();
}

/** Open the SSE stream for live notification pushes. Returns true if
 *  the EventSource was created, false if we should fall back to
 *  polling. Auto-reconnect is handled by the browser; we only fall
 *  back permanently if construction itself throws. */
function _startNotificationStream() {
  if (_notifSSEFailedOnce) {
    _ensureNotificationPolling();
    return false;
  }
  if (typeof EventSource === "undefined") {
    _notifSSEFailedOnce = true;
    _ensureNotificationPolling();
    return false;
  }
  try {
    if (_notifEventSource) { try { _notifEventSource.close(); } catch {} }
    _notifEventSource = new EventSource("/v1/notifications/stream");
  } catch {
    _notifEventSource = null;
    _notifSSEFailedOnce = true;
    _ensureNotificationPolling();
    return false;
  }
  // Initial unread-count sync on connect — saves a /unread-count
  // round-trip the first time the bell wakes up.
  _notifEventSource.addEventListener("count", (event) => {
    try {
      const data = JSON.parse(event.data);
      _setNotificationsBadge(typeof data.unread_count === "number" ? data.unread_count : 0);
    } catch {}
  });
  // Live notification → prepend to cache, re-render if panel is open,
  // bump the badge. Optimistic UI; no round-trip.
  _notifEventSource.addEventListener("notification", (event) => {
    try {
      const n = JSON.parse(event.data);
      if (!n || !n.notification_id) return;
      // Avoid duplicate prepend if the client already has this row
      // (e.g. from a manual refresh that overlapped with the push).
      if (!_notifCache.some((x) => x.notification_id === n.notification_id)) {
        _notifCache.unshift(n);
      }
      _renderNotificationsList();
      _refreshNotificationsCount();
    } catch {}
  });
  _notifEventSource.onerror = () => {
    // Browser handles auto-reconnect. We only flip to permanent
    // polling if the EventSource enters CLOSED (readyState 2) —
    // that means the browser gave up reconnecting.
    if (_notifEventSource && _notifEventSource.readyState === 2) {
      _notifEventSource = null;
      _notifSSEFailedOnce = true;
      _ensureNotificationPolling();
    }
  };
  // Belt-and-suspenders: still poll once every 5 min as a safety net
  // in case SSE silently stalls between events (proxy bug, etc.).
  if (_notifPollTimer) clearInterval(_notifPollTimer);
  _notifPollTimer = setInterval(_refreshNotificationsCount, 5 * 60 * 1000);
  return true;
}

/** Switch to / ensure the polling fallback. Called when SSE isn't
 *  usable. */
function _ensureNotificationPolling() {
  if (_notifPollTimer) clearInterval(_notifPollTimer);
  _notifPollTimer = setInterval(_refreshNotificationsCount, _NOTIF_POLL_MS);
}

/** Imperatively set the badge — used by the SSE count event so the
 *  client doesn't need to refetch immediately on connect. */
function _setNotificationsBadge(unreadCount) {
  const badge = document.getElementById("notifications-bell-count");
  if (!badge) return;
  if (unreadCount > 0) {
    badge.textContent = unreadCount > 99 ? "99+" : String(unreadCount);
    badge.hidden = false;
  } else {
    badge.hidden = true;
    badge.textContent = "0";
  }
}

// Boot the bell once the DOM is ready. Works whether portal.js loads
// before or after DOMContentLoaded because we use a deferred check.
if (typeof document !== "undefined") {
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", _bindNotificationsBell);
  } else {
    setTimeout(_bindNotificationsBell, 0);
  }
}

