  // Re-strip on DOM mutation so dynamically inserted chips (e.g. recipes
  // injected by JS, briefing cards, Honu welcome chips) also get cleaned.
  if (typeof MutationObserver !== "undefined") {
    const _emojiObserver = new MutationObserver(() => {
      // Debounce to one pass per microtask
      if (_emojiObserver._scheduled) return;
      _emojiObserver._scheduled = true;
      Promise.resolve().then(() => {
        _emojiObserver._scheduled = false;
        _stripEmojiFromChips();
      });
    });
    _emojiObserver.observe(document.body, { childList: true, subtree: true });
  }
  // Default: hide PASS cards across diagnostics, halow checks, etc.
